  `work_hours` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '工作时间',
  `price_c1` decimal(10, 2) NULL DEFAULT NULL COMMENT 'C1价格',
  `price_c2` decimal(10, 2) NULL DEFAULT NULL COMMENT 'C2价格',
