INSERT INTO `biz_question` VALUES (1, 1, 1, '驾驶机动车在道路上违反道路交通安全法的行为，属于什么行为？', '违章行为', '违法行为', '过失行为', '违规行为', 'B', '违反道路交通安全法即为违法行为。', NULL, '安全法', '2026-05-09 16:03:40');
INSERT INTO `biz_question` VALUES (2, 1, 2, '驾驶机动车应当随身携带机动车驾驶证。', '正确', '错误', NULL, NULL, 'A', '《道路交通安全法》规定驾驶人应随车携带驾驶证。', NULL, '安全法', '2026-05-09 16:03:40');
INSERT INTO `biz_question` VALUES (3, 1, 3, '下列哪些行为会被记12分？', '饮酒后驾驶机动车', '使用伪造号牌', '超速50%以上', '闯两次红灯', 'ABC', '多项违法可合并记分，具体以当地法规为准。', NULL, '记分', '2026-05-09 16:03:40');
INSERT INTO `biz_question` VALUES (4, 4, 1, '遇行人正在通过人行横道时，应当？', '加速通过', '停车让行', '鸣喇叭驱赶', '绕行', 'B', '人行横道必须礼让行人。', NULL, '文明驾驶', '2026-05-09 16:03:40');
INSERT INTO `biz_question` VALUES (5, 4, 2, '高速公路上车辆发生故障后，警告标志应设置在故障车来车方向多少米以外？', '50米', '100米', '150米', '200米', 'C', '高速公路规定150米以外。', NULL, '高速公路', '2026-05-09 16:03:40');
INSERT INTO `biz_question` VALUES (6, 1, 1, '机动车驾驶人违法驾驶造成重大交通事故构成犯罪的，依法追究什么责任？', '行政责任', '刑事责任', '民事责任', '经济责任', 'B', '构成交通肇事罪等须追究刑事责任。', NULL, '法律责任', '2026-05-09 16:03:54');
INSERT INTO `biz_question` VALUES (7, 1, 1, '初次申领机动车驾驶证的有效期为几年？', '3年', '6年', '10年', '长期', 'B', '初次领证有效期为6年。', NULL, '驾驶证', '2026-05-09 16:03:54');
INSERT INTO `biz_question` VALUES (8, 1, 2, '红色圆圈内白横杠标志表示禁止车辆驶入。', '正确', '错误', NULL, NULL, 'A', '禁止驶入标志为红底白横杠。', NULL, '交通标志', '2026-05-09 16:03:54');
INSERT INTO `biz_question` VALUES (9, 1, 1, '看到“注意儿童”标志时，驾驶人应当？', '加速通过', '适当减速、注意观察', '鸣喇叭驱赶', '停车让行', 'B', '学校、小区附近常见，应减速观察。', NULL, '交通标志', '2026-05-09 16:03:54');
INSERT INTO `biz_question` VALUES (10, 1, 3, '下列哪些情形不得驾驶机动车？', '饮酒', '服用国家管制的精神药品', '过度疲劳', '患有妨碍安全驾驶疾病', 'ABCD', '任一条均不得驾驶。', NULL, '安全驾驶', '2026-05-09 16:03:54');
INSERT INTO `biz_question` VALUES (11, 4, 1, '驾驶机动车通过没有交通信号灯的路口时，应当？', '快速通过', '减速慢行并让行人和优先车辆先行', '鸣喇叭示意', '跟随大车通过', 'B', '无灯路口应礼让、谨慎通过。', NULL, '文明驾驶', '2026-05-09 16:03:54');
INSERT INTO `biz_question` VALUES (12, 4, 1, '雨天行车，制动距离会如何变化？', '变短', '不变', '变长', '视车速而定', 'C', '路面附着系数下降，制动距离变长。', NULL, '恶劣气象', '2026-05-09 16:03:54');
INSERT INTO `biz_question` VALUES (13, 4, 2, '在高速公路上倒车、逆行、穿越中央分隔带掉头的，一次记12分。', '正确', '错误', NULL, NULL, 'A', '高速公路严重违法记分规定。', NULL, '高速公路', '2026-05-09 16:03:54');
INSERT INTO `biz_question` VALUES (14, 4, 1, '车辆发生爆胎时，驾驶人应？', '紧急制动', '猛打方向', '握稳方向、缓踩制动、靠边停车', '立即熄火滑行', 'C', '避免急刹与急打方向导致失控。', NULL, '紧急情况', '2026-05-09 16:03:54');
INSERT INTO `biz_question` VALUES (15, 4, 3, '雾天驾驶机动车在高速公路行驶，下列做法正确的是？', '开启雾灯和危险报警闪光灯', '能见度低于50米时从最近出口驶离', '与前车保持更大安全距离', '超速尽快驶离雾区', 'ABC', '雾天应降速、加大车距、正确用灯。', NULL, '恶劣气象', '2026-05-09 16:03:54');
INSERT INTO `biz_question` VALUES (16, 1, 1, '黄色虚线划于路段中时，用以分隔对向行驶的交通流，车辆可以？', '不得越线', '在确保安全时可以越线超车或掉头', '必须停车', '仅允许左转', 'B', '黄虚线在保证安全时可越线。', NULL, '标线', '2026-05-09 16:03:54');
INSERT INTO `biz_question` VALUES (17, 1, 2, '实习期内驾驶机动车可以单独上高速公路行驶。', '正确', '错误', NULL, NULL, 'B', '须有持相应或更高准驾车型驾驶证3年以上驾驶人陪同。', NULL, '实习期', '2026-05-09 16:03:54');
INSERT INTO `biz_question` VALUES (18, 4, 1, '遇到执行紧急任务的救护车时，应当？', '穿插超越', '让行', '抢行', '紧跟行驶', 'B', '应主动让行特种车辆。', NULL, '文明驾驶', '2026-05-09 16:03:54');
INSERT INTO `biz_question` VALUES (19, 1, 1, '连续驾驶中型以上载客汽车超过4小时未停车休息的，停车休息时间不得少于？', '10分钟', '20分钟', '30分钟', '40分钟', 'B', '防止疲劳驾驶。', NULL, '疲劳', '2026-05-09 16:03:54');
INSERT INTO `biz_question` VALUES (20, 4, 2, '行车中在车内向道路抛撒物品属于违法行为。', '正确', '错误', NULL, NULL, 'A', '影响安全与环境卫生。', NULL, '文明驾驶', '2026-05-09 16:03:54');
INSERT INTO `biz_question` VALUES (21, 1, 1, '驾驶机动车在道路上违反道路交通安全法的行为，属于什么行为？', '违章行为', '违法行为', '过失行为', '违规行为', 'B', '违反道路交通安全法的行为属于违法行为，需承担相应的法律责任。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (22, 1, 1, '机动车驾驶人初次申领驾驶证后的实习期为多长时间？', '6个月', '12个月', '18个月', '24个月', 'B', '机动车驾驶人初次申领驾驶证后的实习期为12个月，实习期内驾驶机动车需遵守相关规定。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (23, 1, 1, '在道路上驾驶机动车，血液酒精含量达到多少毫克/100毫升属于醉酒驾驶？', '20', '40', '60', '80', 'D', '血液酒精含量≥80mg/100ml属于醉酒驾驶，涉嫌危险驾驶罪，需承担刑事责任。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (24, 1, 1, '机动车在高速公路上行驶，最低车速不得低于多少公里/小时？', '60', '80', '100', '120', 'A', '高速公路最低车速不得低于60公里/小时，最高车速不得超过120公里/小时。', NULL, '高速公路', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (25, 1, 1, '驾驶机动车在高速公路上倒车、逆行、穿越中央分隔带掉头的，一次记多少分？', '3分', '6分', '9分', '12分', 'D', '在高速公路上倒车、逆行、穿越中央分隔带掉头的，属于严重交通违法行为，一次记12分。', NULL, '记分', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (26, 1, 1, '驾驶机动车不按规定避让校车的，一次记多少分？', '3分', '6分', '9分', '12分', 'B', '驾驶机动车不按规定避让校车的，一次记6分，同时可处200元罚款。', NULL, '记分', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (27, 1, 1, '在路口遇到红灯时，机动车应当怎么做？', '停在停止线以外', '停在停止线以内', '缓慢通过路口', '加速通过路口', 'A', '红灯亮时，机动车应当停在停止线以外，不得越过停止线进入路口。', NULL, '交通信号', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (28, 1, 1, '驾驶机动车在没有中心线的城市道路上行驶，最高车速不得超过多少公里/小时？', '30', '40', '50', '60', 'A', '在没有中心线的城市道路上行驶，最高车速不得超过30公里/小时，确保行车安全。', NULL, '车速规定', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (29, 1, 1, '机动车在夜间通过没有交通信号灯控制的交叉路口时，应当怎么做？', '使用远光灯', '使用近光灯', '交替使用远近光灯示意', '关闭前照灯', 'C', '夜间通过没有交通信号灯控制的交叉路口，应当交替使用远近光灯示意，提醒其他车辆和行人注意。', NULL, '灯光使用', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (30, 1, 1, '驾驶机动车在高速公路上发生故障，难以移动时，应当在车后多少米以外设置警告标志？', '50米', '100米', '150米', '200米', 'C', '高速公路上车辆发生故障难以移动时，应当在车后150米以外设置警告标志，夜间还需开启示廓灯和后位灯。', NULL, '高速公路', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (31, 1, 1, '下列哪种证件是驾驶机动车上路行驶必须随车携带的？', '机动车登记证', '机动车行驶证', '购车发票', '车辆保险单', 'B', '驾驶机动车上道路行驶，必须随车携带机动车行驶证和驾驶证，未携带的将被处罚。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (32, 1, 1, '驾驶机动车在道路上行驶时，不允许有下列哪种行为？', '按规定使用安全带', '接打手持电话', '按交通信号指示行驶', '按规定车道行驶', 'B', '驾驶机动车时接打手持电话属于违法行为，会分散注意力，增加交通事故风险，一次记3分。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (33, 1, 1, '机动车在狭窄的山路会车有困难时，应当怎么做？', '速度快的一方让行', '重车让空车', '靠山体的一方让行', '不靠山体的一方让行', 'D', '在狭窄的山路会车有困难时，不靠山体的一方应当停车让行，确保会车安全。', NULL, '会车让行', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (34, 1, 1, '驾驶机动车在雨天临时停车时，应当开启什么灯？', '前后雾灯', '危险报警闪光灯', '前大灯', '倒车灯', 'B', '雨天临时停车时，应当开启危险报警闪光灯，提醒其他车辆注意避让，防止发生追尾事故。', NULL, '灯光使用', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (35, 1, 1, '下列哪种车辆不得进入高速公路？', '小型汽车', '摩托车', '拖拉机', '大型客车', 'C', '行人、非机动车、拖拉机、轮式专用机械车、铰接式客车、全挂拖斗车以及其他设计最高时速低于70公里的机动车，不得进入高速公路。', NULL, '高速公路', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (36, 1, 1, '驾驶机动车在高速公路上行驶，与同车道前车的最小安全距离是多少？', '车速超过100公里/小时时，保持100米以上', '车速超过100公里/小时时，保持50米以上', '车速低于100公里/小时时，保持100米以上', '车速低于100公里/小时时，保持30米以上', 'A', '高速公路上行驶，车速超过100公里/小时时，与同车道前车保持100米以上的安全距离；车速低于100公里/小时时，保持50米以上的安全距离。', NULL, '高速公路', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (37, 1, 1, '机动车在道路上发生故障，需要停车排除故障时，驾驶人应当怎么做？', '立即停车，在车后设置警告标志', '继续行驶，寻找维修厂', '停车后不设置警告标志', '在行车道内维修车辆', 'A', '机动车在道路上发生故障，需要停车排除故障时，驾驶人应当立即开启危险报警闪光灯，将机动车移至不妨碍交通的地方停放；难以移动的，应当持续开启危险报警闪光灯，并在车后设置警告标志，夜间还应当同时开启示廓灯和后位灯。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (38, 1, 1, '下列哪种行为属于无证驾驶？', '驾驶证被吊销期间驾驶机动车', '驾驶与驾驶证准驾车型相符的机动车', '驾驶证在有效期内驾驶机动车', '携带驾驶证驾驶机动车', 'A', '未取得机动车驾驶证、机动车驾驶证被吊销或者机动车驾驶证被暂扣期间驾驶机动车的，属于无证驾驶，将被处200元以上2000元以下罚款，可并处15日以下拘留。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (39, 1, 1, '驾驶机动车在有交通信号灯控制的交叉路口，遇到黄灯亮时，应当怎么做？', '加速通过路口', '已越过停止线的车辆可以继续通行', '停车等待红灯', '倒车退回停止线后', 'B', '黄灯亮时，已越过停止线的车辆可以继续通行，未越过停止线的车辆应当停车等待，不得加速抢行。', NULL, '交通信号', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (40, 1, 2, '机动车在夜间通过急弯、坡路、拱桥、人行横道或者没有交通信号灯控制的路口时，应当交替使用远近光灯示意。', '正确', '错误', NULL, NULL, 'A', '夜间通过急弯、坡路、拱桥、人行横道或者没有交通信号灯控制的路口，交替使用远近光灯可以有效提醒其他车辆和行人注意，确保通行安全。', NULL, '灯光使用', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (41, 1, 2, '驾驶机动车在道路上行驶，遇前方车辆停车排队等候或者缓慢行驶时，可以借道超车或者占用对面车道。', '正确', '错误', NULL, NULL, 'B', '遇前方车辆停车排队等候或者缓慢行驶时，应当依次排队，不得借道超车或者占用对面车道，不得穿插等候的车辆。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (42, 1, 2, '机动车在高速公路上行驶，车速超过100公里/小时时，与同车道前车的安全距离不得小于50米。', '正确', '错误', NULL, NULL, 'B', '高速公路上行驶，车速超过100公里/小时时，与同车道前车的安全距离不得小于100米，车速低于100公里/小时时，不得小于50米。', NULL, '高速公路', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (43, 1, 2, '驾驶机动车在道路上行驶，必须按规定使用安全带，驾驶人、乘坐人员都应当按规定使用安全带。', '正确', '错误', NULL, NULL, 'A', '机动车行驶时，驾驶人、乘坐人员应当按规定使用安全带，摩托车驾驶人及乘坐人员应当按规定戴安全头盔。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (44, 1, 2, '机动车在道路上发生故障，难以移动时，只需要开启危险报警闪光灯即可，不需要设置警告标志。', '正确', '错误', NULL, NULL, 'B', '机动车在道路上发生故障难以移动时，除了开启危险报警闪光灯，还应当在车后设置警告标志，夜间还需开启示廓灯和后位灯。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (45, 1, 2, '驾驶机动车在有交通标志、标线控制的路口，应当优先遵守交通警察的指挥。', '正确', '错误', NULL, NULL, 'B', '车辆、行人应当按照交通信号通行；遇有交通警察现场指挥时，应当按照交通警察的指挥通行；在没有交通信号的道路上，应当在确保安全、畅通的原则下通行。', NULL, '交通信号', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (46, 1, 2, '机动车在高速公路上行驶，遇有前方车辆停车排队等候或者缓慢行驶时，不得在应急车道内行驶或者停车。', '正确', '错误', NULL, NULL, 'A', '非紧急情况不得在应急车道行驶或者停车，遇前方拥堵时，应当依次排队等候，不得占用应急车道。', NULL, '高速公路', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (47, 1, 2, '机动车在道路上行驶，遇行人正在通过人行横道时，应当停车让行。', '正确', '错误', NULL, NULL, 'A', '机动车行经人行横道时，应当减速行驶；遇行人正在通过人行横道，应当停车让行，确保行人安全。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (48, 1, 3, '下列哪些行为会被一次记12分？', '饮酒后驾驶机动车', '使用伪造、变造的机动车号牌', '驾驶机动车在高速公路上倒车、逆行', '驾驶机动车不按规定避让校车', 'ABC', '饮酒后驾驶机动车、使用伪造变造的机动车号牌、在高速公路上倒车逆行，均一次记12分；不按规定避让校车一次记6分。', NULL, '记分', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (49, 1, 3, '驾驶机动车在高速公路上行驶，不得有下列哪些行为？', '倒车、逆行、穿越中央分隔带掉头', '在匝道、加速车道或者减速车道上超车', '骑、轧车行道分界线或者在路肩上行驶', '非紧急情况时在应急车道行驶或者停车', 'ABCD', '以上选项均为高速公路上禁止的违法行为，违反者将被依法处罚。', NULL, '高速公路', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (50, 1, 3, '驾驶机动车在夜间行驶，应当正确使用灯光，下列说法正确的有哪些？', '在没有路灯、照明不良的道路上行驶，应当开启远光灯', '遇对向有来车时，应当切换为近光灯', '通过交叉路口时，应当交替使用远近光灯示意', '在照明良好的城市道路上行驶，应当使用近光灯', 'ABCD', '以上选项均为夜间灯光使用的正确规范，合理使用灯光可以有效提升夜间行车安全。', NULL, '灯光使用', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (51, 1, 3, '机动车在道路上发生交通事故，当事人应当怎么做？', '立即停车，保护现场', '造成人身伤亡的，立即抢救受伤人员', '迅速报告执勤的交通警察或者公安机关交通管理部门', '仅造成轻微财产损失，事实清楚的，先撤离现场再协商处理', 'ABCD', '以上选项均为交通事故发生后的正确处理方式，确保事故处理合法、高效。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (52, 1, 3, '下列哪些路段不得超车？', '铁路道口、交叉路口', '窄桥、弯道、陡坡、隧道', '人行横道、市区交通流量大的路段', '前车正在左转弯、掉头、超车的路段', 'ABCD', '以上选项均为禁止超车的路段，在这些路段超车视线受阻、风险极高，极易引发交通事故。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (53, 1, 3, '下列哪些属于交通信号？', '交通信号灯', '交通标志', '交通标线', '交通警察的指挥', 'ABCD', '交通信号包括交通信号灯、交通标志、交通标线和交通警察的指挥，车辆、行人都必须严格遵守。', NULL, '交通信号', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (54, 1, 3, '机动车在高速公路上发生故障，需要停车排除故障时，驾驶人应当怎么做？', '立即开启危险报警闪光灯', '将机动车移至应急车道内停放', '在车后150米以外设置警告标志', '夜间同时开启示廓灯和后位灯', 'ABCD', '以上选项均为高速公路车辆故障后的正确处理方式，确保自身和其他车辆的通行安全。', NULL, '高速公路', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (55, 1, 3, '下列哪些行为会被一次记6分？', '驾驶机动车不按规定避让校车', '驾驶机动车违反道路交通信号灯通行', '驾驶机动车不按规定超车、让行，或者在高速公路、城市快速路以外的道路上逆行', '驾驶机动车在高速公路或者城市快速路上违法占用应急车道行驶', 'ABCD', '以上选项均为一次记6分的交通违法行为，违反者将被依法处罚。', NULL, '记分', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (56, 4, 1, '遇行人正在通过人行横道时，机动车应当怎么做？', '加速通过', '停车让行', '鸣喇叭驱赶', '绕行通过', 'B', '人行横道是行人的专属通行区域，遇行人正在通过时，必须停车让行，确保行人安全，这是文明驾驶的基本要求。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (57, 4, 1, '驾驶机动车在道路上行驶，遇前方有行人横穿道路时，应当怎么做？', '提前减速，必要时停车避让', '鸣喇叭示意行人快速通过', '加速从行人前方绕过', '从行人后方绕行', 'A', '遇行人横穿道路，应当提前减速，注意观察行人动态，必要时停车避让，不得与行人抢行，确保行人安全。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (58, 4, 1, '驾驶机动车在狭窄的道路上会车，遇到对向有来车时，应当怎么做？', '加速通过，抢占道路', '提前减速，靠右行驶，必要时停车让行', '鸣喇叭示意对向车辆让行', '开启远光灯，提醒对向车辆注意', 'B', '狭窄道路会车，应当提前减速，靠右行驶，注意观察对向车辆和道路情况，必要时停车让行，确保会车安全。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (59, 4, 1, '驾驶机动车在道路上行驶，遇前方有非机动车正在行驶时，应当怎么做？', '加速超越非机动车', '保持安全距离，注意观察非机动车动态', '鸣喇叭催促非机动车让行', '紧贴非机动车行驶', 'B', '非机动车灵活性强、稳定性差，遇非机动车行驶时，应当保持安全距离，注意观察其动态，提前预判，避免发生剐蹭事故。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (60, 4, 1, '驾驶机动车在雨天行驶，遇行人撑伞、穿雨衣行走时，应当怎么做？', '加速通过，溅起的雨水不会影响行人', '提前减速，注意避让，避免溅起雨水影响行人', '鸣喇叭示意行人注意避让', '从行人身边快速通过', 'B', '雨天行人撑伞、穿雨衣，视线和行动都会受到影响，驾驶人应当提前减速，注意避让，低速通过，避免溅起雨水影响行人，做到文明驾驶。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (61, 4, 1, '驾驶机动车在道路上行驶，遇前方有车辆正在超车时，应当怎么做？', '加速行驶，不让对方超车', '减速靠右，给对方留出足够的超车空间', '鸣喇叭示意对方不要超车', '向左打方向，阻挡对方超车', 'B', '遇前方车辆正在超车，应当减速靠右，给对方留出足够的超车空间，确保超车安全，不得故意阻挡对方超车。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (62, 4, 1, '驾驶机动车在道路上行驶，遇前方有车辆发生故障，正在缓慢行驶时，应当怎么做？', '加速从故障车辆左侧超越', '提前减速，注意观察，确认安全后再超越', '鸣喇叭催促故障车辆加快速度', '紧跟故障车辆行驶', 'B', '遇前方故障车辆缓慢行驶，应当提前减速，注意观察故障车辆的动态和周围道路情况，确认安全后再超越，不得盲目超车。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (63, 4, 1, '驾驶机动车在道路上行驶，遇前方有行人正在路边行走时，应当怎么做？', '加速通过，不会影响行人', '提前减速，注意观察行人动态，保持安全距离', '鸣喇叭示意行人远离道路', '紧贴路边行驶', 'B', '遇路边行走的行人，应当提前减速，注意观察行人动态，保持足够的安全距离，避免行人突然横穿道路，确保行车安全。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (64, 4, 1, '驾驶机动车在道路上行驶，遇前方有车辆正在停车上下乘客时，应当怎么做？', '加速从停车车辆左侧超越', '提前减速，注意观察，确认安全后再通过', '鸣喇叭示意停车车辆尽快驶离', '从停车车辆右侧绕行', 'B', '遇前方车辆停车上下乘客，应当提前减速，注意观察是否有乘客突然横穿道路，确认安全后再低速通过，不得盲目超车或绕行。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (65, 4, 1, '驾驶机动车在道路上行驶，遇前方有施工路段，正在进行道路施工时，应当怎么做？', '加速通过施工路段', '提前减速，注意观察施工标志和现场情况，按指示通行', '鸣喇叭示意施工人员让行', '从施工区域旁边快速通过', 'B', '遇施工路段，应当提前减速，注意观察施工标志和现场交通情况，严格按照施工路段的交通指示通行，注意避让施工人员和施工车辆，确保安全。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (66, 4, 1, '驾驶机动车在道路上行驶，遇前方有学校区域，有学生正在横穿道路时，应当怎么做？', '加速通过，不会影响学生', '提前减速，停车让行，确保学生安全通过', '鸣喇叭示意学生快速通过', '从学生身边快速通过', 'B', '学校区域学生多，且学生的交通安全意识相对薄弱，遇学生横穿道路，必须提前减速，停车让行，确保学生安全通过，这是文明驾驶的重要要求。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (67, 4, 1, '驾驶机动车在道路上行驶，遇前方有公交车正在进站上下乘客时，应当怎么做？', '加速从公交车左侧超越', '提前减速，注意观察，确认安全后再通过', '鸣喇叭示意公交车尽快驶离', '从公交车右侧绕行', 'B', '公交车进站上下乘客时，会有乘客从公交车前或后横穿道路，驾驶人应当提前减速，注意观察，确认没有行人横穿后，再低速通过，不得盲目超车。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (68, 4, 1, '驾驶机动车在道路上行驶，遇前方有车辆正在倒车时，应当怎么做？', '加速从倒车车辆旁边通过', '提前减速，注意观察，确认安全后再通过', '鸣喇叭示意倒车车辆停止倒车', '紧跟倒车车辆行驶', 'B', '车辆倒车时，驾驶人的视线会受到限制，容易出现盲区，遇前方车辆倒车，应当提前减速，注意观察倒车车辆的动态，确认安全后再通过，不得抢行。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (69, 4, 1, '驾驶机动车在道路上行驶，遇前方有行人正在路边捡拾物品时，应当怎么做？', '加速通过，不会影响行人', '提前减速，注意观察，确认行人不会突然横穿道路后再通过', '鸣喇叭示意行人尽快离开道路', '从行人身边快速通过', 'B', '行人在路边捡拾物品时，注意力会集中在物品上，容易忽视周围的交通情况，甚至会突然横穿道路，驾驶人应当提前减速，注意观察，确认安全后再低速通过。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (70, 4, 1, '驾驶机动车在道路上行驶，遇前方有车辆正在开启左转向灯，准备向左转弯时，应当怎么做？', '加速从前方车辆左侧超越', '提前减速，注意观察，确认安全后再通过', '鸣喇叭示意前方车辆不要转弯', '从前方车辆右侧绕行', 'B', '遇前方车辆开启左转向灯准备转弯，应当提前减速，注意观察前方车辆的转弯动态，确认安全后再通过，不得在对方转弯时超车，避免发生碰撞事故。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (71, 4, 1, '驾驶机动车在道路上行驶，遇前方有车辆正在开启右转向灯，准备向右转弯时，应当怎么做？', '加速从前方车辆右侧超越', '提前减速，注意观察，确认安全后再通过', '鸣喇叭示意前方车辆不要转弯', '从前方车辆左侧绕行', 'B', '遇前方车辆开启右转向灯准备转弯，应当提前减速，注意观察前方车辆的转弯动态，确认安全后再通过，不得在对方转弯时从右侧超车，避免发生碰撞事故。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (72, 4, 1, '驾驶机动车在道路上行驶，遇前方有行人正在使用手机，低头行走时，应当怎么做？', '加速通过，不会影响行人', '提前减速，注意观察，提前避让，确保行人安全', '鸣喇叭示意行人注意看路', '从行人身边快速通过', 'B', '行人低头使用手机行走时，注意力完全集中在手机上，对周围的交通情况完全忽视，极易发生交通事故，驾驶人应当提前减速，注意观察，提前避让，确保行人安全。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (73, 4, 1, '驾驶机动车在道路上行驶，遇前方有车辆正在发生交通事故，现场有人员受伤时，应当怎么做？', '加速通过，不要多管闲事', '立即停车，保护现场，协助抢救受伤人员，并报警', '停车观看，拍摄视频后离开', '绕行通过，不要影响现场', 'B', '遇交通事故有人员受伤，作为驾驶人，有义务立即停车，保护现场，协助抢救受伤人员，并及时报警，这是文明驾驶和社会责任的基本要求。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (74, 4, 1, '驾驶机动车在道路上行驶，遇前方有车辆正在道路上临时停车，开启了危险报警闪光灯时，应当怎么做？', '加速从停车车辆旁边通过', '提前减速，注意观察，确认安全后再通过', '鸣喇叭示意停车车辆尽快驶离', '从停车车辆左侧快速超越', 'B', '车辆开启危险报警闪光灯临时停车，说明车辆有故障或有紧急情况，驾驶人应当提前减速，注意观察停车车辆的动态，确认安全后再低速通过，避免发生意外。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (75, 4, 1, '驾驶机动车在道路上行驶，遇前方有行人正在通过没有人行横道的道路时，应当怎么做？', '加速通过，行人应当避让机动车', '提前减速，注意避让，确保行人安全通过', '鸣喇叭示意行人快速通过', '从行人身边快速通过', 'B', '即使在没有人行横道的道路上，遇行人横穿道路，驾驶人也应当提前减速，注意避让，确保行人安全通过，机动车应当主动避让行人，这是文明驾驶的核心要求。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (76, 4, 2, '驾驶机动车在道路上行驶，遇行人正在通过人行横道时，只要行人走得慢，就可以加速通过。', '正确', '错误', NULL, NULL, 'B', '遇行人正在通过人行横道，必须停车让行，无论行人行走速度快慢，都不得与行人抢行，确保行人安全。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (77, 4, 2, '驾驶机动车在道路上行驶，遇前方有非机动车正在行驶时，鸣喇叭催促非机动车让行，是正确的做法。', '正确', '错误', NULL, NULL, 'B', '遇非机动车行驶，应当保持安全距离，注意观察其动态，不得鸣喇叭催促非机动车让行，避免惊吓到非机动车驾驶人，引发事故。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (78, 4, 2, '驾驶机动车在雨天行驶，遇行人撑伞行走时，低速通过，避免溅起雨水影响行人，是文明驾驶的正确做法。', '正确', '错误', NULL, NULL, 'A', '雨天行人撑伞，视线和行动都会受到影响，低速通过，避免溅起雨水影响行人，是尊重行人、文明驾驶的正确做法。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (79, 4, 2, '驾驶机动车在道路上行驶，遇前方有车辆正在超车时，加速行驶，不让对方超车，是正确的做法。', '正确', '错误', NULL, NULL, 'B', '遇前方车辆正在超车，应当减速靠右，给对方留出足够的超车空间，确保超车安全，不得故意阻挡对方超车，否则极易引发交通事故。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (80, 4, 2, '驾驶机动车在道路上行驶，遇前方有学校区域，有学生正在路边玩耍时，提前减速，注意观察，确保学生安全，是正确的做法。', '正确', '错误', NULL, NULL, 'A', '学校区域学生多，且学生的交通安全意识相对薄弱，提前减速，注意观察，确保学生安全，是文明驾驶的重要要求。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (81, 4, 2, '驾驶机动车在道路上行驶，遇前方有公交车正在进站上下乘客时，加速从公交车左侧超越，是正确的做法。', '正确', '错误', NULL, NULL, 'B', '公交车进站上下乘客时，会有乘客从公交车前或后横穿道路，盲目加速超车极易与横穿的行人发生碰撞，应当提前减速，确认安全后再低速通过。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (82, 4, 2, '驾驶机动车在道路上行驶，遇前方有车辆正在倒车时，提前减速，注意观察，确认安全后再通过，是正确的做法。', '正确', '错误', NULL, NULL, 'A', '车辆倒车时，驾驶人的视线会受到限制，容易出现盲区，提前减速，注意观察，确认安全后再通过，可有效避免发生碰撞事故。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (83, 4, 2, '驾驶机动车在道路上行驶，遇前方有行人正在使用手机低头行走时，鸣喇叭示意行人注意看路，然后加速通过，是正确的做法。', '正确', '错误', NULL, NULL, 'B', '行人低头使用手机行走时，对周围的交通情况完全忽视，鸣喇叭可能会惊吓到行人，导致行人突然做出危险动作，应当提前减速，注意观察，提前避让，确保行人安全。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (84, 4, 2, '驾驶机动车在道路上行驶，遇前方有交通事故，有人员受伤时，立即停车，协助抢救受伤人员并报警，是正确的做法。', '正确', '错误', NULL, NULL, 'A', '遇交通事故有人员受伤，作为驾驶人，有义务立即停车，保护现场，协助抢救受伤人员，并及时报警，这是文明驾驶和社会责任的基本要求。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (85, 4, 2, '驾驶机动车在道路上行驶，遇前方有车辆临时停车，开启了危险报警闪光灯时，加速从旁边通过，是正确的做法。', '正确', '错误', NULL, NULL, 'B', '车辆开启危险报警闪光灯临时停车，说明车辆有故障或有紧急情况，加速通过极易发生意外，应当提前减速，注意观察，确认安全后再低速通过。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (86, 4, 2, '驾驶机动车在道路上行驶，遇前方有行人正在通过没有人行横道的道路时，机动车应当主动避让，确保行人安全。', '正确', '错误', NULL, NULL, 'A', '即使在没有人行横道的道路上，机动车也应当主动避让行人，确保行人安全，这是文明驾驶的核心要求，也是法律的明确规定。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (87, 4, 2, '驾驶机动车在道路上行驶，遇前方有车辆正在开启左转向灯准备转弯时，加速从左侧超越，是正确的做法。', '正确', '错误', NULL, NULL, 'B', '遇前方车辆开启左转向灯准备转弯，在对方转弯时超车，极易与转弯车辆发生碰撞，应当提前减速，注意观察，确认安全后再通过。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (88, 4, 2, '驾驶机动车在道路上行驶，遇前方有车辆正在开启右转向灯准备转弯时，加速从右侧超越，是正确的做法。', '正确', '错误', NULL, NULL, 'B', '遇前方车辆开启右转向灯准备转弯，在对方转弯时从右侧超车，极易与转弯车辆发生碰撞，应当提前减速，注意观察，确认安全后再通过。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (89, 4, 2, '驾驶机动车在道路上行驶，遇前方有施工路段，正在进行道路施工时，提前减速，按施工指示通行，是正确的做法。', '正确', '错误', NULL, NULL, 'A', '施工路段道路情况复杂，提前减速，严格按照施工路段的交通指示通行，注意避让施工人员和施工车辆，可有效确保行车安全。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (90, 4, 2, '驾驶机动车在道路上行驶，遇前方有车辆发生故障，正在缓慢行驶时，鸣喇叭催促故障车辆加快速度，是正确的做法。', '正确', '错误', NULL, NULL, 'B', '车辆发生故障缓慢行驶，驾驶人本身就处于紧张状态，鸣喇叭催促会加剧对方的紧张情绪，甚至引发操作失误，应当提前减速，注意观察，确认安全后再超越。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (91, 4, 2, '驾驶机动车在道路上行驶，遇前方有行人正在路边捡拾物品时，提前减速，注意观察，确认安全后再通过，是正确的做法。', '正确', '错误', NULL, NULL, 'A', '行人在路边捡拾物品时，注意力会集中在物品上，容易忽视周围的交通情况，提前减速，注意观察，确认安全后再低速通过，可有效避免发生交通事故。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (92, 4, 2, '驾驶机动车在道路上行驶，遇前方有车辆正在停车上下乘客时，从车辆右侧绕行，是正确的做法。', '正确', '错误', NULL, NULL, 'B', '车辆停车上下乘客时，会有乘客从车辆右侧下车，从右侧绕行极易与下车的乘客发生碰撞，应当提前减速，注意观察，确认安全后再低速通过。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (93, 4, 2, '驾驶机动车在道路上行驶，遇前方有行人正在路边行走时，提前减速，保持安全距离，是正确的做法。', '正确', '错误', NULL, NULL, 'A', '遇路边行走的行人，提前减速，保持足够的安全距离，避免行人突然横穿道路，确保行车安全，是文明驾驶的基本要求。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (94, 4, 2, '驾驶机动车在道路上行驶，遇前方有车辆正在超车时，鸣喇叭示意对方不要超车，是正确的做法。', '正确', '错误', NULL, NULL, 'B', '遇前方车辆正在超车，只要对方的超车行为是合法合规的，就应当减速靠右，给对方留出足够的超车空间，不得鸣喇叭示意对方不要超车，故意阻挡对方超车。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (95, 4, 2, '驾驶机动车在道路上行驶，遇前方有交通事故，没有人员受伤，仅造成轻微财产损失时，加速通过，不要影响现场，是正确的做法。', '正确', '错误', NULL, NULL, 'B', '遇交通事故，即使没有人员受伤，也应当提前减速，注意观察现场情况，确保安全后再低速通过，不得加速通过，避免影响现场处理，甚至引发二次事故。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (96, 4, 3, '驾驶机动车在道路上行驶，遇行人正在通过人行横道时，正确的做法有哪些？', '立即停车，让行人优先通过', '提前减速，注意观察行人动态', '鸣喇叭示意行人快速通过', '不与行人抢行，确保行人安全', 'ABD', '遇行人正在通过人行横道，应当立即停车，让行人优先通过，提前减速，注意观察行人动态，不与行人抢行，确保行人安全，不得鸣喇叭催促行人。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (97, 4, 3, '驾驶机动车在道路上行驶，遇前方有非机动车正在行驶时，正确的做法有哪些？', '保持安全距离，注意观察非机动车动态', '提前减速，确认安全后再超越', '鸣喇叭催促非机动车让行', '不紧贴非机动车行驶，避免发生剐蹭', 'ABD', '遇非机动车行驶，应当保持安全距离，注意观察非机动车动态，提前减速，确认安全后再超越，不紧贴非机动车行驶，避免发生剐蹭，不得鸣喇叭催促非机动车让行。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (98, 4, 3, '驾驶机动车在雨天行驶，遇行人撑伞、穿雨衣行走时，正确的做法有哪些？', '提前减速，注意观察行人动态', '低速通过，避免溅起雨水影响行人', '鸣喇叭示意行人注意避让', '保持安全距离，提前预判行人动作', 'ABD', '雨天行人撑伞、穿雨衣，视线和行动都会受到影响，应当提前减速，注意观察行人动态，低速通过，避免溅起雨水影响行人，保持安全距离，提前预判行人动作，不得鸣喇叭催促行人。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (99, 4, 3, '驾驶机动车在道路上行驶，遇前方有车辆正在超车时，正确的做法有哪些？', '减速靠右，给对方留出足够的超车空间', '注意观察对方超车动态，确保行车安全', '加速行驶，不让对方超车', '不向左打方向，阻挡对方超车', 'ABD', '遇前方车辆正在超车，应当减速靠右，给对方留出足够的超车空间，注意观察对方超车动态，确保行车安全，不得加速行驶、向左打方向阻挡对方超车。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (100, 4, 3, '驾驶机动车在道路上行驶，遇前方有学校区域，有学生在路边活动时，正确的做法有哪些？', '提前减速，注意观察学生动态', '随时准备停车，避让突然横穿道路的学生', '鸣喇叭示意学生远离道路', '低速通过，确保学生安全', 'ABD', '学校区域学生多，且学生的交通安全意识相对薄弱，应当提前减速，注意观察学生动态，随时准备停车，避让突然横穿道路的学生，低速通过，确保学生安全，不得鸣喇叭催促学生。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (101, 4, 3, '驾驶机动车在道路上行驶，遇前方有公交车正在进站上下乘客时，正确的做法有哪些？', '提前减速，注意观察是否有乘客横穿道路', '确认安全后，低速通过', '加速从公交车左侧超越', '不盲目超车，避免与横穿的乘客发生碰撞', 'ABD', '公交车进站上下乘客时，会有乘客从公交车前或后横穿道路，应当提前减速，注意观察是否有乘客横穿道路，确认安全后，低速通过，不盲目超车，避免与横穿的乘客发生碰撞。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (102, 4, 3, '驾驶机动车在道路上行驶，遇前方有车辆正在倒车时，正确的做法有哪些？', '提前减速，注意观察倒车车辆的动态', '确认安全后，再低速通过', '鸣喇叭示意倒车车辆停止倒车', '不抢行，避免发生碰撞事故', 'ABD', '车辆倒车时，驾驶人的视线会受到限制，容易出现盲区，应当提前减速，注意观察倒车车辆的动态，确认安全后，再低速通过，不抢行，避免发生碰撞事故，不得鸣喇叭催促对方停止倒车。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (103, 4, 3, '驾驶机动车在道路上行驶，遇前方有交通事故，有人员受伤时，正确的做法有哪些？', '立即停车，保护现场', '协助抢救受伤人员', '及时报警，等待交警处理', '加速通过，不要多管闲事', 'ABC', '遇交通事故有人员受伤，作为驾驶人，有义务立即停车，保护现场，协助抢救受伤人员，并及时报警，等待交警处理，不得加速通过，漠视生命。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (104, 4, 3, '驾驶机动车在道路上行驶，遇前方有施工路段，正在进行道路施工时，正确的做法有哪些？', '提前减速，注意观察施工标志和现场情况', '严格按照施工路段的交通指示通行', '注意避让施工人员和施工车辆', '加速通过施工路段，避免影响施工', 'ABC', '施工路段道路情况复杂，应当提前减速，注意观察施工标志和现场情况，严格按照施工路段的交通指示通行，注意避让施工人员和施工车辆，不得加速通过施工路段，避免发生事故。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (105, 4, 3, '驾驶机动车在道路上行驶，遇前方有行人正在使用手机低头行走时，正确的做法有哪些？', '提前减速，注意观察行人动态', '提前避让，确保行人安全', '鸣喇叭示意行人注意看路', '不加速通过，避免发生交通事故', 'ABD', '行人低头使用手机行走时，对周围的交通情况完全忽视，极易发生交通事故，应当提前减速，注意观察行人动态，提前避让，确保行人安全，不加速通过，避免发生交通事故，不得鸣喇叭惊吓行人。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (106, 1, 2, '驾驶机动车在道路上违反道路通行规定应当接受相应的处罚。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核道路交通安全的相关法律法规与安全驾驶要求，题目中的做法符合《中华人民共和国道路交通安全法》及相关实施条例的规定，是安全、合规的驾驶行为。\n【安全意义】严格遵守道路交通安全法律法规，规范自身的驾驶行为，是保障行车安全的核心前提，能有效降低交通事故的发生概率，保障自身与他人的人身、财产安全。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (107, 1, 2, '对未取得驾驶证驾驶机动车的，追究其法律责任。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核机动车驾驶证与记分管理的相关规定。根据《机动车驾驶证申领和使用规定》，机动车驾驶人初次申领机动车驾驶证后的12个月为实习期，实习期内驾驶机动车的，应当在车身后部粘贴或者悬挂统一式样的实习标志。\n【安全意义】驾驶证记分管理是规范机动车驾驶人驾驶行为的核心制度，严格遵守驾驶证管理规定，能有效提升驾驶人的安全驾驶意识，减少交通违法行为的发生。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (108, 1, 2, '对违法驾驶发生重大交通事故且构成犯罪的，不追究其刑事责任。', '正确', '错误', NULL, NULL, 'B', '本题正确答案为B（错误）。\n【考点解析】本题考核道路交通安全的禁止性规定，题目中的做法违反了《中华人民共和国道路交通安全法》及相关实施条例的规定，属于交通违法行为，将面临相应的行政处罚。\n【错误危害】违规驾驶行为会严重破坏正常的道路通行秩序，大幅提升交通事故的发生风险，不仅会对自身的人身、财产安全造成威胁，也会对其他交通参与者的安全造成严重影响。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (109, 1, 2, '驾驶机动车在道路上违反交通安全法规的行为属于违法行为。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核道路交通安全的相关法律法规与安全驾驶要求，题目中的做法符合《中华人民共和国道路交通安全法》及相关实施条例的规定，是安全、合规的驾驶行为。\n【安全意义】严格遵守道路交通安全法律法规，规范自身的驾驶行为，是保障行车安全的核心前提，能有效降低交通事故的发生概率，保障自身与他人的人身、财产安全。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (110, 1, 2, '伪造、变造机动车驾驶证构成犯罪的将被依法追究刑事责任。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核机动车驾驶证与记分管理的相关规定。根据《机动车驾驶证申领和使用规定》，机动车驾驶人初次申领机动车驾驶证后的12个月为实习期，实习期内驾驶机动车的，应当在车身后部粘贴或者悬挂统一式样的实习标志。\n【安全意义】驾驶证记分管理是规范机动车驾驶人驾驶行为的核心制度，严格遵守驾驶证管理规定，能有效提升驾驶人的安全驾驶意识，减少交通违法行为的发生。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (111, 1, 2, '准驾车型为小型自动挡汽车的，可以驾驶低速载货汽车。', '正确', '错误', NULL, NULL, 'B', '本题正确答案为B（错误）。\n【考点解析】本题考核道路交通安全的禁止性规定，题目中的做法违反了《中华人民共和国道路交通安全法》及相关实施条例的规定，属于交通违法行为，将面临相应的行政处罚。\n【错误危害】违规驾驶行为会严重破坏正常的道路通行秩序，大幅提升交通事故的发生风险，不仅会对自身的人身、财产安全造成威胁，也会对其他交通参与者的安全造成严重影响。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (112, 1, 2, '驾驶人持超过有效期的驾驶证可以在1年内驾驶机动车。', '正确', '错误', NULL, NULL, 'B', '本题正确答案为B（错误）。\n【考点解析】本题考核驾驶证记分的强制性规定。根据《机动车驾驶证申领和使用规定》，机动车驾驶人在一个记分周期内记分达到12分的，公安机关交通管理部门应当扣留其机动车驾驶证，该机动车驾驶人应当按照规定参加道路交通安全法律、法规的学习并接受考试，考试合格的，记分予以清除，发还机动车驾驶证；考试不合格的，继续参加学习和考试。\n【错误危害】驾驶证记分达到12分后仍驾驶机动车的，属于无证驾驶行为，将面临严厉的行政处罚，同时也会因驾驶人的安全驾驶意识不足，极易引发交通事故，造成严重的后果。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (113, 1, 2, '驾驶人的驾驶证损毁后不得驾驶机动车。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核机动车驾驶证与记分管理的相关规定。根据《机动车驾驶证申领和使用规定》，机动车驾驶人初次申领机动车驾驶证后的12个月为实习期，实习期内驾驶机动车的，应当在车身后部粘贴或者悬挂统一式样的实习标志。\n【安全意义】驾驶证记分管理是规范机动车驾驶人驾驶行为的核心制度，严格遵守驾驶证管理规定，能有效提升驾驶人的安全驾驶意识，减少交通违法行为的发生。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (114, 1, 2, '机动车驾驶证有效期分为6年、10年、20年。', '正确', '错误', NULL, NULL, 'B', '本题正确答案为B（错误）。\n【考点解析】本题考核驾驶证记分的强制性规定。根据《机动车驾驶证申领和使用规定》，机动车驾驶人在一个记分周期内记分达到12分的，公安机关交通管理部门应当扣留其机动车驾驶证，该机动车驾驶人应当按照规定参加道路交通安全法律、法规的学习并接受考试，考试合格的，记分予以清除，发还机动车驾驶证；考试不合格的，继续参加学习和考试。\n【错误危害】驾驶证记分达到12分后仍驾驶机动车的，属于无证驾驶行为，将面临严厉的行政处罚，同时也会因驾驶人的安全驾驶意识不足，极易引发交通事故，造成严重的后果。', NULL, '记分', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (115, 1, 2, '初次申领的机动车驾驶证的有效期为6年。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核机动车驾驶证与记分管理的相关规定。根据《机动车驾驶证申领和使用规定》，机动车驾驶人初次申领机动车驾驶证后的12个月为实习期，实习期内驾驶机动车的，应当在车身后部粘贴或者悬挂统一式样的实习标志。\n【安全意义】驾驶证记分管理是规范机动车驾驶人驾驶行为的核心制度，严格遵守驾驶证管理规定，能有效提升驾驶人的安全驾驶意识，减少交通违法行为的发生。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (116, 1, 2, '初次申领的机动车驾驶证的有效期为4年。', '正确', '错误', NULL, NULL, 'B', '本题正确答案为B（错误）。\n【考点解析】本题考核驾驶证记分的强制性规定。根据《机动车驾驶证申领和使用规定》，机动车驾驶人在一个记分周期内记分达到12分的，公安机关交通管理部门应当扣留其机动车驾驶证，该机动车驾驶人应当按照规定参加道路交通安全法律、法规的学习并接受考试，考试合格的，记分予以清除，发还机动车驾驶证；考试不合格的，继续参加学习和考试。\n【错误危害】驾驶证记分达到12分后仍驾驶机动车的，属于无证驾驶行为，将面临严厉的行政处罚，同时也会因驾驶人的安全驾驶意识不足，极易引发交通事故，造成严重的后果。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (117, 1, 2, '机动车驾驶证遗失、损毁无法辨认时，机动车驾驶人应当向机动车驾驶证核发地车辆管理所申请补发。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核机动车驾驶证与记分管理的相关规定。根据《机动车驾驶证申领和使用规定》，机动车驾驶人初次申领机动车驾驶证后的12个月为实习期，实习期内驾驶机动车的，应当在车身后部粘贴或者悬挂统一式样的实习标志。\n【安全意义】驾驶证记分管理是规范机动车驾驶人驾驶行为的核心制度，严格遵守驾驶证管理规定，能有效提升驾驶人的安全驾驶意识，减少交通违法行为的发生。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (118, 1, 2, '机动车行驶证灭失、丢失，机动车所有人要向登记地车辆管理所申请补领、换领。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核道路交通安全的相关法律法规与安全驾驶要求，题目中的做法符合《中华人民共和国道路交通安全法》及相关实施条例的规定，是安全、合规的驾驶行为。\n【安全意义】严格遵守道路交通安全法律法规，规范自身的驾驶行为，是保障行车安全的核心前提，能有效降低交通事故的发生概率，保障自身与他人的人身、财产安全。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (119, 1, 2, '机动车号牌损毁，机动车所有人要向登记地车辆管理所申请补领、换领。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核道路交通安全的相关法律法规与安全驾驶要求，题目中的做法符合《中华人民共和国道路交通安全法》及相关实施条例的规定，是安全、合规的驾驶行为。\n【安全意义】严格遵守道路交通安全法律法规，规范自身的驾驶行为，是保障行车安全的核心前提，能有效降低交通事故的发生概率，保障自身与他人的人身、财产安全。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (120, 1, 2, '驾驶人因服兵役、出国（境）等原因延期审验期间不得驾驶机动车。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核道路交通安全的相关法律法规与安全驾驶要求，题目中的做法符合《中华人民共和国道路交通安全法》及相关实施条例的规定，是安全、合规的驾驶行为。\n【安全意义】严格遵守道路交通安全法律法规，规范自身的驾驶行为，是保障行车安全的核心前提，能有效降低交通事故的发生概率，保障自身与他人的人身、财产安全。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (121, 1, 2, '科目三道路驾驶技能和安全文明驾驶常识考试满分分别为100分，成绩分别达到80和90分的为合格。', '正确', '错误', NULL, NULL, 'B', '本题正确答案为B（错误）。\n【考点解析】本题考核文明驾驶的禁止性规定。根据《中华人民共和国道路交通安全法》规定，机动车遇行人正在通过人行横道时，必须停车让行，不得加速通过、鸣喇叭驱赶或者绕行，否则将面临相应的行政处罚。\n【错误危害】不避让行人、不文明驾驶的行为会严重威胁行人的人身安全，极易引发机动车与行人的碰撞事故，同时也会破坏正常的道路通行秩序，引发交通拥堵和次生事故。', NULL, '记分', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (122, 1, 2, '有吸食、注射毒品后驾驶驾车行为的机动车驾驶人，不会被注销驾驶证。', '正确', '错误', NULL, NULL, 'B', '本题正确答案为B（错误）。\n【考点解析】本题考核驾驶证记分的强制性规定。根据《机动车驾驶证申领和使用规定》，机动车驾驶人在一个记分周期内记分达到12分的，公安机关交通管理部门应当扣留其机动车驾驶证，该机动车驾驶人应当按照规定参加道路交通安全法律、法规的学习并接受考试，考试合格的，记分予以清除，发还机动车驾驶证；考试不合格的，继续参加学习和考试。\n【错误危害】驾驶证记分达到12分后仍驾驶机动车的，属于无证驾驶行为，将面临严厉的行政处罚，同时也会因驾驶人的安全驾驶意识不足，极易引发交通事故，造成严重的后果。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (123, 1, 2, '正在执行社区戒毒、强制隔离戒毒、社区康复措施，车辆管理所将注销其驾驶证。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核机动车驾驶证与记分管理的相关规定。根据《机动车驾驶证申领和使用规定》，机动车驾驶人初次申领机动车驾驶证后的12个月为实习期，实习期内驾驶机动车的，应当在车身后部粘贴或者悬挂统一式样的实习标志。\n【安全意义】驾驶证记分管理是规范机动车驾驶人驾驶行为的核心制度，严格遵守驾驶证管理规定，能有效提升驾驶人的安全驾驶意识，减少交通违法行为的发生。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (124, 1, 2, '饮酒后只要不影响驾驶操作可以短距离驾驶机动车。', '正确', '错误', NULL, NULL, 'B', '本题正确答案为B（错误）。\n【考点解析】本题考核道路交通安全的禁止性规定，题目中的做法违反了《中华人民共和国道路交通安全法》及相关实施条例的规定，属于交通违法行为，将面临相应的行政处罚。\n【错误危害】违规驾驶行为会严重破坏正常的道路通行秩序，大幅提升交通事故的发生风险，不仅会对自身的人身、财产安全造成威胁，也会对其他交通参与者的安全造成严重影响。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (125, 1, 2, '上路行驶的机动车未随车携带身份证的，交通警察可依法扣留机动车。', '正确', '错误', NULL, NULL, 'B', '本题正确答案为B（错误）。\n【考点解析】本题考核道路交通安全的禁止性规定，题目中的做法违反了《中华人民共和国道路交通安全法》及相关实施条例的规定，属于交通违法行为，将面临相应的行政处罚。\n【错误危害】违规驾驶行为会严重破坏正常的道路通行秩序，大幅提升交通事故的发生风险，不仅会对自身的人身、财产安全造成威胁，也会对其他交通参与者的安全造成严重影响。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (126, 1, 2, '拼装的机动车只要认为安全就可以上路行驶。', '正确', '错误', NULL, NULL, 'B', '本题正确答案为B（错误）。\n【考点解析】本题考核道路交通安全的禁止性规定，题目中的做法违反了《中华人民共和国道路交通安全法》及相关实施条例的规定，属于交通违法行为，将面临相应的行政处罚。\n【错误危害】违规驾驶行为会严重破坏正常的道路通行秩序，大幅提升交通事故的发生风险，不仅会对自身的人身、财产安全造成威胁，也会对其他交通参与者的安全造成严重影响。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (127, 1, 2, '驾驶机动车上路行驶应当按规定悬挂号牌。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核道路交通安全的相关法律法规与安全驾驶要求，题目中的做法符合《中华人民共和国道路交通安全法》及相关实施条例的规定，是安全、合规的驾驶行为。\n【安全意义】严格遵守道路交通安全法律法规，规范自身的驾驶行为，是保障行车安全的核心前提，能有效降低交通事故的发生概率，保障自身与他人的人身、财产安全。', NULL, '安全法', '2026-05-17 15:20:56');
