INSERT INTO `biz_question` VALUES (135, 1, 2, '驾驶人的机动车驾驶证被依法扣留、暂扣的情况下不得驾驶机动车。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核机动车驾驶证与记分管理的相关规定。根据《机动车驾驶证申领和使用规定》，机动车驾驶人初次申领机动车驾驶证后的12个月为实习期，实习期内驾驶机动车的，应当在车身后部粘贴或者悬挂统一式样的实习标志。\n【安全意义】驾驶证记分管理是规范机动车驾驶人驾驶行为的核心制度，严格遵守驾驶证管理规定，能有效提升驾驶人的安全驾驶意识，减少交通违法行为的发生。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (136, 1, 2, '驾驶人将机动车交给驾驶证被暂扣的人驾驶的，交通警察给予口头警告。', '正确', '错误', NULL, NULL, 'B', '本题正确答案为B（错误）。\n【考点解析】本题考核驾驶证记分的强制性规定。根据《机动车驾驶证申领和使用规定》，机动车驾驶人在一个记分周期内记分达到12分的，公安机关交通管理部门应当扣留其机动车驾驶证，该机动车驾驶人应当按照规定参加道路交通安全法律、法规的学习并接受考试，考试合格的，记分予以清除，发还机动车驾驶证；考试不合格的，继续参加学习和考试。\n【错误危害】驾驶证记分达到12分后仍驾驶机动车的，属于无证驾驶行为，将面临严厉的行政处罚，同时也会因驾驶人的安全驾驶意识不足，极易引发交通事故，造成严重的后果。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (137, 1, 2, '驾驶人驾驶有达到报废标准嫌疑机动车上路的，交通警察依法予以拘留。', '正确', '错误', NULL, NULL, 'B', '本题正确答案为B（错误）。\n【考点解析】本题考核道路交通安全的禁止性规定，题目中的做法违反了《中华人民共和国道路交通安全法》及相关实施条例的规定，属于交通违法行为，将面临相应的行政处罚。\n【错误危害】违规驾驶行为会严重破坏正常的道路通行秩序，大幅提升交通事故的发生风险，不仅会对自身的人身、财产安全造成威胁，也会对其他交通参与者的安全造成严重影响。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (138, 1, 2, '驾驶人在一个记分周期内累积记分达到12分的，交通警察依法扣留驾驶证。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核机动车驾驶证与记分管理的相关规定。根据《机动车驾驶证申领和使用规定》，机动车驾驶人初次申领机动车驾驶证后的12个月为实习期，实习期内驾驶机动车的，应当在车身后部粘贴或者悬挂统一式样的实习标志。\n【安全意义】驾驶证记分管理是规范机动车驾驶人驾驶行为的核心制度，严格遵守驾驶证管理规定，能有效提升驾驶人的安全驾驶意识，减少交通违法行为的发生。', NULL, '记分', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (139, 1, 2, '驾驶人在实习期内驾驶机动车时，应当在车身后部粘贴或者悬挂统一式样的实习标志。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核机动车驾驶证与记分管理的相关规定。根据《机动车驾驶证申领和使用规定》，机动车驾驶人初次申领机动车驾驶证后的12个月为实习期，实习期内驾驶机动车的，应当在车身后部粘贴或者悬挂统一式样的实习标志。\n【安全意义】驾驶证记分管理是规范机动车驾驶人驾驶行为的核心制度，严格遵守驾驶证管理规定，能有效提升驾驶人的安全驾驶意识，减少交通违法行为的发生。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (140, 1, 2, '机动车驾驶人在实习期内有记满12分记录的，注销其实习的准驾车型驾驶资格。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核机动车驾驶证与记分管理的相关规定。根据《机动车驾驶证申领和使用规定》，机动车驾驶人初次申领机动车驾驶证后的12个月为实习期，实习期内驾驶机动车的，应当在车身后部粘贴或者悬挂统一式样的实习标志。\n【安全意义】驾驶证记分管理是规范机动车驾驶人驾驶行为的核心制度，严格遵守驾驶证管理规定，能有效提升驾驶人的安全驾驶意识，减少交通违法行为的发生。', NULL, '记分', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (141, 1, 2, '驾驶人记分没有达到满分，有罚款尚未缴纳的，记分转入下一记分周期。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核机动车驾驶证与记分管理的相关规定。根据《机动车驾驶证申领和使用规定》，机动车驾驶人初次申领机动车驾驶证后的12个月为实习期，实习期内驾驶机动车的，应当在车身后部粘贴或者悬挂统一式样的实习标志。\n【安全意义】驾驶证记分管理是规范机动车驾驶人驾驶行为的核心制度，严格遵守驾驶证管理规定，能有效提升驾驶人的安全驾驶意识，减少交通违法行为的发生。', NULL, '记分', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (142, 1, 2, '驾驶机动车在高速公路上倒车、逆行、穿越中央分隔带掉头的一次记6分。', '正确', '错误', NULL, NULL, 'B', '本题正确答案为B（错误）。\n【考点解析】本题考核高速公路行车的核心禁令。根据《中华人民共和国道路交通安全法》规定，机动车在高速公路上倒车、逆行、穿越中央分隔带掉头的，一次记12分，同时可处200元罚款，情节严重的还将承担刑事责任。\n【错误危害】高速公路上车辆行驶速度快，倒车、逆行行为会让对向/后方正常行驶的车辆完全无法预判，瞬间形成极大的碰撞风险，极易造成车毁人亡的严重后果，同时还会引发大面积的交通拥堵和次生事故。', NULL, '高速公路', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (143, 1, 2, '驾驶人违反交通运输管理法规发生重大事故致人死亡的处3年以上有期徒刑。', '正确', '错误', NULL, NULL, 'B', '本题正确答案为B（错误）。\n【考点解析】本题考核道路交通安全的禁止性规定，题目中的做法违反了《中华人民共和国道路交通安全法》及相关实施条例的规定，属于交通违法行为，将面临相应的行政处罚。\n【错误危害】违规驾驶行为会严重破坏正常的道路通行秩序，大幅提升交通事故的发生风险，不仅会对自身的人身、财产安全造成威胁，也会对其他交通参与者的安全造成严重影响。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (144, 1, 2, '驾驶人违反交通运输管理法规发生重大事故使公私财产遭受重大损失的可能处3年以下徒刑或拘役。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核道路交通安全的相关法律法规与安全驾驶要求，题目中的做法符合《中华人民共和国道路交通安全法》及相关实施条例的规定，是安全、合规的驾驶行为。\n【安全意义】严格遵守道路交通安全法律法规，规范自身的驾驶行为，是保障行车安全的核心前提，能有效降低交通事故的发生概率，保障自身与他人的人身、财产安全。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (145, 1, 2, '驾驶人违反交通运输管理法规发生重大事故后，因逃逸致人死亡的，处3年以上7年以下有期徒刑。', '正确', '错误', NULL, NULL, 'B', '本题正确答案为B（错误）。\n【考点解析】本题考核道路交通安全的禁止性规定，题目中的做法违反了《中华人民共和国道路交通安全法》及相关实施条例的规定，属于交通违法行为，将面临相应的行政处罚。\n【错误危害】违规驾驶行为会严重破坏正常的道路通行秩序，大幅提升交通事故的发生风险，不仅会对自身的人身、财产安全造成威胁，也会对其他交通参与者的安全造成严重影响。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (146, 1, 2, '在路口这个位置时可以加速通过路口。', '正确', '错误', NULL, NULL, 'B', '本题正确答案为B（错误）。\n【考点解析】本题考核交通信号灯的强制性规定。根据《中华人民共和国道路交通安全法》规定，车辆、行人必须严格按照交通信号通行，红灯亮时，禁止车辆越过停止线进入路口，即使路口内没有其他车辆、行人，也不得违规通行。\n【错误危害】闯红灯、违规进入路口的行为会严重破坏路口的通行秩序，极易与横向正常通行的车辆、行人发生碰撞，造成严重的交通事故，同时也会引发路口的交通拥堵，影响整体的通行效率。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (147, 1, 2, '驾驶机动车不能进入红色叉形灯或者红色箭头灯亮的车道。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核道路交通安全的相关法律法规与安全驾驶要求，题目中的做法符合《中华人民共和国道路交通安全法》及相关实施条例的规定，是安全、合规的驾驶行为。\n【安全意义】严格遵守道路交通安全法律法规，规范自身的驾驶行为，是保障行车安全的核心前提，能有效降低交通事故的发生概率，保障自身与他人的人身、财产安全。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (148, 1, 2, '驾驶机动车在沙尘天气条件下行车不用开启前照灯、示廓灯和后位灯。', '正确', '错误', NULL, NULL, 'B', '本题正确答案为B（错误）。\n【考点解析】本题考核道路交通安全的禁止性规定，题目中的做法违反了《中华人民共和国道路交通安全法》及相关实施条例的规定，属于交通违法行为，将面临相应的行政处罚。\n【错误危害】违规驾驶行为会严重破坏正常的道路通行秩序，大幅提升交通事故的发生风险，不仅会对自身的人身、财产安全造成威胁，也会对其他交通参与者的安全造成严重影响。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (149, 1, 2, '驾驶机动车在雾天行车开启雾灯和危险报警闪光灯。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核道路交通安全的相关法律法规与安全驾驶要求，题目中的做法符合《中华人民共和国道路交通安全法》及相关实施条例的规定，是安全、合规的驾驶行为。\n【安全意义】严格遵守道路交通安全法律法规，规范自身的驾驶行为，是保障行车安全的核心前提，能有效降低交通事故的发生概率，保障自身与他人的人身、财产安全。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (150, 1, 2, '在这种急弯道路上行车应交替使用远近光灯。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核机动车灯光使用的相关规定。根据《中华人民共和国道路交通安全法实施条例》规定，机动车在夜间通过急弯、坡路、拱桥、人行横道或者没有交通信号灯控制的路口时，应当交替使用远近光灯示意，目的是提醒对向车辆、行人注意来车，避免因视线盲区引发交通事故。\n【安全意义】正确使用灯光是夜间安全行车的核心要求，合理的灯光示意能有效降低夜间行车的事故风险，保障自身与他人的通行安全。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (151, 1, 2, '夜间驾驶机动车通过人行横道时需要交替使用远近光灯。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核机动车灯光使用的相关规定。根据《中华人民共和国道路交通安全法实施条例》规定，机动车在夜间通过急弯、坡路、拱桥、人行横道或者没有交通信号灯控制的路口时，应当交替使用远近光灯示意，目的是提醒对向车辆、行人注意来车，避免因视线盲区引发交通事故。\n【安全意义】正确使用灯光是夜间安全行车的核心要求，合理的灯光示意能有效降低夜间行车的事故风险，保障自身与他人的通行安全。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (152, 1, 2, '驾驶机动车上坡时,在将要到达坡道顶端时要加速并鸣喇叭。', '正确', '错误', NULL, NULL, 'B', '本题正确答案为B（错误）。\n【考点解析】本题考核道路交通安全的禁止性规定，题目中的做法违反了《中华人民共和国道路交通安全法》及相关实施条例的规定，属于交通违法行为，将面临相应的行政处罚。\n【错误危害】违规驾驶行为会严重破坏正常的道路通行秩序，大幅提升交通事故的发生风险，不仅会对自身的人身、财产安全造成威胁，也会对其他交通参与者的安全造成严重影响。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (153, 1, 2, '驾驶机动车在没有中心线的城市道路上，最高速度不能超过每小时50公里。', '正确', '错误', NULL, NULL, 'B', '本题正确答案为B（错误）。\n【考点解析】本题考核道路交通安全的禁止性规定，题目中的做法违反了《中华人民共和国道路交通安全法》及相关实施条例的规定，属于交通违法行为，将面临相应的行政处罚。\n【错误危害】违规驾驶行为会严重破坏正常的道路通行秩序，大幅提升交通事故的发生风险，不仅会对自身的人身、财产安全造成威胁，也会对其他交通参与者的安全造成严重影响。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (154, 1, 2, '驾驶机动车在没有中心线的公路上，最高速度不能超过每小时70公里。', '正确', '错误', NULL, NULL, 'B', '本题正确答案为B（错误）。\n【考点解析】本题考核道路交通安全的禁止性规定，题目中的做法违反了《中华人民共和国道路交通安全法》及相关实施条例的规定，属于交通违法行为，将面临相应的行政处罚。\n【错误危害】违规驾驶行为会严重破坏正常的道路通行秩序，大幅提升交通事故的发生风险，不仅会对自身的人身、财产安全造成威胁，也会对其他交通参与者的安全造成严重影响。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (155, 1, 2, '车在这种条件的道路上，最高速度不能超过每小时50公里。', '正确', '错误', NULL, NULL, 'B', '本题正确答案为B（错误）。\n【考点解析】本题考核道路交通安全的禁止性规定，题目中的做法违反了《中华人民共和国道路交通安全法》及相关实施条例的规定，属于交通违法行为，将面临相应的行政处罚。\n【错误危害】违规驾驶行为会严重破坏正常的道路通行秩序，大幅提升交通事故的发生风险，不仅会对自身的人身、财产安全造成威胁，也会对其他交通参与者的安全造成严重影响。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (156, 1, 2, '驾驶机动车掉头、转弯、下陡坡时的最高速度不能超过每小时40公里。', '正确', '错误', NULL, NULL, 'B', '本题正确答案为B（错误）。\n【考点解析】本题考核道路交通安全的禁止性规定，题目中的做法违反了《中华人民共和国道路交通安全法》及相关实施条例的规定，属于交通违法行为，将面临相应的行政处罚。\n【错误危害】违规驾驶行为会严重破坏正常的道路通行秩序，大幅提升交通事故的发生风险，不仅会对自身的人身、财产安全造成威胁，也会对其他交通参与者的安全造成严重影响。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (157, 1, 2, '驾驶机动车通过窄路、窄桥时的最高速度不能超过每小时30公里。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核道路交通安全的相关法律法规与安全驾驶要求，题目中的做法符合《中华人民共和国道路交通安全法》及相关实施条例的规定，是安全、合规的驾驶行为。\n【安全意义】严格遵守道路交通安全法律法规，规范自身的驾驶行为，是保障行车安全的核心前提，能有效降低交通事故的发生概率，保障自身与他人的人身、财产安全。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (158, 1, 2, '在交叉路口遇到这种情况享有优先通行权。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核交通信号灯与路口通行的相关规定。根据《中华人民共和国道路交通安全法》规定，车辆、行人应当按照交通信号通行；遇有交通警察现场指挥时，应当按照交通警察的指挥通行；在没有交通信号的道路上，应当在确保安全、畅通的原则下通行。红灯亮时，禁止车辆通行，车辆应当停在停止线以外，不得越过停止线进入路口。\n【安全意义】交通信号灯是维护路口通行秩序的核心设施，严格按照交通信号通行能有效避免路口的交叉碰撞事故，保障路口的通行安全与效率。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (159, 1, 2, '驾驶机动车在道路上超车完毕驶回原车道时开启右转向灯。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核机动车超车与让行的相关规定。根据《中华人民共和国道路交通安全法》规定，机动车超车时，应当提前开启左转向灯、变换使用远、近光灯或者鸣喇叭，确认有充足的安全距离后，从前车的左侧超越，在与被超车辆拉开必要的安全距离后，开启右转向灯，驶回原车道；遇前方车辆停车排队等候或者缓慢行驶时，不得借道超车或者占用对面车道，不得穿插等候的车辆。\n【安全意义】规范的超车与让行行为是维护道路通行秩序的核心，能有效避免因强行超车、抢行引发的刮擦、碰撞等交通事故，保障道路通行的安全与顺畅。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (160, 1, 2, '驾驶机动车超车后立即开启右转向灯驶回原车道。', '正确', '错误', NULL, NULL, 'B', '本题正确答案为B（错误）。\n【考点解析】本题考核机动车超车的禁止性规定。根据《中华人民共和国道路交通安全法实施条例》规定，机动车在与对面来车有会车可能时、前车正在左转弯、掉头、超车时、行经铁路道口、交叉路口、窄桥、弯道、陡坡、隧道、人行横道、市区交通流量大的路段等没有超车条件的，不得超车。\n【错误危害】违规超车、抢行行为会严重破坏正常的通行秩序，极易与对向车辆、前车发生碰撞，同时也会影响周边车辆的正常行驶，引发大面积的交通拥堵和次生事故。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (161, 1, 2, '在道路上遇到这种情况可以从两侧超车。', '正确', '错误', NULL, NULL, 'B', '本题正确答案为B（错误）。\n【考点解析】本题考核机动车超车的禁止性规定。根据《中华人民共和国道路交通安全法实施条例》规定，机动车在与对面来车有会车可能时、前车正在左转弯、掉头、超车时、行经铁路道口、交叉路口、窄桥、弯道、陡坡、隧道、人行横道、市区交通流量大的路段等没有超车条件的，不得超车。\n【错误危害】违规超车、抢行行为会严重破坏正常的通行秩序，极易与对向车辆、前车发生碰撞，同时也会影响周边车辆的正常行驶，引发大面积的交通拥堵和次生事故。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (162, 1, 2, '遇到这种情况下可以从右侧超车。', '正确', '错误', NULL, NULL, 'B', '本题正确答案为B（错误）。\n【考点解析】本题考核机动车超车的禁止性规定。根据《中华人民共和国道路交通安全法实施条例》规定，机动车在与对面来车有会车可能时、前车正在左转弯、掉头、超车时、行经铁路道口、交叉路口、窄桥、弯道、陡坡、隧道、人行横道、市区交通流量大的路段等没有超车条件的，不得超车。\n【错误危害】违规超车、抢行行为会严重破坏正常的通行秩序，极易与对向车辆、前车发生碰撞，同时也会影响周边车辆的正常行驶，引发大面积的交通拥堵和次生事故。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (163, 1, 2, '驾驶机动车行经城市没有列车通过的铁路道口时允许超车。', '正确', '错误', NULL, NULL, 'B', '本题正确答案为B（错误）。\n【考点解析】本题考核机动车超车的禁止性规定。根据《中华人民共和国道路交通安全法实施条例》规定，机动车在与对面来车有会车可能时、前车正在左转弯、掉头、超车时、行经铁路道口、交叉路口、窄桥、弯道、陡坡、隧道、人行横道、市区交通流量大的路段等没有超车条件的，不得超车。\n【错误危害】违规超车、抢行行为会严重破坏正常的通行秩序，极易与对向车辆、前车发生碰撞，同时也会影响周边车辆的正常行驶，引发大面积的交通拥堵和次生事故。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (164, 1, 2, '驾驶机动车在隧道、陡坡等特殊路段不得超车。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核机动车超车与让行的相关规定。根据《中华人民共和国道路交通安全法》规定，机动车超车时，应当提前开启左转向灯、变换使用远、近光灯或者鸣喇叭，确认有充足的安全距离后，从前车的左侧超越，在与被超车辆拉开必要的安全距离后，开启右转向灯，驶回原车道；遇前方车辆停车排队等候或者缓慢行驶时，不得借道超车或者占用对面车道，不得穿插等候的车辆。\n【安全意义】规范的超车与让行行为是维护道路通行秩序的核心，能有效避免因强行超车、抢行引发的刮擦、碰撞等交通事故，保障道路通行的安全与顺畅。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (165, 1, 2, '在这个路口不能掉头。', '正确', '错误', NULL, NULL, 'B', '本题正确答案为B（错误）。\n【考点解析】本题考核交通信号灯的强制性规定。根据《中华人民共和国道路交通安全法》规定，车辆、行人必须严格按照交通信号通行，红灯亮时，禁止车辆越过停止线进入路口，即使路口内没有其他车辆、行人，也不得违规通行。\n【错误危害】闯红灯、违规进入路口的行为会严重破坏路口的通行秩序，极易与横向正常通行的车辆、行人发生碰撞，造成严重的交通事故，同时也会引发路口的交通拥堵，影响整体的通行效率。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (166, 1, 2, '在这段道路上不能掉头。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核道路交通安全的相关法律法规与安全驾驶要求，题目中的做法符合《中华人民共和国道路交通安全法》及相关实施条例的规定，是安全、合规的驾驶行为。\n【安全意义】严格遵守道路交通安全法律法规，规范自身的驾驶行为，是保障行车安全的核心前提，能有效降低交通事故的发生概率，保障自身与他人的人身、财产安全。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (167, 1, 2, '驾驶机动车在铁路道口、桥梁、陡坡、隧道或者容易发生危险的路段不能掉头。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核道路交通安全的相关法律法规与安全驾驶要求，题目中的做法符合《中华人民共和国道路交通安全法》及相关实施条例的规定，是安全、合规的驾驶行为。\n【安全意义】严格遵守道路交通安全法律法规，规范自身的驾驶行为，是保障行车安全的核心前提，能有效降低交通事故的发生概率，保障自身与他人的人身、财产安全。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (168, 1, 2, '在这段道路上，只要不影响其他车辆通行的前提下可以掉头。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核道路交通安全的相关法律法规与安全驾驶要求，题目中的做法符合《中华人民共和国道路交通安全法》及相关实施条例的规定，是安全、合规的驾驶行为。\n【安全意义】严格遵守道路交通安全法律法规，规范自身的驾驶行为，是保障行车安全的核心前提，能有效降低交通事故的发生概率，保障自身与他人的人身、财产安全。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (169, 1, 2, '未上坡的车辆遇到这种情况让对向下坡车先行。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核道路交通安全的相关法律法规与安全驾驶要求，题目中的做法符合《中华人民共和国道路交通安全法》及相关实施条例的规定，是安全、合规的驾驶行为。\n【安全意义】严格遵守道路交通安全法律法规，规范自身的驾驶行为，是保障行车安全的核心前提，能有效降低交通事故的发生概率，保障自身与他人的人身、财产安全。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (170, 1, 2, '驾驶机动车在没有交通信号的路口要尽快通过。', '正确', '错误', NULL, NULL, 'B', '本题正确答案为B（错误）。\n【考点解析】本题考核交通信号灯的强制性规定。根据《中华人民共和国道路交通安全法》规定，车辆、行人必须严格按照交通信号通行，红灯亮时，禁止车辆越过停止线进入路口，即使路口内没有其他车辆、行人，也不得违规通行。\n【错误危害】闯红灯、违规进入路口的行为会严重破坏路口的通行秩序，极易与横向正常通行的车辆、行人发生碰撞，造成严重的交通事故，同时也会引发路口的交通拥堵，影响整体的通行效率。', NULL, '交通信号', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (171, 1, 2, '在没有交通信号指示的交叉路口，转弯的机动车让直行的车辆和行人先行。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核交通信号灯与路口通行的相关规定。根据《中华人民共和国道路交通安全法》规定，车辆、行人应当按照交通信号通行；遇有交通警察现场指挥时，应当按照交通警察的指挥通行；在没有交通信号的道路上，应当在确保安全、畅通的原则下通行。红灯亮时，禁止车辆通行，车辆应当停在停止线以外，不得越过停止线进入路口。\n【安全意义】交通信号灯是维护路口通行秩序的核心设施，严格按照交通信号通行能有效避免路口的交叉碰撞事故，保障路口的通行安全与效率。', NULL, '交通信号', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (172, 1, 2, '这辆小轿车不能在这个位置停车。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核道路交通安全的相关法律法规与安全驾驶要求，题目中的做法符合《中华人民共和国道路交通安全法》及相关实施条例的规定，是安全、合规的驾驶行为。\n【安全意义】严格遵守道路交通安全法律法规，规范自身的驾驶行为，是保障行车安全的核心前提，能有效降低交通事故的发生概率，保障自身与他人的人身、财产安全。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (173, 1, 2, '驾驶机动车找不到停车位时可以借人行道停放。', '正确', '错误', NULL, NULL, 'B', '本题正确答案为B（错误）。\n【考点解析】本题考核道路交通安全的禁止性规定，题目中的做法违反了《中华人民共和国道路交通安全法》及相关实施条例的规定，属于交通违法行为，将面临相应的行政处罚。\n【错误危害】违规驾驶行为会严重破坏正常的道路通行秩序，大幅提升交通事故的发生风险，不仅会对自身的人身、财产安全造成威胁，也会对其他交通参与者的安全造成严重影响。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (174, 1, 2, '距离交叉路口50米以内的路段不能停车。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核交通信号灯与路口通行的相关规定。根据《中华人民共和国道路交通安全法》规定，车辆、行人应当按照交通信号通行；遇有交通警察现场指挥时，应当按照交通警察的指挥通行；在没有交通信号的道路上，应当在确保安全、畅通的原则下通行。红灯亮时，禁止车辆通行，车辆应当停在停止线以外，不得越过停止线进入路口。\n【安全意义】交通信号灯是维护路口通行秩序的核心设施，严格按照交通信号通行能有效避免路口的交叉碰撞事故，保障路口的通行安全与效率。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (175, 1, 2, '这个路段可以在非机动车道上临时停车。', '正确', '错误', NULL, NULL, 'B', '本题正确答案为B（错误）。\n【考点解析】本题考核道路交通安全的禁止性规定，题目中的做法违反了《中华人民共和国道路交通安全法》及相关实施条例的规定，属于交通违法行为，将面临相应的行政处罚。\n【错误危害】违规驾驶行为会严重破坏正常的道路通行秩序，大幅提升交通事故的发生风险，不仅会对自身的人身、财产安全造成威胁，也会对其他交通参与者的安全造成严重影响。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (176, 1, 2, '社会车辆距离消防栓或者消防队(站)门前30米以内的路段不能停车。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核道路交通安全的相关法律法规与安全驾驶要求，题目中的做法符合《中华人民共和国道路交通安全法》及相关实施条例的规定，是安全、合规的驾驶行为。\n【安全意义】严格遵守道路交通安全法律法规，规范自身的驾驶行为，是保障行车安全的核心前提，能有效降低交通事故的发生概率，保障自身与他人的人身、财产安全。', NULL, '会车让行', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (177, 1, 2, '距离桥梁、陡坡、隧道50米以内的路段不能停车。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核道路交通安全的相关法律法规与安全驾驶要求，题目中的做法符合《中华人民共和国道路交通安全法》及相关实施条例的规定，是安全、合规的驾驶行为。\n【安全意义】严格遵守道路交通安全法律法规，规范自身的驾驶行为，是保障行车安全的核心前提，能有效降低交通事故的发生概率，保障自身与他人的人身、财产安全。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (178, 1, 2, '距离宽度不足4米的窄路50米以内的路段不能停车。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核道路交通安全的相关法律法规与安全驾驶要求，题目中的做法符合《中华人民共和国道路交通安全法》及相关实施条例的规定，是安全、合规的驾驶行为。\n【安全意义】严格遵守道路交通安全法律法规，规范自身的驾驶行为，是保障行车安全的核心前提，能有效降低交通事故的发生概率，保障自身与他人的人身、财产安全。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (179, 1, 2, '机动车停稳前不能开车门和上下人员。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核道路交通安全的相关法律法规与安全驾驶要求，题目中的做法符合《中华人民共和国道路交通安全法》及相关实施条例的规定，是安全、合规的驾驶行为。\n【安全意义】严格遵守道路交通安全法律法规，规范自身的驾驶行为，是保障行车安全的核心前提，能有效降低交通事故的发生概率，保障自身与他人的人身、财产安全。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (180, 1, 2, '打开机动车车门时，不得妨碍其他车辆和行人通行。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核文明驾驶与行人避让的相关规定。根据《中华人民共和国道路交通安全法》规定，机动车行经人行横道时，应当减速行驶；遇行人正在通过人行横道，应当停车让行。机动车行经没有交通信号的道路时，遇行人横过道路，应当避让。\n【安全意义】文明驾驶、主动避让行人是机动车驾驶人的法定义务，也是保障道路交通安全的核心要求，能有效减少机动车与行人之间的交通事故，保护行人的人身安全。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (181, 1, 2, '驶离高速公路可以从这个位置直接驶入匝道。', '正确', '错误', NULL, NULL, 'B', '本题正确答案为B（错误）。', NULL, '高速公路', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (182, 1, 2, '这辆小型载客汽车进入高速公路行车道的行为是正确的。', '正确', '错误', NULL, NULL, 'B', '本题正确答案为B（错误）。', NULL, '高速公路', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (183, 1, 2, '这辆小型载客汽车驶离高速公路行车道的方法是正确的。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。', NULL, '高速公路', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (184, 1, 2, '机动车在高速公路上发生故障时，将车上人员迅速转移到右侧路肩上或者应急车道内，并且迅速报警。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核高速公路故障处置的相关规定。根据《中华人民共和国道路交通安全法》规定，机动车在高速公路上发生故障，需要停车排除故障时，驾驶人应当立即开启危险报警闪光灯，将机动车移至不妨碍交通的地方停放；难以移动的，应当持续开启危险报警闪光灯，并在来车方向150米以外设置警告标志，车上人员应当迅速转移到右侧路肩上或者应急车道内，并且迅速报警。\n【安全意义】规范的故障处置流程能最大程度降低故障车辆对正常通行的影响，同时保护驾乘人员的人身安全，避免被后方高速行驶的车辆碰撞。', NULL, '高速公路', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (185, 1, 2, '机动车在高速公路上发生交通事故无法正常行驶时，用救援车、清障车拖曳、牵引。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。', NULL, '高速公路', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (186, 1, 2, '驾驶机动车遇到漫水桥时要察明水情确认安全后再低速通过。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核道路交通安全的相关法律法规与安全驾驶要求，题目中的做法符合《中华人民共和国道路交通安全法》及相关实施条例的规定，是安全、合规的驾驶行为。\n【安全意义】严格遵守道路交通安全法律法规，规范自身的驾驶行为，是保障行车安全的核心前提，能有效降低交通事故的发生概率，保障自身与他人的人身、财产安全。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (187, 1, 2, '遇到这种情况时，要加速从红车前变更车道。', '正确', '错误', NULL, NULL, 'B', '本题正确答案为B（错误）。\n【考点解析】本题考核道路交通安全的禁止性规定，题目中的做法违反了《中华人民共和国道路交通安全法》及相关实施条例的规定，属于交通违法行为，将面临相应的行政处罚。\n【错误危害】违规驾驶行为会严重破坏正常的道路通行秩序，大幅提升交通事故的发生风险，不仅会对自身的人身、财产安全造成威胁，也会对其他交通参与者的安全造成严重影响。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (188, 1, 2, '在交叉路口遇到这种情况时，要在红灯亮以前加速通过路口。', '正确', '错误', NULL, NULL, 'B', '本题正确答案为B（错误）。\n【考点解析】本题考核交通信号灯的强制性规定。根据《中华人民共和国道路交通安全法》规定，车辆、行人必须严格按照交通信号通行，红灯亮时，禁止车辆越过停止线进入路口，即使路口内没有其他车辆、行人，也不得违规通行。\n【错误危害】闯红灯、违规进入路口的行为会严重破坏路口的通行秩序，极易与横向正常通行的车辆、行人发生碰撞，造成严重的交通事故，同时也会引发路口的交通拥堵，影响整体的通行效率。', NULL, '交通信号', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (189, 1, 2, '遇前方路段车道减少，车辆行驶缓慢，为保证道路通畅，应借对向车道迅速通过。', '正确', '错误', NULL, NULL, 'B', '本题正确答案为B（错误）。\n【考点解析】本题考核道路交通安全的禁止性规定，题目中的做法违反了《中华人民共和国道路交通安全法》及相关实施条例的规定，属于交通违法行为，将面临相应的行政处罚。\n【错误危害】违规驾驶行为会严重破坏正常的道路通行秩序，大幅提升交通事故的发生风险，不仅会对自身的人身、财产安全造成威胁，也会对其他交通参与者的安全造成严重影响。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (190, 1, 2, '行车中遇到正在进行作业的道路养护车辆、工程作业车时要注意避让。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核机动车超车与让行的相关规定。根据《中华人民共和国道路交通安全法》规定，机动车超车时，应当提前开启左转向灯、变换使用远、近光灯或者鸣喇叭，确认有充足的安全距离后，从前车的左侧超越，在与被超车辆拉开必要的安全距离后，开启右转向灯，驶回原车道；遇前方车辆停车排队等候或者缓慢行驶时，不得借道超车或者占用对面车道，不得穿插等候的车辆。\n【安全意义】规范的超车与让行行为是维护道路通行秩序的核心，能有效避免因强行超车、抢行引发的刮擦、碰撞等交通事故，保障道路通行的安全与顺畅。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (191, 1, 2, '行至这种情况的铁路道口要停车观察。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核道路交通安全的相关法律法规与安全驾驶要求，题目中的做法符合《中华人民共和国道路交通安全法》及相关实施条例的规定，是安全、合规的驾驶行为。\n【安全意义】严格遵守道路交通安全法律法规，规范自身的驾驶行为，是保障行车安全的核心前提，能有效降低交通事故的发生概率，保障自身与他人的人身、财产安全。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (192, 1, 2, '机动车上路行驶时，前排乘车人可不系安全带。', '正确', '错误', NULL, NULL, 'B', '本题正确答案为B（错误）。\n【考点解析】本题考核安全带使用的强制性规定。根据《中华人民共和国道路交通安全法》规定，机动车行驶时，不仅驾驶人需要按规定使用安全带，车内所有乘坐人员也必须按规定使用安全带，否则将面临相应的行政处罚。\n【错误危害】车辆发生碰撞时，未系安全带的驾乘人员会在惯性作用下高速撞击车内硬物，甚至被甩出车外，造成严重的伤亡后果，同时也会对车内其他人员的安全造成威胁。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (193, 1, 2, '机动车行驶中，车上少年儿童可不使用安全带。', '正确', '错误', NULL, NULL, 'B', '本题正确答案为B（错误）。\n【考点解析】本题考核安全带使用的强制性规定。根据《中华人民共和国道路交通安全法》规定，机动车行驶时，不仅驾驶人需要按规定使用安全带，车内所有乘坐人员也必须按规定使用安全带，否则将面临相应的行政处罚。\n【错误危害】车辆发生碰撞时，未系安全带的驾乘人员会在惯性作用下高速撞击车内硬物，甚至被甩出车外，造成严重的伤亡后果，同时也会对车内其他人员的安全造成威胁。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (194, 1, 2, '在车门、车厢没有关好时不要驾驶机动车起步。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核道路交通安全的相关法律法规与安全驾驶要求，题目中的做法符合《中华人民共和国道路交通安全法》及相关实施条例的规定，是安全、合规的驾驶行为。\n【安全意义】严格遵守道路交通安全法律法规，规范自身的驾驶行为，是保障行车安全的核心前提，能有效降低交通事故的发生概率，保障自身与他人的人身、财产安全。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (195, 1, 2, '不要在驾驶室的前后窗范围内悬挂和放置妨碍驾驶人视线的物品。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核道路交通安全的相关法律法规与安全驾驶要求，题目中的做法符合《中华人民共和国道路交通安全法》及相关实施条例的规定，是安全、合规的驾驶行为。\n【安全意义】严格遵守道路交通安全法律法规，规范自身的驾驶行为，是保障行车安全的核心前提，能有效降低交通事故的发生概率，保障自身与他人的人身、财产安全。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (196, 1, 2, '行车中在道路情况良好的条件下可以观看车载视频。', '正确', '错误', NULL, NULL, 'B', '本题正确答案为B（错误）。\n【考点解析】本题考核道路交通安全的禁止性规定，题目中的做法违反了《中华人民共和国道路交通安全法》及相关实施条例的规定，属于交通违法行为，将面临相应的行政处罚。\n【错误危害】违规驾驶行为会严重破坏正常的道路通行秩序，大幅提升交通事故的发生风险，不仅会对自身的人身、财产安全造成威胁，也会对其他交通参与者的安全造成严重影响。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (197, 1, 2, '驾驶小型汽车下陡坡时允许熄火滑行。', '正确', '错误', NULL, NULL, 'B', '本题正确答案为B（错误）。\n【考点解析】本题考核道路交通安全的禁止性规定，题目中的做法违反了《中华人民共和国道路交通安全法》及相关实施条例的规定，属于交通违法行为，将面临相应的行政处罚。\n【错误危害】违规驾驶行为会严重破坏正常的道路通行秩序，大幅提升交通事故的发生风险，不仅会对自身的人身、财产安全造成威胁，也会对其他交通参与者的安全造成严重影响。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (198, 1, 2, '驾驶机动车时可以向道路上抛撒物品。', '正确', '错误', NULL, NULL, 'B', '本题正确答案为B（错误）。\n【考点解析】本题考核道路交通安全的禁止性规定，题目中的做法违反了《中华人民共和国道路交通安全法》及相关实施条例的规定，属于交通违法行为，将面临相应的行政处罚。\n【错误危害】违规驾驶行为会严重破坏正常的道路通行秩序，大幅提升交通事故的发生风险，不仅会对自身的人身、财产安全造成威胁，也会对其他交通参与者的安全造成严重影响。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (199, 1, 2, '驾驶人在发生交通事故后因抢救伤员变动现场时要标明位置。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核道路交通安全的相关法律法规与安全驾驶要求，题目中的做法符合《中华人民共和国道路交通安全法》及相关实施条例的规定，是安全、合规的驾驶行为。\n【安全意义】严格遵守道路交通安全法律法规，规范自身的驾驶行为，是保障行车安全的核心前提，能有效降低交通事故的发生概率，保障自身与他人的人身、财产安全。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (200, 1, 2, '在道路上发生交通事故造成人身伤亡时，要立即抢救受伤人员并迅速报警。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核道路交通安全的相关法律法规与安全驾驶要求，题目中的做法符合《中华人民共和国道路交通安全法》及相关实施条例的规定，是安全、合规的驾驶行为。\n【安全意义】严格遵守道路交通安全法律法规，规范自身的驾驶行为，是保障行车安全的核心前提，能有效降低交通事故的发生概率，保障自身与他人的人身、财产安全。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (201, 1, 2, '驾驶机动车碰撞建筑物、公共设施后可即行撤离现场。', '正确', '错误', NULL, NULL, 'B', '本题正确答案为B（错误）。\n【考点解析】本题考核道路交通安全的禁止性规定，题目中的做法违反了《中华人民共和国道路交通安全法》及相关实施条例的规定，属于交通违法行为，将面临相应的行政处罚。\n【错误危害】违规驾驶行为会严重破坏正常的道路通行秩序，大幅提升交通事故的发生风险，不仅会对自身的人身、财产安全造成威胁，也会对其他交通参与者的安全造成严重影响。', NULL, '安全法', '2026-05-17 15:20:56');
