INSERT INTO `biz_question` VALUES (211, 1, 2, '已经达到报废标准的机动车经大修后可以上路行驶。', '正确', '错误', NULL, NULL, 'B', '本题正确答案为B（错误）。\n【考点解析】本题考核道路交通安全的禁止性规定，题目中的做法违反了《中华人民共和国道路交通安全法》及相关实施条例的规定，属于交通违法行为，将面临相应的行政处罚。\n【错误危害】违规驾驶行为会严重破坏正常的道路通行秩序，大幅提升交通事故的发生风险，不仅会对自身的人身、财产安全造成威胁，也会对其他交通参与者的安全造成严重影响。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (212, 1, 2, '服用国家管制的精神药品可以短途驾驶机动车。', '正确', '错误', NULL, NULL, 'B', '本题正确答案为B（错误）。\n【考点解析】本题考核道路交通安全的禁止性规定，题目中的做法违反了《中华人民共和国道路交通安全法》及相关实施条例的规定，属于交通违法行为，将面临相应的行政处罚。\n【错误危害】违规驾驶行为会严重破坏正常的道路通行秩序，大幅提升交通事故的发生风险，不仅会对自身的人身、财产安全造成威胁，也会对其他交通参与者的安全造成严重影响。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (213, 1, 2, '交通信号包括交通信号灯、交通标志、交通标线和交通警察的指挥。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核交通信号灯与路口通行的相关规定。根据《中华人民共和国道路交通安全法》规定，车辆、行人应当按照交通信号通行；遇有交通警察现场指挥时，应当按照交通警察的指挥通行；在没有交通信号的道路上，应当在确保安全、畅通的原则下通行。红灯亮时，禁止车辆通行，车辆应当停在停止线以外，不得越过停止线进入路口。\n【安全意义】交通信号灯是维护路口通行秩序的核心设施，严格按照交通信号通行能有效避免路口的交叉碰撞事故，保障路口的通行安全与效率。', NULL, '交通信号', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (214, 1, 2, '交通标志和交通标线不属于交通信号。', '正确', '错误', NULL, NULL, 'B', '本题正确答案为B（错误）。\n【考点解析】本题考核道路交通安全的禁止性规定，题目中的做法违反了《中华人民共和国道路交通安全法》及相关实施条例的规定，属于交通违法行为，将面临相应的行政处罚。\n【错误危害】违规驾驶行为会严重破坏正常的道路通行秩序，大幅提升交通事故的发生风险，不仅会对自身的人身、财产安全造成威胁，也会对其他交通参与者的安全造成严重影响。', NULL, '交通信号', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (215, 1, 2, '交通信号灯由红灯、绿灯和黄灯组成。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核交通信号灯与路口通行的相关规定。根据《中华人民共和国道路交通安全法》规定，车辆、行人应当按照交通信号通行；遇有交通警察现场指挥时，应当按照交通警察的指挥通行；在没有交通信号的道路上，应当在确保安全、畅通的原则下通行。红灯亮时，禁止车辆通行，车辆应当停在停止线以外，不得越过停止线进入路口。\n【安全意义】交通信号灯是维护路口通行秩序的核心设施，严格按照交通信号通行能有效避免路口的交叉碰撞事故，保障路口的通行安全与效率。', NULL, '交通信号', '2026-05-17 15:20:56');
