INSERT INTO `biz_question` VALUES (219, 1, 2, '这个标志的作用是用以警告车辆驾驶人谨慎慢行，注意横向来车。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核道路交通安全的相关法律法规与安全驾驶要求，题目中的做法符合《中华人民共和国道路交通安全法》及相关实施条例的规定，是安全、合规的驾驶行为。\n【安全意义】严格遵守道路交通安全法律法规，规范自身的驾驶行为，是保障行车安全的核心前提，能有效降低交通事故的发生概率，保障自身与他人的人身、财产安全。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (220, 1, 2, '这个标志的含义是前方即将行驶至Y型交叉路口？', '正确', '错误', NULL, NULL, 'B', '本题正确答案为B（错误）。\n【考点解析】本题考核交通信号灯的强制性规定。根据《中华人民共和国道路交通安全法》规定，车辆、行人必须严格按照交通信号通行，红灯亮时，禁止车辆越过停止线进入路口，即使路口内没有其他车辆、行人，也不得违规通行。\n【错误危害】闯红灯、违规进入路口的行为会严重破坏路口的通行秩序，极易与横向正常通行的车辆、行人发生碰撞，造成严重的交通事故，同时也会引发路口的交通拥堵，影响整体的通行效率。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (221, 1, 2, '这个标志的含义是警告前方出现向左的急转弯路。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核道路交通安全的相关法律法规与安全驾驶要求，题目中的做法符合《中华人民共和国道路交通安全法》及相关实施条例的规定，是安全、合规的驾驶行为。\n【安全意义】严格遵守道路交通安全法律法规，规范自身的驾驶行为，是保障行车安全的核心前提，能有效降低交通事故的发生概率，保障自身与他人的人身、财产安全。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (222, 1, 2, '这个标志的含义是警告前方道路易滑，注意慢行。', '正确', '错误', NULL, NULL, 'B', '本题正确答案为B（错误）。\n【考点解析】本题考核道路交通安全的禁止性规定，题目中的做法违反了《中华人民共和国道路交通安全法》及相关实施条例的规定，属于交通违法行为，将面临相应的行政处罚。\n【错误危害】违规驾驶行为会严重破坏正常的道路通行秩序，大幅提升交通事故的发生风险，不仅会对自身的人身、财产安全造成威胁，也会对其他交通参与者的安全造成严重影响。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (223, 1, 2, '这个标志的含义是警告前方有两个相邻的反向转弯道路。', '正确', '错误', NULL, NULL, 'B', '本题正确答案为B（错误）。\n【考点解析】本题考核道路交通安全的禁止性规定，题目中的做法违反了《中华人民共和国道路交通安全法》及相关实施条例的规定，属于交通违法行为，将面临相应的行政处罚。\n【错误危害】违规驾驶行为会严重破坏正常的道路通行秩序，大幅提升交通事故的发生风险，不仅会对自身的人身、财产安全造成威胁，也会对其他交通参与者的安全造成严重影响。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (224, 1, 2, '这个标志的含义是提醒前方桥面宽度变窄。', '正确', '错误', NULL, NULL, 'B', '本题正确答案为B（错误）。\n【考点解析】本题考核道路交通安全的禁止性规定，题目中的做法违反了《中华人民共和国道路交通安全法》及相关实施条例的规定，属于交通违法行为，将面临相应的行政处罚。\n【错误危害】违规驾驶行为会严重破坏正常的道路通行秩序，大幅提升交通事故的发生风险，不仅会对自身的人身、财产安全造成威胁，也会对其他交通参与者的安全造成严重影响。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (225, 1, 2, '这个标志的含义是提醒前方右侧行车道或路面变窄。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核道路交通安全的相关法律法规与安全驾驶要求，题目中的做法符合《中华人民共和国道路交通安全法》及相关实施条例的规定，是安全、合规的驾驶行为。\n【安全意义】严格遵守道路交通安全法律法规，规范自身的驾驶行为，是保障行车安全的核心前提，能有效降低交通事故的发生概率，保障自身与他人的人身、财产安全。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (226, 1, 2, '这个标志的含义是提醒前方左侧行车道或路面变窄。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核道路交通安全的相关法律法规与安全驾驶要求，题目中的做法符合《中华人民共和国道路交通安全法》及相关实施条例的规定，是安全、合规的驾驶行为。\n【安全意义】严格遵守道路交通安全法律法规，规范自身的驾驶行为，是保障行车安全的核心前提，能有效降低交通事故的发生概率，保障自身与他人的人身、财产安全。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (227, 1, 2, '这个标志的含义是提醒前方两侧行车道或路面变窄。', '正确', '错误', NULL, NULL, 'B', '本题正确答案为B（错误）。\n【考点解析】本题考核道路交通安全的禁止性规定，题目中的做法违反了《中华人民共和国道路交通安全法》及相关实施条例的规定，属于交通违法行为，将面临相应的行政处罚。\n【错误危害】违规驾驶行为会严重破坏正常的道路通行秩序，大幅提升交通事故的发生风险，不仅会对自身的人身、财产安全造成威胁，也会对其他交通参与者的安全造成严重影响。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (228, 1, 2, '这个地面标记的含义是预告前方设有交叉路口。', '正确', '错误', NULL, NULL, 'B', '本题正确答案为B（错误）。\n【考点解析】本题考核交通信号灯的强制性规定。根据《中华人民共和国道路交通安全法》规定，车辆、行人必须严格按照交通信号通行，红灯亮时，禁止车辆越过停止线进入路口，即使路口内没有其他车辆、行人，也不得违规通行。\n【错误危害】闯红灯、违规进入路口的行为会严重破坏路口的通行秩序，极易与横向正常通行的车辆、行人发生碰撞，造成严重的交通事故，同时也会引发路口的交通拥堵，影响整体的通行效率。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (229, 1, 2, '夜间行车，驾驶人的视野受限，很难观察到灯光照射区域以外的交通情况，因此要减速行驶。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核机动车灯光使用的相关规定。根据《中华人民共和国道路交通安全法实施条例》规定，机动车在夜间通过急弯、坡路、拱桥、人行横道或者没有交通信号灯控制的路口时，应当交替使用远近光灯示意，目的是提醒对向车辆、行人注意来车，避免因视线盲区引发交通事故。\n【安全意义】正确使用灯光是夜间安全行车的核心要求，合理的灯光示意能有效降低夜间行车的事故风险，保障自身与他人的通行安全。', NULL, '灯光使用', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (230, 1, 2, '夜间驾驶人对事物的观察能力明显比白天差，视距变短。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核道路交通安全的相关法律法规与安全驾驶要求，题目中的做法符合《中华人民共和国道路交通安全法》及相关实施条例的规定，是安全、合规的驾驶行为。\n【安全意义】严格遵守道路交通安全法律法规，规范自身的驾驶行为，是保障行车安全的核心前提，能有效降低交通事故的发生概率，保障自身与他人的人身、财产安全。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (231, 1, 2, '在冰雪道路上行车时，车辆的稳定性降低，加速过急时车轮极易空转或溜滑。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核道路交通安全的相关法律法规与安全驾驶要求，题目中的做法符合《中华人民共和国道路交通安全法》及相关实施条例的规定，是安全、合规的驾驶行为。\n【安全意义】严格遵守道路交通安全法律法规，规范自身的驾驶行为，是保障行车安全的核心前提，能有效降低交通事故的发生概率，保障自身与他人的人身、财产安全。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (232, 1, 2, '雪天行车中，在有车辙的路段应循车辙行驶。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核道路交通安全的相关法律法规与安全驾驶要求，题目中的做法符合《中华人民共和国道路交通安全法》及相关实施条例的规定，是安全、合规的驾驶行为。\n【安全意义】严格遵守道路交通安全法律法规，规范自身的驾驶行为，是保障行车安全的核心前提，能有效降低交通事故的发生概率，保障自身与他人的人身、财产安全。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (233, 1, 2, '车辆在冰雪路面紧急制动易产生侧滑，应低速行驶，可利用发动机制动进行减速。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核道路交通安全的相关法律法规与安全驾驶要求，题目中的做法符合《中华人民共和国道路交通安全法》及相关实施条例的规定，是安全、合规的驾驶行为。\n【安全意义】严格遵守道路交通安全法律法规，规范自身的驾驶行为，是保障行车安全的核心前提，能有效降低交通事故的发生概率，保障自身与他人的人身、财产安全。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (234, 1, 2, '连续降雨天气，山区公路可能会出现路肩疏松和堤坡坍塌现象，行车时应选择道路中间坚实的路面，避免靠近路边行驶。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核道路交通安全的相关法律法规与安全驾驶要求，题目中的做法符合《中华人民共和国道路交通安全法》及相关实施条例的规定，是安全、合规的驾驶行为。\n【安全意义】严格遵守道路交通安全法律法规，规范自身的驾驶行为，是保障行车安全的核心前提，能有效降低交通事故的发生概率，保障自身与他人的人身、财产安全。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (235, 1, 2, '在大雨天行车，为避免发生“水滑”而造成危险，要控制速度行驶。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核道路交通安全的相关法律法规与安全驾驶要求，题目中的做法符合《中华人民共和国道路交通安全法》及相关实施条例的规定，是安全、合规的驾驶行为。\n【安全意义】严格遵守道路交通安全法律法规，规范自身的驾驶行为，是保障行车安全的核心前提，能有效降低交通事故的发生概率，保障自身与他人的人身、财产安全。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (236, 1, 2, '车辆在下坡行驶时，可充分利用空挡滑行。', '正确', '错误', NULL, NULL, 'B', '本题正确答案为B（错误）。\n【考点解析】本题考核道路交通安全的禁止性规定，题目中的做法违反了《中华人民共和国道路交通安全法》及相关实施条例的规定，属于交通违法行为，将面临相应的行政处罚。\n【错误危害】违规驾驶行为会严重破坏正常的道路通行秩序，大幅提升交通事故的发生风险，不仅会对自身的人身、财产安全造成威胁，也会对其他交通参与者的安全造成严重影响。', NULL, '记分', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (237, 1, 2, '车辆进入山区道路后，要特别注意“连续转弯”标志，并主动避让车辆及行人，适时减速和提前鸣喇叭。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核机动车超车与让行的相关规定。根据《中华人民共和国道路交通安全法》规定，机动车超车时，应当提前开启左转向灯、变换使用远、近光灯或者鸣喇叭，确认有充足的安全距离后，从前车的左侧超越，在与被超车辆拉开必要的安全距离后，开启右转向灯，驶回原车道；遇前方车辆停车排队等候或者缓慢行驶时，不得借道超车或者占用对面车道，不得穿插等候的车辆。\n【安全意义】规范的超车与让行行为是维护道路通行秩序的核心，能有效避免因强行超车、抢行引发的刮擦、碰撞等交通事故，保障道路通行的安全与顺畅。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (238, 1, 2, '车辆在山区上坡路驾驶，减挡要及时、准确、迅速，避免拖挡行驶导致发动机动力不足。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核道路交通安全的相关法律法规与安全驾驶要求，题目中的做法符合《中华人民共和国道路交通安全法》及相关实施条例的规定，是安全、合规的驾驶行为。\n【安全意义】严格遵守道路交通安全法律法规，规范自身的驾驶行为，是保障行车安全的核心前提，能有效降低交通事故的发生概率，保障自身与他人的人身、财产安全。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (239, 1, 2, '通过山区危险路段，尤其是通过经常发生塌方、泥石流的山区地段，应谨慎驾驶，避免停车。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核道路交通安全的相关法律法规与安全驾驶要求，题目中的做法符合《中华人民共和国道路交通安全法》及相关实施条例的规定，是安全、合规的驾驶行为。\n【安全意义】严格遵守道路交通安全法律法规，规范自身的驾驶行为，是保障行车安全的核心前提，能有效降低交通事故的发生概率，保障自身与他人的人身、财产安全。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (240, 1, 2, '通过经常发生塌方、泥石流的山区地段，避免停车。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核道路交通安全的相关法律法规与安全驾驶要求，题目中的做法符合《中华人民共和国道路交通安全法》及相关实施条例的规定，是安全、合规的驾驶行为。\n【安全意义】严格遵守道路交通安全法律法规，规范自身的驾驶行为，是保障行车安全的核心前提，能有效降低交通事故的发生概率，保障自身与他人的人身、财产安全。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (241, 1, 2, '车辆在交叉路口绿灯亮后，遇非机动车抢道行驶时，可以不让行。', '正确', '错误', NULL, NULL, 'B', '本题正确答案为B（错误）。\n【考点解析】本题考核机动车超车的禁止性规定。根据《中华人民共和国道路交通安全法实施条例》规定，机动车在与对面来车有会车可能时、前车正在左转弯、掉头、超车时、行经铁路道口、交叉路口、窄桥、弯道、陡坡、隧道、人行横道、市区交通流量大的路段等没有超车条件的，不得超车。\n【错误危害】违规超车、抢行行为会严重破坏正常的通行秩序，极易与对向车辆、前车发生碰撞，同时也会影响周边车辆的正常行驶，引发大面积的交通拥堵和次生事故。', NULL, '交通信号', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (242, 1, 2, '机动车在环形路口内行驶，遇有其他车辆强行驶入时，只要有优先权就可以不避让', '正确', '错误', NULL, NULL, 'B', '本题正确答案为B（错误）。\n【考点解析】本题考核机动车超车的禁止性规定。根据《中华人民共和国道路交通安全法实施条例》规定，机动车在与对面来车有会车可能时、前车正在左转弯、掉头、超车时、行经铁路道口、交叉路口、窄桥、弯道、陡坡、隧道、人行横道、市区交通流量大的路段等没有超车条件的，不得超车。\n【错误危害】违规超车、抢行行为会严重破坏正常的通行秩序，极易与对向车辆、前车发生碰撞，同时也会影响周边车辆的正常行驶，引发大面积的交通拥堵和次生事故。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (243, 1, 2, '车辆行至交叉路口时，左转弯车辆在任何时段都可以进入左弯待转区。', '正确', '错误', NULL, NULL, 'B', '本题正确答案为B（错误）。\n【考点解析】本题考核交通信号灯的强制性规定。根据《中华人民共和国道路交通安全法》规定，车辆、行人必须严格按照交通信号通行，红灯亮时，禁止车辆越过停止线进入路口，即使路口内没有其他车辆、行人，也不得违规通行。\n【错误危害】闯红灯、违规进入路口的行为会严重破坏路口的通行秩序，极易与横向正常通行的车辆、行人发生碰撞，造成严重的交通事故，同时也会引发路口的交通拥堵，影响整体的通行效率。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (244, 1, 2, '行车中，发现行人突然横过道路时，应迅速减速避让。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核机动车超车与让行的相关规定。根据《中华人民共和国道路交通安全法》规定，机动车超车时，应当提前开启左转向灯、变换使用远、近光灯或者鸣喇叭，确认有充足的安全距离后，从前车的左侧超越，在与被超车辆拉开必要的安全距离后，开启右转向灯，驶回原车道；遇前方车辆停车排队等候或者缓慢行驶时，不得借道超车或者占用对面车道，不得穿插等候的车辆。\n【安全意义】规范的超车与让行行为是维护道路通行秩序的核心，能有效避免因强行超车、抢行引发的刮擦、碰撞等交通事故，保障道路通行的安全与顺畅。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (245, 1, 2, '车辆下长坡时要减挡行驶，以充分利用发动机的制动作用。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核道路交通安全的相关法律法规与安全驾驶要求，题目中的做法符合《中华人民共和国道路交通安全法》及相关实施条例的规定，是安全、合规的驾驶行为。\n【安全意义】严格遵守道路交通安全法律法规，规范自身的驾驶行为，是保障行车安全的核心前提，能有效降低交通事故的发生概率，保障自身与他人的人身、财产安全。', NULL, '记分', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (246, 1, 2, '驾驶机动车下长坡时，利用惯性滑行可以减少燃油消耗，值得提倡。', '正确', '错误', NULL, NULL, 'B', '本题正确答案为B（错误）。\n【考点解析】本题考核道路交通安全的禁止性规定，题目中的做法违反了《中华人民共和国道路交通安全法》及相关实施条例的规定，属于交通违法行为，将面临相应的行政处罚。\n【错误危害】违规驾驶行为会严重破坏正常的道路通行秩序，大幅提升交通事故的发生风险，不仅会对自身的人身、财产安全造成威胁，也会对其他交通参与者的安全造成严重影响。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (247, 1, 2, '通过漫水路时要谨慎慢行，不得空挡滑行。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核道路交通安全的相关法律法规与安全驾驶要求，题目中的做法符合《中华人民共和国道路交通安全法》及相关实施条例的规定，是安全、合规的驾驶行为。\n【安全意义】严格遵守道路交通安全法律法规，规范自身的驾驶行为，是保障行车安全的核心前提，能有效降低交通事故的发生概率，保障自身与他人的人身、财产安全。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (248, 1, 2, '车辆行至泥泞或翻浆路段时，应停车观察，选择平整、坚实的路段缓慢通过。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核道路交通安全的相关法律法规与安全驾驶要求，题目中的做法符合《中华人民共和国道路交通安全法》及相关实施条例的规定，是安全、合规的驾驶行为。\n【安全意义】严格遵守道路交通安全法律法规，规范自身的驾驶行为，是保障行车安全的核心前提，能有效降低交通事故的发生概率，保障自身与他人的人身、财产安全。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (249, 1, 2, '车辆在山区道路行车下陡坡时，不得超车。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核机动车超车与让行的相关规定。根据《中华人民共和国道路交通安全法》规定，机动车超车时，应当提前开启左转向灯、变换使用远、近光灯或者鸣喇叭，确认有充足的安全距离后，从前车的左侧超越，在与被超车辆拉开必要的安全距离后，开启右转向灯，驶回原车道；遇前方车辆停车排队等候或者缓慢行驶时，不得借道超车或者占用对面车道，不得穿插等候的车辆。\n【安全意义】规范的超车与让行行为是维护道路通行秩序的核心，能有效避免因强行超车、抢行引发的刮擦、碰撞等交通事故，保障道路通行的安全与顺畅。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (250, 1, 2, '通过隧道时，不得超车。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核机动车超车与让行的相关规定。根据《中华人民共和国道路交通安全法》规定，机动车超车时，应当提前开启左转向灯、变换使用远、近光灯或者鸣喇叭，确认有充足的安全距离后，从前车的左侧超越，在与被超车辆拉开必要的安全距离后，开启右转向灯，驶回原车道；遇前方车辆停车排队等候或者缓慢行驶时，不得借道超车或者占用对面车道，不得穿插等候的车辆。\n【安全意义】规范的超车与让行行为是维护道路通行秩序的核心，能有效避免因强行超车、抢行引发的刮擦、碰撞等交通事故，保障道路通行的安全与顺畅。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (251, 1, 2, '通过铁路道口时，不得超车。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核机动车超车与让行的相关规定。根据《中华人民共和国道路交通安全法》规定，机动车超车时，应当提前开启左转向灯、变换使用远、近光灯或者鸣喇叭，确认有充足的安全距离后，从前车的左侧超越，在与被超车辆拉开必要的安全距离后，开启右转向灯，驶回原车道；遇前方车辆停车排队等候或者缓慢行驶时，不得借道超车或者占用对面车道，不得穿插等候的车辆。\n【安全意义】规范的超车与让行行为是维护道路通行秩序的核心，能有效避免因强行超车、抢行引发的刮擦、碰撞等交通事故，保障道路通行的安全与顺畅。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (252, 1, 2, '通过急转弯路段时，在车辆较少的情况下可以超车。', '正确', '错误', NULL, NULL, 'B', '本题正确答案为B（错误）。\n【考点解析】本题考核机动车超车的禁止性规定。根据《中华人民共和国道路交通安全法实施条例》规定，机动车在与对面来车有会车可能时、前车正在左转弯、掉头、超车时、行经铁路道口、交叉路口、窄桥、弯道、陡坡、隧道、人行横道、市区交通流量大的路段等没有超车条件的，不得超车。\n【错误危害】违规超车、抢行行为会严重破坏正常的通行秩序，极易与对向车辆、前车发生碰撞，同时也会影响周边车辆的正常行驶，引发大面积的交通拥堵和次生事故。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (253, 1, 2, '通过窄路、窄桥时，不得超车。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核机动车超车与让行的相关规定。根据《中华人民共和国道路交通安全法》规定，机动车超车时，应当提前开启左转向灯、变换使用远、近光灯或者鸣喇叭，确认有充足的安全距离后，从前车的左侧超越，在与被超车辆拉开必要的安全距离后，开启右转向灯，驶回原车道；遇前方车辆停车排队等候或者缓慢行驶时，不得借道超车或者占用对面车道，不得穿插等候的车辆。\n【安全意义】规范的超车与让行行为是维护道路通行秩序的核心，能有效避免因强行超车、抢行引发的刮擦、碰撞等交通事故，保障道路通行的安全与顺畅。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (254, 1, 2, '驾驶车辆向右变更车道时，应提前开启右转向灯，注意观察，在确保安全的情况下，驶入要变更的车道。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核道路交通安全的相关法律法规与安全驾驶要求，题目中的做法符合《中华人民共和国道路交通安全法》及相关实施条例的规定，是安全、合规的驾驶行为。\n【安全意义】严格遵守道路交通安全法律法规，规范自身的驾驶行为，是保障行车安全的核心前提，能有效降低交通事故的发生概率，保障自身与他人的人身、财产安全。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (255, 1, 2, '变更车道时只需开启转向灯，便可迅速转向驶入相应的行车道。', '正确', '错误', NULL, NULL, 'B', '本题正确答案为B（错误）。\n【考点解析】本题考核道路交通安全的禁止性规定，题目中的做法违反了《中华人民共和国道路交通安全法》及相关实施条例的规定，属于交通违法行为，将面临相应的行政处罚。\n【错误危害】违规驾驶行为会严重破坏正常的道路通行秩序，大幅提升交通事故的发生风险，不仅会对自身的人身、财产安全造成威胁，也会对其他交通参与者的安全造成严重影响。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (256, 1, 2, '变更车道时，应开启转向灯，迅速驶入侧方车道。', '正确', '错误', NULL, NULL, 'B', '本题正确答案为B（错误）。\n【考点解析】本题考核道路交通安全的禁止性规定，题目中的做法违反了《中华人民共和国道路交通安全法》及相关实施条例的规定，属于交通违法行为，将面临相应的行政处罚。\n【错误危害】违规驾驶行为会严重破坏正常的道路通行秩序，大幅提升交通事故的发生风险，不仅会对自身的人身、财产安全造成威胁，也会对其他交通参与者的安全造成严重影响。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (257, 1, 2, '变更车道时只需开启转向灯，并迅速转向驶入相应的车道，以不妨碍同车道机动车正常行驶。', '正确', '错误', NULL, NULL, 'B', '本题正确答案为B（错误）。\n【考点解析】本题考核道路交通安全的禁止性规定，题目中的做法违反了《中华人民共和国道路交通安全法》及相关实施条例的规定，属于交通违法行为，将面临相应的行政处罚。\n【错误危害】违规驾驶行为会严重破坏正常的道路通行秩序，大幅提升交通事故的发生风险，不仅会对自身的人身、财产安全造成威胁，也会对其他交通参与者的安全造成严重影响。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (258, 1, 2, '驾驶机动车变更车道前应仔细观察，目的是判断有无变更车道的条件。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核道路交通安全的相关法律法规与安全驾驶要求，题目中的做法符合《中华人民共和国道路交通安全法》及相关实施条例的规定，是安全、合规的驾驶行为。\n【安全意义】严格遵守道路交通安全法律法规，规范自身的驾驶行为，是保障行车安全的核心前提，能有效降低交通事故的发生概率，保障自身与他人的人身、财产安全。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (259, 1, 2, '车辆在高速公路匝道提速到每小时60公里以上时，可直接驶入行车道。', '正确', '错误', NULL, NULL, 'B', '本题正确答案为B（错误）。', NULL, '高速公路', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (260, 1, 2, '《道路交通安全法实施条例》规定，高速公路上最高时速不得超过120公里。因此在高速公路上行驶只要时速不超过120公里就不违法。', '正确', '错误', NULL, NULL, 'B', '本题正确答案为B（错误）。', NULL, '高速公路', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (261, 1, 2, '驾驶机动车在高速公路上行驶，能见度小于200米时，车速不得超过每小时60公里。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。', NULL, '高速公路', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (262, 1, 2, '车辆不得在高速公路匝道上掉头。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核高速公路行车的禁止性规定。根据《中华人民共和国道路交通安全法实施条例》规定，机动车在高速公路上行驶，不得倒车、逆行、穿越中央分隔带掉头或者在车道内停车，此类行为属于严重的交通违法行为。\n【安全意义】高速公路为全封闭、单向行驶的快速道路，倒车、逆行等行为会完全破坏正常的通行秩序，与正常行驶的车辆形成极大的速度差，极易引发恶性交通事故。', NULL, '高速公路', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (263, 1, 2, '车辆不得在高速公路匝道上倒车。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核高速公路行车的禁止性规定。根据《中华人民共和国道路交通安全法实施条例》规定，机动车在高速公路上行驶，不得倒车、逆行、穿越中央分隔带掉头或者在车道内停车，此类行为属于严重的交通违法行为。\n【安全意义】高速公路为全封闭、单向行驶的快速道路，倒车、逆行等行为会完全破坏正常的通行秩序，与正常行驶的车辆形成极大的速度差，极易引发恶性交通事故。', NULL, '高速公路', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (264, 1, 2, '车辆应靠高速公路右侧的路肩上行驶。', '正确', '错误', NULL, NULL, 'B', '本题正确答案为B（错误）。', NULL, '高速公路', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (265, 1, 2, '车辆在高速公路上行车，可以频繁地变更车道。', '正确', '错误', NULL, NULL, 'B', '本题正确答案为B（错误）。', NULL, '高速公路', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (266, 1, 2, '高速公路因发生事故造成堵塞时，可在右侧紧急停车带或路肩行驶。', '正确', '错误', NULL, NULL, 'B', '本题正确答案为B（错误）。', NULL, '高速公路', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (267, 1, 2, '在高速公路上遇分流交通管制时，可不驶出高速公路，就地靠边停靠等待管制结束后继续前行。', '正确', '错误', NULL, NULL, 'B', '本题正确答案为B（错误）。', NULL, '高速公路', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (268, 1, 2, '在高速公路上行驶感觉疲劳时，应立即停车休息。', '正确', '错误', NULL, NULL, 'B', '本题正确答案为B（错误）。', NULL, '高速公路', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (269, 1, 2, '车辆在高速公路行驶时，可以仅凭感觉确认车速。', '正确', '错误', NULL, NULL, 'B', '本题正确答案为B（错误）。', NULL, '高速公路', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (270, 1, 2, '车辆后轮胎爆裂，车尾会摇摆不定，驾驶人应双手紧握转向盘，控制车辆保持直线行驶，减速停车。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核道路交通安全的相关法律法规与安全驾驶要求，题目中的做法符合《中华人民共和国道路交通安全法》及相关实施条例的规定，是安全、合规的驾驶行为。\n【安全意义】严格遵守道路交通安全法律法规，规范自身的驾驶行为，是保障行车安全的核心前提，能有效降低交通事故的发生概率，保障自身与他人的人身、财产安全。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (271, 1, 2, '行车中当驾驶人意识到爆胎时，应在控制住方向的情况下，轻踏制动踏板，使车辆缓慢减速，逐渐平稳地停靠于路边。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核道路交通安全的相关法律法规与安全驾驶要求，题目中的做法符合《中华人民共和国道路交通安全法》及相关实施条例的规定，是安全、合规的驾驶行为。\n【安全意义】严格遵守道路交通安全法律法规，规范自身的驾驶行为，是保障行车安全的核心前提，能有效降低交通事故的发生概率，保障自身与他人的人身、财产安全。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (272, 1, 2, '行车中当车辆突然爆胎时，驾驶人切忌慌乱中急踏制动踏板，尽量采用“抢挡”的方法，利用发动机制动使车辆减速。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核道路交通安全的相关法律法规与安全驾驶要求，题目中的做法符合《中华人民共和国道路交通安全法》及相关实施条例的规定，是安全、合规的驾驶行为。\n【安全意义】严格遵守道路交通安全法律法规，规范自身的驾驶行为，是保障行车安全的核心前提，能有效降低交通事故的发生概率，保障自身与他人的人身、财产安全。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (273, 1, 2, '车辆前轮胎爆裂，危险较大，方向会立刻向爆胎车轮一侧跑偏，直接影响驾驶人对转向盘的控制。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核道路交通安全的相关法律法规与安全驾驶要求，题目中的做法符合《中华人民共和国道路交通安全法》及相关实施条例的规定，是安全、合规的驾驶行为。\n【安全意义】严格遵守道路交通安全法律法规，规范自身的驾驶行为，是保障行车安全的核心前提，能有效降低交通事故的发生概率，保障自身与他人的人身、财产安全。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (274, 1, 2, '车辆发生爆胎后，驾驶人在尚未控制住车速前，不要冒险使用行车制动器停车，以避免车辆横甩发生更大的险情。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核机动车车速限制的相关规定。根据《中华人民共和国道路交通安全法实施条例》规定，机动车在道路上行驶不得超过限速标志、标线标明的速度。在没有限速标志、标线的道路上，机动车不得超过下列最高行驶速度：(一)没有道路中心线的道路，城市道路为每小时30公里，公路为每小时40公里；(二)同方向只有1条机动车道的道路，城市道路为每小时50公里，公路为每小时70公里。\n【安全意义】合理的车速是行车安全的核心保障，严格遵守限速规定能有效降低事故的发生概率，同时也能减少事故的严重程度，保障驾乘人员的人身安全。', NULL, '车速规定', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (275, 1, 2, '行车中当车辆前轮爆胎已发生转向时，驾驶人应双手紧握转向盘，尽力控制车辆直线行驶。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核道路交通安全的相关法律法规与安全驾驶要求，题目中的做法符合《中华人民共和国道路交通安全法》及相关实施条例的规定，是安全、合规的驾驶行为。\n【安全意义】严格遵守道路交通安全法律法规，规范自身的驾驶行为，是保障行车安全的核心前提，能有效降低交通事故的发生概率，保障自身与他人的人身、财产安全。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (276, 1, 2, '行车中当驾驶人意识到车辆爆胎时，应在控制住方向的情况下采取紧急制动，迫使车辆迅速停住。', '正确', '错误', NULL, NULL, 'B', '本题正确答案为B（错误）。\n【考点解析】本题考核道路交通安全的禁止性规定，题目中的做法违反了《中华人民共和国道路交通安全法》及相关实施条例的规定，属于交通违法行为，将面临相应的行政处罚。\n【错误危害】违规驾驶行为会严重破坏正常的道路通行秩序，大幅提升交通事故的发生风险，不仅会对自身的人身、财产安全造成威胁，也会对其他交通参与者的安全造成严重影响。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (277, 1, 2, '夜间会车时，若对方车辆不关闭远光灯，可变换灯光提示对向车辆，同时减速靠右侧行驶或停车。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核机动车灯光使用的相关规定。根据《中华人民共和国道路交通安全法实施条例》规定，机动车在夜间通过急弯、坡路、拱桥、人行横道或者没有交通信号灯控制的路口时，应当交替使用远近光灯示意，目的是提醒对向车辆、行人注意来车，避免因视线盲区引发交通事故。\n【安全意义】正确使用灯光是夜间安全行车的核心要求，合理的灯光示意能有效降低夜间行车的事故风险，保障自身与他人的通行安全。', NULL, '灯光使用', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (278, 1, 2, '夜间通过没有路灯或路灯照明不良时，应将近光灯转换为远光灯，但同向行驶的后车不得使用远光灯。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核机动车灯光使用的相关规定。根据《中华人民共和国道路交通安全法实施条例》规定，机动车在夜间通过急弯、坡路、拱桥、人行横道或者没有交通信号灯控制的路口时，应当交替使用远近光灯示意，目的是提醒对向车辆、行人注意来车，避免因视线盲区引发交通事故。\n【安全意义】正确使用灯光是夜间安全行车的核心要求，合理的灯光示意能有效降低夜间行车的事故风险，保障自身与他人的通行安全。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (279, 1, 2, '夜间行车，遇对面来车未关闭远光灯时，应减速行驶，以防两车灯光的交汇处有行人通过时发生事故。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核机动车灯光使用的相关规定。根据《中华人民共和国道路交通安全法实施条例》规定，机动车在夜间通过急弯、坡路、拱桥、人行横道或者没有交通信号灯控制的路口时，应当交替使用远近光灯示意，目的是提醒对向车辆、行人注意来车，避免因视线盲区引发交通事故。\n【安全意义】正确使用灯光是夜间安全行车的核心要求，合理的灯光示意能有效降低夜间行车的事故风险，保障自身与他人的通行安全。', NULL, '灯光使用', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (280, 1, 2, '夜间通过无交通信号灯控制的交叉路口时，不得变换远、近光灯。', '正确', '错误', NULL, NULL, 'B', '本题正确答案为B（错误）。\n【考点解析】本题考核机动车灯光使用的禁止性规定。根据《中华人民共和国道路交通安全法实施条例》规定，夜间在没有中心隔离设施或者没有中心线的道路上，机动车遇相对方向来车时应当在距相对方向来车150米以外改用近光灯，在窄路、窄桥与非机动车会车时应当使用近光灯，不得长时间使用远光灯。\n【错误危害】违规使用远光灯会造成对向车辆驾驶人眩目，瞬间失去对前方路况的判断能力，极易引发正面碰撞、刮擦等严重交通事故，同时也会影响前方同向车辆的行驶安全。', NULL, '交通信号', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (281, 1, 2, '夜间行车，要尽量避免超车，确需超车时，可变换远近光灯向前车示意。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核机动车灯光使用的相关规定。根据《中华人民共和国道路交通安全法实施条例》规定，机动车在夜间通过急弯、坡路、拱桥、人行横道或者没有交通信号灯控制的路口时，应当交替使用远近光灯示意，目的是提醒对向车辆、行人注意来车，避免因视线盲区引发交通事故。\n【安全意义】正确使用灯光是夜间安全行车的核心要求，合理的灯光示意能有效降低夜间行车的事故风险，保障自身与他人的通行安全。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (282, 1, 2, '夜间尾随前车行驶时，后车可以使用远光灯。', '正确', '错误', NULL, NULL, 'B', '本题正确答案为B（错误）。\n【考点解析】本题考核机动车灯光使用的禁止性规定。根据《中华人民共和国道路交通安全法实施条例》规定，夜间在没有中心隔离设施或者没有中心线的道路上，机动车遇相对方向来车时应当在距相对方向来车150米以外改用近光灯，在窄路、窄桥与非机动车会车时应当使用近光灯，不得长时间使用远光灯。\n【错误危害】违规使用远光灯会造成对向车辆驾驶人眩目，瞬间失去对前方路况的判断能力，极易引发正面碰撞、刮擦等严重交通事故，同时也会影响前方同向车辆的行驶安全。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (283, 1, 2, '车辆通过学校和小区应注意观察标志标线，低速行驶，不要鸣喇叭。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核文明驾驶与行人避让的相关规定。根据《中华人民共和国道路交通安全法》规定，机动车行经人行横道时，应当减速行驶；遇行人正在通过人行横道，应当停车让行。机动车行经没有交通信号的道路时，遇行人横过道路，应当避让。\n【安全意义】文明驾驶、主动避让行人是机动车驾驶人的法定义务，也是保障道路交通安全的核心要求，能有效减少机动车与行人之间的交通事故，保护行人的人身安全。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (284, 1, 2, '在高速公路变更车道时，应提前开启转向灯，观察情况，确认安全后，驶入需要变更的车道。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。', NULL, '高速公路', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (285, 1, 2, '机动车在高速公路上遇前方交通受阻时，应当跟随前车顺序排队，并立即开启危险报警闪光灯，防止追尾。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。', NULL, '高速公路', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (286, 1, 2, '风、雨、雪、雾等复杂气象条件，遇前车速度较低时，应开启前照灯，连续鸣喇叭迅速超越。', '正确', '错误', NULL, NULL, 'B', '本题正确答案为B（错误）。\n【考点解析】本题考核机动车车速限制的禁止性规定。根据《中华人民共和国道路交通安全法》规定，机动车行驶超过规定时速50%的，一次记12分，同时可处200元以上2000元以下罚款，可以并处吊销机动车驾驶证。\n【错误危害】超速行驶会大幅缩短驾驶人的反应时间和制动距离，同时也会降低车辆的操控稳定性，一旦遇到突发情况，驾驶人很难及时做出正确的处置，极易引发严重的交通事故，造成车毁人亡的后果。', NULL, '车速规定', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (287, 1, 2, '驾驶车辆在道路上行驶时，应当按照规定的速度安全行驶。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核道路交通安全的相关法律法规与安全驾驶要求，题目中的做法符合《中华人民共和国道路交通安全法》及相关实施条例的规定，是安全、合规的驾驶行为。\n【安全意义】严格遵守道路交通安全法律法规，规范自身的驾驶行为，是保障行车安全的核心前提，能有效降低交通事故的发生概率，保障自身与他人的人身、财产安全。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (288, 1, 2, '驾驶人一边驾车，一边打手持电话是违法行为。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核道路交通安全的相关法律法规与安全驾驶要求，题目中的做法符合《中华人民共和国道路交通安全法》及相关实施条例的规定，是安全、合规的驾驶行为。\n【安全意义】严格遵守道路交通安全法律法规，规范自身的驾驶行为，是保障行车安全的核心前提，能有效降低交通事故的发生概率，保障自身与他人的人身、财产安全。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (289, 1, 2, '谨慎驾驶的三原则是集中注意力、仔细观察和提前预防。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核道路交通安全的相关法律法规与安全驾驶要求，题目中的做法符合《中华人民共和国道路交通安全法》及相关实施条例的规定，是安全、合规的驾驶行为。\n【安全意义】严格遵守道路交通安全法律法规，规范自身的驾驶行为，是保障行车安全的核心前提，能有效降低交通事故的发生概率，保障自身与他人的人身、财产安全。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (290, 1, 2, '遇到路口情况复杂时，应做到“宁停三分，不抢一秒”。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核交通信号灯与路口通行的相关规定。根据《中华人民共和国道路交通安全法》规定，车辆、行人应当按照交通信号通行；遇有交通警察现场指挥时，应当按照交通警察的指挥通行；在没有交通信号的道路上，应当在确保安全、畅通的原则下通行。红灯亮时，禁止车辆通行，车辆应当停在停止线以外，不得越过停止线进入路口。\n【安全意义】交通信号灯是维护路口通行秩序的核心设施，严格按照交通信号通行能有效避免路口的交叉碰撞事故，保障路口的通行安全与效率。', NULL, '记分', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (291, 1, 2, '行车中要文明驾驶，礼让行车，做到不开英雄车、冒险车、赌气车和带病车。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核机动车超车与让行的相关规定。根据《中华人民共和国道路交通安全法》规定，机动车超车时，应当提前开启左转向灯、变换使用远、近光灯或者鸣喇叭，确认有充足的安全距离后，从前车的左侧超越，在与被超车辆拉开必要的安全距离后，开启右转向灯，驶回原车道；遇前方车辆停车排队等候或者缓慢行驶时，不得借道超车或者占用对面车道，不得穿插等候的车辆。\n【安全意义】规范的超车与让行行为是维护道路通行秩序的核心，能有效避免因强行超车、抢行引发的刮擦、碰撞等交通事故，保障道路通行的安全与顺畅。', NULL, '会车让行', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (292, 1, 2, '女驾驶人穿高跟鞋驾驶车辆，不利于安全行车。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核道路交通安全的相关法律法规与安全驾驶要求，题目中的做法符合《中华人民共和国道路交通安全法》及相关实施条例的规定，是安全、合规的驾驶行为。\n【安全意义】严格遵守道路交通安全法律法规，规范自身的驾驶行为，是保障行车安全的核心前提，能有效降低交通事故的发生概率，保障自身与他人的人身、财产安全。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (293, 1, 2, '驾驶车辆时，长时间左臂搭在车门窗上，或者长时间右手抓住变速器操纵杆，是一种驾驶陋习。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核道路交通安全的相关法律法规与安全驾驶要求，题目中的做法符合《中华人民共和国道路交通安全法》及相关实施条例的规定，是安全、合规的驾驶行为。\n【安全意义】严格遵守道路交通安全法律法规，规范自身的驾驶行为，是保障行车安全的核心前提，能有效降低交通事故的发生概率，保障自身与他人的人身、财产安全。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (294, 1, 2, '驾驶人一边驾车，一边吸烟对安全行车无影响。', '正确', '错误', NULL, NULL, 'B', '本题正确答案为B（错误）。\n【考点解析】本题考核道路交通安全的禁止性规定，题目中的做法违反了《中华人民共和国道路交通安全法》及相关实施条例的规定，属于交通违法行为，将面临相应的行政处罚。\n【错误危害】违规驾驶行为会严重破坏正常的道路通行秩序，大幅提升交通事故的发生风险，不仅会对自身的人身、财产安全造成威胁，也会对其他交通参与者的安全造成严重影响。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (295, 1, 2, '车辆在路边起步后应尽快提速，并向左迅速转向驶入正常行驶道路。', '正确', '错误', NULL, NULL, 'B', '本题正确答案为B（错误）。\n【考点解析】本题考核道路交通安全的禁止性规定，题目中的做法违反了《中华人民共和国道路交通安全法》及相关实施条例的规定，属于交通违法行为，将面临相应的行政处罚。\n【错误危害】违规驾驶行为会严重破坏正常的道路通行秩序，大幅提升交通事故的发生风险，不仅会对自身的人身、财产安全造成威胁，也会对其他交通参与者的安全造成严重影响。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (296, 1, 2, '车辆转弯时应沿道路右侧行驶，不要侵占对方的车道，做到“左转转大弯，右转转小弯”。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核道路交通安全的相关法律法规与安全驾驶要求，题目中的做法符合《中华人民共和国道路交通安全法》及相关实施条例的规定，是安全、合规的驾驶行为。\n【安全意义】严格遵守道路交通安全法律法规，规范自身的驾驶行为，是保障行车安全的核心前提，能有效降低交通事故的发生概率，保障自身与他人的人身、财产安全。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (297, 1, 2, '当行人出现交通安全违法行为时，车辆可以不给行人让行。', '正确', '错误', NULL, NULL, 'B', '本题正确答案为B（错误）。\n【考点解析】本题考核机动车超车的禁止性规定。根据《中华人民共和国道路交通安全法实施条例》规定，机动车在与对面来车有会车可能时、前车正在左转弯、掉头、超车时、行经铁路道口、交叉路口、窄桥、弯道、陡坡、隧道、人行横道、市区交通流量大的路段等没有超车条件的，不得超车。\n【错误危害】违规超车、抢行行为会严重破坏正常的通行秩序，极易与对向车辆、前车发生碰撞，同时也会影响周边车辆的正常行驶，引发大面积的交通拥堵和次生事故。', NULL, '会车让行', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (298, 1, 2, '行车中遇残疾人影响通行时，应主动减速礼让。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核道路交通安全的相关法律法规与安全驾驶要求，题目中的做法符合《中华人民共和国道路交通安全法》及相关实施条例的规定，是安全、合规的驾驶行为。\n【安全意义】严格遵守道路交通安全法律法规，规范自身的驾驶行为，是保障行车安全的核心前提，能有效降低交通事故的发生概率，保障自身与他人的人身、财产安全。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (299, 1, 2, '设有安全带装置的车辆，应要求车内乘员系安全带。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核机动车安全防护的相关规定。根据《中华人民共和国道路交通安全法》规定，机动车行驶时，驾驶人、乘坐人员应当按规定使用安全带，摩托车驾驶人及乘坐人员应当按规定戴安全头盔。\n【安全意义】安全带是车辆发生碰撞时保护驾乘人员生命安全的核心装置，能有效降低碰撞事故中驾乘人员的伤亡率，是行车安全的第一道防线。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (300, 1, 2, '行车中前方遇自行车影响通行时，可鸣喇叭提示，加速绕行。', '正确', '错误', NULL, NULL, 'B', '本题正确答案为B（错误）。\n【考点解析】本题考核道路交通安全的禁止性规定，题目中的做法违反了《中华人民共和国道路交通安全法》及相关实施条例的规定，属于交通违法行为，将面临相应的行政处罚。\n【错误危害】违规驾驶行为会严重破坏正常的道路通行秩序，大幅提升交通事故的发生风险，不仅会对自身的人身、财产安全造成威胁，也会对其他交通参与者的安全造成严重影响。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (301, 1, 2, '车辆长时间停放时，应选择停车场停车。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核道路交通安全的相关法律法规与安全驾驶要求，题目中的做法符合《中华人民共和国道路交通安全法》及相关实施条例的规定，是安全、合规的驾驶行为。\n【安全意义】严格遵守道路交通安全法律法规，规范自身的驾驶行为，是保障行车安全的核心前提，能有效降低交通事故的发生概率，保障自身与他人的人身、财产安全。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (302, 1, 2, '在行驶过程中，机动车驾驶人要注意与前车保持安全距离。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核道路交通安全的相关法律法规与安全驾驶要求，题目中的做法符合《中华人民共和国道路交通安全法》及相关实施条例的规定，是安全、合规的驾驶行为。\n【安全意义】严格遵守道路交通安全法律法规，规范自身的驾驶行为，是保障行车安全的核心前提，能有效降低交通事故的发生概率，保障自身与他人的人身、财产安全。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (303, 1, 2, '专用车道规定的专用使用时间之外，其他车辆可以进入专用车道行驶。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核道路交通安全的相关法律法规与安全驾驶要求，题目中的做法符合《中华人民共和国道路交通安全法》及相关实施条例的规定，是安全、合规的驾驶行为。\n【安全意义】严格遵守道路交通安全法律法规，规范自身的驾驶行为，是保障行车安全的核心前提，能有效降低交通事故的发生概率，保障自身与他人的人身、财产安全。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (304, 1, 1, '驾驶机动车跨越双实线行驶属于什么行为？', '违章行为', '违法行为', '过失行为', '违规行为', 'B', '本题为单选题，正确答案为B（违法行为）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项违章行为错误； C选项过失行为错误； D选项违规行为错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (305, 1, 1, '驾驶机动车发生交通事故，仅造成财产损失的， 但是对交通事故事实及成因有争议的，\n应当怎么处理？', '迅速报警', '占道继续和对方争辩', '找中间人帮忙解决', '自行协商损害赔偿事宜', 'A', '本题为单选题，正确答案为A（	迅速报警）。 其他选项均不符合相关法律法规及安全驾驶要求： B选项	占道继续和对方争辩错误； C选项找中间人帮忙解决错误； D选项自行协商损害赔偿事宜错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (306, 1, 1, '准驾车型为小型自动挡汽车的，可以驾驶以下哪种车型？', '低速载货汽车', '小型汽车', '二轮摩托车', '轻型自动挡载货汽车', 'D', '本题为单选题，正确答案为D（轻型自动挡载货汽车）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项低速载货汽车错误； B选项小型汽车错误； C选项二轮摩托车错误； 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (307, 1, 1, '准驾车型为C1驾照，还可以驾驶下列哪种车型？', 'C2小型自动挡汽车', 'C3低速载货汽车', 'C4三轮汽车', '以上都可', 'D', '本题为单选题，正确答案为D（以上都可）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项C2小型自动挡汽车错误； B选项C3低速载货汽车错误； C选项C4三轮汽车错误； 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (308, 1, 1, '驾驶人户籍迁出原车辆管理所需要向什么地方的车辆管所提出申请？', '迁出地', '居住地', '所在地', '迁入地', 'D', '本题为单选题，正确答案为D（迁入地）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项迁出地错误； B选项居住地错误； C选项所在地错误； 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (309, 1, 1, '驾驶证记载的驾驶人信息发生变化的要在多长时间内申请换证？', '60日', '50日', '40日', '30日', 'D', '本题为单选题，正确答案为D（30日）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项60日错误； B选项50日错误； C选项40日错误； 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (310, 1, 1, '机动车购买后尚未注册登记，需要临时上道路行驶的，可以凭什么临时上道路行驶？', '合法来源凭证', '临时行驶车号牌', '借用的机动车号牌', '法人单位证明', 'B', '本题为单选题，正确答案为B（临时行驶车号牌）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项合法来源凭证错误； C选项借用的机动车号牌错误； D选项法人单位证明错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (311, 1, 1, '已注册登记的小型载客汽车有下列哪种情形，所有人不需要办理变更登记？', '机动车更换发动机', '加装前后防撞装置', '改变车身颜色', '更换车身或者车架', 'B', '本题为单选题，正确答案为B（加装前后防撞装置）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项机动车更换发动机错误； C选项改变车身颜色错误； D选项更换车身或者车架错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (312, 1, 1, '下列哪种证件是驾驶机动车上路行驶应当随车携带？', '机动车登记证', '机动车保险单', '机动车行驶证', '出厂合格证明', 'C', '本题为单选题，正确答案为C（机动车行驶证）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项机动车登记证错误； B选项机动车保险单错误； D选项出厂合格证明错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (313, 1, 1, '申请人有下列哪种行为，三年内不得再次申领机动车驾驶证？', '实习期记满12分，注销驾驶证的', '申请人在考试过程中有舞弊行为的', '申请人以欺骗、贿赂等不正当手段取得机动车驾驶证的', '申请人未能在培训过程中认真联系的', 'C', '本题为单选题，正确答案为C（申请人以欺骗、贿赂等不正当手段取得机动车驾驶证的）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项实习期记满12分，注销驾驶证的错误； B选项申请人在考试过程中有舞弊行为的错误； D选项申请人未能在培训过程中认真联系的错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (314, 1, 1, '持有小型汽车驾驶证的驾驶人在下列哪种情况下需要接受审验？', '有效期满换发驾驶证时', '一个记分周期末', '记分周期未满分', '记分周期满12分', 'A', '本题为单选题，正确答案为A（有效期满换发驾驶证时）。 其他选项均不符合相关法律法规及安全驾驶要求： B选项一个记分周期末错误； C选项记分周期未满分错误； D选项记分周期满12分错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (315, 1, 1, '驾驶人因服兵役、出国（境）等原因无法办理审验时，延期审验期限最长不超过多长时间？', '1年', '2年', '3年', '5年', 'C', '本题为单选题，正确答案为C（3年）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项1年错误； B选项2年错误； D选项5年错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (316, 1, 1, '年龄在70周岁以上的机动车驾驶人，应当每年进行一次身体检查的目的是什么？', '体现对老年人的关心', '例行程序仅供参考', '检查是否患有老年常见病', '检查是否患有妨碍安全驾驶的疾病', 'D', '本题为单选题，正确答案为D（检查是否患有妨碍安全驾驶的疾病）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项体现对老年人的关心错误； B选项例行程序仅供参考错误； C选项检查是否患有老年常见病错误； 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (317, 1, 1, '以欺骗、贿赂等不正当手段取得驾驶证被依法撤销驾驶许可的，多长时间不得重新申请驾驶许可？', '3年内', '终身', '1年内', '5年内', 'A', '本题为单选题，正确答案为A（3年内）。 其他选项均不符合相关法律法规及安全驾驶要求： B选项终身错误； C选项1年内错误； D选项5年内错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (318, 1, 1, '申请人以欺骗、贿赂等不正当手段取得机动车驾驶证的（被撤销的），申请人在多长时间内不得再次申领机动车驾驶证。', '6个月', '1年', '2年', '3年', 'D', '本题为单选题，正确答案为D（3年）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项6个月错误； B选项1年错误； C选项2年错误； 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (319, 1, 1, '提供虚假材料申领驾驶证的申请人会承担下列哪种法律责任？', '处20元以上200元以下罚款', '取消申领驾驶证资格', '1年内不得再次申领驾驶证', '2年内不能再次申领驾驶证', 'C', '本题为单选题，正确答案为C（1年内不得再次申领驾驶证）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项处20元以上200元以下罚款错误； B选项取消申领驾驶证资格错误； D选项2年内不能再次申领驾驶证错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
