INSERT INTO `biz_question` VALUES (321, 1, 1, '3年内有下列哪种行为的人不得申请机动车驾驶证？', '吸烟成瘾', '注射毒品', '注射胰岛素', '酒醉经历', 'B', '本题为单选题，正确答案为B（注射毒品）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项吸烟成瘾错误； C选项注射胰岛素错误； D选项酒醉经历错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (322, 1, 1, '机动车驾驶证被依法扣押、扣留、暂扣期间能否申请补发？', '可以申请', '扣留期间可以临时申请', '暂扣期间可以临时申请', '不得申请补发', 'D', '本题为单选题，正确答案为D（不得申请补发）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项可以申请错误； B选项扣留期间可以临时申请错误； C选项暂扣期间可以临时申请错误； 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (323, 1, 1, '以下哪种身体条件，不可以申请机动车驾驶证？', '糖尿病', '红绿色盲', '高血压', '怀孕', 'B', '本题为单选题，正确答案为B（红绿色盲）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项糖尿病错误； C选项高血压错误； D选项怀孕错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (324, 1, 1, '申请小型汽车准驾车型驾驶证的人年龄条件是多少？', '18周岁以上60周岁以下', '18周岁以上不设上限', '21周岁以上50周岁以下', '24周岁以上70周岁以下', 'B', '本题为单选题，正确答案为B（18周岁以上不设上限）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项18周岁以上60周岁以下错误； C选项21周岁以上50周岁以下错误； D选项24周岁以上70周岁以下错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (325, 1, 1, '关于醉酒驾驶机动车的处罚，以下说法错误的是什么？', '公安机关交通管理部门约束至酒醒', '吊销驾驶证', '五年内不得重新取得机动车驾驶证', '记6分', 'D', '本题为单选题，正确答案为D（记6分）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项公安机关交通管理部门约束至酒醒错误； B选项吊销驾驶证错误； C选项五年内不得重新取得机动车驾驶证错误； 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (326, 1, 1, '在道路上驾驶机动车追逐竞驶，情节恶劣的，或者在道路上醉酒驾驶机动车的如何处罚？', '3年以下有期徒刑', '7年以下有期徒刑', '处拘役、并处罚金', '10年以下有期徒刑', 'C', '本题为单选题，正确答案为C（处拘役、并处罚金）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项3年以下有期徒刑错误； B选项7年以下有期徒刑错误； D选项10年以下有期徒刑错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
