INSERT INTO `biz_question` VALUES (330, 1, 1, '驾驶人未携带哪种证件驾驶机动车上路，交通警察可依法扣留车辆？', '机动车驾驶证', '居民身份证', '从业资格证', '机动车通行证', 'A', '本题为单选题，正确答案为A（机动车驾驶证）。 其他选项均不符合相关法律法规及安全驾驶要求： B选项居民身份证错误； C选项从业资格证错误； D选项机动车通行证错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (331, 1, 1, '驾驶人将机动车交由什么样的人驾驶的，交通警察可依法扣留机动车驾驶证？', '实习期驾驶人', '取得驾驶证的人', '驾驶证被吊销的人', '驾驶证记分达到6分的人', 'C', '本题为单选题，正确答案为C（驾驶证被吊销的人）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项实习期驾驶人错误； B选项取得驾驶证的人错误； D选项驾驶证记分达到6分的人错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (332, 1, 1, '机动车驾驶人初次取得汽车类或者摩托车类准驾车型的实习期是多长时间？', '6个月', '12个月', '16个月', '18个月', 'B', '本题为单选题，正确答案为B（12个月）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项6个月错误； C选项16个月错误； D选项18个月错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (333, 1, 1, '在实习期内驾驶机动车的，应当在车身后部粘贴或者悬挂哪种标志？', '注意新手标志', '注意避让标志', '统一式样的实习标志', '注意车距标志', 'C', '本题为单选题，正确答案为C（统一式样的实习标志）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项注意新手标志错误； B选项注意避让标志错误； D选项注意车距标志错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (334, 1, 1, '公安机关交通管理部门对驾驶人的交通违法行为除依法给予行政处罚外,实行下列哪种制度？', '违法登记制度', '奖励里程制度', '累积记分制度', '强制报废制度', 'C', '本题为单选题，正确答案为C（累积记分制度）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项违法登记制度错误； B选项奖励里程制度错误； D选项强制报废制度错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (335, 1, 1, '道路交通安全违法行为累积记分的周期是多长时间？', '3个月', '6个月', '12个月', '24个月', 'C', '本题为单选题，正确答案为C（12个月）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项3个月错误； B选项6个月错误； D选项24个月错误。 本题考核交通违法行为记分相关规定，需牢记各类违法行为的记分分值，避免违法记分。', NULL, '记分', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (336, 1, 1, '公安机关交通管理部门对累积记分达到规定分值的驾驶人怎样处理？', '依法追究刑事责任', '处15日以下拘留', '终生禁驾', '参加满分学习、考试', 'D', '本题为单选题，正确答案为D（参加满分学习、考试）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项依法追究刑事责任错误； B选项处15日以下拘留错误； C选项终生禁驾错误； 本题考核交通违法行为记分相关规定，需牢记各类违法行为的记分分值，避免违法记分。', NULL, '记分', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (337, 1, 1, '车辆在一般道路上发生故障后，应开启危险报警闪光灯，并在车后50-100米设置警告标志，如不按规定使用灯光和设置警告标志的，将被—次记多少分？', '1分', '2分', '3分', '6分', 'C', '本题为单选题，正确答案为C（3分）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项1分错误； B选项2分错误； D选项6分错误。 本题考核交通违法行为记分相关规定，需牢记各类违法行为的记分分值，避免违法记分。', NULL, '记分', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (338, 1, 1, '驾驶人驾驶机动车不按交通信号灯指示通行的，一次记多少分？', '记1分', '记3分', '记6分', '记12分', 'C', '本题为单选题，正确答案为C（记6分）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项记1分错误； B选项记3分错误； D选项记12分错误。 本题考核交通违法行为记分相关规定，需牢记各类违法行为的记分分值，避免违法记分。', NULL, '记分', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (339, 1, 1, '驾驶人违反交通运输管理法规发生重大事故使公私财产遭受重大损失，可能会受到什么刑罚？', '处5年以上徒刑', '处3年以下徒刑或者拘役', '处3年以上徒刑', '处3年以上7年以下徒刑', 'B', '本题为单选题，正确答案为B（处3年以下徒刑或者拘役）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项处5年以上徒刑错误； C选项处3年以上徒刑错误； D选项处3年以上7年以下徒刑错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (340, 1, 1, '驾驶人违反交通运输管理法规发生重大事故后，因逃逸致人死亡的，处多少年有期徒刑？', '2年以下', '3年以下', '7年以下', '7年以上', 'D', '本题为单选题，正确答案为D（7年以上）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项2年以下错误； B选项3年以下错误； C选项7年以下错误； 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (341, 1, 1, '交通肇事致一人以上重伤，负事故全部或者主要责任，并具有下列哪种行为的，构成交通肇事罪?', '未报警', '酒后、吸食毒品后驾驶机动车辆的', '未带驾驶证', '未抢救受伤人员', 'B', '本题为单选题，正确答案为B（酒后、吸食毒品后驾驶机动车辆的）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项未报警错误； C选项未带驾驶证错误； D选项未抢救受伤人员错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (342, 1, 1, '前方路口这种信号灯亮表示什么意思？', '路口警示', '禁止通行', '准许通行', '提醒注意', 'C', '本题为单选题，正确答案为C（准许通行）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项路口警示错误； B选项禁止通行错误； D选项提醒注意错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (343, 1, 1, '有这种信号灯的路口允许机动车如何行驶？', '向左转弯', '直行通过', '向右转弯', '停车等待', 'C', '本题为单选题，正确答案为C（向右转弯）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项向左转弯错误； B选项直行通过错误； D选项停车等待错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (344, 1, 1, '遇到这种情况的路口怎样通过？', '左转弯加速通过', '加速直行通过', '右转弯加速通过', '确认安全后通过', 'D', '本题为单选题，正确答案为D（确认安全后通过）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项左转弯加速通过错误； B选项加速直行通过错误； C选项右转弯加速通过错误； 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (345, 1, 1, '在这个路口怎样左转弯？', '靠路口中心点右侧转弯', '靠路口中心点左侧转弯', '不能左转弯', '骑路口中心点转弯', 'B', '本题为单选题，正确答案为B（靠路口中心点左侧转弯）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项靠路口中心点右侧转弯错误； C选项不能左转弯错误； D选项骑路口中心点转弯错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (346, 1, 1, '驾驶机动车在路口遇到这种情况如何行驶？', '可以向右转弯', '靠右侧直行', '遵守交通信号灯', '停车等待', 'D', '本题为单选题，正确答案为D（停车等待）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项可以向右转弯错误； B选项靠右侧直行错误； C选项遵守交通信号灯错误； 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (347, 1, 1, '驾驶机动车在道路上靠路边停车过程中如何使用灯光？', '变换使用远近光灯', '不用指示灯提示', '开启危险报警闪光灯', '提前开启右转向灯', 'D', '本题为单选题，正确答案为D（提前开启右转向灯）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项变换使用远近光灯错误； B选项不用指示灯提示错误； C选项开启危险报警闪光灯错误； 本题考核机动车灯光使用相关规定，需正确使用灯光，确保行车安全。', NULL, '灯光使用', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (348, 1, 1, '机动车向左转弯、向左变更车道，驶离停车地点及掉头时，提前开启左转向灯是为了什么？', '提示后车，将要向左变更行驶路线', '提示前车，将要向右变更行驶路线', '提示前车，将要向左变更行驶路线', '提示后车，将要向右变更行驶路线', 'A', '本题为单选题，正确答案为A（提示后车，将要向左变更行驶路线）。 其他选项均不符合相关法律法规及安全驾驶要求： B选项提示前车，将要向右变更行驶路线错误； C选项提示前车，将要向左变更行驶路线错误； D选项提示后车，将要向右变更行驶路线错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (349, 1, 1, '驾驶机动车在道路上向左变更车道时如何使用灯光？', '不用开启转向灯', '提前开启右转向灯', '提前开启左转向灯', '提前开启近光灯', 'C', '本题为单选题，正确答案为C（提前开启左转向灯）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项不用开启转向灯错误； B选项提前开启右转向灯错误； D选项提前开启近光灯错误。 本题考核机动车灯光使用相关规定，需正确使用灯光，确保行车安全。', NULL, '灯光使用', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (350, 1, 1, '在这种天气条件下行车如何使用灯光？', '使用近光灯', '不使用灯光', '使用远光灯', '使用雾灯', 'A', '本题为单选题，正确答案为A（使用近光灯）。 其他选项均不符合相关法律法规及安全驾驶要求： B选项不使用灯光错误； C选项使用远光灯错误； D选项使用雾灯错误。 本题考核机动车灯光使用相关规定，需正确使用灯光，确保行车安全。', NULL, '灯光使用', '2026-05-17 15:20:56');
