INSERT INTO `biz_question` VALUES (353, 1, 1, '关于机动车灯光的使用，以下说法正确的是什么?', '机动车灯光的作用仅仅是为了在夜间照明', '夜间驾驶机动车在照明条件良好的路段可以不使用灯光', '机动车灯光一个重要的作用是提示其他机动车驾驶人和行人', '夜间驾驶机动车在照明条件良好的路段必须使用远光灯', 'C', '本题为单选题，正确答案为C（机动车灯光一个重要的作用是提示其他机动车驾驶人和行人）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项机动车灯光的作用仅仅是为了在夜间照明错误； B选项夜间驾驶机动车在照明条件良好的路段可以不使用灯光错误； D选项夜间驾驶机动车在照明条件良好的路段必须使用远光灯错误。 本题考核机动车灯光使用相关规定，需正确使用灯光，确保行车安全。', NULL, '灯光使用', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (354, 1, 1, '前方车辆开启转向灯表示要如何行驶？', '准备向左转弯', '前方有障碍物', '准备向左变道', '超越前方车辆', 'C', '本题为单选题，正确答案为C（准备向左变道）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项准备向左转弯错误； B选项前方有障碍物错误； D选项超越前方车辆错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
