INSERT INTO `biz_question` VALUES (370, 1, 1, '在路口直行时,遇这种情形如何通行？', '让左方道路车辆先行', '让右方道路车辆先行', '直接加速直行通过', '开启危险报警闪光灯通行', 'B', '本题为单选题，正确答案为B（让右方道路车辆先行）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项让左方道路车辆先行错误； C选项直接加速直行通过错误； D选项开启危险报警闪光灯通行错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (371, 1, 1, '道路没有划分机动车道、非机动车道和人行道的，以下说法正确的是什么？', '机动车在道路左侧通行，非机动车和行人随意通行', '机动车在道路左侧通行，非机动车和行人在道路两侧通行', '机动车在道路中间通行，非机动车和行人在道路两侧通行', '机动车、非机动车和行人可随意通行', 'C', '本题为单选题，正确答案为C（机动车在道路中间通行，非机动车和行人在道路两侧通行）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项机动车在道路左侧通行，非机动车和行人随意通行错误； B选项机动车在道路左侧通行，非机动车和行人在道路两侧通行错误； D选项机动车、非机动车和行人可随意通行错误。 本题考核交通违法行为记分相关规定，需牢记各类违法行为的记分分值，避免违法记分。', NULL, '记分', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (372, 1, 1, '机动车在道路上变更车道需要注意什么？', '尽快加速进入左侧车道', '不能影响其他车辆正常行驶', '进入左侧车道时适当减速', '开启转向灯迅速向左转向', 'B', '本题为单选题，正确答案为B（不能影响其他车辆正常行驶）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项尽快加速进入左侧车道错误； C选项进入左侧车道时适当减速错误； D选项开启转向灯迅速向左转向错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
