INSERT INTO `biz_question` VALUES (387, 1, 1, '在这个路口右转弯如何通行？', '先让对面车左转弯', '直接向右转弯', '抢在对面车前右转弯', '鸣喇叭催促', 'A', '本题为单选题，正确答案为A（先让对面车左转弯）。 其他选项均不符合相关法律法规及安全驾驶要求： B选项直接向右转弯错误； C选项抢在对面车前右转弯错误； D选项鸣喇叭催促错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (388, 1, 1, '驾驶机动车需要在路边停车时怎样选择停车地点？', '在人行道上停放', '在路边随意停放', '在停车泊位内停放', '靠左侧路边逆向停放', 'C', '本题为单选题，正确答案为C（在停车泊位内停放）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项在人行道上停放错误； B选项在路边随意停放错误； D选项靠左侧路边逆向停放错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (389, 1, 1, '这样在路边临时停放机动车有什么违法行为？', '在非机动车道停车', '在人行横道上停车', '距离路边超过30厘米', '在有禁停标线路段停车', 'B', '本题为单选题，正确答案为B（在人行横道上停车）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项在非机动车道停车错误； C选项距离路边超过30厘米错误； D选项在有禁停标线路段停车错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (390, 1, 1, '这样临时停放红色轿车有什么违法行为？', '距离加油站不到30米', '停车占用非机动车道', '距离路边超过30厘米', '在有禁停标线路段停车', 'A', '本题为单选题，正确答案为A（距离加油站不到30米）。 其他选项均不符合相关法律法规及安全驾驶要求： B选项停车占用非机动车道错误； C选项距离路边超过30厘米错误； D选项在有禁停标线路段停车错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (391, 1, 1, '这样停放机动车什么违法行为？', '停车占用人行道', '在公共汽车站停车', '在有禁停标志路段停车', '在非机动车道停车', 'B', '本题为单选题，正确答案为B（在公共汽车站停车）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项停车占用人行道错误； C选项在有禁停标志路段停车错误； D选项在非机动车道停车错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (392, 1, 1, '在距这段路多少米以内的路段不能停放机动车？', '5米以内', '10米以内', '30米以内', '50米以内', 'D', '本题为单选题，正确答案为D（50米以内）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项5米以内错误； B选项10米以内错误； C选项30米以内错误； 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (393, 1, 1, '这个标志是何含义？', '提醒车辆驾驶人前方道路沿水库、湖泊、河流', '提醒车辆驾驶人前方有向上的陡坡路段', '.提醒车辆驾驶人前方有两个及以上的连续上坡路段', '提醒车辆驾驶人前方有向下的陡坡路段', 'B', '本题为单选题，正确答案为B（提醒车辆驾驶人前方有向上的陡坡路段）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项提醒车辆驾驶人前方道路沿水库、湖泊、河流错误； C选项.提醒车辆驾驶人前方有两个及以上的连续上坡路段错误； D选项提醒车辆驾驶人前方有向下的陡坡路段错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (394, 1, 1, '进入减速车道时怎样使用灯光？', '开启左转向灯', '开启右转向灯', '开启危险报警闪光灯', '开启前照灯', 'B', '本题为单选题，正确答案为B（开启右转向灯）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项开启左转向灯错误； C选项开启危险报警闪光灯错误； D选项开启前照灯错误。 本题考核机动车灯光使用相关规定，需正确使用灯光，确保行车安全。', NULL, '灯光使用', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (395, 1, 1, '驾驶机动车驶离高速公路时，在这个位置怎样行驶？', '继续向前行驶', '驶入减速车道', '车速保持100公里/小时', '车速降到40公里/小时以下', 'B', '本题为单选题，正确答案为B（驶入减速车道）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项继续向前行驶错误； C选项车速保持100公里/小时错误； D选项车速降到40公里/小时以下错误。 本题考核高速公路行车安全相关规定，需严格遵守高速公路通行规则，确保高速行车安全。', NULL, '高速公路', '2026-05-17 15:20:56');
