INSERT INTO `biz_question` VALUES (401, 1, 1, '驾驶机动车在高速公路遇到能见度低于100米的气象条件时，最高车速是多少？', '不得超过40公里/小时', '不得超过60公里/小时', '不得超过80公里/小时', '不得超过90公里/小时', 'A', '本题为单选题，正确答案为A（不得超过40公里/小时）。 其他选项均不符合相关法律法规及安全驾驶要求： B选项不得超过60公里/小时错误； C选项不得超过80公里/小时错误； D选项不得超过90公里/小时错误。 本题考核高速公路行车安全相关规定，需严格遵守高速公路通行规则，确保高速行车安全。', NULL, '高速公路', '2026-05-17 15:20:56');
