INSERT INTO `biz_question` VALUES (405, 1, 1, '雪天在高速公路上驾驶时，关于安全车距错误的说法是什么？', '雪天路滑，制动距离比干燥柏油路更长', '雪天能见度低，应该根据能见度控制安全距离', '能见度小于200m时，与前车至少保持50M的安全距离', '能见度小于50M时，应该驶离高速公路', 'C', '本题为单选题，正确答案为C（能见度小于200m时，与前车至少保持50M的安全距离）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项雪天路滑，制动距离比干燥柏油路更长错误； B选项雪天能见度低，应该根据能见度控制安全距离错误； D选项能见度小于50M时，应该驶离高速公路错误。 本题考核高速公路行车安全相关规定，需严格遵守高速公路通行规则，确保高速行车安全。', NULL, '高速公路', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (406, 1, 1, '这辆在高速公路上临时停放的故障车，警告标志应该设置在车后多远处？', '150米以外', '50～150米', '50～100米', '50米以内', 'A', '本题为单选题，正确答案为A（150米以外）。 其他选项均不符合相关法律法规及安全驾驶要求： B选项50～150米错误； C选项50～100米错误； D选项50米以内错误。 本题考核高速公路行车安全相关规定，需严格遵守高速公路通行规则，确保高速行车安全。', NULL, '高速公路', '2026-05-17 15:20:56');
