INSERT INTO `biz_question` VALUES (408, 1, 1, '机动车在高速公路上发生故障或交通事故无法正常行驶时由什么车拖曳或牵引？', '过路车', '大客车', '同行车', '清障车', 'D', '本题为单选题，正确答案为D（清障车）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项过路车错误； B选项大客车错误； C选项同行车错误； 本题考核高速公路行车安全相关规定，需严格遵守高速公路通行规则，确保高速行车安全。', NULL, '高速公路', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (409, 1, 1, '在涉水路段跟车时，应当怎样做?', '紧跟其后', '并行通过', '适当增加车距', '超越前车，抢先通过', 'C', '本题为单选题，正确答案为C（适当增加车距）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项紧跟其后错误； B选项并行通过错误； D选项超越前车，抢先通过错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (410, 1, 1, '下面关于下坡熄火滑行的说法错误的是？', '对于采用真空助力刹车系统的车辆而言，下坡时的熄火会使刹车系统失效', '对于采用了助力转向系统的车辆而言，下坡时熄火会使转向盘变重，难以控制', '下坡道熄火时，车辆不能使用发动机制动', '下坡滑行是利用坡道的位能推动汽车前进，发动机不工作，可以节油，应大力提倡', 'D', '本题为单选题，正确答案为D（下坡滑行是利用坡道的位能推动汽车前进，发动机不工作，可以节油，应大力提倡）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项对于采用真空助力刹车系统的车辆而言，下坡时的熄火会使刹车系统失效错误； B选项对于采用了助力转向系统的车辆而言，下坡时熄火会使转向盘变重，难以控制错误； C选项下坡道熄火时，车辆不能使用发动机制动错误； 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (411, 1, 1, '遇有这种排队等候的情形怎么做？', '依次排队等候', '从右侧借道超越', '从左侧跨越实线超越', '从两侧随意超越', 'A', '本题为单选题，正确答案为A（依次排队等候）。 其他选项均不符合相关法律法规及安全驾驶要求： B选项从右侧借道超越错误； C选项从左侧跨越实线超越错误； D选项从两侧随意超越错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (412, 1, 1, '遇到前方车辆缓慢行驶时怎样行驶？', '从两侧随意超越', '从右侧借道超越', '占对向车道超越', '依次排队行驶', 'D', '本题为单选题，正确答案为D（依次排队行驶）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项从两侧随意超越错误； B选项从右侧借道超越错误； C选项占对向车道超越错误； 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (413, 1, 1, '在路口遇到这种情形时怎样做？', '停在网状线区域内等待', '停在路口以外等待', '跟随前车通过路口', '停在路口内等待', 'B', '本题为单选题，正确答案为B（停在路口以外等待）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项停在网状线区域内等待错误； C选项跟随前车通过路口错误； D选项停在路口内等待错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (414, 1, 1, '驾驶机动车在车道减少的路口，遇到前方车辆依次停车或缓慢行驶时怎么办？', '从前车右侧路肩进入路口', '从有空隙一侧进入路口', '每车道一辆依次交替驶入路口', '向左变道穿插进入路口', 'C', '本题为单选题，正确答案为C（每车道一辆依次交替驶入路口）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项从前车右侧路肩进入路口错误； B选项从有空隙一侧进入路口错误； D选项向左变道穿插进入路口错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (415, 1, 1, '驾驶机动车遇到前方车辆停车排队等候或缓慢行驶时怎么办？', '可借道超车', '占用对面车道', '穿插等候的车辆', '依次行驶', 'D', '本题为单选题，正确答案为D（依次行驶）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项可借道超车错误； B选项占用对面车道错误； C选项穿插等候的车辆错误； 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (416, 1, 1, '驾驶机动车遇有前方交叉路口交通阻塞时怎么办？', '依次停在路口外等候', '可借对向车道通过', '从前车两侧穿插通过', '进入路口内等候', 'A', '本题为单选题，正确答案为A（依次停在路口外等候）。 其他选项均不符合相关法律法规及安全驾驶要求： B选项可借对向车道通过错误； C选项从前车两侧穿插通过错误； D选项进入路口内等候错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (417, 1, 1, '在这种情形中前车怎样行驶？', '正常行驶', '及时让行', '开启危险报警闪光灯行驶', '不得变更车道', 'B', '本题为单选题，正确答案为B（及时让行）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项正常行驶错误； C选项开启危险报警闪光灯行驶错误； D选项不得变更车道错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (418, 1, 1, '怎样通过这样的路口？', '不减速通过', '加速尽快通过', '空挡滑行通过', '减速或停车观察', 'D', '本题为单选题，正确答案为D（减速或停车观察）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项不减速通过错误； B选项加速尽快通过错误； C选项空挡滑行通过错误； 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (419, 1, 1, '驾驶机动车通过没有交通信号和管理人员的铁路道口怎样通过？', '适当减速通过', '空挡滑行通过', '停车确认安全后通过', '加速尽快通过', 'C', '本题为单选题，正确答案为C（停车确认安全后通过）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项适当减速通过错误； B选项空挡滑行通过错误； D选项加速尽快通过错误。 本题考核交通信号相关规定，需严格按照交通信号指示通行，确保路口行车安全。', NULL, '交通信号', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (420, 1, 1, '夜间驾驶机动车在没有中心隔离设施或者没有中心线的道路上行驶，以下哪种情况下应当改用近光灯？', '接近没有交通信号灯控制的交叉路口时', '与对向机动车会车时', '接近人行横道时', '城市道路照明条件不良时', 'B', '本题为单选题，正确答案为B（与对向机动车会车时）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项接近没有交通信号灯控制的交叉路口时错误； C选项接近人行横道时错误； D选项城市道路照明条件不良时错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (421, 1, 1, '这位驾驶人违反法律规定的行为是什么？', '没按规定握转向盘', '座椅角度不对', '没系安全带', '驾驶姿势不正确', 'C', '本题为单选题，正确答案为C（没系安全带）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项没按规定握转向盘错误； B选项座椅角度不对错误； D选项驾驶姿势不正确错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (422, 1, 1, '驾驶人连续驾驶4小时以上，停车休息的时间不得少于多少？', '5分钟', '10分钟', '15分钟', '20分钟', 'D', '本题为单选题，正确答案为D（20分钟）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项5分钟错误； B选项10分钟错误； C选项15分钟错误； 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (423, 1, 1, '在什么情况下不得行车？', '车窗没关闭', '车门没关闭', '音响没关闭', '顶窗没关闭', 'B', '本题为单选题，正确答案为B（车门没关闭）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项车窗没关闭错误； C选项音响没关闭错误； D选项顶窗没关闭错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (424, 1, 1, '驾驶机动车下陡坡时不得有哪些危险行为？', '提前减挡', '空挡滑行', '低挡行驶', '制动减速', 'B', '本题为单选题，正确答案为B（空挡滑行）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项提前减挡错误； C选项低挡行驶错误； D选项制动减速错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (425, 1, 1, '发生无人员伤亡的、财产轻微损失的交通事故后，以下做法正确的是什么？', '必须报警，等候警察处理', '开车离开现场', '确保安全的情况下，对现场拍照，然后将车辆移至路边等不妨碍交通的地点', '停在现场保持不动', 'C', '本题为单选题，正确答案为C（确保安全的情况下，对现场拍照，然后将车辆移至路边等不妨碍交通的地点）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项必须报警，等候警察处理错误； B选项开车离开现场错误； D选项停在现场保持不动错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (426, 1, 1, '找出这辆故障车有哪种违法行为？', '没有设置警告标志', '没有开启危险报警闪光灯', '没有将车停到路边', '没有立即排除故障', 'A', '本题为单选题，正确答案为A（没有设置警告标志）。 其他选项均不符合相关法律法规及安全驾驶要求： B选项没有开启危险报警闪光灯错误； C选项没有将车停到路边错误； D选项没有立即排除故障错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (427, 1, 1, '机动车在道路上发生故障，需要停车排除时，驾驶人应该怎么办？', '就地停车排除故障', '开启近光灯或雾灯', '将车停到不妨碍交通的地方', '将车停在道路中间', 'C', '本题为单选题，正确答案为C（将车停到不妨碍交通的地方）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项就地停车排除故障错误； B选项开启近光灯或雾灯错误； D选项将车停在道路中间错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (428, 1, 1, '机动车在道路上发生故障，难以移动时下列做法正确的是什么？', '开启危险报警闪光灯', '开启车上所有灯光', '禁止车上人员下车', '在车前方设置警告标志', 'A', '本题为单选题，正确答案为A（开启危险报警闪光灯）。 其他选项均不符合相关法律法规及安全驾驶要求： B选项开启车上所有灯光错误； C选项禁止车上人员下车错误； D选项在车前方设置警告标志错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (429, 1, 3, '驾驶车辆时在道路上抛撒物品，以下说法正确的是什么？', '抛撒纸张等轻质物品会阻挡驾驶人视线分散驾驶人的注意力', '破坏环境，影响环境整洁，甚至造成路面的损坏', '为了保持车内整洁可以偶尔做出这种行为', '有可能引起其他驾驶人紧急躲避等应激反应，进而引发事故', 'ABD', '本题为多选题，正确答案为ABD。 正确选项符合相关法律法规及安全驾驶要求： A选项抛撒纸张等轻质物品会阻挡驾驶人视线分散驾驶人的注意力正确； B选项破坏环境，影响环境整洁，甚至造成路面的损坏正确； D选项有可能引起其他驾驶人紧急躲避等应激反应，进而引发事故正确。 其他选项均不符合相关要求： C选项为了保持车内整洁可以偶尔做出这种行为错误； 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝各类交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (430, 1, 1, '未取得驾驶证的学员在道路上学习驾驶技能，下列哪种做法是正确的？', '使用所学车型的教练车由教练员随车指导', '使用所学车型的教练车单独驾驶学习', '使用私家车由教练员随车指导', '使用所学车型的教练车由非教练员的驾驶人随车指导', 'A', '本题为单选题，正确答案为A（使用所学车型的教练车由教练员随车指导）。 其他选项均不符合相关法律法规及安全驾驶要求： B选项使用所学车型的教练车单独驾驶学习错误； C选项使用私家车由教练员随车指导错误； D选项使用所学车型的教练车由非教练员的驾驶人随车指导错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (431, 1, 1, '驾驶达到报废标准的机动车上道路行驶的，公安交通管理部门将会予以收缴。以下说法错误的是什么？', '驾驶报废车影晌驾驶人行车安全', '报废车机械老化、容易发生交通事故', '车辆不符合安全技术标准，需要强制报废', '不美观，影晌城市形象', 'D', '本题为单选题，正确答案为D（不美观，影晌城市形象）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项驾驶报废车影晌驾驶人行车安全错误； B选项报废车机械老化、容易发生交通事故错误； C选项车辆不符合安全技术标准，需要强制报废错误； 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (432, 1, 1, '驾驶机动车不按规定会车的，将被一次记多少分？', '1分', '2分', '3分', '4分', 'A', '本题为单选题，正确答案为A（1分）。 其他选项均不符合相关法律法规及安全驾驶要求： B选项2分错误； C选项3分错误； D选项4分错误。 本题考核交通违法行为记分相关规定，需牢记各类违法行为的记分分值，避免违法记分。', NULL, '记分', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (433, 1, 1, '遇到交通信号灯、交通标志或交通标线与交通警察的指挥不一致时，应如何行驶？', '按交通信号灯行驶', '按交通警察指挥行驶', '按交通标志行驶', '按交通标线行驶', 'B', '本题为单选题，正确答案为B（按交通警察指挥行驶）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项按交通信号灯行驶错误； C选项按交通标志行驶错误； D选项按交通标线行驶错误。 本题考核交通信号相关规定，需严格按照交通信号指示通行，确保路口行车安全。', NULL, '交通信号', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (434, 1, 1, '非机动车驾驶人、行人与处于静止状态的机动车发生交通事故造成损失，机动车—方无责任的，关于机动车—方的赔偿责任，下面说法哪种是正确的？', '不承担赔偿责任', '承担10%赔偿责任', '承担60%赔偿责任', '承担全部责任', 'A', '本题为单选题，正确答案为A（不承担赔偿责任）。 其他选项均不符合相关法律法规及安全驾驶要求： B选项承担10%赔偿责任错误； C选项承担60%赔偿责任错误； D选项承担全部责任错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (435, 1, 1, '申请C1/C2/ C3驾驶证的， 两眼裸视力或矫正视力应达到对数视力表多少以上？', '4.7', '4.8', '4.9', '5.0', 'C', '本题为单选题，正确答案为C（4.9）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项4.7错误； B选项4.8错误； D选项5.0错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (436, 1, 1, '驾驶机动车超过规定时速50%的会受到什么处罚？', '200元以上2000元以下罚款', '处15日以下拘留', '依法追究刑事责任', '吊销机动车行驶证', 'A', '本题为单选题，正确答案为A（200元以上2000元以下罚款）。 其他选项均不符合相关法律法规及安全驾驶要求： B选项处15日以下拘留错误； C选项依法追究刑事责任错误； D选项吊销机动车行驶证错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (437, 1, 1, '对未按照国家规定投保交强险的车辆，除扣留机动车外，还会受到什么处罚？', '投保最低责任限额应缴纳保费的2倍罚款', '投保最低责任限额应缴纳保费的3倍罚款', '投保最低责任限额应缴纳保费的4倍罚款', '投保最低责任限额应缴纳保费的5倍罚款', 'A', '本题为单选题，正确答案为A（投保最低责任限额应缴纳保费的2倍罚款）。 其他选项均不符合相关法律法规及安全驾驶要求： B选项投保最低责任限额应缴纳保费的3倍罚款错误； C选项投保最低责任限额应缴纳保费的4倍罚款错误； D选项投保最低责任限额应缴纳保费的5倍罚款错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (438, 1, 1, '使用软连接牵引装置时，牵引车与被牵引车之间应当保持多远距离？', '小于0.5米', '小于4米', '大于4米小于10米', '大于10米', 'C', '本题为单选题，正确答案为C（大于4米小于10米）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项小于0.5米错误； B选项小于4米错误； D选项大于10米错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (439, 1, 1, '机动车驾驶证损毁无法辨认的，要在多长时间内申请换证？', '60日', '50日', '40日', '30日', 'D', '本题为单选题，正确答案为D（30日）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项60日错误； B选项50日错误； C选项40日错误； 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (440, 1, 1, '对道路交通安全违法行为的处罚种类不包括（）？', '警告', '罚款', '暂扣', '训诫', 'D', '本题为单选题，正确答案为D（训诫）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项警告错误； B选项罚款错误； C选项暂扣错误； 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (441, 1, 1, '机动车购买后尚未登记，需要临时上道路行驶的，应当如何做？', '取得临时通行牌证', '带上身份证', '直接上路行驶', '在车窗上张贴合格证', 'A', '本题为单选题，正确答案为A（取得临时通行牌证）。 其他选项均不符合相关法律法规及安全驾驶要求： B选项带上身份证错误； C选项直接上路行驶错误； D选项在车窗上张贴合格证错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (442, 1, 1, '驾驶人在实习期内单独驾驶机动车上高速公路行驶，会受到什么处罚？', '二十元以上二百元以下罚款', '记3分', '记6分', '吊销驾驶证', 'A', '本题为单选题，正确答案为A（二十元以上二百元以下罚款）。 其他选项均不符合相关法律法规及安全驾驶要求： B选项记3分错误； C选项记6分错误； D选项吊销驾驶证错误。 本题考核高速公路行车安全相关规定，需严格遵守高速公路通行规则，确保高速行车安全。', NULL, '高速公路', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (443, 1, 1, '当事人有下列哪种行为，要承担交通事故全部责任？', '在高速公路上撞伤行人的', '在路口直行与转弯车辆刮碰的', '在快车道与摩托车刮碰的', '发生事故后故意损坏、伪造现场、毁灭证据的', 'D', '本题为单选题，正确答案为D（发生事故后故意损坏、伪造现场、毁灭证据的）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项在高速公路上撞伤行人的错误； B选项在路口直行与转弯车辆刮碰的错误； C选项在快车道与摩托车刮碰的错误； 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (444, 1, 1, '关于驾驶机动车时转向灯的使用，以下说法正确的是什么？', '超车完毕驶回原车道时可不开转向灯', '驶离停车地点时不必开启转向灯', '靠边停车时应提前开启右转向灯', '准备变更车道时可以不开转向灯', 'C', '本题为单选题，正确答案为C（靠边停车时应提前开启右转向灯）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项超车完毕驶回原车道时可不开转向灯错误； B选项驶离停车地点时不必开启转向灯错误； D选项准备变更车道时可以不开转向灯错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (445, 1, 1, '驾驶机动车不按规定使用灯光的，将被—次记多少分？', '1分', '2分', '3分', '6分', 'A', '本题为单选题，正确答案为A（1分）。 其他选项均不符合相关法律法规及安全驾驶要求： B选项2分错误； C选项3分错误； D选项6分错误。 本题考核交通违法行为记分相关规定，需牢记各类违法行为的记分分值，避免违法记分。', NULL, '记分', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (446, 1, 1, '造成交通事故后逃逸，尚不构成犯罪的，公安机关交通管理部门会处以何种处罚？', '200元以上2000元以下罚款', '1000元以上3000元以下罚款', '5000元以上10000元以下罚款', '—次记6分', 'A', '本题为单选题，正确答案为A（200元以上2000元以下罚款）。 其他选项均不符合相关法律法规及安全驾驶要求： B选项1000元以上3000元以下罚款错误； C选项5000元以上10000元以下罚款错误； D选项—次记6分错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (447, 1, 1, '在几年内无累积记分的机动车驾驶人，可以延长机动车驾驶证的审验期？', '1年', '2年', '5年', '6年', 'A', '本题为单选题，正确答案为A（1年）。 其他选项均不符合相关法律法规及安全驾驶要求： B选项2年错误； C选项5年错误； D选项6年错误。 本题考核交通违法行为记分相关规定，需牢记各类违法行为的记分分值，避免违法记分。', NULL, '记分', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (448, 1, 1, '申请残疾人专用小型自动挡载客汽车驾驶证的人年龄条件是多少？', '18周岁以上，无上限年龄', '18周岁以上60周岁以下', '20周岁以上70周岁以下', '20周岁以上60周岁以下', 'A', '本题为单选题，正确答案为A（18周岁以上，无上限年龄）。 其他选项均不符合相关法律法规及安全驾驶要求： B选项18周岁以上60周岁以下错误； C选项20周岁以上70周岁以下错误； D选项20周岁以上60周岁以下错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (449, 1, 1, '以隐瞒、欺骗手段补领机动车驾驶证的，会受到下列哪种处罚？', '处15日以下拘留', '收回机动车行驶证', '处200元以上500元以下罚款', '依法追究刑事责任', 'C', '本题为单选题，正确答案为C（处200元以上500元以下罚款）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项处15日以下拘留错误； B选项收回机动车行驶证错误； D选项依法追究刑事责任错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (450, 1, 1, '机动车驾驶证被暂扣期间驾驶机动车的，由公安机关交通管理部门处多少元罚款？', '20元以上200元以下', '200元以上2000元以下', '1000元以上2000元以下', '2000元以上5000元以下', 'B', '本题为单选题，正确答案为B（200元以上2000元以下）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项20元以上200元以下错误； C选项1000元以上2000元以下错误； D选项2000元以上5000元以下错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (451, 1, 1, '驾驶机动车超员、超速，构成犯罪，被吊销驾驶证的，几年内不得申请机动车驾驶证？', '1', '3', '5', '10', 'C', '本题为单选题，正确答案为C（5）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项1错误； B选项3错误； D选项10错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
