INSERT INTO `biz_question` VALUES (453, 1, 1, '申请增加轻型牵引挂车准驾车型的，应取得驾驶小型汽车、小型自动挡汽车准驾车型资格几年以上？', '1', '2', '3', '5', 'A', '本题为单选题，正确答案为A（1）。 其他选项均不符合相关法律法规及安全驾驶要求： B选项2错误； C选项3错误； D选项5错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (454, 1, 1, '申请增加准驾车型的，申请人应向哪里的车辆管理所申领机动车驾驶证？', '居住地', '户籍所在地', '全国任意车管所', '所持驾驶证核发地', 'D', '本题为单选题，正确答案为D（所持驾驶证核发地）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项居住地错误； B选项户籍所在地错误； C选项全国任意车管所错误； 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
