INSERT INTO `biz_question` VALUES (457, 1, 1, '驾驶人有下列哪种违法行为—次记9分？', '驾驶7座以上载客汽车载人超过核定人数百分之五十以上未达到百分之百的', '代替实际机动车驾驶人接受交通违法行为处罚和记分牟取经济利益的', '驾驶校车超过核定人数20%以上的', '驾驶中型以上载客汽车在高速公路上超速20%以上的', 'A', '本题为单选题，正确答案为A（驾驶7座以上载客汽车载人超过核定人数百分之五十以上未达到百分之百的）。 其他选项均不符合相关法律法规及安全驾驶要求： B选项代替实际机动车驾驶人接受交通违法行为处罚和记分牟取经济利益的错误； C选项驾驶校车超过核定人数20%以上的错误； D选项驾驶中型以上载客汽车在高速公路上超速20%以上的错误。 本题考核交通违法行为记分相关规定，需牢记各类违法行为的记分分值，避免违法记分。', NULL, '记分', '2026-05-17 15:20:56');
