INSERT INTO `biz_question` VALUES (478, 1, 1, '根据交通违法行为的严重程度，对—次记分分值的分类正确的是什么？', '12分、6分、3分、2分、1分', '12分、9分、6分、3分、1分', '12分、9分、6分、3分、2分、1分', '12分、9分、6分、2分、1分', 'B', '本题为单选题，正确答案为B（12分、9分、6分、3分、1分）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项12分、6分、3分、2分、1分错误； C选项12分、9分、6分、3分、2分、1分错误； D选项12分、9分、6分、2分、1分错误。 本题考核交通违法行为记分相关规定，需牢记各类违法行为的记分分值，避免违法记分。', NULL, '记分', '2026-05-17 15:20:56');
