INSERT INTO `biz_question` VALUES (480, 1, 1, '驾驶人有下列哪种违法行为—次记1分？', '连续驾驶载货汽车超过4个小时未停车休息', '在高速公路上行驶低于规定最低时速的', '驾驶不按规定安装机动车号牌的机动车', '不按规定会车', 'D', '本题为单选题，正确答案为D（不按规定会车）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项连续驾驶载货汽车超过4个小时未停车休息错误； B选项在高速公路上行驶低于规定最低时速的错误； C选项驾驶不按规定安装机动车号牌的机动车错误； 本题考核交通违法行为记分相关规定，需牢记各类违法行为的记分分值，避免违法记分。', NULL, '记分', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (481, 1, 1, '机动车驾驶人请他人代为接受交通违法行为处罚和记分，并支付经济利益的，会被处以所支付经济利益三倍以下的罚款，但最高不得超过多少元？', '2万', '3万', '8万', '5万', 'D', '本题为单选题，正确答案为D（5万）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项2万错误； B选项3万错误； C选项8万错误； 本题考核交通违法行为记分相关规定，需牢记各类违法行为的记分分值，避免违法记分。', NULL, '记分', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (482, 1, 1, '驾驶机动车在道路上行驶，错误使用危险报警闪光灯的，一次记多少分？', '6分', '3分', '2分', '1分', 'D', '本题为单选题，正确答案为D（1分）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项6分错误； B选项3分错误； C选项2分错误； 本题考核交通违法行为记分相关规定，需牢记各类违法行为的记分分值，避免违法记分。', NULL, '记分', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (483, 1, 1, '货车上高速公路行驶超过规定限宽或者限高的，一次记记分？', '9分', '6分', '3分', '1分', 'D', '本题为单选题，正确答案为D（1分）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项9分错误； B选项6分错误； C选项3分错误； 本题考核高速公路行车安全相关规定，需严格遵守高速公路通行规则，确保高速行车安全。', NULL, '高速公路', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (484, 1, 1, '属于申请增加轻型牵引挂车准驾车型的，车辆管理所应在多长时间内核发学习驾驶证明？', '受理后直接发', '1日内', '3日内', '5日内', 'A', '本题为单选题，正确答案为A（受理后直接发）。 其他选项均不符合相关法律法规及安全驾驶要求： B选项1日内错误； C选项3日内错误； D选项5日内错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (485, 1, 1, '机动车驾驶证被依法扣押、扣留或者暂扣期间，采用隐瞒、欺骗手段补领机动车驾驶证的，会收到下列哪种处罚？', '吊销驾驶证', '处二十元以上二百元以下罚款', '处二百元以上五百元以下罚款', '吊销行驶证', 'C', '本题为单选题，正确答案为C（处二百元以上五百元以下罚款）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项吊销驾驶证错误； B选项处二十元以上二百元以下罚款错误； D选项吊销行驶证错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (486, 1, 1, 'B2表示哪种准驾车型？', '重型牵引挂车', '大型货车', '中型客车', '大型客车', 'B', '本题为单选题，正确答案为B（大型货车）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项重型牵引挂车错误； C选项中型客车错误； D选项大型客车错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (487, 1, 1, '组织他人在驾驶人参加审验教育时在签注学习记录、学习过程中弄虚作假，由公安机关交通管理部门处多少元以下罚款？', '一干元', '二干元', '二万元', '三万元', 'C', '本题为单选题，正确答案为C（二万元）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项一干元错误； B选项二干元错误； D选项三万元错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (488, 1, 1, '以下哪个代号表示中型载货汽车？', 'A1', 'B1', 'A2', 'B2', 'D', '本题为单选题，正确答案为D（B2）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项A1错误； B选项B1错误； C选项A2错误； 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (489, 1, 1, 'A2实习期驾驶人驾驶机动车上高速公路行驶，以下做法正确的是什么？', '应当由持有B2准驾车型驾驶证三年以上的驾驶人陪同', '应当由持有B1准驾车型驾驶证三年以上的驾驶人陪同', '应当由持有A1准驾车型驾驶证三年以上的驾驶人陪同', '应当由持有A2准驾车型驾驶证三年以上的驾驶人陪同', 'D', '本题为单选题，正确答案为D（应当由持有A2准驾车型驾驶证三年以上的驾驶人陪同）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项应当由持有B2准驾车型驾驶证三年以上的驾驶人陪同错误； B选项应当由持有B1准驾车型驾驶证三年以上的驾驶人陪同错误； C选项应当由持有A1准驾车型驾驶证三年以上的驾驶人陪同错误； 本题考核高速公路行车安全相关规定，需严格遵守高速公路通行规则，确保高速行车安全。', NULL, '高速公路', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (490, 1, 1, '驾驶人出现以下哪种情况时，不得驾驶机动车？', '驾驶证丢失、损毁', '驾驶证接近有效期', '记分达到10分', '记分达到6分', 'A', '本题为单选题，正确答案为A（驾驶证丢失、损毁）。 其他选项均不符合相关法律法规及安全驾驶要求： B选项驾驶证接近有效期错误； C选项记分达到10分错误； D选项记分达到6分错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (491, 1, 1, '机动车驾驶人处理完交通违法行为记录后累积记分未满12分，参加公安机关交通管理部门组织的交通安全教育并达到规定要求的，可以申请在机动车驾驶人现有累积记分分值中扣减记分。在—个记分周期内累计最高可以扣减几分？', '3分', '6分', '9分', '12分', 'B', '本题为单选题，正确答案为B（6分）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项3分错误； C选项9分错误； D选项12分错误。 本题考核交通违法行为记分相关规定，需牢记各类违法行为的记分分值，避免违法记分。', NULL, '记分', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (492, 1, 1, '下列哪种情形不会被扣留车辆？', '没有按规定悬挂号牌', '没有放置保险标志', '未随车携带灭火器', '未随车携带行驶证', 'C', '本题为单选题，正确答案为C（未随车携带灭火器）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项没有按规定悬挂号牌错误； B选项没有放置保险标志错误； D选项未随车携带行驶证错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (493, 1, 1, '参加公安机关交通管理部门组织的交通安全公益活动的，满多长时间为一次，一次扣减几分？', '2小时；2分', '1小时；1分', '2小时；1分', '1小时；2分', 'B', '本题为单选题，正确答案为B（1小时；1分）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项2小时；2分错误； C选项2小时；1分错误； D选项1小时；2分错误。 本题考核交通违法行为记分相关规定，需牢记各类违法行为的记分分值，避免违法记分。', NULL, '记分', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (494, 1, 1, '未取得校车驾驶资格驾驶校车的，一次记多少分？', '12分', '9分', '6分', '3分', 'B', '本题为单选题，正确答案为B（9分）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项12分错误； C选项6分错误； D选项3分错误。 本题考核交通违法行为记分相关规定，需牢记各类违法行为的记分分值，避免违法记分。', NULL, '记分', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (495, 1, 1, '驾驶校车、中型以上载客载货汽车、危险物品运输车辆以外的机动车在高速公路上行驶超过规定时速百分之二十以上未达到百分之五十的，—次记多少分？', '9分', '3分', '1分', '6分', 'D', '本题为单选题，正确答案为D（6分）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项9分错误； B选项3分错误； C选项1分错误； 本题考核高速公路行车安全相关规定，需严格遵守高速公路通行规则，确保高速行车安全。', NULL, '高速公路', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (496, 1, 1, '同一机动车所有人名下两辆机动车的号牌号码互换，以下说法正确的是什么？', '同一机动车一年内可以多次互换变更机动车号牌号码', '两辆机动车使用性质为非营运可以申请互换', '申请前两车无未处理的道路交通安全违法和交通事故记录', '两辆机动车在不同辖区车辆管理所登记可以申请互换', 'C', '本题为单选题，正确答案为C（申请前两车无未处理的道路交通安全违法和交通事故记录）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项同一机动车一年内可以多次互换变更机动车号牌号码错误； B选项两辆机动车使用性质为非营运可以申请互换错误； D选项两辆机动车在不同辖区车辆管理所登记可以申请互换错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (497, 1, 1, '机动车驾驶人在—个记分周期内累积记分达到多少分的，公安机关交通管理部门将通知其参加满分学习、考试？', '6分', '9分', '12分', '24分', 'C', '本题为单选题，正确答案为C（12分）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项6分错误； B选项9分错误； D选项24分错误。 本题考核交通违法行为记分相关规定，需牢记各类违法行为的记分分值，避免违法记分。', NULL, '记分', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (498, 1, 1, '驾驶校车、公路客运汽车、旅游客运汽车载人超过核定人数百分之多少以上的，一次记12分？', '百分之五', '百分之十', '百分之十五', '百分之二十', 'D', '本题为单选题，正确答案为D（百分之二十）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项百分之五错误； B选项百分之十错误； C选项百分之十五错误； 本题考核交通违法行为记分相关规定，需牢记各类违法行为的记分分值，避免违法记分。', NULL, '记分', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (499, 1, 1, '交通违法行为累积记分未满多少分的情况下，可以处理其驾驶的其他机动车的交通违法处罚记录？', '3分', '12分', '9分', '6分', 'B', '本题为单选题，正确答案为B（12分）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项3分错误； C选项9分错误； D选项6分错误。 本题考核交通违法行为记分相关规定，需牢记各类违法行为的记分分值，避免违法记分。', NULL, '记分', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (500, 1, 1, '在最近几个记分周期内，机动车驾驶人因饮酒后驾驶机动车受到过处罚的，不得通过交通安全教育扣减交通违法行为记分？', '1个', '2个', '3个', '4个', 'C', '本题为单选题，正确答案为C（3个）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项1个错误； B选项2个错误； D选项4个错误。 本题考核交通违法行为记分相关规定，需牢记各类违法行为的记分分值，避免违法记分。', NULL, '记分', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (501, 1, 1, '满20周岁的，不可以初次申请以下哪种准驾车型？', '大型货车', '大型客车', '中型客车', '城市公交车', 'B', '本题为单选题，正确答案为B（大型客车）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项大型货车错误； C选项中型客车错误； D选项城市公交车错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (502, 1, 1, '驾驶人有下列哪种违法行为一次记9分？', '驾驶7座以上载客汽车载人超过核定人数百分之五十以上未达到百分之百的', '驾驶校车载人超过核定人数百分之二十以上的', '代替实际机动车驾驶人接受交通违法行为处罚和记分牟取经济利益的', '使用伪造、变造的机动车号牌或者使用其他机动车号牌的', 'A', '本题为单选题，正确答案为A（驾驶7座以上载客汽车载人超过核定人数百分之五十以上未达到百分之百的）。 其他选项均不符合相关法律法规及安全驾驶要求： B选项驾驶校车载人超过核定人数百分之二十以上的错误； C选项代替实际机动车驾驶人接受交通违法行为处罚和记分牟取经济利益的错误； D选项使用伪造、变造的机动车号牌或者使用其他机动车号牌的错误。 本题考核交通违法行为记分相关规定，需牢记各类违法行为的记分分值，避免违法记分。', NULL, '记分', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (503, 1, 1, '关于申请增加轻型牵引挂车准驾车型的要求，以下正确的说法是什么？', '取得小型汽车、小型自动挡汽车驾驶证1年', '本记分周期和最近连续三个以上记分周期内没有记满12分记录的', '本记分周期和最近连续一个记分周期内有记满12分记录的，已参加满分教育且考试通过', '取得小型自动挡汽车驾驶证3年以上', 'A', '本题为单选题，正确答案为A（取得小型汽车、小型自动挡汽车驾驶证1年）。 其他选项均不符合相关法律法规及安全驾驶要求： B选项本记分周期和最近连续三个以上记分周期内没有记满12分记录的错误； C选项本记分周期和最近连续一个记分周期内有记满12分记录的，已参加满分教育且考试通过错误； D选项取得小型自动挡汽车驾驶证3年以上错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (504, 1, 1, '驾驶校车、公路客运汽车、 旅游客运汽车载人超过核定人数未达20%的，一次记几分？', '3分', '6分', '9分', '12分', 'B', '本题为单选题，正确答案为B（6分）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项3分错误； C选项9分错误； D选项12分错误。 本题考核交通违法行为记分相关规定，需牢记各类违法行为的记分分值，避免违法记分。', NULL, '记分', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (505, 1, 1, '驾驶人有下列哪种违法行为一次记12分？', '驾驶货车运载爆炸物品，未按指定的时间、路线行驶的', '代替实际机动车驾驶人接受交通违法行为处罚和记分牟取经济利益的', '驾驶小型客车在高速公路上行驶超过规定时速百分之二十以上未达到百分之五十的', '驾驶机动车运载却限的不可解体的物品，未按指定时间、路线行驶的', 'B', '本题为单选题，正确答案为B（代替实际机动车驾驶人接受交通违法行为处罚和记分牟取经济利益的）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项驾驶货车运载爆炸物品，未按指定的时间、路线行驶的错误； C选项驾驶小型客车在高速公路上行驶超过规定时速百分之二十以上未达到百分之五十的错误； D选项驾驶机动车运载却限的不可解体的物品，未按指定时间、路线行驶的错误。 本题考核交通违法行为记分相关规定，需牢记各类违法行为的记分分值，避免违法记分。', NULL, '记分', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (506, 1, 1, '驾驶人有下列哪种违法行为一次记1分？', '驾驶载货汽车载物超过最大允许总质量百分之五十以上的', '驾驶机动车在道路上行驶时，机动车驾驶人未按规定系安全带的', '驾驶与准驾车型不符的机动车的', '驾驶机动车不按交通信号灯指示通行的', 'B', '本题为单选题，正确答案为B（驾驶机动车在道路上行驶时，机动车驾驶人未按规定系安全带的）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项驾驶载货汽车载物超过最大允许总质量百分之五十以上的错误； C选项驾驶与准驾车型不符的机动车的错误； D选项驾驶机动车不按交通信号灯指示通行的错误。 本题考核交通违法行为记分相关规定，需牢记各类违法行为的记分分值，避免违法记分。', NULL, '记分', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (507, 1, 1, '驾驶校车、中型以上载客载货汽车、危险物品运输车辆以外的机动车在高速公路、城市快速路以外的道路上行驶超过规定时速50%以上的，一次记几分？', '1分', '3分', '6分', '9分', 'C', '本题为单选题，正确答案为C（6分）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项1分错误； B选项3分错误； D选项9分错误。 本题考核高速公路行车安全相关规定，需严格遵守高速公路通行规则，确保高速行车安全。', NULL, '高速公路', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (508, 1, 1, '驾驶中型客车在高速公路上行驶，最高速度不能超过多少？', '80公里／小时', '100公里／小时', '110公里／小时', '120公里／小时', 'B', '本题为单选题，正确答案为B（100公里／小时）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项80公里／小时错误； C选项110公里／小时错误； D选项120公里／小时错误。 本题考核高速公路行车安全相关规定，需严格遵守高速公路通行规则，确保高速行车安全。', NULL, '高速公路', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (509, 1, 1, '机动车驾驶人初次取得汽车类准驾车型或者初次取得摩托车类准驾车型后的实习期是多长时间？', '18个月', '16个月', '12个月', '6个月', 'C', '本题为单选题，正确答案为C（12个月）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项18个月错误； B选项16个月错误； D选项6个月错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (510, 1, 1, '驾驶校车在高速公路、城市快速路上行驶超速未达20%的，一次记多少分？', '12分', '9分', '6分', '3分', 'C', '本题为单选题，正确答案为C（6分）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项12分错误； B选项9分错误； D选项3分错误。 本题考核高速公路行车安全相关规定，需严格遵守高速公路通行规则，确保高速行车安全。', NULL, '高速公路', '2026-05-17 15:20:56');
