INSERT INTO `biz_question` VALUES (512, 1, 1, '驾驶机动车在没有中心线的城市道路上行驶，以下说法正确的是什么？', '最高速度为每小时30公里', '最低速度为每小时30公里', '行驶速度可以为每小时50公里', '最低速度为每小时40公里', 'A', '本题为单选题，正确答案为A（最高速度为每小时30公里）。 其他选项均不符合相关法律法规及安全驾驶要求： B选项最低速度为每小时30公里错误； C选项行驶速度可以为每小时50公里错误； D选项最低速度为每小时40公里错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
