INSERT INTO `biz_question` VALUES (576, 1, 1, '发现前方道路堵塞，正确的做法是什么？', '继续穿插绕行', '选择空当逐车超越', '鸣喇叭示意前方车辆快速行驶', '按顺序停车等候', 'D', '本题为单选题，正确答案为D（按顺序停车等候）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项继续穿插绕行错误； B选项选择空当逐车超越错误； C选项鸣喇叭示意前方车辆快速行驶错误； 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (577, 1, 1, '车辆在拥挤路段低速行驶时，遇其他车辆强行插队，应怎样做？', '鸣喇叭警告，不得进入', '加速行驶，紧跟前车，不让其进入', '主动礼让，确保行车安全', '挤靠“加塞”车辆，逼其离开', 'C', '本题为单选题，正确答案为C（主动礼让，确保行车安全）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项鸣喇叭警告，不得进入错误； B选项加速行驶，紧跟前车，不让其进入错误； D选项挤靠“加塞”车辆，逼其离开错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (578, 1, 1, '行车中需要借道绕过前方障碍物，但对向来车已接近障碍物时，应怎样做？', '降低速度或停车，让对向来车优先通行', '加速提前抢过', '鸣喇叭示意对向车辆让道', '迅速占用车道，迫使对向来车停车让道', 'A', '本题为单选题，正确答案为A（降低速度或停车，让对向来车优先通行）。 其他选项均不符合相关法律法规及安全驾驶要求： B选项加速提前抢过错误； C选项鸣喇叭示意对向车辆让道错误； D选项迅速占用车道，迫使对向来车停车让道错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (579, 1, 1, '在堵车的交叉路口绿灯亮时，车辆应怎样做？', '可直接驶入交叉路口', '不能驶入交叉路口', '在保证安全的情况下驶入交叉路口', '可借对向车道通过路口', 'B', '本题为单选题，正确答案为B（不能驶入交叉路口）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项可直接驶入交叉路口错误； C选项在保证安全的情况下驶入交叉路口错误； D选项可借对向车道通过路口错误。 本题考核交通信号相关规定，需严格按照交通信号指示通行，确保路口行车安全。', NULL, '交通信号', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (580, 1, 1, '山区道路对安全行车的主要影响是什么？', '道路标志少', '交通情况单一', '坡长弯急，视距不足', '车流密度大', 'C', '本题为单选题，正确答案为C（坡长弯急，视距不足）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项道路标志少错误； B选项交通情况单一错误； D选项车流密度大错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (581, 1, 1, '驾驶车辆行至道路急转弯处，应怎样做？', '借对向车道行驶', '急剧制动低速通过', '靠弯道外侧行驶', '充分减速并靠右侧行驶', 'D', '本题为单选题，正确答案为D（充分减速并靠右侧行驶）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项借对向车道行驶错误； B选项急剧制动低速通过错误； C选项靠弯道外侧行驶错误； 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (582, 1, 1, '山区道路车辆进入弯道前，在对面没有来车的情况下，应怎样做？', '应“减速、鸣喇叭、靠右行”', '可靠弯道外侧行驶', '可短时间借用对方的车道', '可加速沿弯道切线方向通过', 'A', '本题为单选题，正确答案为A（应“减速、鸣喇叭、靠右行”）。 其他选项均不符合相关法律法规及安全驾驶要求： B选项可靠弯道外侧行驶错误； C选项可短时间借用对方的车道错误； D选项可加速沿弯道切线方向通过错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (583, 1, 1, '车辆行至交叉路口，遇有转弯的车辆抢行，应怎样做？', '停车避让', '保持正常车速行驶', '提高车速抢先通过', '鸣喇叭抢先通过', 'A', '本题为单选题，正确答案为A（停车避让）。 其他选项均不符合相关法律法规及安全驾驶要求： B选项保持正常车速行驶错误； C选项提高车速抢先通过错误； D选项鸣喇叭抢先通过错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (584, 1, 1, '行驶车道绿灯亮时，但车辆前方人行横道仍有行人行走，应怎样做？', '直接起步通过', '起步后从行人后方绕过', '起步后从行人前方绕过', '等行人通过后再起步', 'D', '本题为单选题，正确答案为D（等行人通过后再起步）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项直接起步通过错误； B选项起步后从行人后方绕过错误； C选项起步后从行人前方绕过错误； 本题考核交通信号相关规定，需严格按照交通信号指示通行，确保路口行车安全。', NULL, '交通信号', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (585, 1, 1, '下长坡连续使用行车制动会导致什么？', '会缩短发动机寿命', '增加驾驶人的劳动强度', '会使制动器温度升高而使制动效果急剧下降', '容易造成车辆倾翻', 'C', '本题为单选题，正确答案为C（会使制动器温度升高而使制动效果急剧下降）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项会缩短发动机寿命错误； B选项增加驾驶人的劳动强度错误； D选项容易造成车辆倾翻错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (586, 1, 1, '当驾驶车辆行经两侧有非机动车行驶且有积水的路面时，应怎样做？', '减速慢行', '正常行驶', '加速通过', '连续鸣喇叭', 'A', '本题为单选题，正确答案为A（减速慢行）。 其他选项均不符合相关法律法规及安全驾驶要求： B选项正常行驶错误； C选项加速通过错误； D选项连续鸣喇叭错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (587, 1, 1, '在山区道路遇对向来车时，应怎样会车？', '不减速', '紧靠道路中心', '加速', '减速或停车让行', 'D', '本题为单选题，正确答案为D（减速或停车让行）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项不减速错误； B选项紧靠道路中心错误； C选项加速错误； 本题为驾考核心考点，需牢记相关规则，严格遵守交通法规，确保行车安全。', NULL, '会车让行', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (588, 1, 1, '车辆在较窄的山路上行驶时，如果靠山体的一方不让行，应怎样做？', '向左占道，谨慎驶过', '提前减速或停车避让', '保持正常车速行驶', '鸣喇叭催其让行', 'B', '本题为单选题，正确答案为B（提前减速或停车避让）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项向左占道，谨慎驶过错误； C选项保持正常车速行驶错误； D选项鸣喇叭催其让行错误。 本题为驾考核心考点，需牢记相关规则，严格遵守交通法规，确保行车安全。', NULL, '会车让行', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (589, 1, 1, '在一般道路倒车时，若发现有过往车辆通过，应怎样做？', '继续倒车', '鸣喇叭示意', '主动停车避让', '加速倒车', 'C', '本题为单选题，正确答案为C（主动停车避让）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项继续倒车错误； B选项鸣喇叭示意错误； D选项加速倒车错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (590, 1, 1, '驾驶人在超车时，前方车辆不减速、不让道，应怎样做？', '连续鸣喇叭加速超越', '加速继续超越', '停止继续超车', '紧跟其后，伺机再超', 'C', '本题为单选题，正确答案为C（停止继续超车）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项连续鸣喇叭加速超越错误； B选项加速继续超越错误； D选项紧跟其后，伺机再超错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (591, 1, 1, '驾驶的车辆正在被其他车辆超越时，应怎样做？', '继续加速行驶', '减速，靠右侧行驶', '靠道路中心行驶', '加速让路', 'B', '本题为单选题，正确答案为B（减速，靠右侧行驶）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项继续加速行驶错误； C选项靠道路中心行驶错误； D选项加速让路错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (592, 1, 1, '遇后车发出超车信号后，只要具备让超条件应怎样做？', '迅速减速或紧急制动', '让出适当空间加速行驶', '主动减速并靠右侧行驶', '靠道路右侧加速行驶', 'C', '本题为单选题，正确答案为C（主动减速并靠右侧行驶）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项迅速减速或紧急制动错误； B选项让出适当空间加速行驶错误； D选项靠道路右侧加速行驶错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (593, 1, 1, '夜间行车，可选择下列哪个地段超车？', '交叉路口', '弯道陡坡', '路宽车少', '窄路窄桥', 'C', '本题为单选题，正确答案为C（路宽车少）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项交叉路口错误； B选项弯道陡坡错误； D选项窄路窄桥错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (594, 1, 1, '驾驶机动车正在被其他车辆超越时，被超车辆减速靠右侧行驶的目的是什么?', '以便随时停车', '给该车让出足够的超车空间', '避让行人与非机动车', '以上选项都不正确', 'B', '本题为单选题，正确答案为B（给该车让出足够的超车空间）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项以便随时停车错误； C选项避让行人与非机动车错误； D选项以上选项都不正确错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (595, 1, 1, '驾驶车辆进入高速公路加速车道后，应尽快将车速提高到每小时多少公里以上？', '30', '40', '50', '60', 'D', '本题为单选题，正确答案为D（60）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项30错误； B选项40错误； C选项50错误； 本题考核高速公路行车安全相关规定，需严格遵守高速公路通行规则，确保高速行车安全。', NULL, '高速公路', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (596, 1, 1, '在标志、标线齐全的高速公路上行车，应当按照什么规定的车道和车速行驶？', '《道路交通安全法》', '标志或标线', '车辆说明书', '地方法规', 'B', '本题为单选题，正确答案为B（标志或标线）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项《道路交通安全法》错误； C选项车辆说明书错误； D选项地方法规错误。 本题考核高速公路行车安全相关规定，需严格遵守高速公路通行规则，确保高速行车安全。', NULL, '高速公路', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (597, 1, 1, '在同向4车道高速公路上行车，车速高于每小时110公里的车辆应在哪条车道上行驶？', '最左侧', '第二条', '第三条', '最右侧', 'A', '本题为单选题，正确答案为A（最左侧）。 其他选项均不符合相关法律法规及安全驾驶要求： B选项第二条错误； C选项第三条错误； D选项最右侧错误。 本题考核高速公路行车安全相关规定，需严格遵守高速公路通行规则，确保高速行车安全。', NULL, '高速公路', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (598, 1, 1, '在高速公路上驾驶机动车， 车辆发生故障后的处置方法，以下说法错误的是什么？', '打开危险报警闪光灯，夜间还应开启示廓灯、后位灯', '在车后150米以外设置安全警告标志', '车内乘员应下车辅助将故障车辆推移到紧急停车带上', '所有人员需离开故障车辆，在紧急停车带或护栏以外安全位置报警并等候救援', 'C', '本题为单选题，正确答案为C（车内乘员应下车辅助将故障车辆推移到紧急停车带上）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项打开危险报警闪光灯，夜间还应开启示廓灯、后位灯错误； B选项在车后150米以外设置安全警告标志错误； D选项所有人员需离开故障车辆，在紧急停车带或护栏以外安全位置报警并等候救援错误。 本题考核高速公路行车安全相关规定，需严格遵守高速公路通行规则，确保高速行车安全。', NULL, '高速公路', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (599, 1, 1, '驾驶机动车在高速公路上行驶，遇有雾、雨、雪、沙尘、冰雹等低能见度气象条件下， 能见度在100米以下时，车速不得超过每小时多少公里，与同车道前车至少保持多少米的距离？', '40.50', '40.40', '50.40', '50.30', 'A', '本题为单选题，正确答案为A（40.50）。 其他选项均不符合相关法律法规及安全驾驶要求： B选项40.40错误； C选项50.40错误； D选项50.30错误。 本题考核高速公路行车安全相关规定，需严格遵守高速公路通行规则，确保高速行车安全。', NULL, '高速公路', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (600, 1, 1, '轮胎气压过低时，高速行驶轮胎会出现波浪变形温度升高而导致什么？', '气压不稳', '气压更低', '行驶阻力增大', '爆胎', 'D', '本题为单选题，正确答案为D（爆胎）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项气压不稳错误； B选项气压更低错误； C选项行驶阻力增大错误； 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (601, 1, 1, '避免爆胎的错误的做法是什么？', '降低轮胎气压', '定期检查轮胎', '及时清理轮胎沟槽里的异物', '更换有裂纹或有很深损伤的轮胎', 'A', '本题为单选题，正确答案为A（降低轮胎气压）。 其他选项均不符合相关法律法规及安全驾驶要求： B选项定期检查轮胎错误； C选项及时清理轮胎沟槽里的异物错误； D选项更换有裂纹或有很深损伤的轮胎错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (602, 1, 1, '行车中遇有前方发生交通事故，需要帮助时，应怎样做？', '尽量绕道躲避', '立即报警，停车观望', '协助保护现场，并立即报警', '加速通过，不予理睬', 'C', '本题为单选题，正确答案为C（协助保护现场，并立即报警）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项尽量绕道躲避错误； B选项立即报警，停车观望错误； D选项加速通过，不予理睬错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (603, 1, 1, '行车中遇交通事故受伤者需要抢救时，应怎样做？', '及时将伤者送医院抢救或拨打急救电话', '尽量避开，少惹麻烦', '绕过现场行驶', '借故避开现场', 'A', '本题为单选题，正确答案为A（及时将伤者送医院抢救或拨打急救电话）。 其他选项均不符合相关法律法规及安全驾驶要求： B选项尽量避开，少惹麻烦错误； C选项绕过现场行驶错误； D选项借故避开现场错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (604, 1, 1, '饮酒后或者醉酒驾驶机动车发生重大交通事故构成犯罪的，依法追究刑事责任，吊销机动车驾驶证，将多少年内不得申请机动车驾驶证？', '五年', '十年', '二十年', '终生', 'D', '本题为单选题，正确答案为D（终生）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项五年错误； B选项十年错误； C选项二十年错误； 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (605, 1, 1, '上道路行驶的机动车驾驶人未携带机动车驾驶证、行驶证的，除扣留机动车外，并受到什么处罚？', '警告', '罚款', '拘留', '吊销驾驶证', 'B', '本题为单选题，正确答案为B（罚款）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项警告错误； C选项拘留错误； D选项吊销驾驶证错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (606, 1, 1, '申请人在考试过程中有贿赂、舞弊行为的，申请人在多少年内不得再次申领机动车驾\n驶证？', '1年', '2年', '3年', '4年', 'A', '本题为单选题，正确答案为A（1年）。 其他选项均不符合相关法律法规及安全驾驶要求： B选项2年错误； C选项3年错误； D选项4年错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (607, 1, 1, '机动车驾驶人有以下哪种违法行为的， 暂扣六个月机动车驾驶证？', '醉酒后驾驶机动车的', '伪造、变造机动车驾驶证的', '饮酒后驾驶机动车的', '使用伪造、变造机动车驾驶证的', 'C', '本题为单选题，正确答案为C（饮酒后驾驶机动车的）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项醉酒后驾驶机动车的错误； B选项伪造、变造机动车驾驶证的错误； D选项使用伪造、变造机动车驾驶证的错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (608, 1, 1, '夜间行车中，前方出现弯道时，灯光照射会发生怎样的变化？', '距离不变', '由高变低', '离开路面', '由路中移到路侧', 'D', '本题为单选题，正确答案为D（由路中移到路侧）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项距离不变错误； B选项由高变低错误； C选项离开路面错误； 本题考核机动车灯光使用相关规定，需正确使用灯光，确保行车安全。', NULL, '灯光使用', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (609, 1, 1, '遇有浓雾或特大雾天能见度过低，行车困难时，应怎样做？', '开启前照灯，继续行驶', '开启示廓灯、雾灯，靠右行驶', '开启危险报警闪光灯和雾灯，选择安全地点停车', '开启危险报警闪光灯，继续行驶', 'C', '本题为单选题，正确答案为C（开启危险报警闪光灯和雾灯，选择安全地点停车）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项开启前照灯，继续行驶错误； B选项开启示廓灯、雾灯，靠右行驶错误； D选项开启危险报警闪光灯，继续行驶错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (610, 1, 1, '车辆驶入双向行驶隧道前，应开启什么灯？', '危险报警闪光灯', '远光灯', '雾灯', '示廓灯或近光灯', 'D', '本题为单选题，正确答案为D（示廓灯或近光灯）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项危险报警闪光灯错误； B选项远光灯错误； C选项雾灯错误； 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (611, 1, 1, '行人参与道路交通的主要特点是什么？', '行动迟缓', '喜欢聚集、围观', '行走随意性大，方向多变', '以上都是', 'C', '本题为单选题，正确答案为C（行走随意性大，方向多变）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项行动迟缓错误； B选项喜欢聚集、围观错误； D选项以上都是错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (612, 1, 1, '行车中超越右侧停放的车辆时，为预防其突然起步或开启车门，应怎样做？', '预留出横向安全距离，减速行驶', '保持正常速度行驶', '长鸣喇叭', '加速通过', 'A', '本题为单选题，正确答案为A（预留出横向安全距离，减速行驶）。 其他选项均不符合相关法律法规及安全驾驶要求： B选项保持正常速度行驶错误； C选项长鸣喇叭错误； D选项加速通过错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (613, 1, 1, '行车中遇有非机动车准备绕过停放的车辆时，应怎样做？', '鸣喇叭示意其让道', '让其先行', '加速绕过', '紧随其后鸣喇叭', 'B', '本题为单选题，正确答案为B（让其先行）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项鸣喇叭示意其让道错误； C选项加速绕过错误； D选项紧随其后鸣喇叭错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (614, 1, 1, '行车中，遇非机动车抢行时，应怎样做？', '鸣喇叭警告', '加速通过', '减速让行', '临近时突然加速', 'C', '本题为单选题，正确答案为C（减速让行）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项鸣喇叭警告错误； B选项加速通过错误； D选项临近时突然加速错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (615, 1, 1, '行车中遇儿童时，应怎样做？', '长鸣喇叭催促', '减速慢行，必要时停车避让', '迅速从一侧通过', '加速绕行', 'B', '本题为单选题，正确答案为B（减速慢行，必要时停车避让）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项长鸣喇叭催促错误； C选项迅速从一侧通过错误； D选项加速绕行错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (616, 1, 1, '行车中遇列队横过道路的学生时，应怎样做？', '提前加速抢行', '停车让行', '降低车速、缓慢通过', '连续鸣喇叭催促', 'B', '本题为单选题，正确答案为B（停车让行）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项提前加速抢行错误； C选项降低车速、缓慢通过错误； D选项连续鸣喇叭催促错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (617, 1, 1, '车辆通过凹凸路面时，应怎样做？', '低速缓慢平稳通过', '依靠惯性加速冲过', '挂空挡滑行驶过', '保持原速通过', 'A', '本题为单选题，正确答案为A（低速缓慢平稳通过）。 其他选项均不符合相关法律法规及安全驾驶要求： B选项依靠惯性加速冲过错误； C选项挂空挡滑行驶过错误； D选项保持原速通过错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (618, 1, 1, '行车中超越同向行驶的自行车时，应怎样做？', '让自行车先行', '注意观察动态，减速慢行，留有足够的安全距离', '连续鸣喇叭提醒其让路', '持续鸣喇叭并加速超越', 'B', '本题为单选题，正确答案为B（注意观察动态，减速慢行，留有足够的安全距离）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项让自行车先行错误； C选项连续鸣喇叭提醒其让路错误； D选项持续鸣喇叭并加速超越错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (619, 1, 1, '夜间驾驶车辆遇自行车对向驶来时，应怎样做？', '连续变换远、近光灯', '不断鸣喇叭', '使用远光灯', '使用近光灯，减速或停车避让', 'D', '本题为单选题，正确答案为D（使用近光灯，减速或停车避让）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项连续变换远、近光灯错误； B选项不断鸣喇叭错误； C选项使用远光灯错误； 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (620, 1, 1, '车辆在主干道上行驶，驶近主支干道交汇处时，为防止与从支路突然驶入的车辆相撞，应怎样做？', '提前减速、观察，谨慎驾驶', '保持正常速度行驶', '鸣喇叭，迅速通过', '提前加速通过', 'A', '本题为单选题，正确答案为A（提前减速、观察，谨慎驾驶）。 其他选项均不符合相关法律法规及安全驾驶要求： B选项保持正常速度行驶错误； C选项鸣喇叭，迅速通过错误； D选项提前加速通过错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (621, 1, 1, '驾驶人行车中看到注意儿童标志的时候，应怎样做？', '加速行驶', '绕道行驶', '谨慎选择行车速度', '保持正常车速行驶', 'C', '本题为单选题，正确答案为C（谨慎选择行车速度）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项加速行驶错误； B选项绕道行驶错误； D选项保持正常车速行驶错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (622, 1, 1, '车辆驶近停在车站的公交车辆时，为预防公交车突然起步或行人从车前穿出，应怎样做？', '减速，保持足够间距，随时准备停车', '保持正常车速行驶', '随时准备紧急制动', '鸣喇叭提醒，加速通过', 'A', '本题为单选题，正确答案为A（减速，保持足够间距，随时准备停车）。 其他选项均不符合相关法律法规及安全驾驶要求： B选项保持正常车速行驶错误； C选项随时准备紧急制动错误； D选项鸣喇叭提醒，加速通过错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (623, 1, 1, '遇前方路段车道减少，车辆行驶缓慢，为保证安全有序应该怎样做?', '依次交替通行', '穿插到前方排队车辆中通过', '加速从前车左右超越', '借对向车道迅速通过', 'A', '本题为单选题，正确答案为A（依次交替通行）。 其他选项均不符合相关法律法规及安全驾驶要求： B选项穿插到前方排队车辆中通过错误； C选项加速从前车左右超越错误； D选项借对向车道迅速通过错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (624, 1, 1, '驾驶机动车准备驶离环岛时，应如何使用灯光？', '提前开启左转向灯', '不用指示灯提示', '开启危险报警闪光灯', '提前开启右转向灯', 'D', '本题为单选题，正确答案为D（提前开启右转向灯）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项提前开启左转向灯错误； B选项不用指示灯提示错误； C选项开启危险报警闪光灯错误； 本题考核机动车灯光使用相关规定，需正确使用灯光，确保行车安全。', NULL, '灯光使用', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (625, 1, 1, '车辆在泥冲路上发生侧滑时，以下做法正确的是？', '向侧滑的—侧转动转向盘适量修正', '向侧滑的另—侧转动转向盘适量修正', '迅速制动减速', '迅速制动停车', 'A', '本题为单选题，正确答案为A（向侧滑的—侧转动转向盘适量修正）。 其他选项均不符合相关法律法规及安全驾驶要求： B选项向侧滑的另—侧转动转向盘适量修正错误； C选项迅速制动减速错误； D选项迅速制动停车错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (626, 1, 1, '元某在未取得驾驶证的情况下，借用黄某的小型汽车上路行驶，元某的行为将受到下列哪种处罚？', '处20元以上200元以下罚款', '记12分', '处十日以下拘留', '处罚款，并处拘留', 'D', '本题为单选题，正确答案为D（处罚款，并处拘留）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项处20元以上200元以下罚款错误； B选项记12分错误； C选项处十日以下拘留错误； 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (627, 1, 1, '驾驶机动车在高速公路上遇雾天时，以下说法正确的是什么？', '能见度小于100米时， 车速不得超过60km/h', '能见度小于50米时， 车速不得超过20km/h,	从最近的出口驶离高速公路', '能见度小于200米时， 车速不得超过80km/h', '能见度小于30米时， 直接在行车道内停车等待', 'B', '本题为单选题，正确答案为B（能见度小于50米时， 车速不得超过20km/h,	从最近的出口驶离高速公路）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项能见度小于100米时， 车速不得超过60km/h错误； C选项能见度小于200米时， 车速不得超过80km/h错误； D选项能见度小于30米时， 直接在行车道内停车等待错误。 本题考核高速公路行车安全相关规定，需严格遵守高速公路通行规则，确保高速行车安全。', NULL, '高速公路', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (628, 1, 1, '雾天驾驶机动车跟车行驶，以下做法错误的是什么？', '加大两车间的距离', '时刻注意前车刹车灯的变化', '降低行车速度', '鸣喇叭提醒前车提高车速，避免后车追尾', 'D', '本题为单选题，正确答案为D（鸣喇叭提醒前车提高车速，避免后车追尾）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项加大两车间的距离错误； B选项时刻注意前车刹车灯的变化错误； C选项降低行车速度错误； 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (629, 1, 1, '驾驶人连续驾驶机动车超过多长时间时，应停车休息至少20分钟？', '2小时', '4小时', '6小时', '8小时', 'B', '本题为单选题，正确答案为B（4小时）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项2小时错误； C选项6小时错误； D选项8小时错误。 本题考核交通违法行为记分相关规定，需牢记各类违法行为的记分分值，避免违法记分。', NULL, '记分', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (630, 1, 1, '驾驶机动车在道路上发生交通事故，难以移动时，正确的做法是？', '开启危险报警闪光灯，并在车后设置警告标志', '在车前放置警告标志', '交替使用远近光灯提示其他车辆', '车上人员在车内等待救援', 'A', '本题为单选题，正确答案为A（开启危险报警闪光灯，并在车后设置警告标志）。 其他选项均不符合相关法律法规及安全驾驶要求： B选项在车前放置警告标志错误； C选项交替使用远近光灯提示其他车辆错误； D选项车上人员在车内等待救援错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (631, 1, 1, '驾驶人机动车驾驶证被吊销后，使用伪造的机动车驾驶证，会受到下列哪种处罚？', '处20元以上200元以下罚款', '一次记6分', '暂扣伪造的机动车驾驶证', '处十五日以下拘留并处罚金', 'D', '本题为单选题，正确答案为D（处十五日以下拘留并处罚金）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项处20元以上200元以下罚款错误； B选项一次记6分错误； C选项暂扣伪造的机动车驾驶证错误； 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (632, 1, 1, '在道路上发生交通事故，未造成人身伤亡，当事人对事实及成因无争议的，应当如何处理？', '即行撤离现场，自行协商处理损害赔偿事宜', '将车停在原地，保护好现场，等待交通警察前来处理', '保护现场，请保险公司定损', '不得撤离现场', 'A', '本题为单选题，正确答案为A（即行撤离现场，自行协商处理损害赔偿事宜）。 其他选项均不符合相关法律法规及安全驾驶要求： B选项将车停在原地，保护好现场，等待交通警察前来处理错误； C选项保护现场，请保险公司定损错误； D选项不得撤离现场错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (633, 1, 1, '上车前，驾驶人应该如何进行绕车检查？', '顺时针绕车一周', '逆时针绕车一周', '任意方向绕车一周', '可直接上车', 'B', '本题为单选题，正确答案为B（逆时针绕车一周）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项顺时针绕车一周错误； C选项任意方向绕车一周错误； D选项可直接上车错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (634, 1, 1, '驾驶机动车上高速公路行驶，以下正确的说法是什么？', '可在匝道、加速车道、减速车道上超车', '不准倒车、逆行、穿越中央分隔带掉头', '非紧急情况时可在应急车道行驶', '可以试车或学习驾驶', 'B', '本题为单选题，正确答案为B（不准倒车、逆行、穿越中央分隔带掉头）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项可在匝道、加速车道、减速车道上超车错误； C选项非紧急情况时可在应急车道行驶错误； D选项可以试车或学习驾驶错误。 本题考核高速公路行车安全相关规定，需严格遵守高速公路通行规则，确保高速行车安全。', NULL, '高速公路', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (635, 1, 1, '机动车在没有限速标志的路段，应怎样行驶？', '不受速度限制', '按自己的意愿行驶', '应当保持安全车速', '应当以最高设计车速行驶', 'C', '本题为单选题，正确答案为C（应当保持安全车速）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项不受速度限制错误； B选项按自己的意愿行驶错误； D选项应当以最高设计车速行驶错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (636, 1, 1, '大雾天在高速公路遇事故不能继续行驶时怎样处置？', '车上人员要迅速从左侧车门离开', '在来车方向100米处设置警告标志', '开启危险报警闪光灯和远光灯', '车上人员站到护栏以外安全的地方', 'D', '本题为单选题，正确答案为D（车上人员站到护栏以外安全的地方）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项车上人员要迅速从左侧车门离开错误； B选项在来车方向100米处设置警告标志错误； C选项开启危险报警闪光灯和远光灯错误； 本题考核高速公路行车安全相关规定，需严格遵守高速公路通行规则，确保高速行车安全。', NULL, '高速公路', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (637, 1, 1, '在山区宽阔的缓上坡路段超车时，错误的做法是什么？', '开启左转向灯', '提前鸣喇叭示意', '开启右转向灯', '具备超车条件后超越', 'C', '本题为单选题，正确答案为C（开启右转向灯）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项开启左转向灯错误； B选项提前鸣喇叭示意错误； D选项具备超车条件后超越错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (638, 1, 1, '以下哪种违法行为的机动车驾驶人将被一次记6分？', '驾驶与准驾车型不符的机动车', '在高速公路车速超过规定时速50%以上', '驾驶机动车违反道路交通信号灯', '未取得校车驾驶资格驾驶校车', 'C', '本题为单选题，正确答案为C（驾驶机动车违反道路交通信号灯）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项驾驶与准驾车型不符的机动车错误； B选项在高速公路车速超过规定时速50%以上错误； D选项未取得校车驾驶资格驾驶校车错误。 本题考核交通违法行为记分相关规定，需牢记各类违法行为的记分分值，避免违法记分。', NULL, '记分', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (639, 1, 1, '以下哪种行为机动车驾驶人将被—次记9分？', '驾驶机动车不按规定避让校车的', '驾驶证被暂扣期间驾驶机动车的', '驾驶机动车不按交通信号灯指示通行的', '驾驶与准驾车型不符的机动车的', 'D', '本题为单选题，正确答案为D（驾驶与准驾车型不符的机动车的）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项驾驶机动车不按规定避让校车的错误； B选项驾驶证被暂扣期间驾驶机动车的错误； C选项驾驶机动车不按交通信号灯指示通行的错误； 本题考核交通违法行为记分相关规定，需牢记各类违法行为的记分分值，避免违法记分。', NULL, '记分', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (640, 1, 1, '驾驶机动车在高速公路上行驶，速度为100km/h ,危险车间距是多少？', '50米', '100米', '110米', '150 米', 'A', '本题为单选题，正确答案为A（50米）。 其他选项均不符合相关法律法规及安全驾驶要求： B选项100米错误； C选项110米错误； D选项150 米错误。 本题考核高速公路行车安全相关规定，需严格遵守高速公路通行规则，确保高速行车安全。', NULL, '高速公路', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (641, 1, 1, '以下选项中，车辆导航的英文缩写是什么？', 'ACC', 'ETC', 'LDW', 'GPS', 'D', '本题为单选题，正确答案为D（GPS）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项ACC错误； B选项ETC错误； C选项LDW错误； 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
