INSERT INTO `biz_question` VALUES (670, 1, 1, '以下哪种情形机动车所有人应申请办理注销登记？', '机动车所有人联系方式变更的', '机动车已达到国家强制报废标准的', '机动车发生损坏的', '车辆识别代号因磨损、锈蚀、事故等原因辨认不清或者损坏的', 'B', '本题为单选题，正确答案为B（机动车已达到国家强制报废标准的）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项机动车所有人联系方式变更的错误； C选项机动车发生损坏的错误； D选项车辆识别代号因磨损、锈蚀、事故等原因辨认不清或者损坏的错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (671, 1, 1, '机动车所有人的住所迁出、迁入车辆管理所管辖区域的，应当向登记地车辆管理所申请什么登记？', '注册', '转移', '注销', '变更', 'D', '本题为单选题，正确答案为D（变更）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项注册错误； B选项转移错误； C选项注销错误； 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (672, 1, 1, '机动车已达到国家强制报废标准的，申请注销登记时应将机动车怎么处理？', '交售给回收企业', '卖给废品收购站', '交给车辆管理所', '交给安全技术检验机构', 'A', '本题为单选题，正确答案为A（交售给回收企业）。 其他选项均不符合相关法律法规及安全驾驶要求： B选项卖给废品收购站错误； C选项交给车辆管理所错误； D选项交给安全技术检验机构错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (673, 1, 1, '以下哪种情形已注册登记的机动车会被车辆管理所注销？', '距离达到国家强制报废标准—年以内', '机动车登记的使用性质改变的', '机动车登记被依法撤销的', '机动车属于被盗抢骗的', 'C', '本题为单选题，正确答案为C（机动车登记被依法撤销的）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项距离达到国家强制报废标准—年以内错误； B选项机动车登记的使用性质改变的错误； D选项机动车属于被盗抢骗的错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (674, 1, 1, '办理机动车变更登记、转让登记或者注销登记后，原机动车所有人重新申请机动车登记时，若想使用原机动车号牌号码，应满足以下哪项条件？', '在办理机动车迁出、共同所有人变更转让登记或者注销登记后三年内提出申请', '机动车所有人拥有原机动车且使用原号牌号码两年以上', '涉及原机动车的道路交通安全违法行为和交通事故处理完毕', '机动车所有人的驾驶证未扣满12分', 'C', '本题为单选题，正确答案为C（涉及原机动车的道路交通安全违法行为和交通事故处理完毕）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项在办理机动车迁出、共同所有人变更转让登记或者注销登记后三年内提出申请错误； B选项机动车所有人拥有原机动车且使用原号牌号码两年以上错误； D选项机动车所有人的驾驶证未扣满12分错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (675, 1, 1, '车辆管理所收到机动车所有人补领、换领机动车号牌的申请后，自受理之日起多少日内补发、换发号牌？', '三日', '五日', '十日', '十五日', 'D', '本题为单选题，正确答案为D（十五日）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项三日错误； B选项五日错误； C选项十日错误； 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (676, 1, 1, '补发、换发号牌期间，申请人可以申领有效期不超过多少日的临时行驶车号牌？', '三日', '五日', '十日', '十五日', 'D', '本题为单选题，正确答案为D（十五日）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项三日错误； B选项五日错误； C选项十日错误； 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (677, 1, 1, '以下哪种情形会被公安机关交通管理部门处警告或者二百元以下罚款？', '机动车喷涂、粘贴标识或者车身广告，影响安全驾驶的', '以欺骗、贿赂等不正当手段取得机动车登记的', '隐瞒有关情况申请机动车登记的', '提供虚假材料申请机动车登记的', 'A', '本题为单选题，正确答案为A（机动车喷涂、粘贴标识或者车身广告，影响安全驾驶的）。 其他选项均不符合相关法律法规及安全驾驶要求： B选项以欺骗、贿赂等不正当手段取得机动车登记的错误； C选项隐瞒有关情况申请机动车登记的错误； D选项提供虚假材料申请机动车登记的错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (678, 1, 1, '机动车所有人联系方式变更的，应当在信息或者事项变更后多少日内，向登记地车辆管理所申请变更备案？', '十日', '十五日', '二十日', '三十日', 'D', '本题为单选题，正确答案为D（三十日）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项十日错误； B选项十五日错误； C选项二十日错误； 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (679, 1, 1, '因质量问题退车的，机动车所有人应当向哪个车辆管理所申请注销登记？', '居住地', '户籍地', '登记地', '暂住地', 'C', '本题为单选题，正确答案为C（登记地）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项居住地错误； B选项户籍地错误； D选项暂住地错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (680, 1, 1, '机动车未达到国家强制报废标准，机动车所有人自愿报废的，机动车所有人应当向哪个车辆管理所申请注销登记？', '居住地', '户籍地', '登记地', '暂住地', 'C', '本题为单选题，正确答案为C（登记地）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项居住地错误； B选项户籍地错误； D选项暂住地错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (681, 1, 1, '现机动车所有人住所不在车辆管理所管辖区域内的，转出地车辆管理所应当自受理之日起多少日内，查验机动车？', '一日', '三日', '五日', '十日', 'B', '本题为单选题，正确答案为B（三日）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项一日错误； C选项五日错误； D选项十日错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (682, 1, 1, '机动车所有人收到机动车号牌之日起多少日后，临时行驶车号牌作废，不得继续使用？', '一日', '二日', '三日', '五日', 'C', '本题为单选题，正确答案为C（三日）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项一日错误； B选项二日错误； D选项五日错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (683, 1, 1, '未取得机动车驾驶证驾驶机动车，发生负同等以上责任交通事故造成人员重伤或者死亡未满多少年的，不得申请机动车驾驶证？', '一年', '三年', '五年', '十年', 'D', '本题为单选题，正确答案为D（十年）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项一年错误； B选项三年错误； C选项五年错误； 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (684, 1, 1, '驾驶机动车在道路上向右转弯时，以下说法正确的是？', '提前开启右转向灯', '不受信号灯限制', '不受车速限制', '迅速右转以防堵塞', 'A', '本题为单选题，正确答案为A（提前开启右转向灯）。 其他选项均不符合相关法律法规及安全驾驶要求： B选项不受信号灯限制错误； C选项不受车速限制错误； D选项迅速右转以防堵塞错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (685, 1, 1, '以下哪个位置可以掉头？', '设有禁止左转标志', '设有禁止掉头标志', '设有允许掉头标志', '道路中心线为黄色实线处', 'C', '本题为单选题，正确答案为C（设有允许掉头标志）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项设有禁止左转标志错误； B选项设有禁止掉头标志错误； D选项道路中心线为黄色实线处错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (686, 1, 1, '下列说法正确的是什么？', '从匝道驶入高速公路，应提前开启右转向灯', '驶离高速公路进入匝道时，应提前开启右转向灯', '匝道路段可以超车', '驶入错误的匝道后，可倒车驶回高速公路', 'B', '本题为单选题，正确答案为B（驶离高速公路进入匝道时，应提前开启右转向灯）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项从匝道驶入高速公路，应提前开启右转向灯错误； C选项匝道路段可以超车错误； D选项驶入错误的匝道后，可倒车驶回高速公路错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (687, 1, 1, '车辆停稳后，为了避免车辆溜动，应当使用以下哪个装置？', '变速器操纵杆', '节气门操纵杆', '离合器操纵杆', '驻车制动器操作杆', 'D', '本题为单选题，正确答案为D（驻车制动器操作杆）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项变速器操纵杆错误； B选项节气门操纵杆错误； C选项离合器操纵杆错误； 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (688, 1, 1, '申请人办理机动车登记提交的证明、凭证齐全、有效的，公安机关交通管理部门应当（）办理登记手续。', '1周内', '隔天', '1个月内', '当场', 'D', '本题为单选题，正确答案为D（当场）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项1周内错误； B选项隔天错误； C选项1个月内错误； 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (689, 1, 1, '申请机动车注册登记时，以下哪项材料不需要提交？', '身份证明', '购车发票', '交强险证明', '行驶证', 'D', '本题为单选题，正确答案为D（行驶证）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项身份证明错误； B选项购车发票错误； C选项交强险证明错误； 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (690, 1, 1, '未取得机动车驾驶证驾驶机动车，发生负同等以上责任交通事\n故造成人员重伤或者死亡未满多少年的，不得申请机动车驾驶证？', '一年', '三年', '五年', '十年', 'D', '本题为单选题，正确答案为D（十年）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项一年错误； B选项三年错误； C选项五年错误； 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (691, 1, 1, '驾驶机动车在道路上行驶突然熄火，以下错误的做法是什么？', '开危险报警闪光灯', '放置警告标志', '车辆移到安全地点', '立即停车检修', 'D', '本题为单选题，正确答案为D（立即停车检修）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项开危险报警闪光灯错误； B选项放置警告标志错误； C选项车辆移到安全地点错误； 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (692, 1, 1, '驾驶未按规定定期进行安全技术检验的小车，摩托车上道路行驶的，—次记几分？', '1分', '3分', '6分', '9分', 'A', '本题为单选题，正确答案为A（1分）。 其他选项均不符合相关法律法规及安全驾驶要求： B选项3分错误； C选项6分错误； D选项9分错误。 本题考核交通违法行为记分相关规定，需牢记各类违法行为的记分分值，避免违法记分。', NULL, '记分', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (693, 1, 1, '关于分道通行，以下说法错误的是什么？', '机动车、非机动车、行人实行分道通行', '在没有划分车道的道路上通行，机动车在道路右侧通行', '道路划分为机动车道、非机动车道和人行道', '在没有划分车道的道路上通行，非机动车和行人在道路两侧通行', 'B', '本题为单选题，正确答案为B（在没有划分车道的道路上通行，机动车在道路右侧通行）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项机动车、非机动车、行人实行分道通行错误； C选项道路划分为机动车道、非机动车道和人行道错误； D选项在没有划分车道的道路上通行，非机动车和行人在道路两侧通行错误。 本题考核交通违法行为记分相关规定，需牢记各类违法行为的记分分值，避免违法记分。', NULL, '记分', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (694, 1, 1, '驾驶小型汽车的高速公路上行驶超过规定时速的20%未达50%的，一次记多少分？', '2分', '3分', '6分', '12分', 'C', '本题为单选题，正确答案为C（6分）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项2分错误； B选项3分错误； D选项12分错误。 本题考核高速公路行车安全相关规定，需严格遵守高速公路通行规则，确保高速行车安全。', NULL, '高速公路', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (695, 1, 1, '下列交通违法行为，—次记12分的是什么？', '连续驾驶中型以上载客汽车、危险物品运输车超过4小时未停车休息的', '驾驶机动车在高速公路或者城市快速路上违法占用应急车道行驶的', '驾驶机动车在城市快速路上倒车的', '机动车驾驶证被暂扣或者扣留期间驾驶机动车的', 'C', '本题为单选题，正确答案为C（驾驶机动车在城市快速路上倒车的）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项连续驾驶中型以上载客汽车、危险物品运输车超过4小时未停车休息的错误； B选项驾驶机动车在高速公路或者城市快速路上违法占用应急车道行驶的错误； D选项机动车驾驶证被暂扣或者扣留期间驾驶机动车的错误。 本题考核交通违法行为记分相关规定，需牢记各类违法行为的记分分值，避免违法记分。', NULL, '记分', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (696, 1, 1, '下列哪种行为会受到200元以上2000元以下罚款，并处吊销机动车驾驶证？', '违反道路通行规定', '造成交通事故后逃逸', '驾车没带驾驶证', '将机动车交由未取得机动车驾驶证的人驾驶的', 'D', '本题为单选题，正确答案为D（将机动车交由未取得机动车驾驶证的人驾驶的）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项违反道路通行规定错误； B选项造成交通事故后逃逸错误； C选项驾车没带驾驶证错误； 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (697, 1, 1, '机动车驾驶人身体条件发生变化不适合驾驶机动车，仍驾驶机动车的，处多少元罚款？', '20元以上200元以下', '200元以上500元以下', '1000元以上2000元以下', '200元以上1000元以下', 'B', '本题为单选题，正确答案为B（200元以上500元以下）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项20元以上200元以下错误； C选项1000元以上2000元以下错误； D选项200元以上1000元以下错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (698, 1, 1, '驾驶人在实习期内驾驶机动车牵引挂车的，由公安机关交通管理部门处多少元罚款？', '20元以上200元以下', '200元以上500元以下', '500元以上1000元以下', '1000元以上2000元以下', 'A', '本题为单选题，正确答案为A（20元以上200元以下）。 其他选项均不符合相关法律法规及安全驾驶要求： B选项200元以上500元以下错误； C选项500元以上1000元以下错误； D选项1000元以上2000元以下错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (699, 1, 1, '驾驶7座以下载客汽车载人超过核定人数百分之二十以上未达百分之五十的，一次记记分？', '6分', '9分', '3分', '1分', 'C', '本题为单选题，正确答案为C（3分）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项6分错误； B选项9分错误； D选项1分错误。 本题考核交通违法行为记分相关规定，需牢记各类违法行为的记分分值，避免违法记分。', NULL, '记分', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (700, 1, 1, '以下选项中，车辆盲点辅助系统的英文缩写是什么？', 'BSD', 'BSA', 'AEB', 'FCW', 'B', '本题为单选题，正确答案为B（BSA）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项BSD错误； C选项AEB错误； D选项FCW错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (701, 1, 1, '驾驶人有下列哪种违法行为一次记6分？', '造成致人轻伤以上或者死亡的交通事故后逃逸，尚不构成犯罪的', '使用伪造、变造的机动车号牌', '造成致人轻微伤或者财产损失的交通事故后逃逸，尚不构成犯罪 的', '驾驶机动车在高速公路或者城市快速路上不按规定车道行驶的', 'C', '本题为单选题，正确答案为C（造成致人轻微伤或者财产损失的交通事故后逃逸，尚不构成犯罪 的）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项造成致人轻伤以上或者死亡的交通事故后逃逸，尚不构成犯罪的错误； B选项使用伪造、变造的机动车号牌错误； D选项驾驶机动车在高速公路或者城市快速路上不按规定车道行驶的错误。 本题考核交通违法行为记分相关规定，需牢记各类违法行为的记分分值，避免违法记分。', NULL, '记分', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (702, 1, 1, '机动车驾驶人在满分学习考试中弄虚作假的，相应考试成绩无效，并会被处以多少罚款？', '一干元以下', '—干元以上', '二干元以上', '三干元以上', 'A', '本题为单选题，正确答案为A（一干元以下）。 其他选项均不符合相关法律法规及安全驾驶要求： B选项—干元以上错误； C选项二干元以上错误； D选项三干元以上错误。 本题考核交通违法行为记分相关规定，需牢记各类违法行为的记分分值，避免违法记分。', NULL, '记分', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (703, 1, 1, '关于电动汽车的能量回收功能，以下不正确的说法是什么？', '可以省电', '可以节省刹车片', '可以提高刹车效果', '可以当制动使用', 'D', '本题为单选题，正确答案为D（可以当制动使用）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项可以省电错误； B选项可以节省刹车片错误； C选项可以提高刹车效果错误； 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (704, 1, 1, '年龄在70周岁以上的机动车驾驶人发生责任交通事故造成人员重伤或者死亡的，应当在本记分周期结束后多少日内到公安机关交通管理部门接受审验？', '60日', '15日', '10日', '30日', 'D', '本题为单选题，正确答案为D（30日）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项60日错误； B选项15日错误； C选项10日错误； 本题考核交通违法行为记分相关规定，需牢记各类违法行为的记分分值，避免违法记分。', NULL, '记分', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (705, 1, 1, '专属停车位的停车标线应该用什么颜色表示？', '蓝色', '白色', '黄色', '红色', 'C', '本题为单选题，正确答案为C（黄色）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项蓝色错误； B选项白色错误； D选项红色错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (706, 1, 1, '年满20周岁的，不可以申请以下哪种准驾车型？', '大型货车', '大型客车', '中型客车', '城市公交车', 'B', '本题为单选题，正确答案为B（大型客车）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项大型货车错误； C选项中型客车错误； D选项城市公交车错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (707, 1, 1, '非营运小微型载客汽车自注册登记之日起，超过几年的每年检验一次？', '1年', '5年', '8年', '10年', 'D', '本题为单选题，正确答案为D（10年）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项1年错误； B选项5年错误； C选项8年错误； 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (708, 1, 1, '关于驾驶机动车牵引挂车，以下正确的说法是什么？', '低速载货汽车可以牵引挂车', '三轮汽车不得牵引挂车', '载货汽车所牵引挂车的载质量可以超过载货汽车本身的载质量', '半挂牵引车可以牵引2辆挂车', 'B', '本题为单选题，正确答案为B（三轮汽车不得牵引挂车）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项低速载货汽车可以牵引挂车错误； C选项载货汽车所牵引挂车的载质量可以超过载货汽车本身的载质量错误； D选项半挂牵引车可以牵引2辆挂车错误。 本题考核《道路交通安全法》相关规定，需严格遵守法律法规要求，杜绝交通违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (709, 1, 1, '机动车驾驶人在参加接受交通安全教育扣减交通违法行为记分中弄虚作假的，由公安机关交通管理部门撤销相应记分扣减记录，恢复相应记分，处多少元以下罚款？', '一千', '五百', '两千', '三千', 'A', '本题为单选题，正确答案为A（一千）。 其他选项均不符合相关法律法规及安全驾驶要求： B选项五百错误； C选项两千错误； D选项三千错误。 本题考核交通违法行为记分相关规定，需牢记各类违法行为的记分分值，避免违法记分。', NULL, '记分', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (710, 1, 1, '驾驶机动车在城市主干道不按规定掉头的，—次记多少分？', '1分', '3分', '6分', '12分', 'A', '本题为单选题，正确答案为A（1分）。 其他选项均不符合相关法律法规及安全驾驶要求： B选项3分错误； C选项6分错误； D选项12分错误。 本题考核交通违法行为记分相关规定，需牢记各类违法行为的记分分值，避免违法记分。', NULL, '记分', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (711, 1, 1, '在高速公路上车辆发生故障需要停车时，以下做法正确的是什么？', '开启危险报警闪光灯后立即停车', '开启左转向灯行驶至最左侧车道内缓慢停车', '开启右转向灯缓慢行驶至右侧应急车道停车', '紧急制动后立即停车', 'C', '本题为单选题，正确答案为C（开启右转向灯缓慢行驶至右侧应急车道停车）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项开启危险报警闪光灯后立即停车错误； B选项开启左转向灯行驶至最左侧车道内缓慢停车错误； D选项紧急制动后立即停车错误。 本题考核高速公路行车安全相关规定，需严格遵守高速公路通行规则，确保高速行车安全。', NULL, '高速公路', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (712, 4, 2, '右侧标志警告距前方有人看守铁路道口100米。', '正确', '错误', NULL, NULL, 'B', '本题正确答案为B（错误）。\n【考点解析】本题考核道路交通安全的禁止性规定，题目中的做法违反了《中华人民共和国道路交通安全法》及相关实施条例的规定，属于交通违法行为，将面临相应的行政处罚。\n【错误危害】违规驾驶行为会严重破坏正常的道路通行秩序，大幅提升交通事故的发生风险，不仅会对自身的人身、财产安全造成威胁，也会对其他交通参与者的安全造成严重影响。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (713, 4, 2, '右侧标志警告距前方有人看守铁路道口150米。', '正确', '错误', NULL, NULL, 'B', '本题正确答案为B（错误）。\n【考点解析】本题考核道路交通安全的禁止性规定，题目中的做法违反了《中华人民共和国道路交通安全法》及相关实施条例的规定，属于交通违法行为，将面临相应的行政处罚。\n【错误危害】违规驾驶行为会严重破坏正常的道路通行秩序，大幅提升交通事故的发生风险，不仅会对自身的人身、财产安全造成威胁，也会对其他交通参与者的安全造成严重影响。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (714, 4, 2, '右侧标志警告前方150米是无人看守铁路道口。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核道路交通安全的相关法律法规与安全驾驶要求，题目中的做法符合《中华人民共和国道路交通安全法》及相关实施条例的规定，是安全、合规的驾驶行为。\n【安全意义】严格遵守道路交通安全法律法规，规范自身的驾驶行为，是保障行车安全的核心前提，能有效降低交通事故的发生概率，保障自身与他人的人身、财产安全。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (715, 4, 2, '右侧标志提醒前方是非机动车道。', '正确', '错误', NULL, NULL, 'B', '本题正确答案为B（错误）。\n【考点解析】本题考核道路交通安全的禁止性规定，题目中的做法违反了《中华人民共和国道路交通安全法》及相关实施条例的规定，属于交通违法行为，将面临相应的行政处罚。\n【错误危害】违规驾驶行为会严重破坏正常的道路通行秩序，大幅提升交通事故的发生风险，不仅会对自身的人身、财产安全造成威胁，也会对其他交通参与者的安全造成严重影响。', NULL, '文明驾驶', '2026-05-17 15:20:56');
