INSERT INTO `biz_question` VALUES (721, 4, 2, '右侧这个标志警告进入隧道减速慢行。', '正确', '错误', NULL, NULL, 'B', '本题正确答案为B（错误）。\n【考点解析】本题考核道路交通安全的禁止性规定，题目中的做法违反了《中华人民共和国道路交通安全法》及相关实施条例的规定，属于交通违法行为，将面临相应的行政处罚。\n【错误危害】违规驾驶行为会严重破坏正常的道路通行秩序，大幅提升交通事故的发生风险，不仅会对自身的人身、财产安全造成威胁，也会对其他交通参与者的安全造成严重影响。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (722, 4, 2, '左侧标志警告前方注意左侧路口有汇入车辆。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核交通信号灯与路口通行的相关规定。根据《中华人民共和国道路交通安全法》规定，车辆、行人应当按照交通信号通行；遇有交通警察现场指挥时，应当按照交通警察的指挥通行；在没有交通信号的道路上，应当在确保安全、畅通的原则下通行。红灯亮时，禁止车辆通行，车辆应当停在停止线以外，不得越过停止线进入路口。\n【安全意义】交通信号灯是维护路口通行秩序的核心设施，严格按照交通信号通行能有效避免路口的交叉碰撞事故，保障路口的通行安全与效率。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (723, 4, 2, '右侧标志警告前方注意右侧路口有汇入车辆。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核交通信号灯与路口通行的相关规定。根据《中华人民共和国道路交通安全法》规定，车辆、行人应当按照交通信号通行；遇有交通警察现场指挥时，应当按照交通警察的指挥通行；在没有交通信号的道路上，应当在确保安全、畅通的原则下通行。红灯亮时，禁止车辆通行，车辆应当停在停止线以外，不得越过停止线进入路口。\n【安全意义】交通信号灯是维护路口通行秩序的核心设施，严格按照交通信号通行能有效避免路口的交叉碰撞事故，保障路口的通行安全与效率。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (724, 4, 2, '右侧标志提醒前方右侧500米有避险车道。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核道路交通安全的相关法律法规与安全驾驶要求，题目中的做法符合《中华人民共和国道路交通安全法》及相关实施条例的规定，是安全、合规的驾驶行为。\n【安全意义】严格遵守道路交通安全法律法规，规范自身的驾驶行为，是保障行车安全的核心前提，能有效降低交通事故的发生概率，保障自身与他人的人身、财产安全。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (725, 4, 2, '路中黄色斜线填充标记警告前方有固定性障碍物。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核道路交通安全的相关法律法规与安全驾驶要求，题目中的做法符合《中华人民共和国道路交通安全法》及相关实施条例的规定，是安全、合规的驾驶行为。\n【安全意义】严格遵守道路交通安全法律法规，规范自身的驾驶行为，是保障行车安全的核心前提，能有效降低交通事故的发生概率，保障自身与他人的人身、财产安全。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (726, 4, 2, '路面菱形块虚线警告前方道路要减速慢行。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核道路交通安全的相关法律法规与安全驾驶要求，题目中的做法符合《中华人民共和国道路交通安全法》及相关实施条例的规定，是安全、合规的驾驶行为。\n【安全意义】严格遵守道路交通安全法律法规，规范自身的驾驶行为，是保障行车安全的核心前提，能有效降低交通事故的发生概率，保障自身与他人的人身、财产安全。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (727, 4, 2, '路中心黄色实虚线指示允许超车时越过。', '正确', '错误', NULL, NULL, 'B', '本题正确答案为B（错误）。\n【考点解析】本题考核机动车超车的禁止性规定。根据《中华人民共和国道路交通安全法实施条例》规定，机动车在与对面来车有会车可能时、前车正在左转弯、掉头、超车时、行经铁路道口、交叉路口、窄桥、弯道、陡坡、隧道、人行横道、市区交通流量大的路段等没有超车条件的，不得超车。\n【错误危害】违规超车、抢行行为会严重破坏正常的通行秩序，极易与对向车辆、前车发生碰撞，同时也会影响周边车辆的正常行驶，引发大面积的交通拥堵和次生事故。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (728, 4, 2, '路中心黄色虚实线指示允许暂时越过超车。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核机动车超车与让行的相关规定。根据《中华人民共和国道路交通安全法》规定，机动车超车时，应当提前开启左转向灯、变换使用远、近光灯或者鸣喇叭，确认有充足的安全距离后，从前车的左侧超越，在与被超车辆拉开必要的安全距离后，开启右转向灯，驶回原车道；遇前方车辆停车排队等候或者缓慢行驶时，不得借道超车或者占用对面车道，不得穿插等候的车辆。\n【安全意义】规范的超车与让行行为是维护道路通行秩序的核心，能有效避免因强行超车、抢行引发的刮擦、碰撞等交通事故，保障道路通行的安全与顺畅。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (729, 4, 2, '路中心黄色双实线指示可以暂时跨越超车。', '正确', '错误', NULL, NULL, 'B', '本题正确答案为B（错误）。\n【考点解析】本题考核机动车超车的禁止性规定。根据《中华人民共和国道路交通安全法实施条例》规定，机动车在与对面来车有会车可能时、前车正在左转弯、掉头、超车时、行经铁路道口、交叉路口、窄桥、弯道、陡坡、隧道、人行横道、市区交通流量大的路段等没有超车条件的，不得超车。\n【错误危害】违规超车、抢行行为会严重破坏正常的通行秩序，极易与对向车辆、前车发生碰撞，同时也会影响周边车辆的正常行驶，引发大面积的交通拥堵和次生事故。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (730, 4, 2, '黄色斜线填充线指示该区域禁止进入或压线行驶。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核道路交通安全的相关法律法规与安全驾驶要求，题目中的做法符合《中华人民共和国道路交通安全法》及相关实施条例的规定，是安全、合规的驾驶行为。\n【安全意义】严格遵守道路交通安全法律法规，规范自身的驾驶行为，是保障行车安全的核心前提，能有效降低交通事故的发生概率，保障自身与他人的人身、财产安全。', NULL, '文明驾驶', '2026-05-17 15:20:56');
