INSERT INTO `biz_question` VALUES (732, 4, 2, '路面同向车行道分界线指示不允许跨越超车。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核机动车超车与让行的相关规定。根据《中华人民共和国道路交通安全法》规定，机动车超车时，应当提前开启左转向灯、变换使用远、近光灯或者鸣喇叭，确认有充足的安全距离后，从前车的左侧超越，在与被超车辆拉开必要的安全距离后，开启右转向灯，驶回原车道；遇前方车辆停车排队等候或者缓慢行驶时，不得借道超车或者占用对面车道，不得穿插等候的车辆。\n【安全意义】规范的超车与让行行为是维护道路通行秩序的核心，能有效避免因强行超车、抢行引发的刮擦、碰撞等交通事故，保障道路通行的安全与顺畅。', NULL, '文明驾驶', '2026-05-17 15:20:56');
