INSERT INTO `biz_question` VALUES (734, 4, 2, '路缘石的黄色实线指示路边允许临时停、放车辆。', '正确', '错误', NULL, NULL, 'B', '本题正确答案为B（错误）。\n【考点解析】本题考核道路交通安全的禁止性规定，题目中的做法违反了《中华人民共和国道路交通安全法》及相关实施条例的规定，属于交通违法行为，将面临相应的行政处罚。\n【错误危害】违规驾驶行为会严重破坏正常的道路通行秩序，大幅提升交通事故的发生风险，不仅会对自身的人身、财产安全造成威胁，也会对其他交通参与者的安全造成严重影响。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (735, 4, 2, '前方路口停车让行线表示减速让干道车先行。', '正确', '错误', NULL, NULL, 'B', '本题正确答案为B（错误）。\n【考点解析】本题考核机动车超车的禁止性规定。根据《中华人民共和国道路交通安全法实施条例》规定，机动车在与对面来车有会车可能时、前车正在左转弯、掉头、超车时、行经铁路道口、交叉路口、窄桥、弯道、陡坡、隧道、人行横道、市区交通流量大的路段等没有超车条件的，不得超车。\n【错误危害】违规超车、抢行行为会严重破坏正常的通行秩序，极易与对向车辆、前车发生碰撞，同时也会影响周边车辆的正常行驶，引发大面积的交通拥堵和次生事故。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (736, 4, 2, '前方路口减速让行线表示要停车让干道车先行。', '正确', '错误', NULL, NULL, 'B', '本题正确答案为B（错误）。\n【考点解析】本题考核机动车超车的禁止性规定。根据《中华人民共和国道路交通安全法实施条例》规定，机动车在与对面来车有会车可能时、前车正在左转弯、掉头、超车时、行经铁路道口、交叉路口、窄桥、弯道、陡坡、隧道、人行横道、市区交通流量大的路段等没有超车条件的，不得超车。\n【错误危害】违规超车、抢行行为会严重破坏正常的通行秩序，极易与对向车辆、前车发生碰撞，同时也会影响周边车辆的正常行驶，引发大面积的交通拥堵和次生事故。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (737, 4, 2, '路口两侧导流线表示直行或右转弯不得压线或越线行驶。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核交通信号灯与路口通行的相关规定。根据《中华人民共和国道路交通安全法》规定，车辆、行人应当按照交通信号通行；遇有交通警察现场指挥时，应当按照交通警察的指挥通行；在没有交通信号的道路上，应当在确保安全、畅通的原则下通行。红灯亮时，禁止车辆通行，车辆应当停在停止线以外，不得越过停止线进入路口。\n【安全意义】交通信号灯是维护路口通行秩序的核心设施，严格按照交通信号通行能有效避免路口的交叉碰撞事故，保障路口的通行安全与效率。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (738, 4, 2, '路口内中心圈标示左小转弯要沿内侧行驶。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核交通信号灯与路口通行的相关规定。根据《中华人民共和国道路交通安全法》规定，车辆、行人应当按照交通信号通行；遇有交通警察现场指挥时，应当按照交通警察的指挥通行；在没有交通信号的道路上，应当在确保安全、畅通的原则下通行。红灯亮时，禁止车辆通行，车辆应当停在停止线以外，不得越过停止线进入路口。\n【安全意义】交通信号灯是维护路口通行秩序的核心设施，严格按照交通信号通行能有效避免路口的交叉碰撞事故，保障路口的通行安全与效率。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (739, 4, 2, '路面网状线标示允许进入该区域内等待。', '正确', '错误', NULL, NULL, 'B', '本题正确答案为B（错误）。\n【考点解析】本题考核道路交通安全的禁止性规定，题目中的做法违反了《中华人民共和国道路交通安全法》及相关实施条例的规定，属于交通违法行为，将面临相应的行政处罚。\n【错误危害】违规驾驶行为会严重破坏正常的道路通行秩序，大幅提升交通事故的发生风险，不仅会对自身的人身、财产安全造成威胁，也会对其他交通参与者的安全造成严重影响。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (740, 4, 2, '路面网状线标示不准进入该区域内停车等待。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核道路交通安全的相关法律法规与安全驾驶要求，题目中的做法符合《中华人民共和国道路交通安全法》及相关实施条例的规定，是安全、合规的驾驶行为。\n【安全意义】严格遵守道路交通安全法律法规，规范自身的驾驶行为，是保障行车安全的核心前提，能有效降低交通事故的发生概率，保障自身与他人的人身、财产安全。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (741, 4, 2, '右侧车道路面标线表示可以临时借公交专用车道行驶。', '正确', '错误', NULL, NULL, 'B', '本题正确答案为B（错误）。\n【考点解析】本题考核道路交通安全的禁止性规定，题目中的做法违反了《中华人民共和国道路交通安全法》及相关实施条例的规定，属于交通违法行为，将面临相应的行政处罚。\n【错误危害】违规驾驶行为会严重破坏正常的道路通行秩序，大幅提升交通事故的发生风险，不仅会对自身的人身、财产安全造成威胁，也会对其他交通参与者的安全造成严重影响。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (742, 4, 2, '路面标记指示前方路口禁止车辆掉头。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核交通信号灯与路口通行的相关规定。根据《中华人民共和国道路交通安全法》规定，车辆、行人应当按照交通信号通行；遇有交通警察现场指挥时，应当按照交通警察的指挥通行；在没有交通信号的道路上，应当在确保安全、畅通的原则下通行。红灯亮时，禁止车辆通行，车辆应当停在停止线以外，不得越过停止线进入路口。\n【安全意义】交通信号灯是维护路口通行秩序的核心设施，严格按照交通信号通行能有效避免路口的交叉碰撞事故，保障路口的通行安全与效率。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (743, 4, 2, '路面标记指示前方路口仅允许车辆向右转弯。', '正确', '错误', NULL, NULL, 'B', '本题正确答案为B（错误）。\n【考点解析】本题考核交通信号灯的强制性规定。根据《中华人民共和国道路交通安全法》规定，车辆、行人必须严格按照交通信号通行，红灯亮时，禁止车辆越过停止线进入路口，即使路口内没有其他车辆、行人，也不得违规通行。\n【错误危害】闯红灯、违规进入路口的行为会严重破坏路口的通行秩序，极易与横向正常通行的车辆、行人发生碰撞，造成严重的交通事故，同时也会引发路口的交通拥堵，影响整体的通行效率。', NULL, '文明驾驶', '2026-05-17 15:20:56');
