INSERT INTO `biz_question` VALUES (767, 4, 2, '驾驶机动车在这种情况下不能直行和左转弯', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核道路交通安全的相关法律法规与安全驾驶要求，题目中的做法符合《中华人民共和国道路交通安全法》及相关实施条例的规定，是安全、合规的驾驶行为。\n【安全意义】严格遵守道路交通安全法律法规，规范自身的驾驶行为，是保障行车安全的核心前提，能有效降低交通事故的发生概率，保障自身与他人的人身、财产安全。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (768, 4, 2, '驾驶机动车遇到校车在道路右侧停车上下学生，同向有两条机动车道时，左侧车道后方机动车应当停车等待。', '正确', '错误', NULL, NULL, 'A', '本题正确答案为A（正确）。\n【考点解析】本题考核道路交通安全的相关法律法规与安全驾驶要求，题目中的做法符合《中华人民共和国道路交通安全法》及相关实施条例的规定，是安全、合规的驾驶行为。\n【安全意义】严格遵守道路交通安全法律法规，规范自身的驾驶行为，是保障行车安全的核心前提，能有效降低交通事故的发生概率，保障自身与他人的人身、财产安全。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (769, 4, 2, '驾驶机动车在这种情况下要跟前车进入路口等待。', '正确', '错误', NULL, NULL, 'B', '本题正确答案为B（错误）。\n【考点解析】本题考核交通信号灯的强制性规定。根据《中华人民共和国道路交通安全法》规定，车辆、行人必须严格按照交通信号通行，红灯亮时，禁止车辆越过停止线进入路口，即使路口内没有其他车辆、行人，也不得违规通行。\n【错误危害】闯红灯、违规进入路口的行为会严重破坏路口的通行秩序，极易与横向正常通行的车辆、行人发生碰撞，造成严重的交通事故，同时也会引发路口的交通拥堵，影响整体的通行效率。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (770, 4, 2, '驾驶机动车在遇到有前方机动车停车排队等候或者缓慢行驶时，可进入网状线区域停车等候。', '正确', '错误', NULL, NULL, 'B', '本题正确答案为B（错误）。\n【考点解析】本题考核道路交通安全的禁止性规定，题目中的做法违反了《中华人民共和国道路交通安全法》及相关实施条例的规定，属于交通违法行为，将面临相应的行政处罚。\n【错误危害】违规驾驶行为会严重破坏正常的道路通行秩序，大幅提升交通事故的发生风险，不仅会对自身的人身、财产安全造成威胁，也会对其他交通参与者的安全造成严重影响。', NULL, '文明驾驶', '2026-05-17 15:20:56');
