INSERT INTO `biz_question` VALUES (772, 4, 2, '如动画所示，驾驶人的行为是否正确？', '正确', '错误', NULL, NULL, 'B', '本题正确答案为B（错误）。\n【考点解析】本题考核道路交通安全的禁止性规定，题目中的做法违反了《中华人民共和国道路交通安全法》及相关实施条例的规定，属于交通违法行为，将面临相应的行政处罚。\n【错误危害】违规驾驶行为会严重破坏正常的道路通行秩序，大幅提升交通事故的发生风险，不仅会对自身的人身、财产安全造成威胁，也会对其他交通参与者的安全造成严重影响。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (773, 4, 3, '8毫克/百毫升。林某的主要违法行为是什么？', '醉酒驾驶', '超速驾驶', '疲劳驾驶', '肇事逃逸', 'ABD', '本题为多选题，正确答案为ABD。 正确选项符合相关法律法规及安全驾驶要求： A选项醉酒驾驶正确； B选项超速驾驶正确； D选项肇事逃逸正确。 其他选项均不符合相关要求： C选项疲劳驾驶错误； 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、全面规避行车风险。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (774, 4, 1, '5米的陡坎下，造成13人死亡、9人受伤。冉某的主要违法行为是什么？', '超速行驶', '不按交通标线行驶', '客车超员', '疲劳驾驶', 'D', '本题为单选题，正确答案为D（疲劳驾驶）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项超速行驶错误； B选项不按交通标线行驶错误； C选项客车超员错误； 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、安全驾驶。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (775, 4, 3, '2吨）侧面相撞，造成12人死亡、17人受伤。此事故中的主要违法行为是什么？', '客车超员', '客车超速行驶', '货车超载', '货车驾驶人经验不足', 'BC', '本题为多选题，正确答案为BC。 正确选项符合相关法律法规及安全驾驶要求： B选项客车超速行驶正确； C选项货车超载正确； 其他选项均不符合相关要求： A选项客车超员错误； D选项货车驾驶人经验不足错误。 本题为驾考核心考点，需全面牢记相关规则，严格遵守交通法规，确保行车安全。', NULL, '事故处理', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (776, 4, 3, '7吨货物（核载25吨），行至大广高速公路一下坡路段，追尾碰撞一辆由李某驾驶在应急车道内行驶的重型自卸货车（货箱内装载3.17立方黄土并搭乘24人），造成16人死亡、13人受伤。此事故中的主要违法行为是什么？', '彭某超速行驶', '彭某驾驶机动车超载', '李某在应急车道内行驶', '李某货车车厢内违法载人', 'BCD', '本题为多选题，正确答案为BCD。 正确选项符合相关法律法规及安全驾驶要求： B选项彭某驾驶机动车超载正确； C选项李某在应急车道内行驶正确； D选项李某货车车厢内违法载人正确。 其他选项均不符合相关要求： A选项彭某超速行驶错误； 本题考核高速公路行车安全相关规定，需严格遵守高速公路通行规则，全面保障高速行车安全。', NULL, '高速公路', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (777, 4, 3, '05吨货物（核载1.2吨），行驶至宁津县境内314省道51公里加260米处，在越过道路中心线超越前方同向行驶的机动车时，与对向正常行驶的中型客车（乘载12人，核载11人）正面相撞，造成10人死亡、2人受伤。此事故中的违法行为是什么？', '货车超载', '货车违法超车', '客车超员', '客车驾驶人疲劳驾驶', 'ABC', '本题为多选题，正确答案为ABC。 正确选项符合相关法律法规及安全驾驶要求： A选项货车超载正确； B选项货车违法超车正确； C选项客车超员正确； 其他选项均不符合相关要求： D选项客车驾驶人疲劳驾驶错误。 本题为驾考核心考点，需全面牢记相关规则，严格遵守交通法规，确保行车安全。', NULL, '事故处理', '2026-05-17 15:20:56');
