INSERT INTO `biz_question` VALUES (798, 4, 1, '驾驶机动车遇到这种情况怎样应对？', '连续鸣喇叭警告', '加速从前方绕过', '出现危险再减速', '主动减速让行', 'D', '本题为单选题，正确答案为D（主动减速让行）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项连续鸣喇叭警告错误； B选项加速从前方绕过错误； C选项出现危险再减速错误； 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、安全驾驶。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (799, 4, 1, '机动车在道路上行驶时，属于交通陋习的是什么行为？', '按规定使用灯光', '带行驶证、驾驶证', '随意向车外抛洒物品', '遵守交通信号', 'C', '本题为单选题，正确答案为C（随意向车外抛洒物品）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项按规定使用灯光错误； B选项带行驶证、驾驶证错误； D选项遵守交通信号错误。 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、安全驾驶。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (800, 4, 1, '驾驶人边驾车边吸烟的做法有什么影响？', '妨碍安全驾驶', '可提高注意力', '可缓解驾驶疲劳', '不影响驾驶操作', 'A', '本题为单选题，正确答案为A（妨碍安全驾驶）。 其他选项均不符合相关法律法规及安全驾驶要求： B选项可提高注意力错误； C选项可缓解驾驶疲劳错误； D选项不影响驾驶操作错误。 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、安全驾驶。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (801, 4, 1, '驾驶机动车，遇前方停驶的油料运输车起火冒烟，以下做法正确的是什么？', '为减少交会时间，加速通过', '停车后围观', '立即停车，尽量远离，拨打报警电话', '立即停车，上前查看是否有被困人员', 'C', '本题为单选题，正确答案为C（立即停车，尽量远离，拨打报警电话）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项为减少交会时间，加速通过错误； B选项停车后围观错误； D选项立即停车，上前查看是否有被困人员错误。 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、安全驾驶。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (802, 4, 1, '当你看到前方车辆行驶线路左右摆动，以下说法正确的是什么?', '此情况较为安全，可以紧密跟随', '车内驾驶人可能为酒后驾车，可以加速超过', '车内驾驶人可能为吸毒后驾车，可以加速超过', '车内驾驶人可能为酒后驾车，应当保持距离', 'D', '本题为单选题，正确答案为D（车内驾驶人可能为酒后驾车，应当保持距离）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项此情况较为安全，可以紧密跟随错误； B选项车内驾驶人可能为酒后驾车，可以加速超过错误； C选项车内驾驶人可能为吸毒后驾车，可以加速超过错误； 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、安全驾驶。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (803, 4, 1, '行车中遇抢救伤员的救护车从本车道逆向驶来时，要怎样做？', '靠边减速或停车让行', '占用其他车道行驶', '加速变更车道避让', '在原车道内继续行驶', 'A', '本题为单选题，正确答案为A（靠边减速或停车让行）。 其他选项均不符合相关法律法规及安全驾驶要求： B选项占用其他车道行驶错误； C选项加速变更车道避让错误； D选项在原车道内继续行驶错误。 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、安全驾驶。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (804, 4, 1, '驾驶机动车在交叉路口遇到这种情况如何对待？', '直接进入路口内等待', '在路口停止线外等待', '从右侧非机动车道通过', '借对向车道通过路口', 'B', '本题为单选题，正确答案为B（在路口停止线外等待）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项直接进入路口内等待错误； C选项从右侧非机动车道通过错误； D选项借对向车道通过路口错误。 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、安全驾驶。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (805, 4, 1, '驾驶机动车在拥堵的路口遇到这种情况怎样处置？', '逼其回原车道', '紧跟前车不让行', '礼让通行', '鸣喇叭开前照灯', 'C', '本题为单选题，正确答案为C（礼让通行）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项逼其回原车道错误； B选项紧跟前车不让行错误； D选项鸣喇叭开前照灯错误。 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、安全驾驶。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (806, 4, 1, '如动画所示，驾驶人应当怎样做？', '寻找机会超越前车', '从机动车空间穿插通过', '减速停车，依次排队等候', '鸣喇叭催促', 'C', '本题为单选题，正确答案为C（减速停车，依次排队等候）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项寻找机会超越前车错误； B选项从机动车空间穿插通过错误； D选项鸣喇叭催促错误。 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、安全驾驶。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (807, 4, 3, '关于超车，以下说法正确的是什么?', '完成超车后并回行车道要开启右转向灯', '切换远、近光灯提醒前方被超车辆驾驶人', '超车前提前开启左转向灯，提醒前方被超车辆驾驶人', '长时间鸣喇叭警示被超车辆驾驶人', 'ABC', '本题为多选题，正确答案为ABC。 正确选项符合相关法律法规及安全驾驶要求： A选项完成超车后并回行车道要开启右转向灯正确； B选项切换远、近光灯提醒前方被超车辆驾驶人正确； C选项超车前提前开启左转向灯，提醒前方被超车辆驾驶人正确； 其他选项均不符合相关要求： D选项长时间鸣喇叭警示被超车辆驾驶人错误。 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、全面规避行车风险。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (808, 4, 1, '驾驶机动车在雨天遇到撑雨伞和穿雨衣的行人在路边行走怎样礼让？', '以正常速度行驶', '临近鸣喇叭示意', '加速从左侧绕行', '提前减速鸣喇叭', 'D', '本题为单选题，正确答案为D（提前减速鸣喇叭）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项以正常速度行驶错误； B选项临近鸣喇叭示意错误； C选项加速从左侧绕行错误； 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、安全驾驶。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (809, 4, 3, '交通技术监控设备记录或者录入道路交通违法信息管理系统的违法行为信息，有下列情形之一并经核实的，应当予以消除？', '因交通信号指示不一致造成的', '有证据证明救助危难或者紧急避险造成的', '机动车被盗抢期间发生的', '因使用伪造、变造或者其他机动车号牌发生违法行为造成合法机动车被记录的', 'ABCD', '本题为多选题，正确答案为ABCD。 正确选项符合相关法律法规及安全驾驶要求： A选项因交通信号指示不一致造成的正确； B选项有证据证明救助危难或者紧急避险造成的正确； C选项机动车被盗抢期间发生的正确； D选项因使用伪造、变造或者其他机动车号牌发生违法行为造成合法机动车被记录的正确。 其他选项均不符合相关要求： 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、全面规避行车风险。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (810, 4, 3, '当出现下列哪种情形时，保险公司不承担赔偿责任？', '驾驶人未取得驾驶资格证或者醉酒的', '被保险人机动车被盗抢期间肇事的', '被保险人故意制造道路交通事故的', '因驾驶技术不娴熟造成事故的', 'ABC', '本题为多选题，正确答案为ABC。 正确选项符合相关法律法规及安全驾驶要求： A选项驾驶人未取得驾驶资格证或者醉酒的正确； B选项被保险人机动车被盗抢期间肇事的正确； C选项被保险人故意制造道路交通事故的正确； 其他选项均不符合相关要求： D选项因驾驶技术不娴熟造成事故的错误。 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、全面规避行车风险。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (811, 4, 3, '行车中看到前方车辆行驶线路左右摆动，以下说法错误的是什么？', '车内驾驶人可能为酒后驾车，应当保持距离', '车内驾驶人可能为酒后驾车，可以加速\n超过', '车内驾驶人可能为吸毒后驾车，可以加\n速超过', '此情况较为安全，可以紧密跟随', 'BCD', '本题为多选题，正确答案为BCD。 正确选项符合相关法律法规及安全驾驶要求： B选项车内驾驶人可能为酒后驾车，可以加速\n超过正确； C选项车内驾驶人可能为吸毒后驾车，可以加\n速超过正确； D选项此情况较为安全，可以紧密跟随正确。 其他选项均不符合相关要求： A选项车内驾驶人可能为酒后驾车，应当保持距离错误； 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、全面规避行车风险。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (812, 4, 3, '行车中突遇对方车辆强行超车，占据自己车道，不利于安全行车的做法是什么？', '超速行驶', '尽量减速避让、直至停车', '保持原车速行驶', '挡住其去路', 'ACD', '本题为多选题，正确答案为ACD。 正确选项符合相关法律法规及安全驾驶要求： A选项超速行驶正确； C选项保持原车速行驶正确； D选项挡住其去路正确。 其他选项均不符合相关要求： B选项尽量减速避让、直至停车错误； 本题为驾考核心考点，需全面牢记相关规则，严格遵守交通法规，确保行车安全。', NULL, '安全行车', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (813, 4, 1, '按照防御性驾驶技术要求，驾驶机动车在道路上行驶，在下列哪种情形下应当提前开启右转向灯？', '向右转弯', '靠路边停车', '向右变更车道', '超车完毕驶回原车道', 'A', '本题为单选题，正确答案为A（向右转弯）。 其他选项均不符合相关法律法规及安全驾驶要求： B选项靠路边停车错误； C选项向右变更车道错误； D选项超车完毕驶回原车道错误。 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、安全驾驶。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (814, 4, 1, '驾驶人分心驾驶的危害是什么？', '驾驶人注意力分散', '视线离开路面，无法提前观察道路交通信息', '会引起驾驶姿势的变化', '会引起操作动作的变化', 'A', '本题为单选题，正确答案为A（驾驶人注意力分散）。 其他选项均不符合相关法律法规及安全驾驶要求： B选项视线离开路面，无法提前观察道路交通信息错误； C选项会引起驾驶姿势的变化错误； D选项会引起操作动作的变化错误。 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、安全驾驶。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (815, 4, 1, '会车前选择的交会位置不理想时，错误的做法是？', '减速、低速会车或停车让行', '向左占道，让对方减速让行', '打开前照灯，示意对方停车让行', '加速选择理想位置', 'B', '本题为单选题，正确答案为B（向左占道，让对方减速让行）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项减速、低速会车或停车让行错误； C选项打开前照灯，示意对方停车让行错误； D选项加速选择理想位置错误。 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、安全驾驶。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (816, 4, 1, '驾驶机动车在距离加油站、消防栓前多少米以内的路段不得停车？', '30米', '50米', '80米', '100米', 'A', '本题为单选题，正确答案为A（30米）。 其他选项均不符合相关法律法规及安全驾驶要求： B选项50米错误； C选项80米错误； D选项100米错误。 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、安全驾驶。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (817, 4, 1, '驾驶机动车距离窄桥多少米内不得停车？', '30米', '50米', '80米', '100米', 'B', '本题为单选题，正确答案为B（50米）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项30米错误； C选项80米错误； D选项100米错误。 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、安全驾驶。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (818, 4, 1, '驾驶机动车在高速公路上遇前方车流缓行时，以下做法正确的是什么？', '跟随车流行驶，保持安全车距', '进入应急车道行驶', '可以倒车', '持续鸣喇叭', 'A', '本题为单选题，正确答案为A（跟随车流行驶，保持安全车距）。 其他选项均不符合相关法律法规及安全驾驶要求： B选项进入应急车道行驶错误； C选项可以倒车错误； D选项持续鸣喇叭错误。 本题考核高速公路行车安全相关规定，需严格遵守高速公路通行规则，确保高速行车安全。', NULL, '高速公路', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (819, 4, 1, '驾驶机动车前要对车辆座椅进行调整，以下说法正确的是什么？', '调整驾驶座椅，保证踩踏踏板舒适', '调整安全带的松紧与高低', '调整适合驾驶的方向盘位置', '调整安全头枕高度，使头枕正对驾驶人的颈椎', 'A', '本题为单选题，正确答案为A（调整驾驶座椅，保证踩踏踏板舒适）。 其他选项均不符合相关法律法规及安全驾驶要求： B选项调整安全带的松紧与高低错误； C选项调整适合驾驶的方向盘位置错误； D选项调整安全头枕高度，使头枕正对驾驶人的颈椎错误。 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、安全驾驶。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (820, 4, 1, '不同疲劳程度下驾驶人的状态和表现不同，轻微疲劳的表现是什么？', '频打哈欠', '眼皮沉重', '忘记操作', '短时间睡眠现象', 'A', '本题为单选题，正确答案为A（频打哈欠）。 其他选项均不符合相关法律法规及安全驾驶要求： B选项眼皮沉重错误； C选项忘记操作错误； D选项短时间睡眠现象错误。 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、安全驾驶。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (821, 4, 1, '不同疲劳程度下驾驶人的状态和表现不同，中度疲劳的表现是什么？', '频打哈欠', '眼皮沉重', '忘记操作', '短时间睡眠现象', 'C', '本题为单选题，正确答案为C（忘记操作）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项频打哈欠错误； B选项眼皮沉重错误； D选项短时间睡眠现象错误。 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、安全驾驶。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (822, 4, 1, '下列属于预防疲劳驾驶的措施有哪些？', '—天行车时间不超过8小时', '连续驾驶不得超过4小时', '深夜行车不得连续超过2天', '注意劳逸结合，保证充足睡眠', 'A', '本题为单选题，正确答案为A（—天行车时间不超过8小时）。 其他选项均不符合相关法律法规及安全驾驶要求： B选项连续驾驶不得超过4小时错误； C选项深夜行车不得连续超过2天错误； D选项注意劳逸结合，保证充足睡眠错误。 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、安全驾驶。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (823, 4, 1, '不同疲劳程度下驾驶人的状态和表现不同，重度疲劳的表现是什么？', '频打哈欠', '眼皮沉重', '忘记操作', '短时间睡眠现象', 'D', '本题为单选题，正确答案为D（短时间睡眠现象）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项频打哈欠错误； B选项眼皮沉重错误； C选项忘记操作错误； 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、安全驾驶。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (824, 4, 1, '驾驶机动车临近高速公路出入口时，驾驶人需要注意什么？', '低速行驶的车辆', '突然变更车道的车辆', '紧急制动的车辆', '掉头或逆行的车辆', 'A', '本题为单选题，正确答案为A（低速行驶的车辆）。 其他选项均不符合相关法律法规及安全驾驶要求： B选项突然变更车道的车辆错误； C选项紧急制动的车辆错误； D选项掉头或逆行的车辆错误。 本题考核高速公路行车安全相关规定，需严格遵守高速公路通行规则，确保高速行车安全。', NULL, '高速公路', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (825, 4, 1, '驾驶机动车遇乘客干扰驾驶时，以下做法正确的是什么？', '紧急制动', '据理力争', '直接打开车门让该乘客下车', '保证安全靠边停车、及时报警', 'D', '本题为单选题，正确答案为D（保证安全靠边停车、及时报警）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项紧急制动错误； B选项据理力争错误； C选项直接打开车门让该乘客下车错误； 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、安全驾驶。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (826, 4, 3, '吸食注射毒品对驾驶行为的影晌主要表现有什么？', '毒品对人体中枢神经产生作用，吸毒以后会产生幻觉', '吸毒后驾驶，驾驶人的身体协调能力明显下降', '可能会有情绪上的亢奋，影晌驾驶人交通状况的观察感知', '吸毒后驾驶，驾驶人的反应力明显下降', 'ABCD', '本题为多选题，正确答案为ABCD。 正确选项符合相关法律法规及安全驾驶要求： A选项毒品对人体中枢神经产生作用，吸毒以后会产生幻觉正确； B选项吸毒后驾驶，驾驶人的身体协调能力明显下降正确； C选项可能会有情绪上的亢奋，影晌驾驶人交通状况的观察感知正确； D选项吸毒后驾驶，驾驶人的反应力明显下降正确。 其他选项均不符合相关要求： 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、全面规避行车风险。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (827, 4, 1, '在雨天哪类路面最容易发生侧滑？', '刚下雨的路面', '大雨过后路面', '暴雨中的路面', '大雨中的路面', 'A', '本题为单选题，正确答案为A（刚下雨的路面）。 其他选项均不符合相关法律法规及安全驾驶要求： B选项大雨过后路面错误； C选项暴雨中的路面错误； D选项大雨中的路面错误。 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、安全驾驶。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (828, 4, 3, '雨天影响安全行车的主要因素有哪些？', '视线受阻', '路面湿滑', '附着力变小', '行驶阻力增大', 'ABC', '本题为多选题，正确答案为ABC。 正确选项符合相关法律法规及安全驾驶要求： A选项视线受阻正确； B选项路面湿滑正确； C选项附着力变小正确； 其他选项均不符合相关要求： D选项行驶阻力增大错误。 本题为驾考核心考点，需全面牢记相关规则，严格遵守交通法规，确保行车安全。', NULL, '安全行车', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (829, 4, 3, '雨天遇到这种行人占道行走时怎样通行？', '提前减速行驶', '提前鸣喇叭提醒', '不得急加速绕行', '保持安全间距', 'ABCD', '本题为多选题，正确答案为ABCD。 正确选项符合相关法律法规及安全驾驶要求： A选项提前减速行驶正确； B选项提前鸣喇叭提醒正确； C选项不得急加速绕行正确； D选项保持安全间距正确。 其他选项均不符合相关要求： 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、全面规避行车风险。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (830, 4, 1, '在普通道路驾车遇暴雨，刮水器无法改善驾驶人视线，此时要采取的措施是：', '减速行驶', '集中注意力谨滇驾驶', '立即减速靠边停驶', '以正常速度行驶', 'C', '本题为单选题，正确答案为C（立即减速靠边停驶）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项减速行驶错误； B选项集中注意力谨滇驾驶错误； D选项以正常速度行驶错误。 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、安全驾驶。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (831, 4, 1, '最容易发生侧滑的路面是：', '干燥水泥路面', '下雨开始时的路面', '潮湿水泥路面', '大雨中的路面', 'B', '本题为单选题，正确答案为B（下雨开始时的路面）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项干燥水泥路面错误； C选项潮湿水泥路面错误； D选项大雨中的路面错误。 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、安全驾驶。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (832, 4, 1, '驾驶机动车在雨天临时停车注意什么？', '开启危险报警闪光灯', '开启前后雾灯', '开启近光灯', '在车后设置警告标志', 'A', '本题为单选题，正确答案为A（开启危险报警闪光灯）。 其他选项均不符合相关法律法规及安全驾驶要求： B选项开启前后雾灯错误； C选项开启近光灯错误； D选项在车后设置警告标志错误。 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、安全驾驶。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (833, 4, 1, '当机动车在湿滑路面上行驶时， 路面附着力随着车速的增加如何变化？', '急剧增大', '逐渐增大', '急剧减小', '没有变化', 'C', '本题为单选题，正确答案为C（急剧减小）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项急剧增大错误； B选项逐渐增大错误； D选项没有变化错误。 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、安全驾驶。', NULL, '文明驾驶', '2026-05-17 15:20:56');
