INSERT INTO `biz_question` VALUES (865, 4, 1, '驾驶汽车在进出隧道时应注意什么？', '开启远光灯', '适当提高车速', '关闭近光灯', '提前降低车速', 'D', '本题为单选题，正确答案为D（提前降低车速）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项开启远光灯错误； B选项适当提高车速错误； C选项关闭近光灯错误； 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、安全驾驶。', NULL, '文明驾驶', '2026-05-17 15:20:56');
