INSERT INTO `biz_question` VALUES (885, 4, 1, '机动车上高速公路，以下哪种说法是正确的？', '可在匝道、加速车道、减速车道上超车', '不准倒车、逆行、穿越中央分隔带掉头', '非紧急情况时可在应急车道行驶', '可以试车或学习驾驶', 'B', '本题为单选题，正确答案为B（不准倒车、逆行、穿越中央分隔带掉头）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项可在匝道、加速车道、减速车道上超车错误； C选项非紧急情况时可在应急车道行驶错误； D选项可以试车或学习驾驶错误。 本题考核高速公路行车安全相关规定，需严格遵守高速公路通行规则，确保高速行车安全。', NULL, '高速公路', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (886, 4, 1, '机动车上高速公路，以下哪种说法是错误的？', '不可骑、轧车道分界线行驶', '不可在路肩上行驶', '可以在匝道、加速车道或者减速车道上超车', '不可学习驾驶', 'C', '本题为单选题，正确答案为C（可以在匝道、加速车道或者减速车道上超车）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项不可骑、轧车道分界线行驶错误； B选项不可在路肩上行驶错误； D选项不可学习驾驶错误。 本题考核高速公路行车安全相关规定，需严格遵守高速公路通行规则，确保高速行车安全。', NULL, '高速公路', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (887, 4, 3, '以下关于驶离高速公路的做法正确的是什么？', '提前开启右转向灯', '驶入减速车道', '按减速车道规定的时速行驶', '加速直接驶离高速公路', 'ABC', '本题为多选题，正确答案为ABC。 正确选项符合相关法律法规及安全驾驶要求： A选项提前开启右转向灯正确； B选项驶入减速车道正确； C选项按减速车道规定的时速行驶正确； 其他选项均不符合相关要求： D选项加速直接驶离高速公路错误。 本题考核高速公路行车安全相关规定，需严格遵守高速公路通行规则，全面保障高速行车安全。', NULL, '高速公路', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (888, 4, 1, '机动车在高速公路行驶，以下哪种说法是正确的？', '可在应急车道停车上下人员', '可在紧急停车带停车装卸货物', '可在减速或加速车道上超车、停车', '非紧急情况时不得在应急车道行驶或者停车', 'D', '本题为单选题，正确答案为D（非紧急情况时不得在应急车道行驶或者停车）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项可在应急车道停车上下人员错误； B选项可在紧急停车带停车装卸货物错误； C选项可在减速或加速车道上超车、停车错误； 本题考核高速公路行车安全相关规定，需严格遵守高速公路通行规则，确保高速行车安全。', NULL, '高速公路', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (889, 4, 1, '发生紧急故障必须停车检查时，要在什么地方停车？', '最外侧行车道上', '内侧行车道上', '应急车道', '匝道口', 'C', '本题为单选题，正确答案为C（应急车道）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项最外侧行车道上错误； B选项内侧行车道上错误； D选项匝道口错误。 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、安全驾驶。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (890, 4, 1, '机动车因故障或者事故在高速公路行车道上紧急停车时，驾乘人员怎么办？', '站在机动车前方', '留在车上等待救援', '站在机动车后方', '迅速转移至右侧路肩上或应急车道内', 'D', '本题为单选题，正确答案为D（迅速转移至右侧路肩上或应急车道内）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项站在机动车前方错误； B选项留在车上等待救援错误； C选项站在机动车后方错误； 本题考核高速公路行车安全相关规定，需严格遵守高速公路通行规则，确保高速行车安全。', NULL, '高速公路', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (891, 4, 1, '夜间会车前，两车在相距150米之外交替变换前照灯远近光的作用是什么？', '会车前两车之间相互提示', '驾驶操作的习惯行为', '便于双方观察前方情况', '驾驶人之间的一种礼节', 'C', '本题为单选题，正确答案为C（便于双方观察前方情况）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项会车前两车之间相互提示错误； B选项驾驶操作的习惯行为错误； D选项驾驶人之间的一种礼节错误。 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、安全驾驶。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (892, 4, 3, '驾驶机动车在长距离隧道群路段行驶时，影晌安全驾驶的因素有哪些？', '在单—的环境下长时间驾驶会对速度变化产生错觉，易超速行驶', '驾驶环境单—，长时间易出现视觉疲劳', '环境狭窄密封，驾驶人易产生急躁情绪', '通风不良导致驾驶人疲劳，容易反应迟缓', 'ABCD', '本题为多选题，正确答案为ABCD。 正确选项符合相关法律法规及安全驾驶要求： A选项在单—的环境下长时间驾驶会对速度变化产生错觉，易超速行驶正确； B选项驾驶环境单—，长时间易出现视觉疲劳正确； C选项环境狭窄密封，驾驶人易产生急躁情绪正确； D选项通风不良导致驾驶人疲劳，容易反应迟缓正确。 其他选项均不符合相关要求： 本题为驾考核心考点，需全面牢记相关规则，严格遵守交通法规，确保行车安全。', NULL, '安全行车', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (893, 4, 1, '逃离隧道火灾现场时，应向哪个方向逃跑？', '烟雾流相反方向', '烟雾流相同方向', '人多的方向', '原地等待救援', 'A', '本题为单选题，正确答案为A（烟雾流相反方向）。 其他选项均不符合相关法律法规及安全驾驶要求： B选项烟雾流相同方向错误； C选项人多的方向错误； D选项原地等待救援错误。 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、安全驾驶。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (894, 4, 1, '机动车进入环岛路口应如何行驶？', '顺时针方向行驶', '逆时针方向行驶', '逆时针、顺时针方向均可', '随意行驶', 'B', '本题为单选题，正确答案为B（逆时针方向行驶）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项顺时针方向行驶错误； C选项逆时针、顺时针方向均可错误； D选项随意行驶错误。 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、安全驾驶。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (895, 4, 3, '驾驶机动车在隧道中行驶，以下做法错误的是什么？', '注意和前车保持安全距离', '按照规定限速行驶', '提高车速，尽快驶离', '在隧道内紧急停车带停车休息', 'CD', '本题为多选题，正确答案为CD。 正确选项符合相关法律法规及安全驾驶要求： C选项提高车速，尽快驶离正确； D选项在隧道内紧急停车带停车休息正确。 其他选项均不符合相关要求： A选项注意和前车保持安全距离错误； B选项按照规定限速行驶错误； 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、全面规避行车风险。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (896, 4, 3, '驾驶机动车在高速公路上遇到雨雪天气时，需要降低车速、保持安全距离的原因，以下说法正确的是什么？', '能见度下降，驾驶人难以及时发现前方车辆', '此类天气条件下的道路上，车辆的制动距离变长', '为车辆安全行驶提供足够的安全距离', '降低恶劣天气对车辆造成的损害', 'ABC', '本题为多选题，正确答案为ABC。 正确选项符合相关法律法规及安全驾驶要求： A选项能见度下降，驾驶人难以及时发现前方车辆正确； B选项此类天气条件下的道路上，车辆的制动距离变长正确； C选项为车辆安全行驶提供足够的安全距离正确； 其他选项均不符合相关要求： D选项降低恶劣天气对车辆造成的损害错误。 本题考核高速公路行车安全相关规定，需严格遵守高速公路通行规则，全面保障高速行车安全。', NULL, '高速公路', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (897, 4, 1, '驾驶机动车通过立交桥时，如发现选择路线错误，应该如何行驶？', '在原地掉头', '在原地倒车驶回', '继续向前行驶，寻找下—个允许掉头的路口', '立即停车', 'C', '本题为单选题，正确答案为C（继续向前行驶，寻找下—个允许掉头的路口）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项在原地掉头错误； B选项在原地倒车驶回错误； D选项立即停车错误。 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、安全驾驶。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (898, 4, 1, '驾驶人通过仅能单车通行且无信号灯控制的窄隧道时，要注意什么？', '加速通过', '开启危险报警闪光灯', '开启远光灯', '提前减速，开启前照灯，确认安全后再通过', 'D', '本题为单选题，正确答案为D（提前减速，开启前照灯，确认安全后再通过）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项加速通过错误； B选项开启危险报警闪光灯错误； C选项开启远光灯错误； 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、安全驾驶。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (899, 4, 3, '泥泞道路的特点及对安全行车的影晌有哪些？', '行驶阻力大，附着力减小', '容易陷车', '路面松软、黏稠', '行驶极易滑转和侧滑', 'ABCD', '本题为多选题，正确答案为ABCD。 正确选项符合相关法律法规及安全驾驶要求： A选项行驶阻力大，附着力减小正确； B选项容易陷车正确； C选项路面松软、黏稠正确； D选项行驶极易滑转和侧滑正确。 其他选项均不符合相关要求： 本题为驾考核心考点，需全面牢记相关规则，严格遵守交通法规，确保行车安全。', NULL, '安全行车', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (900, 4, 1, '李某驾驶机动车在某高速公路途中行驶时，车辆后轮突然发生爆胎。李某凭借多年的驾驶经验，终于将车辆安全停下，此时应该怎么办？', '留在车内等待救援', '下车拦截其他车辆请求帮助', '站在机动车后方', '驾乘人员转移至右侧路肩上或应急车道内', 'D', '本题为单选题，正确答案为D（驾乘人员转移至右侧路肩上或应急车道内）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项留在车内等待救援错误； B选项下车拦截其他车辆请求帮助错误； C选项站在机动车后方错误； 本题考核高速公路行车安全相关规定，需严格遵守高速公路通行规则，确保高速行车安全。', NULL, '高速公路', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (901, 4, 3, '驾驶机动车在窄路直线行驶时，下列做法正确的是什么？', '注意观察车辆前方的路况', '注意观察前方是否有对向车辆', '有对向车辆时注意礼让', '会车时要迅速交会', 'ABC', '本题为多选题，正确答案为ABC。 正确选项符合相关法律法规及安全驾驶要求： A选项注意观察车辆前方的路况正确； B选项注意观察前方是否有对向车辆正确； C选项有对向车辆时注意礼让正确； 其他选项均不符合相关要求： D选项会车时要迅速交会错误。 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、全面规避行车风险。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (902, 4, 1, '驾驶装有动力转向的机动车发现转向困难怎样处置？', '停车查明原因', '控制转向缓慢行驶', '降低车速行驶', '保持机动车直线行驶', 'A', '本题为单选题，正确答案为A（停车查明原因）。 其他选项均不符合相关法律法规及安全驾驶要求： B选项控制转向缓慢行驶错误； C选项降低车速行驶错误； D选项保持机动车直线行驶错误。 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、安全驾驶。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (903, 4, 1, '行车中遇到转向失控，行驶方向偏离时怎样处置？', '迅速转向调整', '尽快减速停车', '向无障碍—侧躲避', '向有障碍—侧躲避', 'B', '本题为单选题，正确答案为B（尽快减速停车）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项迅速转向调整错误； C选项向无障碍—侧躲避错误； D选项向有障碍—侧躲避错误。 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、安全驾驶。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (904, 4, 1, '转向失控后，若机动车偏离直线行驶方向，应怎样使机动车尽快减速停车？', '轻踏制动踏板', '拉紧驻车制动器操纵杆', '迅速抢挡减速', '果断地连续踩踏、放松制动踏板', 'D', '本题为单选题，正确答案为D（果断地连续踩踏、放松制动踏板）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项轻踏制动踏板错误； B选项拉紧驻车制动器操纵杆错误； C选项迅速抢挡减速错误； 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、安全驾驶。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (905, 4, 1, '下坡路行车中制动突然失效怎样处置？', '可利用避险车道减速停车', '越二级挡位减挡', '挂倒挡迫使停车', '拉紧驻车制动器减速', 'A', '本题为单选题，正确答案为A（可利用避险车道减速停车）。 其他选项均不符合相关法律法规及安全驾驶要求： B选项越二级挡位减挡错误； C选项挂倒挡迫使停车错误； D选项拉紧驻车制动器减速错误。 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、安全驾驶。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (906, 4, 1, '下坡路制动突然失效后，不可采用的办法是什么？', '将机动车向上坡道方向行驶', '用车身靠向路旁的岩石或树林碰擦', '利用道路边专设的避险车道停车', '拉紧驻车制动器操纵杆或越二级挡位减挡', 'D', '本题为单选题，正确答案为D（拉紧驻车制动器操纵杆或越二级挡位减挡）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项将机动车向上坡道方向行驶错误； B选项用车身靠向路旁的岩石或树林碰擦错误； C选项利用道路边专设的避险车道停车错误； 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、安全驾驶。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (907, 4, 3, '机动车在行驶中突遇制动失灵时，驾驶人要采取什么措施？', '握稳方向', '抢挂低速挡减速', '使用驻车制动器减速', '开启危险报警闪光灯', 'ABCD', '本题为多选题，正确答案为ABCD。 正确选项符合相关法律法规及安全驾驶要求： A选项握稳方向正确； B选项抢挂低速挡减速正确； C选项使用驻车制动器减速正确； D选项开启危险报警闪光灯正确。 其他选项均不符合相关要求： 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、全面规避行车风险。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (908, 4, 3, '下坡路行驶，制动突然失效后，可采用的减速方法是什么？', '利用道路边专设避险车道减速停车', '用车身靠向路旁的岩石或树木碰擦', '首先拉紧驻车制动', '抢挂低速档', 'ABD', '本题为多选题，正确答案为ABD。 正确选项符合相关法律法规及安全驾驶要求： A选项利用道路边专设避险车道减速停车正确； B选项用车身靠向路旁的岩石或树木碰擦正确； D选项抢挂低速档正确。 其他选项均不符合相关要求： C选项首先拉紧驻车制动错误； 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、全面规避行车风险。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (909, 4, 1, '机动车在什么样的路面上制动时车轮最容易抱死?', '混凝土路', '土路', '冰雪路面', '沙土路', 'C', '本题为单选题，正确答案为C（冰雪路面）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项混凝土路错误； B选项土路错误； D选项沙土路错误。 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、安全驾驶。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (910, 4, 1, '轮胎气压过低时，高速行驶可能导致什么结果？', '气压不稳', '气压增高', '行驶阻力减小', '爆胎', 'D', '本题为单选题，正确答案为D（爆胎）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项气压不稳错误； B选项气压增高错误； C选项行驶阻力减小错误； 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、安全驾驶。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (911, 4, 1, '行车中发现左侧轮胎漏气时怎样处置？', '慢慢制动减速', '迅速制动减速', '迅速向右转向', '采取紧急制动', 'A', '本题为单选题，正确答案为A（慢慢制动减速）。 其他选项均不符合相关法律法规及安全驾驶要求： B选项迅速制动减速错误； C选项迅速向右转向错误； D选项采取紧急制动错误。 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、安全驾驶。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (912, 4, 1, '行车中发现右侧轮胎漏气时怎样处置？', '迅速制动减速', '慢慢制动减速', '迅速向左转向', '采取紧急制动', 'B', '本题为单选题，正确答案为B（慢慢制动减速）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项迅速制动减速错误； C选项迅速向左转向错误； D选项采取紧急制动错误。 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、安全驾驶。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (913, 4, 1, '前轮爆胎时，驾驶人控制住行驶方向后，要采取什么措施减速停车？', '抢挂高速挡', '抢挂低速挡', '抢挂空挡', '紧急制动', 'B', '本题为单选题，正确答案为B（抢挂低速挡）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项抢挂高速挡错误； C选项抢挂空挡错误； D选项紧急制动错误。 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、安全驾驶。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (914, 4, 1, '行车中轮胎突然爆裂时的不正确做法是什么？', '保持镇静，缓抬加速踏板', '紧握转向盘，控制机动车直线行驶', '采取紧急制动，在最短的时间内停车', '待车速降低后，再轻踏制动踏板', 'C', '本题为单选题，正确答案为C（采取紧急制动，在最短的时间内停车）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项保持镇静，缓抬加速踏板错误； B选项紧握转向盘，控制机动车直线行驶错误； D选项待车速降低后，再轻踏制动踏板错误。 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、安全驾驶。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (915, 4, 1, '行车中轮胎突然爆裂时的应急措施是什么？', '迅速制动减速', '紧握转向盘，尽快平稳停车', '迅速转动转向盘调整方向', '低速行驶，寻找换轮胎地点', 'B', '本题为单选题，正确答案为B（紧握转向盘，尽快平稳停车）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项迅速制动减速错误； C选项迅速转动转向盘调整方向错误； D选项低速行驶，寻找换轮胎地点错误。 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、安全驾驶。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (916, 4, 1, '轮胎气压过低时，高速行驶轮胎会出现波浪变形温度升高而导致什么情况发生？', '气压不稳', '气压更低', '行驶阻力增大', '爆胎', 'D', '本题为单选题，正确答案为D（爆胎）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项气压不稳错误； B选项气压更低错误； C选项行驶阻力增大错误； 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、安全驾驶。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (917, 4, 1, '避免爆胎的错误做法是什么？', '降低轮胎气压', '定期检查轮胎', '及时清理轮胎沟槽里的异物', '更换有裂纹或有很深损伤的轮胎', 'A', '本题为单选题，正确答案为A（降低轮胎气压）。 其他选项均不符合相关法律法规及安全驾驶要求： B选项定期检查轮胎错误； C选项及时清理轮胎沟槽里的异物错误； D选项更换有裂纹或有很深损伤的轮胎错误。 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、安全驾驶。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (918, 4, 3, '机动车在高速行驶中，突然爆胎要采取的安全措施是什么？', '紧急制动，靠边停车', '牢牢地握住转向盘，保持直行', '立即松开加速踏板', '轻踩制动踏板', 'BCD', '本题为多选题，正确答案为BCD。 正确选项符合相关法律法规及安全驾驶要求： B选项牢牢地握住转向盘，保持直行正确； C选项立即松开加速踏板正确； D选项轻踩制动踏板正确。 其他选项均不符合相关要求： A选项紧急制动，靠边停车错误； 本题为驾考核心考点，需全面牢记相关规则，严格遵守交通法规，确保行车安全。', NULL, '安全行车', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (919, 4, 3, '以下哪些能够引起轮胎爆裂？', '轮胎磨损严重', '轮胎气压过高', '尖锐物体剌伤轮胎', '车辆超载超员', 'ABCD', '本题为多选题，正确答案为ABCD。 正确选项符合相关法律法规及安全驾驶要求： A选项轮胎磨损严重正确； B选项轮胎气压过高正确； C选项尖锐物体剌伤轮胎正确； D选项车辆超载超员正确。 其他选项均不符合相关要求： 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、全面规避行车风险。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (920, 4, 1, '机动车燃油着火时，不能用于灭火的是什么？', '路边沙土', '棉衣', '工作服', '水', 'D', '本题为单选题，正确答案为D（水）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项路边沙土错误； B选项棉衣错误； C选项工作服错误； 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、安全驾驶。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (921, 4, 1, '发动机着火后首先怎样处置？', '迅速关闭发动机', '用水进行灭火', '开启发动机罩灭火', '站在下风处灭火', 'A', '本题为单选题，正确答案为A（迅速关闭发动机）。 其他选项均不符合相关法律法规及安全驾驶要求： B选项用水进行灭火错误； C选项开启发动机罩灭火错误； D选项站在下风处灭火错误。 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、安全驾驶。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (922, 4, 1, '怎样正确使用灭火器灭火？', '人要站在下风处', '灭火器瞄准火源', '尽量接近火源', '灭火器瞄准火苗', 'B', '本题为单选题，正确答案为B（灭火器瞄准火源）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项人要站在下风处错误； C选项尽量接近火源错误； D选项灭火器瞄准火苗错误。 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、安全驾驶。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (923, 4, 1, '机动车不慎落水，车门无法开启时，可选择的自救方法是什么？', '敲碎侧窗玻璃', '关闭车窗', '打电话求救', '用工具撬开车门', 'A', '本题为单选题，正确答案为A（敲碎侧窗玻璃）。 其他选项均不符合相关法律法规及安全驾驶要求： B选项关闭车窗错误； C选项打电话求救错误； D选项用工具撬开车门错误。 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、安全驾驶。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (924, 4, 1, '机动车在高速公路上发生故障需检查时怎样停车？', '在最外侧行车道上停车', '在内侧行车道上停车', '在应急车道停车', '在匝道口三角地带停车', 'C', '本题为单选题，正确答案为C（在应急车道停车）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项在最外侧行车道上停车错误； B选项在内侧行车道上停车错误； D选项在匝道口三角地带停车错误。 本题考核高速公路行车安全相关规定，需严格遵守高速公路通行规则，确保高速行车安全。', NULL, '高速公路', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (925, 4, 1, '在高速公路行车选择什么地方停车？', '服务区', '加速车道', '减速车道', '匝道', 'A', '本题为单选题，正确答案为A（服务区）。 其他选项均不符合相关法律法规及安全驾驶要求： B选项加速车道错误； C选项减速车道错误； D选项匝道错误。 本题考核高速公路行车安全相关规定，需严格遵守高速公路通行规则，确保高速行车安全。', NULL, '高速公路', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (926, 4, 1, '高速公路行车紧急情况避险的处理原则是什么？', '先避车后避物', '先避人后避物', '先避车后避人', '先避物后避人', 'B', '本题为单选题，正确答案为B（先避人后避物）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项先避车后避物错误； C选项先避车后避人错误； D选项先避物后避人错误。 本题考核高速公路行车安全相关规定，需严格遵守高速公路通行规则，确保高速行车安全。', NULL, '高速公路', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (927, 4, 1, '在车速较高可能与前方机动车发生碰撞时，驾驶人要采取什么措施？', '先制动减速，后转向避让', '急转方向向左避让', '急打方向，向右避让', '先转向避让，后制动减速', 'A', '本题为单选题，正确答案为A（先制动减速，后转向避让）。 其他选项均不符合相关法律法规及安全驾驶要求： B选项急转方向向左避让错误； C选项急打方向，向右避让错误； D选项先转向避让，后制动减速错误。 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、安全驾驶。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (928, 4, 1, '行车中与其他机动车发生正面碰撞已不可避免时怎样处置？', '变正面碰撞为侧面碰撞', '向右急转转向盘躲避', '迅速采取紧急制动', '向左急转转向盘躲避', 'C', '本题为单选题，正确答案为C（迅速采取紧急制动）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项变正面碰撞为侧面碰撞错误； B选项向右急转转向盘躲避错误； D选项向左急转转向盘躲避错误。 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、安全驾驶。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (929, 4, 1, '在高速公路驾驶机动车意外碰撞护栏时采取什么保护措施？', '握紧转向盘，适量修正', '迅速向相反方向转向', '迅速采取紧急制动', '迅速向碰撞一侧转向', 'A', '本题为单选题，正确答案为A（握紧转向盘，适量修正）。 其他选项均不符合相关法律法规及安全驾驶要求： B选项迅速向相反方向转向错误； C选项迅速采取紧急制动错误； D选项迅速向碰撞一侧转向错误。 本题考核高速公路行车安全相关规定，需严格遵守高速公路通行规则，确保高速行车安全。', NULL, '高速公路', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (930, 4, 1, '关于机动车轮胎胎压过高的危害，以下说法正确的是什么？', '加速轮胎胎面中央的花纹磨损，缩短轮胎的使用寿命', '导致爆胎', '轮胎的摩擦力、附着力降低，影晌制动效果', '导致转向盘震动、跑偏', 'A', '本题为单选题，正确答案为A（加速轮胎胎面中央的花纹磨损，缩短轮胎的使用寿命）。 其他选项均不符合相关法律法规及安全驾驶要求： B选项导致爆胎错误； C选项轮胎的摩擦力、附着力降低，影晌制动效果错误； D选项导致转向盘震动、跑偏错误。 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、安全驾驶。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (931, 4, 1, '如遇隧道内发生火灾时，以下做法正确的有哪些？', '尖利物体敲碎车窗逃生', '走“人行横洞”', '若视线不清，可以用手机手电筒照明', '打电话报警求助', 'A', '本题为单选题，正确答案为A（尖利物体敲碎车窗逃生）。 其他选项均不符合相关法律法规及安全驾驶要求： B选项走“人行横洞”错误； C选项若视线不清，可以用手机手电筒照明错误； D选项打电话报警求助错误。 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、安全驾驶。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (932, 4, 1, '驾驶机动车运载爆炸物品、易燃易爆化学物品以及剧毒、放射性等危险物品时，应该怎样做？', '按指定的时间、路线、速度行驶', '经公安机关批准', '悬挂警示标志', '采取必要的安全措施', 'A', '本题为单选题，正确答案为A（按指定的时间、路线、速度行驶）。 其他选项均不符合相关法律法规及安全驾驶要求： B选项经公安机关批准错误； C选项悬挂警示标志错误； D选项采取必要的安全措施错误。 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、安全驾驶。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (933, 4, 1, '驾驶机动车需要从车窗逃生时，要用安全锤敲击玻璃的哪个部位？', '四个角落', '中心部位', '任意部位', '中下部位', 'A', '本题为单选题，正确答案为A（四个角落）。 其他选项均不符合相关法律法规及安全驾驶要求： B选项中心部位错误； C选项任意部位错误； D选项中下部位错误。 本题为驾考核心考点，需牢记相关规则，严格遵守交通法规，确保行车安全。', NULL, '安全行车', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (934, 4, 1, '机动车燃油着火时，可以用于灭火的是什么？', '路边沙土', '棉衣', '工作服', '水', 'A', '本题为单选题，正确答案为A（路边沙土）。 其他选项均不符合相关法律法规及安全驾驶要求： B选项棉衣错误； C选项工作服错误； D选项水错误。 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、安全驾驶。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (935, 4, 1, '驾驶机动车在高速公路行驶，雨天发生“水滑“现象时，以下做法错误的是什么？', '逐渐降低车速', '双手握稳转向盘', '迅速转向调整', '急踏制动踏板减速', 'C', '本题为单选题，正确答案为C（迅速转向调整）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项逐渐降低车速错误； B选项双手握稳转向盘错误； D选项急踏制动踏板减速错误。 本题考核高速公路行车安全相关规定，需严格遵守高速公路通行规则，确保高速行车安全。', NULL, '高速公路', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (936, 4, 1, '在高速公路上驾驶机动车遇后轮爆胎时，以下做法正确的是什么？', '第—时间握紧转向盘，收油减挡缓慢制动', '安全驶离行车道停车后开启危险报警闪光灯', '车后150米以外设置警告标志', '车上人员迅速撤离到安全地点报警求助', 'A', '本题为单选题，正确答案为A（第—时间握紧转向盘，收油减挡缓慢制动）。 其他选项均不符合相关法律法规及安全驾驶要求： B选项安全驶离行车道停车后开启危险报警闪光灯错误； C选项车后150米以外设置警告标志错误； D选项车上人员迅速撤离到安全地点报警求助错误。 本题考核高速公路行车安全相关规定，需严格遵守高速公路通行规则，确保高速行车安全。', NULL, '高速公路', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (937, 4, 1, '在高速公路上发生碰撞前，驾驶人要采取什么措施？', '先制动，后转向', '边制动边转向', '先转向后制动', '立即停车', 'A', '本题为单选题，正确答案为A（先制动，后转向）。 其他选项均不符合相关法律法规及安全驾驶要求： B选项边制动边转向错误； C选项先转向后制动错误； D选项立即停车错误。 本题考核高速公路行车安全相关规定，需严格遵守高速公路通行规则，确保高速行车安全。', NULL, '高速公路', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (938, 4, 1, '机动车在高速行驶时，前面扬起的飞石或是遗撒物将挡风玻璃击裂，造成视线模糊不清的状况下，驾驶人应如何应对？', '逐渐降低车速', '保持高速尽快驶离', '开启危险报警闪光灯', '将车辆移至不妨碍交通的地点', 'A', '本题为单选题，正确答案为A（逐渐降低车速）。 其他选项均不符合相关法律法规及安全驾驶要求： B选项保持高速尽快驶离错误； C选项开启危险报警闪光灯错误； D选项将车辆移至不妨碍交通的地点错误。 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、安全驾驶。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (939, 4, 1, '驾驶机动车发生可以自行协商处理的财产损失事故，当事人不可以通过下列哪些方式协商处理？', '当场口头协商处理', '当场通过互联网在线进行处理', '在离开现场后通过互联网在线进行协商处理', '必须等保险公司人员到场鉴定后再协商处理', 'D', '本题为单选题，正确答案为D（必须等保险公司人员到场鉴定后再协商处理）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项当场口头协商处理错误； B选项当场通过互联网在线进行处理错误； C选项在离开现场后通过互联网在线进行协商处理错误； 本题为驾考核心考点，需牢记相关规则，严格遵守交通法规，确保行车安全。', NULL, '事故处理', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (940, 4, 1, '车辆因故障等原因需被牵引时，以下说法错误的是什么？', '牵引车与被牵引车都要开启危险报警闪光灯', '所有车辆都应让行', '牵引车与被牵引车尽量快速行驶', '行驶过程中不受交通信号限制', 'B', '本题为单选题，正确答案为B（所有车辆都应让行）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项牵引车与被牵引车都要开启危险报警闪光灯错误； C选项牵引车与被牵引车尽量快速行驶错误； D选项行驶过程中不受交通信号限制错误。 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、安全驾驶。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (941, 4, 1, '前轮胎爆裂已出现转向时，驾驶人在控制住方向的情况下，应如何使车辆缓慢减速？', '采取紧急制动', '使用驻车制动', '轻踏制动踏板', '迅速踏下制动踏板', 'C', '本题为单选题，正确答案为C（轻踏制动踏板）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项采取紧急制动错误； B选项使用驻车制动错误； D选项迅速踏下制动踏板错误。 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、安全驾驶。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (942, 4, 1, '机动车制动时，若前轮抱死容易出现什么现象？', '爆胎', '跑偏', '甩尾', '转向失控', 'D', '本题为单选题，正确答案为D（转向失控）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项爆胎错误； B选项跑偏错误； C选项甩尾错误； 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、安全驾驶。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (943, 4, 1, '行车中发现异常行驶的车辆时，车辆驾驶人可能存在什么行为？', '可能处于醉驾或毒驾状态', '可能处于疲劳驾驶状态', '可能驾驶经验不足', '可能在打电话、玩手机或是在找路', 'A', '本题为单选题，正确答案为A（可能处于醉驾或毒驾状态）。 其他选项均不符合相关法律法规及安全驾驶要求： B选项可能处于疲劳驾驶状态错误； C选项可能驾驶经验不足错误； D选项可能在打电话、玩手机或是在找路错误。 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、安全驾驶。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (944, 4, 1, '机动车涉水后，以下做法错误的是什么？', '保持低速行驶', '擦干被水浸湿部位', '间断轻踩制动踏板', '持续重踏制动踏板', 'D', '本题为单选题，正确答案为D（持续重踏制动踏板）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项保持低速行驶错误； B选项擦干被水浸湿部位错误； C选项间断轻踩制动踏板错误； 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、安全驾驶。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (945, 4, 1, '雾天驾驶机动车在高速公路遇事故不能继续行驶时，以下做法错误的是什么？', '车上人员要迅速从左侧车门离开', '在来车方向100米处设置警告标志', '开启危险报警闪光灯和远光灯', '车上人员站到护栏以外安全的地方', 'A', '本题为单选题，正确答案为A（车上人员要迅速从左侧车门离开）。 其他选项均不符合相关法律法规及安全驾驶要求： B选项在来车方向100米处设置警告标志错误； C选项开启危险报警闪光灯和远光灯错误； D选项车上人员站到护栏以外安全的地方错误。 本题考核高速公路行车安全相关规定，需严格遵守高速公路通行规则，确保高速行车安全。', NULL, '高速公路', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (946, 4, 1, '抢救骨折伤员时注意什么？', '迅速抬上担架送往医院', '适当调整损伤时的姿势', '用绷带对骨折部位进行包扎', '不要移动身体骨折部位', 'D', '本题为单选题，正确答案为D（不要移动身体骨折部位）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项迅速抬上担架送往医院错误； B选项适当调整损伤时的姿势错误； C选项用绷带对骨折部位进行包扎错误； 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、安全驾驶。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (947, 4, 1, '采用指压止血法为动脉出血伤员止血时， 拇指压住伤口的什么位置？', '近心端动脉', '血管下方动脉', '远心端动脉', '血管中部', 'A', '本题为单选题，正确答案为A（近心端动脉）。 其他选项均不符合相关法律法规及安全驾驶要求： B选项血管下方动脉错误； C选项远心端动脉错误； D选项血管中部错误。 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、安全驾驶。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (948, 4, 1, '火柴、硫黄和赤磷属于哪类危险化学品？', '爆炸品', '氧化性物质', '自燃物品', '易燃固体', 'D', '本题为单选题，正确答案为D（易燃固体）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项爆炸品错误； B选项氧化性物质错误； C选项自燃物品错误； 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、安全驾驶。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (949, 4, 1, '现场救护应遵循什么原则？', '安全原则', '避免二次伤害原则', '先救命后治伤原则', '争取时间原则', 'A', '本题为单选题，正确答案为A（安全原则）。 其他选项均不符合相关法律法规及安全驾驶要求： B选项避免二次伤害原则错误； C选项先救命后治伤原则错误； D选项争取时间原则错误。 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、安全驾驶。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (950, 4, 1, '在为成人做心肺复苏时，胸外按压频率是多少？', '60- 80次／分', '80- 100次／分', '100- 120次／分', '120- 140次／分', 'C', '本题为单选题，正确答案为C（100- 120次／分）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项60- 80次／分错误； B选项80- 100次／分错误； D选项120- 140次／分错误。 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、安全驾驶。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (951, 4, 3, '驾驶车辆时在道路上抛洒物品，以下说法正确的是什么？', '可能引起其他驾驶人紧急躲避等应激反应，进而引发事故', '破坏环境，影响环境整洁，甚至造成路面损坏', '抛洒纸张等轻质物品会阻挡驾驶人视线，分散驾驶人的注意力', '为了保持车内整洁可以偶尔做出这种行为', 'ABC', '本题为多选题，正确答案为ABC。 正确选项符合相关法律法规及安全驾驶要求： A选项可能引起其他驾驶人紧急躲避等应激反应，进而引发事故正确； B选项破坏环境，影响环境整洁，甚至造成路面损坏正确； C选项抛洒纸张等轻质物品会阻挡驾驶人视线，分散驾驶人的注意力正确； 其他选项均不符合相关要求： D选项为了保持车内整洁可以偶尔做出这种行为错误。 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、全面规避行车风险。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (952, 4, 3, '行至漫水路段时，应如何行驶？', '停车察明水情', '确认行车安全', '快速通过', '低速通过', 'ABD', '本题为多选题，正确答案为ABD。 正确选项符合相关法律法规及安全驾驶要求： A选项停车察明水情正确； B选项确认行车安全正确； D选项低速通过正确。 其他选项均不符合相关要求： C选项快速通过错误； 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、全面规避行车风险。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (953, 4, 3, '当车辆驶出隧道时，驾驶人易出现“明适应”现象，以下做法错误的是什么？', '变更至车辆较少的车道，迅速驶出隧道', '与前车保持安全距离，降低行驶车速，驶出隧道', '减少与前车距离，利用前车挡住强光', '加速驶出隧道', 'ACD', '本题为多选题，正确答案为ACD。 正确选项符合相关法律法规及安全驾驶要求： A选项变更至车辆较少的车道，迅速驶出隧道正确； C选项减少与前车距离，利用前车挡住强光正确； D选项加速驶出隧道正确。 其他选项均不符合相关要求： B选项与前车保持安全距离，降低行驶车速，驶出隧道错误； 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、全面规避行车风险。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (954, 4, 1, '车辆在冰雪道路跟车行驶时，应怎样做？', '保持较大的跟车距离', '开启危险报警闪光灯', '不断表换远、近光灯', '持续鸣喇叭提示前车', 'A', '本题为单选题，正确答案为A（保持较大的跟车距离）。 其他选项均不符合相关法律法规及安全驾驶要求： B选项开启危险报警闪光灯错误； C选项不断表换远、近光灯错误； D选项持续鸣喇叭提示前车错误。 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、安全驾驶。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (955, 4, 1, '夜间在视线较差的路口转弯，应在距离路口多远时关闭远光灯？', '50-100米', '30-100米', '60-100米', '50-150米', 'B', '本题为单选题，正确答案为B（30-100米）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项50-100米错误； C选项60-100米错误； D选项50-150米错误。 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、安全驾驶。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (956, 4, 3, '驾驶机动车在山区道路上坡路段接近坡顶时， 超车存在风险，以下说法正确的是什么？', '接近坡顶时视线受阻，无法观察对向来车情况', '接近坡顶时车速较慢', '接近坡顶时视线受阻，无法观察坡顶之后是否有障碍物', '接近坡顶时视线受阻，无法观察坡顶之后道路走向', 'ACD', '本题为多选题，正确答案为ACD。 正确选项符合相关法律法规及安全驾驶要求： A选项接近坡顶时视线受阻，无法观察对向来车情况正确； C选项接近坡顶时视线受阻，无法观察坡顶之后是否有障碍物正确； D选项接近坡顶时视线受阻，无法观察坡顶之后道路走向正确。 其他选项均不符合相关要求： B选项接近坡顶时车速较慢错误； 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、全面规避行车风险。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (957, 4, 3, '贾某驾车在高速公路上行驶，遇到大雾，能见度小于50米，贾某开启了雾灯、示廓灯、危险警报灯，以时速40公里行驶，并与同车道保持50米距离，经过三个出口驶离高速公路。贾某的主要违法行为是什么？', '未按规定开启相应的灯光', '未及时从最近的出口驶离高速公路', '与同车道前车距离不足', '超速行驶', 'ABD', '本题为多选题，正确答案为ABD。 正确选项符合相关法律法规及安全驾驶要求： A选项未按规定开启相应的灯光正确； B选项未及时从最近的出口驶离高速公路正确； D选项超速行驶正确。 其他选项均不符合相关要求： C选项与同车道前车距离不足错误； 本题考核高速公路行车安全相关规定，需严格遵守高速公路通行规则，全面保障高速行车安全。', NULL, '高速公路', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (958, 4, 3, '机动车驾驶人有下列哪种行为，会被吊销驾驶证？', '饮酒后驾驶机动车', '醉酒驾驶机动车', '饮酒后驾驶营运机动车', '因饮酒后驾驶机动车被处罚，再次饮酒后驾驶机动车', 'BCD', '本题为多选题，正确答案为BCD。 正确选项符合相关法律法规及安全驾驶要求： B选项醉酒驾驶机动车正确； C选项饮酒后驾驶营运机动车正确； D选项因饮酒后驾驶机动车被处罚，再次饮酒后驾驶机动车正确。 其他选项均不符合相关要求： A选项饮酒后驾驶机动车错误； 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、全面规避行车风险。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (959, 4, 3, '大风天行车需要注意什么？', '注意车辆的横向移动', '尽量减少超车', '尽量避免制动', '关紧车窗', 'ACD', '本题为多选题，正确答案为ACD。 正确选项符合相关法律法规及安全驾驶要求： A选项注意车辆的横向移动正确； C选项尽量避免制动正确； D选项关紧车窗正确。 其他选项均不符合相关要求： B选项尽量减少超车错误； 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、全面规避行车风险。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (960, 4, 3, '交通技术监控设备记录或者录入道路交通违法信息管理系统的违\n法行为信息，有下列哪些情形并经核实的，应当予以消除？', '因交通信号指示不一致造成的', '有证据证明救助危难或者紧急避险造成的', '机动车所有人或者管理人提供报案记录证明机动车被盗抢期间、机动车号牌被他人冒用期间交通技术监控设备记录的违法行为', '已经在现场被交通警察处理的交通技术监控设备记录的违法行为', 'ABCD', '本题为多选题，正确答案为ABCD。 正确选项符合相关法律法规及安全驾驶要求： A选项因交通信号指示不一致造成的正确； B选项有证据证明救助危难或者紧急避险造成的正确； C选项机动车所有人或者管理人提供报案记录证明机动车被盗抢期间、机动车号牌被他人冒用期间交通技术监控设备记录的违法行为正确； D选项已经在现场被交通警察处理的交通技术监控设备记录的违法行为正确。 其他选项均不符合相关要求： 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、全面规避行车风险。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (961, 4, 3, '因饮酒后驾驶机动车被处罚，再次饮酒后驾驶机动车的，将会受到什么样的处罚？', '吊销驾驶证', '10日以下拘留', '一干元以上二干元以下罚款', '暂扣六个月机动车驾驶证', 'ABC', '本题为多选题，正确答案为ABC。 正确选项符合相关法律法规及安全驾驶要求： A选项吊销驾驶证正确； B选项10日以下拘留正确； C选项一干元以上二干元以下罚款正确； 其他选项均不符合相关要求： D选项暂扣六个月机动车驾驶证错误。 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、全面规避行车风险。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (962, 4, 1, '驾驶机动车在城市道路行驶，距前方障碍物很近时，应采取什么应急措施？', '先制动减速，后转向避让', '边制动减速边转向避让', '先转向避让，后制动减速', '立即停车', 'C', '本题为单选题，正确答案为C（先转向避让，后制动减速）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项先制动减速，后转向避让错误； B选项边制动减速边转向避让错误； D选项立即停车错误。 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、安全驾驶。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (963, 4, 3, '隧道内的行车环境有哪些特点？', '路面条件差', '空间狭小', '疏导救援难度大', '能见度低', 'BCD', '本题为多选题，正确答案为BCD。 正确选项符合相关法律法规及安全驾驶要求： B选项空间狭小正确； C选项疏导救援难度大正确； D选项能见度低正确。 其他选项均不符合相关要求： A选项路面条件差错误； 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、全面规避行车风险。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (964, 4, 1, '驾驶机动车突然发现转向困难、 操作费力时，以下正确的说法是什么？', '尽快减速', '靠右行驶', '选择安全地点停车', '加速开往维修地点进行维修', 'A', '本题为单选题，正确答案为A（尽快减速）。 其他选项均不符合相关法律法规及安全驾驶要求： B选项靠右行驶错误； C选项选择安全地点停车错误； D选项加速开往维修地点进行维修错误。 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、安全驾驶。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (965, 4, 3, '抢救烧伤伤员时，可采取的急救措施有哪些？', '脱去烧伤处的衣物或饰品', '用冷清水冲洗或浸泡伤处', '伤员口渴可口服少量淡盐水', '使用油膏或油等敷抹烧伤处', 'BC', '本题为多选题，正确答案为BC。 正确选项符合相关法律法规及安全驾驶要求： B选项用冷清水冲洗或浸泡伤处正确； C选项伤员口渴可口服少量淡盐水正确； 其他选项均不符合相关要求： A选项脱去烧伤处的衣物或饰品错误； D选项使用油膏或油等敷抹烧伤处错误。 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、全面规避行车风险。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (966, 4, 3, '驾驶机动车在隧道内通行，哪些行为是不正确的？', '会车使用远光灯', '在隧道内超车', '开启近光灯行驶', '会车时保持安全车距', 'AB', '本题为多选题，正确答案为AB。 正确选项符合相关法律法规及安全驾驶要求： A选项会车使用远光灯正确； B选项在隧道内超车正确； 其他选项均不符合相关要求： C选项开启近光灯行驶错误； D选项会车时保持安全车距错误。 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、全面规避行车风险。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (967, 4, 3, '机动车驾驶人下列哪些行为会被吊销驾驶证？', '醉酒驾驶机动车的', '造成交通事故后逃逸，构成犯罪的', '饮酒后驾驶营运机动车的', '非法安装警报器、标志灯具的', 'ABC', '本题为多选题，正确答案为ABC。 正确选项符合相关法律法规及安全驾驶要求： A选项醉酒驾驶机动车的正确； B选项造成交通事故后逃逸，构成犯罪的正确； C选项饮酒后驾驶营运机动车的正确； 其他选项均不符合相关要求： D选项非法安装警报器、标志灯具的错误。 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、全面规避行车风险。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (968, 4, 1, '驾驶新能源汽车过程中发现电池起火，以下做法正确的是什么？', '在起火初期使用普通灭火器灭火', '火势较大无法控制时使用专用灭火器灭火', '使用大量清水灭火', '在起火初期使用专用灭火器灭火', 'D', '本题为单选题，正确答案为D（在起火初期使用专用灭火器灭火）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项在起火初期使用普通灭火器灭火错误； B选项火势较大无法控制时使用专用灭火器灭火错误； C选项使用大量清水灭火错误； 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、安全驾驶。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (969, 4, 3, '关于雾天驾驶机动车时车辆灯光的使用，以下正确的说法是什么？', '雾天驾驶机动车，必须开启雾灯', '雾天驾驶机动车，在能见度低时，应开启远光灯', '雾灯亮度高、穿透性强，不会因雾气而产生漫反射', '多雾季节正确使用雾灯，能有效性低交通事故的发生几率', 'ACD', '本题为多选题，正确答案为ACD。 正确选项符合相关法律法规及安全驾驶要求： A选项雾天驾驶机动车，必须开启雾灯正确； C选项雾灯亮度高、穿透性强，不会因雾气而产生漫反射正确； D选项多雾季节正确使用雾灯，能有效性低交通事故的发生几率正确。 其他选项均不符合相关要求： B选项雾天驾驶机动车，在能见度低时，应开启远光灯错误； 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、全面规避行车风险。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (970, 4, 3, '关于电动汽车，以下正确的说法是什么？', '出行前，应确认剩余电量', '避免长时间停放于高温环境中', '电量不足时要及时充电', '避免过度充电', 'ABCD', '本题为多选题，正确答案为ABCD。 正确选项符合相关法律法规及安全驾驶要求： A选项出行前，应确认剩余电量正确； B选项避免长时间停放于高温环境中正确； C选项电量不足时要及时充电正确； D选项避免过度充电正确。 其他选项均不符合相关要求： 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、全面规避行车风险。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (971, 4, 1, '驾驶机动车遇隧道内结冰或路面湿滑时怎么办？', '保持低速行驶', '急踩制动踏板', '尽快制动停车', '加速驶出隧道', 'A', '本题为单选题，正确答案为A（保持低速行驶）。 其他选项均不符合相关法律法规及安全驾驶要求： B选项急踩制动踏板错误； C选项尽快制动停车错误； D选项加速驶出隧道错误。 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、安全驾驶。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (972, 4, 1, '驾驶机动车在道路上行驶遇到大型车辆，以下错误的说法是什么？', '与大货车并排行驶', '大车转弯盲区大，不要抢行', '避免在大车后方行驶', '被大车跟随时应及时变道', 'A', '本题为单选题，正确答案为A（与大货车并排行驶）。 其他选项均不符合相关法律法规及安全驾驶要求： B选项大车转弯盲区大，不要抢行错误； C选项避免在大车后方行驶错误； D选项被大车跟随时应及时变道错误。 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、安全驾驶。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (973, 4, 1, '驾驶机动车经过医院区域时，以下正确的做法是什么？', '连续鸣喇叭警告', '加速行驶通过', '减速让行，必要时停车', '无需观察', 'C', '本题为单选题，正确答案为C（减速让行，必要时停车）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项连续鸣喇叭警告错误； B选项加速行驶通过错误； D选项无需观察错误。 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、安全驾驶。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (974, 4, 1, '驾驶危险货物运输车辆在运输过程中发生追尾，引发火灾事故，以下错误的做法是什么？', '拨打报警电话', '立即在安全的地方停车', '远离被大火吞没的罐体，站在下风处等待救援', '用反光锥在事故车辆周围设置安全警戒区', 'C', '本题为单选题，正确答案为C（远离被大火吞没的罐体，站在下风处等待救援）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项拨打报警电话错误； B选项立即在安全的地方停车错误； D选项用反光锥在事故车辆周围设置安全警戒区错误。 本题为驾考核心考点，需牢记相关规则，严格遵守交通法规，确保行车安全。', NULL, '事故处理', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (975, 4, 3, '交通肇事致—人以上重伤，负事故全部或者主要责任，并具有下列哪种行为的，构成交通肇事罪？', '严重超载驾驶的', '无驾驶资格驾驶机动车辆的', '为逃避法律追究逃离事故现场的', '酒后、吸食毒品后驾驶机动车辆', 'ABCD', '本题为多选题，正确答案为ABCD。 正确选项符合相关法律法规及安全驾驶要求： A选项严重超载驾驶的正确； B选项无驾驶资格驾驶机动车辆的正确； C选项为逃避法律追究逃离事故现场的正确； D选项酒后、吸食毒品后驾驶机动车辆正确。 其他选项均不符合相关要求： 本题为驾考核心考点，需全面牢记相关规则，严格遵守交通法规，确保行车安全。', NULL, '事故处理', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (976, 4, 1, '驾驶机动车在以下哪个交通场景中可以开启定速巡航功能？', '长距离下坡路段', '交通拥堵的城市道路', '山区弯路', '车流量少的高速公路', 'D', '本题为单选题，正确答案为D（车流量少的高速公路）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项长距离下坡路段错误； B选项交通拥堵的城市道路错误； C选项山区弯路错误； 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、安全驾驶。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (977, 4, 1, '机动车在通过有交通信号灯控制的交叉路口时，以下做法正确的是什么？', '遇放行信号时，依次通过', '准备进入环形路口的让已在路口内的机动车先行', '在右转车道直行', '鸣喇叭催促同车道前车让路', 'A', '本题为单选题，正确答案为A（遇放行信号时，依次通过）。 其他选项均不符合相关法律法规及安全驾驶要求： B选项准备进入环形路口的让已在路口内的机动车先行错误； C选项在右转车道直行错误； D选项鸣喇叭催促同车道前车让路错误。 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、安全驾驶。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (978, 4, 1, '新能源电动汽车电池着火时，以下错误的说法是什么？', '灭火时电池不再有明火即可', '注意防高温、毒气', '报警时告知起火汽车的品牌和型号', '火势刚起能够断电时，立即断电', 'A', '本题为单选题，正确答案为A（灭火时电池不再有明火即可）。 其他选项均不符合相关法律法规及安全驾驶要求： B选项注意防高温、毒气错误； C选项报警时告知起火汽车的品牌和型号错误； D选项火势刚起能够断电时，立即断电错误。 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、安全驾驶。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (979, 4, 3, '机动车在隧道内容易打滑的原因，以下说法正确的是什么？', '寒冷天气靠近隧道出口容易遇冷结冰', '隧道路面平坦，驾驶人容易提高车速行驶', '汽车尾气油烟沉积在路面上，使路面形成一层油膜', '受环境影响隧道路面易返潮湿滑', 'ACD', '本题为多选题，正确答案为ACD。 正确选项符合相关法律法规及安全驾驶要求： A选项寒冷天气靠近隧道出口容易遇冷结冰正确； C选项汽车尾气油烟沉积在路面上，使路面形成一层油膜正确； D选项受环境影响隧道路面易返潮湿滑正确。 其他选项均不符合相关要求： B选项隧道路面平坦，驾驶人容易提高车速行驶错误； 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、全面规避行车风险。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (980, 4, 1, '驾驶机动车长时间在隧道内行驶，驾驶环境单一，驾驶人容易产生什么心理？', '寂寞或孤单', '兴奋或刺激', '压抑或烦躁', '紧张或不适', 'C', '本题为单选题，正确答案为C（压抑或烦躁）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项寂寞或孤单错误； B选项兴奋或刺激错误； D选项紧张或不适错误。 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、安全驾驶。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (981, 4, 1, '驾驶机动车在高速公路隧道内发生交通事故时，以下错误的做法是什么？', '在车上等待救援', '在来车方向150 米以外设置警告标志', '立即报警', '开启危险报警闪光灯', 'A', '本题为单选题，正确答案为A（在车上等待救援）。 其他选项均不符合相关法律法规及安全驾驶要求： B选项在来车方向150 米以外设置警告标志错误； C选项立即报警错误； D选项开启危险报警闪光灯错误。 本题考核高速公路行车安全相关规定，需严格遵守高速公路通行规则，确保高速行车安全。', NULL, '高速公路', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (982, 4, 3, '关于酒精对驾驶人的影响，以下正确的说法是什么？', '影响驾驶人对车辆的操纵能力', '会导致驾驶人反应速度变慢', '会导致驾驶人判断能力下降', '会使驾驶人亢奋，开车更警觉', 'ABC', '本题为多选题，正确答案为ABC。 正确选项符合相关法律法规及安全驾驶要求： A选项影响驾驶人对车辆的操纵能力正确； B选项会导致驾驶人反应速度变慢正确； C选项会导致驾驶人判断能力下降正确； 其他选项均不符合相关要求： D选项会使驾驶人亢奋，开车更警觉错误。 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、全面规避行车风险。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (983, 4, 3, '驾驶人刘某（无证）驾驶制动摩擦片严重磨损的小型客车以70公里/小时的速度行驶至隧道入口（限速40公里/小时）， 因雨 天路滑导致车辆失控后驶往道路左侧，与对向行驶的由驾驶人王某驾驶的速度为48公里/小时的重型自卸货车（空载）相撞， 造成3人死亡。此事故中驾驶人的违法行为有哪些？', '王某超速行驶', '刘某驾驶具有安全隐患的机动车辆上道路行驶', '刘某超速行驶', '刘某无证驾驶', 'ABCD', '本题为多选题，正确答案为ABCD。 正确选项符合相关法律法规及安全驾驶要求： A选项王某超速行驶正确； B选项刘某驾驶具有安全隐患的机动车辆上道路行驶正确； C选项刘某超速行驶正确； D选项刘某无证驾驶正确。 其他选项均不符合相关要求： 本题为驾考核心考点，需全面牢记相关规则，严格遵守交通法规，确保行车安全。', NULL, '事故处理', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (984, 4, 3, '在没有划分机动车道、非机动车道和人行道的道路上，应如何通行？', '机动车在道路左侧通行，非机动车和行人在道路两侧通行', '机动车、非机动车和行人可随意通行', '机动车在道路中间通行', '非机动车和行人在道路两侧通行', 'CD', '本题为多选题，正确答案为CD。 正确选项符合相关法律法规及安全驾驶要求： C选项机动车在道路中间通行正确； D选项非机动车和行人在道路两侧通行正确。 其他选项均不符合相关要求： A选项机动车在道路左侧通行，非机动车和行人在道路两侧通行错误； B选项机动车、非机动车和行人可随意通行错误； 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、全面规避行车风险。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (985, 4, 3, '以下哪种情况下，机动车可能会爆胎？', '轮胎漏气，轮胎与地面摩擦产生高温', '严重超载', '胎压过低，高速行驶导致轮胎变形', '夏季高温，轮胎气压过高', 'ABCD', '本题为多选题，正确答案为ABCD。 正确选项符合相关法律法规及安全驾驶要求： A选项轮胎漏气，轮胎与地面摩擦产生高温正确； B选项严重超载正确； C选项胎压过低，高速行驶导致轮胎变形正确； D选项夏季高温，轮胎气压过高正确。 其他选项均不符合相关要求： 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、全面规避行车风险。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (986, 4, 1, '以下对驾驶机动车时接打电话容易引发事故的原因表述错误的是什么？', '单手握方向盘，对机动车控制力下降', '驾驶人注意力不集中，不能及时判断危险', '电话的信号会对汽车电子设备的运行造成干扰', '驾驶人对路况观察不到位，容易导致操作失误', 'C', '本题为单选题，正确答案为C（电话的信号会对汽车电子设备的运行造成干扰）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项单手握方向盘，对机动车控制力下降错误； B选项驾驶人注意力不集中，不能及时判断危险错误； D选项驾驶人对路况观察不到位，容易导致操作失误错误。 本题为驾考核心考点，需牢记相关规则，严格遵守交通法规，确保行车安全。', NULL, '事故处理', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (987, 4, 1, '下雨后路面湿滑，车辆行驶中紧急制动时，容易导致什么？', '引起发动机熄火', '不被其他车辆驾驶人发现', '因视线模糊而撞车', '发生侧滑、引发交通事故', 'D', '本题为单选题，正确答案为D（发生侧滑、引发交通事故）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项引起发动机熄火错误； B选项不被其他车辆驾驶人发现错误； C选项因视线模糊而撞车错误； 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、安全驾驶。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (988, 4, 1, '驾驶机动车驶出地下车库时，以下做法错误的是什么？', '按照导向箭头的方向行驶，不得逆行', '适当增大与前车的安全距离，以免前车溜车造成事故', '注意观察行人和其他车辆', '在确认安全的情况下从车库入口驶出', 'D', '本题为单选题，正确答案为D（在确认安全的情况下从车库入口驶出）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项按照导向箭头的方向行驶，不得逆行错误； B选项适当增大与前车的安全距离，以免前车溜车造成事故错误； C选项注意观察行人和其他车辆错误； 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、安全驾驶。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (989, 4, 1, '大风天气行车需要注意什么？', '尽量减少超车', '注意车辆的横向移动', '尽量避免制动', '关紧车窗', 'B', '本题为单选题，正确答案为B（注意车辆的横向移动）。 其他选项均不符合相关法律法规及安全驾驶要求： A选项尽量减少超车错误； C选项尽量避免制动错误； D选项关紧车窗错误。 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、安全驾驶。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (990, 4, 1, '机动车高速行驶中出现转向失控时，驾驶人要如何处置？', '开启危险报警闪光灯', '合理使用行车制动和驻车制动，避免紧急制动', '抢挂低速挡', '紧急制动', 'A', '本题为单选题，正确答案为A（开启危险报警闪光灯）。 其他选项均不符合相关法律法规及安全驾驶要求： B选项合理使用行车制动和驻车制动，避免紧急制动错误； C选项抢挂低速挡错误； D选项紧急制动错误。 本题考核安全文明驾驶相关要求，行车中需做到文明礼让、提前预判、安全驾驶。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (991, 1, 2, '机动车行经人行横道时，应当减速行驶；遇行人正在通过人行横道，应当停车让行。', '正确', '错误', NULL, NULL, 'A', '根据《道路交通安全法》规定，机动车行经人行横道时，应当减速行驶；遇行人正在通过人行横道，应当停车让行，这是驾驶人的法定义务。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (992, 1, 2, '驾驶机动车在高速公路上行驶，车速超过每小时100公里时，应当与同车道前车保持100米以上的距离。', '正确', '错误', NULL, NULL, 'A', '高速公路上行驶，车速超过100公里/小时，与前车的安全距离不得少于100米，确保有足够的反应和制动距离。', NULL, '高速公路', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (993, 1, 2, '驾驶机动车在道路上发生故障，需要停车排除故障时，驾驶人应当立即开启危险报警闪光灯，将机动车移至不妨碍交通的地方停放。', '正确', '错误', NULL, NULL, 'A', '机动车在道路上发生故障，需要停车排除故障时，首先开启危险报警闪光灯，然后将车辆移至不妨碍交通的地方，避免影响其他车辆通行。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (994, 1, 2, '饮酒后驾驶机动车的，处暂扣六个月机动车驾驶证，并处一千元以上二千元以下罚款。', '正确', '错误', NULL, NULL, 'A', '根据《道路交通安全法》规定，饮酒后驾驶机动车的，处暂扣六个月机动车驾驶证，并处一千元以上二千元以下罚款，一次记12分。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (995, 1, 3, '下列哪些行为会被记12分？', '饮酒后驾驶机动车', '使用伪造、变造的机动车号牌', '驾驶机动车在高速公路上倒车、逆行、穿越中央分隔带掉头', '驾驶机动车不按规定避让校车', 'ABC', '饮酒后驾驶机动车、使用伪造变造号牌、高速倒车逆行掉头，均属于严重违法行为，一次记12分；不按规定避让校车一次记6分。', NULL, '记分', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (996, 1, 3, '驾驶机动车在高速公路上发生故障，难以移动时，以下做法正确的是什么？', '立即开启危险报警闪光灯', '在车后150米以外设置警告标志', '车上人员应当迅速转移到右侧路肩上或者应急车道内', '在车内等待救援', 'ABC', '高速上车辆发生故障难以移动时，应立即开启危险报警闪光灯，在车后150米外设置警告标志，车上人员迅速转移到安全区域，避免在车内停留，防止发生二次事故。', NULL, '高速公路', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (997, 1, 3, '下列哪些属于违法行为？', '驾驶机动车时接打手持电话', '驾驶机动车时不按规定使用安全带', '驾驶机动车时超速行驶', '驾驶机动车时按照交通信号指示行驶', 'ABC', '接打手持电话、不按规定使用安全带、超速行驶，均属于违反道路交通安全法的行为；按照交通信号指示行驶是合法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (998, 1, 3, '驾驶机动车遇有前方车辆停车排队等候或者缓慢行驶时，不得有下列哪些行为？', '借道超车', '占用对面车道', '穿插等候的车辆', '依次排队行驶', 'ABC', '前方车辆排队等候或缓慢行驶时，借道超车、占用对面车道、穿插等候车辆，均属于违法行为，会加剧交通拥堵，引发交通事故；依次排队行驶是正确做法。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (999, 1, 3, '下列哪些情形下，驾驶机动车不得超车？', '前车正在左转弯、掉头、超车的', '与对面来车有会车可能的', '前车为执行紧急任务的警车、消防车、救护车、工程救险车的', '行经铁路道口、交叉路口、窄桥、弯道、陡坡、隧道、人行横道、市区交通流量大的路段等没有超车条件的', 'ABCD', '以上四种情形均不具备超车条件，强行超车极易引发交通事故，属于违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1000, 1, 3, '驾驶机动车在夜间会车时，以下做法正确的是什么？', '在距对向来车150米以外，将远光灯改用近光灯', '在窄路、窄桥与非机动车会车时，应当使用近光灯', '遇对向来车未关闭远光灯时，连续使用远光灯对射', '遇对向来车未关闭远光灯时，减速或停车避让', 'ABD', '夜间会车时，应提前将远光灯改为近光灯，窄路窄桥会车使用近光灯，遇对方未关远光灯时，应减速或停车避让，避免使用远光灯对射，以免影响对方视线，引发事故。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1001, 1, 3, '下列哪些行为会被记6分？', '驾驶机动车不按交通信号灯指示通行的', '驾驶机动车违法占用应急车道行驶的', '驾驶机动车不按规定避让校车的', '驾驶机动车在高速公路上倒车、逆行的', 'ABC', '不按交通信号灯通行、违法占用应急车道、不按规定避让校车，均一次记6分；高速倒车逆行一次记12分。', NULL, '记分', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1002, 1, 3, '驾驶机动车在道路上发生交通事故，以下做法正确的是什么？', '立即停车，保护现场', '造成人身伤亡的，车辆驾驶人应当立即抢救受伤人员，并迅速报告执勤的交通警察或者公安机关交通管理部门', '仅造成轻微财产损失，并且基本事实清楚的，当事人应当先撤离现场再进行协商处理', '发生交通事故后逃逸，迅速离开现场', 'ABC', '发生交通事故后，应立即停车保护现场，抢救伤员，报警；轻微事故应先撤离再协商；逃逸属于严重违法行为，会被追究法律责任。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1003, 1, 3, '驾驶机动车在高速公路上行驶，遇有低能见度气象条件时，以下做法正确的是什么？', '能见度小于200米时，车速不得超过每小时60公里，与前车保持100米以上的距离', '能见度小于100米时，车速不得超过每小时40公里，与前车保持50米以上的距离', '能见度小于50米时，车速不得超过每小时20公里，并从最近的出口尽快驶离高速公路', '能见度低时，开启远光灯，提高视线', 'ABC', '低能见度气象条件下，应根据能见度降低车速，保持安全距离，能见度小于50米时尽快驶离高速；应开启雾灯和近光灯，远光灯会产生反光，反而影响视线。', NULL, '高速公路', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1004, 4, 1, '车辆在拥挤路段低速行驶，遇其他车辆强行插队，应怎样做?', '鸣喇叭警告，不得进入', '加速行驶，紧跟前车，不让其进入', '主动礼让，确保行车安全', '挤靠“加塞”车辆，逼其离开', 'C', '文明礼让第一，斗气、加速、挤靠全错，主动礼让能避免交通事故，确保行车安全。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1005, 4, 1, '驾驶机动车在交叉路口前变更车道，应怎样驶入要变更的车道?', '在路口前实线区内根据需要', '进入路口实线区内', '在虚线区按导向箭头指示', '在路口停止线前', 'C', '实线不变道、虚线按箭头，路口实线必错，变更车道应在虚线区按导向箭头指示驶入。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1006, 4, 1, '救助全身燃烧伤员，采取哪种应急措施?', '用沙土覆盖火焰灭火', '向身上喷冷水灭火', '用灭火器进行灭火', '帮助脱掉燃烧的衣服', 'B', '冷水降温，沙土、灭火器伤皮肤，脱衣易撕烂皮肤，向身上喷冷水是最安全的应急措施。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1007, 4, 1, '会车中道路一侧有障碍，双方机动车应如何做?', '无障碍一方让对向先行', '速度慢的让速度快的先行', '有障碍的一方让对向先行', '速度快的让速度慢的先行', 'C', '有障碍的一方让对向先行，确保会车安全，避免因障碍导致的碰撞事故。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1008, 4, 3, '驾驶机动车在山区道路下坡路段尽量避免超车，以下说法正确的是什么?', '下坡路段车辆阻力很大', '下坡路段车辆惯性大，超车时车速过快，易引发事故', '下坡路段超车视线受阻，无法观察对向车辆情况', '下坡路段超车时，前车车速过快，无法超越', 'BC', '山区下坡路段车辆惯性大，车速快，超车时易引发事故，且下坡路段视线受阻，无法观察对向车辆情况，因此应尽量避免超车。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1009, 4, 3, '驾驶机动车在高速公路上行驶，遇有雾、雨、雪、沙尘、冰雹等低能见度气象条件时，以下做法正确的是什么?', '立即减速，适当加大与前车的安全距离', '开启雾灯、近光灯、示廓灯和前后位灯', '能见度小于50米时，立即驶离高速公路', '在应急车道上停车等待，等待能见度好转', 'ABC', '低能见度气象条件下，应减速慢行，加大安全距离，开启相应的灯光，能见度小于50米时尽快驶离高速；应急车道仅用于紧急情况，不得随意停车等待。', NULL, '高速公路', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1010, 4, 3, '驾驶机动车在道路上发生交通事故，造成人员伤亡，以下做法正确的是什么?', '立即停车，保护现场', '立即抢救受伤人员', '迅速报警，等待交警处理', '立即将车辆移至路边，避免影响交通', 'ABC', '发生交通事故造成人员伤亡时，应立即停车保护现场，抢救伤员，报警等待交警处理；在未固定证据前，不得随意移动车辆，以免破坏现场。', NULL, '事故处理', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1011, 4, 3, '驾驶机动车在夜间行驶，以下做法正确的是什么?', '在没有路灯、照明不良的道路上行驶，开启远光灯', '遇对向有来车时，提前150米将远光灯改为近光灯', '在窄路、窄桥与非机动车会车时，使用近光灯', '夜间超车时，连续使用远光灯对射，提醒前车让行', 'ABC', '夜间行驶时，无路灯照明不良的道路开启远光灯，会车时提前改为近光灯，窄路窄桥会车使用近光灯；夜间超车应交替使用远近光灯提醒前车，不得使用远光灯对射。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1012, 4, 3, '驾驶机动车在山区道路行驶，以下做法正确的是什么?', '上坡路段提前减挡，保持充足的动力', '下坡路段利用发动机制动，避免长时间踩刹车', '弯道处减速慢行，鸣喇叭示意对向车辆', '在狭窄的山路会车时，靠山体的一方让行', 'ABC', '山区道路行驶，上坡提前减挡，下坡利用发动机制动，弯道减速鸣喇叭，都是正确的做法；狭窄山路会车时，不靠山体的一方让行，因为靠山体的一方更安全。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1013, 4, 3, '驾驶机动车在高速公路上行驶，以下做法错误的是什么?', '在应急车道上行驶', '倒车、逆行、穿越中央分隔带掉头', '在车道内停车，等待朋友', '按照交通标志、标线指示行驶', 'ABC', '在应急车道行驶、高速倒车逆行掉头、在车道内停车等待，均属于严重违法行为；按照交通标志标线指示行驶是正确的做法。', NULL, '高速公路', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1014, 4, 2, '驾驶机动车在道路上行驶，遇到行人正在通过人行横道，应当停车让行。', '正确', '错误', NULL, NULL, 'A', '人行横道是行人的优先通行区域，遇到行人正在通过时，必须停车让行，保障行人安全。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1015, 4, 2, '驾驶机动车在高速公路上行驶，为了节省时间，可以在应急车道上行驶。', '正确', '错误', NULL, NULL, 'B', '应急车道是供紧急情况下使用的，非紧急情况不得在应急车道行驶，否则属于违法行为。', NULL, '高速公路', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1016, 4, 2, '驾驶机动车在夜间会车时，遇对向来车未关闭远光灯，应当连续使用远光灯对射，提醒对方关闭。', '正确', '错误', NULL, NULL, 'B', '遇对向来车未关闭远光灯，应当减速或停车避让，避免使用远光灯对射，以免影响对方视线，引发事故。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1017, 4, 2, '驾驶机动车在山区道路下坡路段，应当空挡滑行，节省燃油。', '正确', '错误', NULL, NULL, 'B', '山区下坡路段空挡滑行，会导致车辆失去发动机制动，车速过快，极易引发事故，属于违法行为。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1018, 4, 2, '驾驶机动车在道路上发生交通事故，仅造成轻微财产损失，当事人应当先撤离现场，再协商处理赔偿事宜。', '正确', '错误', NULL, NULL, 'A', '轻微交通事故，当事人应先撤离现场，避免造成交通拥堵，再协商赔偿事宜，符合快速处理原则。', NULL, '事故处理', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1019, 4, 2, '驾驶机动车在有导向车道的交叉路口，应当按照所需行进方向驶入导向车道，不得在导向车道内变更车道。', '正确', '错误', NULL, NULL, 'A', '在有导向车道的交叉路口，应按行进方向驶入导向车道，不得在导向车道内变更车道或压线行驶，否则属于违法行为。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1020, 4, 2, '驾驶机动车在高速公路上行驶，遇有低能见度气象条件，能见度小于50米时，应当继续行驶，尽快通过该路段。', '正确', '错误', NULL, NULL, 'B', '高速公路能见度小于50米时，视线极差，继续行驶风险极高，应当尽快驶离高速公路，避免在高速上停留。', NULL, '高速公路', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1021, 4, 2, '驾驶机动车在道路上超车时，应当从前车的左侧超越，不得从右侧超越。', '正确', '错误', NULL, NULL, 'A', '超车应当从前车的左侧超越，右侧超车视线受阻，容易发生交通事故，属于违法行为。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1022, 4, 2, '驾驶机动车在道路上临时停车时，应当开启危险报警闪光灯，提醒其他车辆注意。', '正确', '错误', NULL, NULL, 'A', '道路上临时停车时，开启危险报警闪光灯，能提醒其他车辆注意前方有停车，避免发生碰撞事故。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1023, 4, 2, '驾驶机动车在实习期内驾驶机动车上高速公路，应当由持相应或者包含其准驾车型驾驶证三年以上的驾驶人陪同。', '正确', '错误', NULL, NULL, 'A', '驾驶人在实习期内驾驶机动车上高速公路，必须由持相应或者包含其准驾车型驾驶证三年以上的驾驶人陪同，不得单独上高速，否则属于违法行为。', NULL, '高速公路', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1024, 1, 2, '饮酒后驾驶营运机动车的，吊销机动车驾驶证，5年内不得重新取得。', '正确', '错误', NULL, NULL, 'A', '营运车（比如出租车、货车）酒后驾驶，比普通私家车处罚重，5年不能重考，还要罚款。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1025, 1, 2, '雾天在高速公路行驶，能见度小于50米时，车速不得超过每小时20公里，且需尽快驶离高速。', '正确', '错误', NULL, NULL, 'A', '口诀52离，能见度50米，限速20，赶紧下高速，别在高速上停留。', NULL, '高速公路', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1026, 1, 2, '驾驶机动车不按规定使用灯光的，一次记3分。', '正确', '错误', NULL, NULL, 'B', '不按规定使用灯光，比如会车不开近光、夜间不开灯，一次记1分，不是3分。', NULL, '记分', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1027, 1, 2, '机动车未悬挂机动车号牌的，一次记9分。', '正确', '错误', NULL, NULL, 'A', '没挂车牌、故意遮挡车牌，都是记9分，这是重点，千万别犯。', NULL, '记分', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1028, 1, 2, '驾驶机动车通过没有交通信号灯的交叉路口，先到的车辆先行。', '正确', '错误', NULL, NULL, 'B', '无信号灯路口，不是先到先行，而是遵循“右方来车先行”“让行标志先行”，别搞错了。', NULL, '交通信号', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1029, 1, 2, '提供虚假材料申领驾驶证，3年内不得再次申请。', '正确', '错误', NULL, NULL, 'B', '提供虚假材料申领驾驶证，1年内不得再次申请，不是3年。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1030, 1, 2, '驾驶机动车在高速公路上倒车、逆行、穿越中央分隔带掉头的，一次记12分。', '正确', '错误', NULL, NULL, 'A', '高速公路上倒车、逆行、掉头，属于严重违法行为，一次记12分，并处200元罚款。', NULL, '高速公路', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1031, 1, 2, '驾驶机动车不按规定避让校车的，一次记6分。', '正确', '错误', NULL, NULL, 'A', '不按规定避让校车，一次记6分，并处200元罚款，保障学生上下学安全。', NULL, '记分', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1032, 1, 2, '驾驶机动车在道路上发生交通事故，造成人员伤亡，当事人应当先撤离现场，再协商处理。', '正确', '错误', NULL, NULL, 'B', '发生交通事故造成人员伤亡的，应当立即停车，抢救伤员，报警，不得擅自撤离现场，破坏现场。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1033, 1, 2, '驾驶机动车在道路上行驶，不按规定使用安全带的，一次记1分。', '正确', '错误', NULL, NULL, 'A', '不按规定使用安全带，一次记1分，并处20-200元罚款，安全带是生命带，必须正确使用。', NULL, '记分', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1034, 1, 2, '驾驶机动车在道路上行驶，接打手持电话的，一次记3分。', '正确', '错误', NULL, NULL, 'A', '接打手持电话，一次记3分，并处20-200元罚款，开车时接打电话会分散注意力，极易引发事故。', NULL, '记分', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1035, 1, 2, '驾驶机动车在道路上行驶，违反禁令标志、禁止标线指示的，一次记3分。', '正确', '错误', NULL, NULL, 'A', '违反禁令标志、禁止标线指示，一次记3分，并处20-200元罚款，比如禁止停车、禁止左转等区域违规通行。', NULL, '记分', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1036, 1, 2, '驾驶机动车在道路上行驶，在人行横道前不按规定减速、停车、避让行人的，一次记3分。', '正确', '错误', NULL, NULL, 'A', '人行横道前不按规定减速、停车、避让行人，一次记3分，并处20-200元罚款，保障行人通行安全是驾驶人的法定义务。', NULL, '记分', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1037, 1, 2, '驾驶机动车在道路上行驶，在高速公路上违法占用应急车道行驶的，一次记6分。', '正确', '错误', NULL, NULL, 'A', '违法占用应急车道行驶，一次记6分，并处200元罚款，应急车道是生命通道，非紧急情况不得占用。', NULL, '高速公路', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1038, 1, 2, '驾驶机动车在道路上行驶，在高速公路上不按规定车道行驶的，一次记3分。', '正确', '错误', NULL, NULL, 'A', '高速公路上不按规定车道行驶，一次记3分，并处20-200元罚款，比如在快车道低速行驶、在慢车道超速行驶等。', NULL, '高速公路', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1039, 1, 2, '驾驶机动车在道路上行驶，在高速公路上倒车、逆行、穿越中央分隔带掉头的，一次记12分。', '正确', '错误', NULL, NULL, 'A', '高速公路上倒车、逆行、掉头，属于严重违法行为，一次记12分，并处200元罚款，极易引发重大交通事故。', NULL, '高速公路', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1040, 1, 2, '驾驶机动车在道路上行驶，在高速公路上停车的，一次记6分。', '正确', '错误', NULL, NULL, 'B', '高速公路上非紧急情况停车，一次记6分；紧急情况停车，按规定设置警告标志的，不处罚。', NULL, '高速公路', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1041, 1, 2, '驾驶机动车在道路上行驶，在高速公路上超车时，应当从前车的左侧超越。', '正确', '错误', NULL, NULL, 'A', '高速公路上超车，应当从前车的左侧超越，右侧超车视线受阻，容易发生交通事故，属于违法行为。', NULL, '高速公路', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1042, 1, 2, '驾驶机动车在道路上行驶，在高速公路上会车时，应当使用近光灯。', '正确', '错误', NULL, NULL, 'A', '高速公路上会车时，应当使用近光灯，远光灯会导致对向驾驶人视线受阻，极易引发碰撞事故。', NULL, '高速公路', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1043, 1, 1, '驾驶机动车在道路上行驶，超过规定时速50%以上的，一次记多少分？', '3分', '6分', '9分', '12分', 'D', '超速50%以上，属于严重违法行为，一次记12分，并处200-2000元罚款，可并处吊销驾驶证。', NULL, '记分', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1044, 1, 1, '驾驶机动车在道路上行驶，接打手持电话的，一次记多少分？', '1分', '3分', '6分', '12分', 'B', '接打手持电话，一次记3分，并处20-200元罚款，开车时接打电话会分散注意力，极易引发事故。', NULL, '记分', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1045, 1, 1, '驾驶机动车在道路上行驶，不按规定使用安全带的，一次记多少分？', '1分', '3分', '6分', '12分', 'A', '不按规定使用安全带，一次记1分，并处20-200元罚款，安全带是生命带，必须正确使用。', NULL, '记分', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1046, 1, 1, '驾驶机动车在道路上行驶，违反禁令标志、禁止标线指示的，一次记多少分？', '1分', '3分', '6分', '12分', 'B', '违反禁令标志、禁止标线指示，一次记3分，并处20-200元罚款，比如禁止停车、禁止左转等区域违规通行。', NULL, '记分', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1047, 1, 1, '驾驶机动车在道路上行驶，在人行横道前不按规定减速、停车、避让行人的，一次记多少分？', '1分', '3分', '6分', '12分', 'B', '人行横道前不按规定减速、停车、避让行人，一次记3分，并处20-200元罚款，保障行人通行安全是驾驶人的法定义务。', NULL, '记分', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1048, 1, 1, '驾驶机动车在道路上行驶，在高速公路上违法占用应急车道行驶的，一次记多少分？', '3分', '6分', '9分', '12分', 'B', '违法占用应急车道行驶，一次记6分，并处200元罚款，应急车道是生命通道，非紧急情况不得占用。', NULL, '高速公路', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1049, 1, 1, '驾驶机动车在道路上行驶，在高速公路上不按规定车道行驶的，一次记多少分？', '1分', '3分', '6分', '12分', 'B', '高速公路上不按规定车道行驶，一次记3分，并处20-200元罚款，比如在快车道低速行驶、在慢车道超速行驶等。', NULL, '高速公路', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1050, 1, 1, '驾驶机动车在道路上行驶，在高速公路上倒车、逆行、穿越中央分隔带掉头的，一次记多少分？', '3分', '6分', '9分', '12分', 'D', '高速公路上倒车、逆行、掉头，属于严重违法行为，一次记12分，并处200元罚款，极易引发重大交通事故。', NULL, '高速公路', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1051, 1, 1, '驾驶机动车在道路上行驶，不按规定使用灯光的，一次记多少分？', '1分', '3分', '6分', '12分', 'A', '不按规定使用灯光，比如会车不开近光、夜间不开灯，一次记1分，不是3分。', NULL, '记分', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1052, 1, 1, '驾驶机动车在道路上行驶，机动车未悬挂机动车号牌的，一次记多少分？', '3分', '6分', '9分', '12分', 'C', '没挂车牌、故意遮挡车牌，都是记9分，这是重点，千万别犯。', NULL, '记分', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1053, 1, 1, '驾驶机动车在道路上行驶，饮酒后驾驶机动车的，一次记多少分？', '3分', '6分', '9分', '12分', 'D', '饮酒后驾驶机动车，一次记12分，并处暂扣驾驶证6个月、罚款1000-2000元。', NULL, '记分', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1054, 1, 1, '驾驶机动车在道路上行驶，造成交通事故后逃逸，尚不构成犯罪的，一次记多少分？', '3分', '6分', '9分', '12分', 'D', '造成交通事故后逃逸，尚不构成犯罪的，一次记12分，并处200-2000元罚款，可并处15日以下拘留。', NULL, '记分', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1055, 1, 1, '驾驶机动车在道路上行驶，使用伪造、变造的机动车号牌、行驶证、驾驶证的，一次记多少分？', '3分', '6分', '9分', '12分', 'D', '使用伪造、变造的机动车号牌、行驶证、驾驶证的，一次记12分，并处2000-5000元罚款，可并处15日以下拘留。', NULL, '记分', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1056, 1, 1, '驾驶机动车在道路上行驶，在高速公路上停车的，非紧急情况一次记多少分？', '3分', '6分', '9分', '12分', 'B', '高速公路上非紧急情况停车，一次记6分；紧急情况停车，按规定设置警告标志的，不处罚。', NULL, '高速公路', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1057, 1, 1, '驾驶机动车在道路上行驶，在高速公路上超车时，应当从前车的哪一侧超越？', '左侧', '右侧', '两侧都可以', '以上都不对', 'A', '高速公路上超车，应当从前车的左侧超越，右侧超车视线受阻，容易发生交通事故，属于违法行为。', NULL, '高速公路', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1058, 1, 1, '驾驶机动车在道路上行驶，在高速公路上会车时，应当使用什么灯光？', '远光灯', '近光灯', '雾灯', '危险报警闪光灯', 'B', '高速公路上会车时，应当使用近光灯，远光灯会导致对向驾驶人视线受阻，极易引发碰撞事故。', NULL, '高速公路', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1059, 1, 1, '驾驶机动车在道路上行驶，雾天在高速公路行驶，能见度小于50米时，车速不得超过每小时多少公里？', '20公里', '30公里', '40公里', '60公里', 'A', '口诀52离，能见度50米，限速20，赶紧下高速，别在高速上停留。', NULL, '高速公路', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1060, 1, 1, '驾驶机动车在道路上行驶，饮酒后驾驶营运机动车的，吊销机动车驾驶证，几年内不得重新取得？', '2年', '3年', '5年', '终身', 'C', '营运车（比如出租车、货车）酒后驾驶，比普通私家车处罚重，5年不能重考，还要罚款。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1061, 1, 1, '驾驶机动车在道路上行驶，提供虚假材料申领驾驶证，几年内不得再次申请？', '1年', '2年', '3年', '5年', 'A', '提供虚假材料申领驾驶证，1年内不得再次申请，不是3年。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1062, 1, 1, '驾驶机动车在道路上行驶，通过没有交通信号灯的交叉路口，应当遵循什么原则？', '先到先行', '右方来车先行', '左方来车先行', '以上都不对', 'B', '无信号灯路口，不是先到先行，而是遵循“右方来车先行”“让行标志先行”，别搞错了。', NULL, '交通信号', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1063, 1, 3, '驾驶机动车在高速公路上行驶，应当遵守下列哪些规定？', '不得倒车、逆行、穿越中央分隔带掉头', '不得在车道内停车', '不得在匝道、加速车道或者减速车道上超车', '不得骑、轧车行道分界线或者在路肩上行驶', 'ABCD', '以上四项均为高速公路行驶的禁止性规定，违反任何一项均属于违法行为，会被依法处罚。', NULL, '高速公路', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1064, 1, 3, '下列哪些属于紧急情况处置的正确做法？', '车辆发生爆胎时，立即紧急制动', '车辆发生火灾时，立即停车，关闭发动机，用灭火器灭火', '车辆发生碰撞时，驾驶人应当立即系好安全带，保护头部和胸部', '车辆落水时，立即打开车门逃生', 'BC', '车辆发生爆胎时，不能立即紧急制动，应松抬加速踏板，抢挂低速挡，利用发动机制动减速；车辆落水时，应先关闭车窗，待车内进水，内外压力平衡后，再打开车门逃生，否则车门会被水压顶住，无法打开。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1065, 1, 3, '驾驶机动车应当避让的车辆和行人包括哪些？', '执行紧急任务的警车、消防车、救护车、工程救险车', '正在通过人行横道的行人', '正在作业的道路养护车辆、工程作业车', '盲人、残疾人', 'ABCD', '以上四项均为应当避让的对象，不按规定避让的，属于违法行为，会被依法处罚。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1066, 1, 3, '下列关于机动车停放的说法，正确的有哪些？', '不得在禁止停车的路段停车', '不得在人行道上停车', '可以在公交站台内停车', '夜间停车应当开启示廓灯和后位灯', 'ABD', '公交站台内不得停车，属于禁止停车的区域，其他三项均为正确的停车规定。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1067, 1, 3, '下列哪些行为会被记3分？', '驾驶机动车接打手持电话的', '驾驶机动车违反禁令标志、禁止标线指示的', '驾驶机动车在人行横道前不按规定减速、停车、避让行人的', '驾驶机动车在高速公路上不按规定车道行驶的', 'ABCD', '以上四项均一次记3分，并处相应的罚款处罚。', NULL, '记分', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1068, 1, 3, '下列哪些行为会被记1分？', '驾驶机动车不按规定使用安全带的', '驾驶机动车不按规定使用灯光的', '驾驶机动车未放置检验合格标志、保险标志的', '驾驶机动车在道路上行驶，机动车未悬挂机动车号牌的', 'ABC', '机动车未悬挂机动车号牌的，一次记9分，不是1分，其他三项均一次记1分。', NULL, '记分', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1069, 1, 3, '驾驶机动车在道路上发生交通事故，以下做法正确的有哪些？', '立即停车，保护现场', '造成人身伤亡的，立即抢救受伤人员', '迅速报警，等待交警处理', '未造成人身伤亡，仅造成轻微财产损失的，先撤离现场，再协商处理', 'ABCD', '以上四项均为交通事故的正确处理方式，符合《道路交通安全法》的规定。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1070, 1, 3, '驾驶机动车在夜间行驶，以下做法正确的有哪些？', '在没有路灯、照明不良的道路上行驶，开启远光灯', '遇对向有来车时，提前150米将远光灯改为近光灯', '在窄路、窄桥与非机动车会车时，使用近光灯', '夜间超车时，交替使用远近光灯提醒前车', 'ABCD', '以上四项均为夜间行驶的正确灯光使用方法，符合《道路交通安全法实施条例》的规定。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1071, 4, 1, '驾驶机动车在道路上行驶，遇到前方车辆停车排队等候或者缓慢行驶时，以下做法正确的是什么？', '借道超车', '占用对面车道', '穿插等候的车辆', '依次排队行驶', 'D', '前方车辆排队等候或缓慢行驶时，依次排队行驶是正确的做法，其他做法均属于违法行为，会加剧交通拥堵，引发交通事故。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1072, 4, 1, '驾驶机动车在道路上行驶，通过没有交通信号灯的交叉路口，以下做法正确的是什么？', '加速通过', '减速慢行，注意观察，确认安全后通过', '鸣喇叭示意，快速通过', '以上都不对', 'B', '通过没有交通信号灯的交叉路口，应当减速慢行，注意观察，确认安全后通过，其他做法均存在安全隐患，属于违法行为。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1073, 4, 1, '驾驶机动车在道路上行驶，在狭窄的山路会车时，以下做法正确的是什么？', '靠山体的一方让行', '不靠山体的一方让行', '双方都可以不让行', '以上都不对', 'B', '在狭窄的山路会车时，不靠山体的一方应当停车让行，因为靠山体的一方更安全，避免发生坠崖事故。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1074, 4, 3, '驾驶机动车在高速公路上行驶，遇有雾、雨、雪、沙尘、冰雹等低能见度气象条件时，以下做法正确的是什么？', '立即减速，适当加大与前车的安全距离', '开启雾灯、近光灯、示廓灯和前后位灯', '能见度小于50米时，立即驶离高速公路', '在应急车道上停车等待，等待能见度好转', 'ABC', '低能见度气象条件下，应减速慢行，加大安全距离，开启相应的灯光，能见度小于50米时尽快驶离高速；应急车道仅用于紧急情况，不得随意停车等待。', NULL, '高速公路', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1075, 4, 3, '驾驶机动车在道路上发生交通事故，造成人员伤亡，以下做法正确的是什么？', '立即停车，保护现场', '立即抢救受伤人员', '迅速报警，等待交警处理', '立即将车辆移至路边，避免影响交通', 'ABC', '发生交通事故造成人员伤亡时，应立即停车保护现场，抢救伤员，报警等待交警处理；在未固定证据前，不得随意移动车辆，以免破坏现场。', NULL, '事故处理', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1076, 4, 3, '驾驶机动车在夜间行驶，以下做法正确的是什么？', '在没有路灯、照明不良的道路上行驶，开启远光灯', '遇对向有来车时，提前150米将远光灯改为近光灯', '在窄路、窄桥与非机动车会车时，使用近光灯', '夜间超车时，连续使用远光灯对射，提醒前车让行', 'ABC', '夜间行驶时，无路灯照明不良的道路开启远光灯，会车时提前改为近光灯，窄路窄桥会车使用近光灯；夜间超车应交替使用远近光灯提醒前车，不得使用远光灯对射。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1077, 4, 3, '驾驶机动车在山区道路行驶，以下做法正确的是什么？', '上坡路段提前减挡，保持充足的动力', '下坡路段利用发动机制动，避免长时间踩刹车', '弯道处减速慢行，鸣喇叭示意对向车辆', '在狭窄的山路会车时，靠山体的一方让行', 'ABC', '山区道路行驶，上坡提前减挡，下坡利用发动机制动，弯道减速鸣喇叭，都是正确的做法；狭窄山路会车时，不靠山体的一方让行，因为靠山体的一方更安全。', NULL, '文明驾驶', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1078, 4, 3, '驾驶机动车在高速公路上行驶，以下做法错误的是什么？', '在应急车道上行驶', '倒车、逆行、穿越中央分隔带掉头', '在车道内停车，等待朋友', '按照交通标志、标线指示行驶', 'ABC', '在应急车道行驶、高速倒车逆行掉头、在车道内停车等待，均属于严重违法行为；按照交通标志标线指示行驶是正确的做法。', NULL, '高速公路', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1079, 1, 1, '2026年科目一官方题库总量约为多少道题，正式考试时由计算机系统随机抽取100道组成试卷？', '1600', '2309', '3000', '1000', 'B', '根据2026年最新驾考新规，科目一官方题库总量约2309道题，涵盖交通法规、交通信号、安全行车等核心知识点，其他选项均不符合官方公布的题库数量，练题时优先以官方题库为准。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1080, 1, 1, '科目一考试时间为多少分钟，满分100分，合格分数线为90分？', '30', '45', '60', '90', 'B', '科目一考试统一规定时间为45分钟，考生必须在规定时间内完成答题，没答完就视为考试不合格，平时练题可以刻意控制时间，适应考试节奏。', NULL, '记分', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1081, 1, 1, '机动车驾驶人初次取得汽车类准驾车型或者初次取得摩托车类准驾车型后的多长时间为实习期？', '6个月', '12个月', '18个月', '24个月', 'B', '新规明确，初次拿C1、C2或摩托车驾照后的实习期为12个月，实习期内驾驶机动车需遵守相关规定，不得单独上高速等。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1082, 1, 1, '驾驶机动车在道路上行驶时，使用手机拨打或接听手持电话，将被记多少分？', '1分', '2分', '3分', '6分', 'C', '根据《道路交通安全违法行为记分管理办法》，驾驶机动车时有拨打、接听手持电话等妨碍安全驾驶行为的，一次记3分。此为近年高频考点，因“分心驾驶”引发事故率高，执法力度持续加强。', NULL, '记分', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1083, 1, 1, '机动车行经人行横道时，遇行人正在通过，应当如何操作？', '减速慢行，观察后通过', '鸣笛示意行人让行', '停车让行', '加速通过，避免拥堵', 'C', '《道路交通安全法》第四十七条规定：机动车行经人行横道时，应当减速行驶；遇行人正在通过人行横道，应当停车让行。此为“礼让行人”强制性规定，2024年起多地启用AI抓拍，误判即扣3分，是近年最高频考点之一。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1084, 1, 1, '饮酒后驾驶机动车的，处暂扣多长时间机动车驾驶证，并处一千元以上二千元以下罚款？', '一个月以上三个月以下', '三个月以上六个月以下', '六个月以上十二个月以下', '十二个月以上', 'B', '根据《道路交通安全法》规定，饮酒后驾驶机动车的，处暂扣六个月机动车驾驶证，并处一千元以上二千元以下罚款，一次记12分。', NULL, '驾驶证相关', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1085, 1, 1, '驾驶机动车在高速公路上行驶，最低车速不得低于每小时多少公里？', '50', '60', '80', '90', 'B', '高速公路最低车速不得低于60公里/小时，最高车速不得超过120公里/小时，不同车道有不同的车速限制，需按规定行驶。', NULL, '高速公路', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1086, 1, 1, '机动车在道路上发生故障，需要停车排除故障时，驾驶人应当立即开启什么灯，将机动车移至不妨碍交通的地方停放？', '危险报警闪光灯', '示廓灯', '近光灯', '远光灯', 'A', '机动车在道路上发生故障，需要停车排除故障时，首先开启危险报警闪光灯，提醒其他车辆注意，然后将车辆移至不妨碍交通的地方，避免影响其他车辆通行。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1087, 1, 1, '驾驶人在驾驶证有效期满前多长时间申请换证？', '60日内', '30日内', '6个月内', '90日内', 'D', '根据《机动车驾驶证申领和使用规定》，驾驶人应当在驾驶证有效期满前90日内，向驾驶证核发地或者核发地以外的车辆管理所申请换证。', NULL, '驾驶证相关', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1088, 1, 1, '年满20周岁的，不可以初次申请下列哪种准驾车型？', '城市公交车', '小型汽车', '大型客车', '大型货车', 'C', '根据《机动车驾驶证申领和使用规定》，申请大型客车准驾车型的，年龄需在22周岁以上，60周岁以下，因此年满20周岁的，不可以初次申请大型客车准驾车型。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1089, 1, 2, '在高速公路上，可以在应急车道上临时停车休息。', '正确', '错误', NULL, NULL, 'B', '应急车道仅限车辆发生故障、事故或紧急情况时临时停放，非紧急情况不得在应急车道上停车休息，否则属于违法行为，一次记6分。', NULL, '高速公路', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1090, 1, 1, '驾驶机动车在高速公路上行驶，遇能见度小于200米的气象条件时，车速不得超过每小时多少公里？', '40', '60', '80', '100', 'B', '高速低能见度行车有明确规矩，能见度小于200米时，车速不能超60公里/小时，同时要和前车保持100米以上距离，记住“能见度越近，车速越慢”。', NULL, '高速公路', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1091, 1, 1, '下列哪种行为会被一次记12分？', '驾驶机动车不按规定使用灯光的', '驾驶机动车在高速公路上倒车、逆行、穿越中央分隔带掉头的', '驾驶机动车不按规定避让校车的', '驾驶机动车在道路上接打手持电话的', 'B', '驾驶机动车在高速公路上倒车、逆行、穿越中央分隔带掉头的，属于严重违法行为，一次记12分，并处200元罚款。', NULL, '记分', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1092, 1, 1, '驾驶机动车在道路上车辆发生故障、事故停车后，不按规定使用灯光或者设置警告标志的，一次记多少分？', '1分', '3分', '6分', '12分', 'A', '在道路上车辆发生故障、事故停车后，不按规定使用灯光或者设置警告标志的，一次记1分，并处20-200元罚款。', NULL, '记分', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1093, 1, 2, '驾驶机动车在道路上行驶，不得超过限速标志标明的最高时速，在没有限速标志的路段，应当保持安全车速。', '正确', '错误', NULL, NULL, 'A', '根据《道路交通安全法》规定，机动车上道路行驶，不得超过限速标志标明的最高时速。在没有限速标志的路段，应当保持安全车速，该说法正确。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1094, 1, 2, '驾驶机动车在道路上行驶，应当按照交通信号通行；遇有交通警察现场指挥时，应当按照交通警察的指挥通行。', '正确', '错误', NULL, NULL, 'A', '根据《道路交通安全法》规定，车辆、行人应当按照交通信号通行；遇有交通警察现场指挥时，应当按照交通警察的指挥通行，该说法正确。', NULL, '交通信号', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1095, 1, 2, '驾驶机动车在道路上行驶，不得在禁止超车的路段超车。', '正确', '错误', NULL, NULL, 'A', '根据《道路交通安全法》规定，同车道行驶的机动车，后车应当与前车保持足以采取紧急制动措施的安全距离。有下列情形之一的，不得超车：（一）前车正在左转弯、掉头、超车的；（二）与对面来车有会车可能的；（三）前车为执行紧急任务的警车、消防车、救护车、工程救险车的；（四）行经铁路道口、交叉路口、窄桥、弯道、陡坡、隧道、人行横道、市区交通流量大的路段等没有超车条件的，该说法正确。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1096, 1, 2, '驾驶机动车在道路上行驶，不得在禁止停车的路段停车。', '正确', '错误', NULL, NULL, 'A', '根据《道路交通安全法》规定，机动车在道路上临时停车，应当遵守下列规定：（一）在设有禁停标志、标线的路段，在机动车道与非机动车道、人行道之间设有隔离设施的路段以及人行横道、施工地段，不得停车；（二）交叉路口、铁路道口、急弯路、宽度不足4米的窄路、桥梁、陡坡、隧道以及距离上述地点50米以内的路段，不得停车；（三）公共汽车站、急救站、加油站、消防栓或者消防队（站）门前以及距离上述地点30米以内的路段，除使用上述设施的以外，不得停车，该说法正确。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1097, 1, 2, '驾驶机动车在道路上行驶，应当按照规定使用安全带。', '正确', '错误', NULL, NULL, 'A', '根据《道路交通安全法》规定，机动车行驶时，驾驶人、乘坐人员应当按规定使用安全带，摩托车驾驶人及乘坐人员应当按规定戴安全头盔，该说法正确。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1098, 1, 2, '驾驶机动车在道路上行驶，不得在道路上倒车、逆行、穿越中央分隔带掉头。', '正确', '错误', NULL, NULL, 'A', '根据《道路交通安全法》规定，机动车在道路上行驶，不得倒车、逆行、穿越中央分隔带掉头或者在车道内停车，该说法正确。', NULL, '记分', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1099, 1, 2, '驾驶机动车在道路上行驶，不得在道路上骑、轧车行道分界线或者在路肩上行驶。', '正确', '错误', NULL, NULL, 'A', '根据《道路交通安全法》规定，机动车在道路上行驶，不得骑、轧车行道分界线或者在路肩上行驶，该说法正确。', NULL, '记分', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1100, 1, 2, '驾驶机动车在道路上行驶，不得在道路上学习驾驶机动车。', '正确', '错误', NULL, NULL, 'A', '根据《道路交通安全法》规定，在道路上学习驾驶，应当按照公安机关交通管理部门指定的路线、时间进行。在道路上学习机动车驾驶技能应当使用教练车，在教练员随车指导下进行，与教学无关的人员不得乘坐教练车，该说法正确。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1101, 1, 2, '驾驶机动车在道路上行驶，不得在道路上试车或者学习驾驶机动车。', '正确', '错误', NULL, NULL, 'A', '根据《道路交通安全法》规定，机动车在道路上试车，应当按照公安机关交通管理部门指定的路线、时间进行，该说法正确。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1102, 1, 2, '驾驶机动车在道路上行驶，不得在道路上停放车辆，妨碍其他车辆和行人通行。', '正确', '错误', NULL, NULL, 'A', '根据《道路交通安全法》规定，机动车在道路上临时停车，不得妨碍其他车辆和行人通行，该说法正确。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1103, 1, 3, '驾驶机动车在道路上行驶，不得有下列哪些行为？', '在道路上倒车、逆行、穿越中央分隔带掉头', '在道路上骑、轧车行道分界线或者在路肩上行驶', '在道路上学习驾驶机动车', '在道路上试车或者学习驾驶机动车', 'ABCD', '以上四项均为《道路交通安全法》规定的机动车行驶禁止的行为，违反任何一项均属于违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1104, 1, 3, '驾驶机动车在道路上临时停车，应当遵守下列哪些规定？', '在设有禁停标志、标线的路段，不得停车', '交叉路口、铁路道口、急弯路、宽度不足4米的窄路、桥梁、陡坡、隧道以及距离上述地点50米以内的路段，不得停车', '公共汽车站、急救站、加油站、消防栓或者消防队（站）门前以及距离上述地点30米以内的路段，除使用上述设施的以外，不得停车', '不得妨碍其他车辆和行人通行', 'ABCD', '以上四项均为《道路交通安全法》规定的机动车临时停车应当遵守的规定，违反任何一项均属于违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1105, 1, 3, '驾驶机动车在道路上行驶，遇有下列哪些情形的，不得超车？', '前车正在左转弯、掉头、超车的', '与对面来车有会车可能的', '前车为执行紧急任务的警车、消防车、救护车、工程救险车的', '行经铁路道口、交叉路口、窄桥、弯道、陡坡、隧道、人行横道、市区交通流量大的路段等没有超车条件的', 'ABCD', '以上四项均为《道路交通安全法》规定的不得超车的情形，违反任何一项均属于违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1106, 1, 3, '驾驶机动车在道路上行驶，应当按照规定使用的灯光包括哪些？', '夜间行驶，在没有路灯、照明不良的道路上行驶，开启远光灯', '遇对向有来车时，提前150米将远光灯改为近光灯', '在窄路、窄桥与非机动车会车时，使用近光灯', '夜间超车时，交替使用远近光灯提醒前车', 'ABCD', '以上四项均为《道路交通安全法实施条例》规定的机动车灯光使用方法，违反任何一项均属于违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1107, 1, 3, '驾驶机动车在高速公路上行驶，遇有雾、雨、雪、沙尘、冰雹等低能见度气象条件时，应当遵守下列哪些规定？', '能见度小于200米时，车速不得超过每小时60公里，与前车保持100米以上的距离', '能见度小于100米时，车速不得超过每小时40公里，与前车保持50米以上的距离', '能见度小于50米时，车速不得超过每小时20公里，并从最近的出口尽快驶离高速公路', '开启雾灯、近光灯、示廓灯和前后位灯', 'ABCD', '以上四项均为《道路交通安全法实施条例》规定的高速公路低能见度气象条件下的行驶规定，违反任何一项均属于违法行为。', NULL, '高速公路', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1108, 1, 3, '驾驶机动车在道路上发生交通事故，应当遵守下列哪些规定？', '立即停车，保护现场', '造成人身伤亡的，立即抢救受伤人员', '迅速报警，等待交警处理', '未造成人身伤亡，仅造成轻微财产损失的，先撤离现场，再协商处理', 'ABCD', '以上四项均为《道路交通安全法》规定的交通事故处理方式，符合法律规定。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1109, 1, 3, '驾驶机动车在道路上行驶，应当避让的车辆和行人包括哪些？', '执行紧急任务的警车、消防车、救护车、工程救险车', '正在通过人行横道的行人', '正在作业的道路养护车辆、工程作业车', '盲人、残疾人', 'ABCD', '以上四项均为《道路交通安全法》规定的应当避让的对象，不按规定避让的，属于违法行为。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1110, 1, 3, '驾驶机动车在道路上行驶，不得有下列哪些妨碍安全驾驶的行为？', '接打手持电话', '不按规定使用安全带', '违反禁令标志、禁止标线指示', '不按规定使用灯光', 'ABCD', '以上四项均为妨碍安全驾驶的行为，违反任何一项均属于违法行为，会被依法处罚。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1111, 4, 1, '驾驶机动车在道路上行驶，在高速公路上非紧急情况停车的，一次记多少分？', '3分', '6分', '9分', '12分', 'B', '驾驶机动车在高速公路或者城市快速路上违法占用应急车道行驶的，一次记6分，非紧急情况停车属于违法占用应急车道，一次记6分。', NULL, '高速公路', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1112, 1, 1, '驾驶机动车上道路行驶，应当悬挂机动车号牌，放置检验合格标志、保险标志，并随车携带什么证件？', '机动车登记证书', '机动车行驶证', '机动车购车发票', '机动车购置税完税证明', 'B', '根据《中华人民共和国道路交通安全法》第十一条规定，驾驶机动车上道路行驶，应当悬挂机动车号牌，放置检验合格标志、保险标志，并随车携带机动车行驶证。机动车号牌应当按照规定悬挂并保持清晰、完整，不得故意遮挡、污损。A选项机动车登记证书无需随车携带，C、D选项均为车辆登记相关凭证，不强制随车携带，因此正确答案为B。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1113, 1, 1, '申请小型汽车、小型自动挡汽车、残疾人专用小型自动挡载客汽车、轻便摩托车准驾车型的，年龄应在多少周岁以上、70周岁以下？', '16', '18', '20', '22', 'B', '《机动车驾驶证申领和使用规定》第十四条明确，申请小型汽车、小型自动挡汽车、残疾人专用小型自动挡载客汽车、轻便摩托车准驾车型的，在18周岁以上、70周岁以下。16周岁未达到法定驾驶年龄，20周岁、22周岁为大型车辆或其他准驾车型的年龄要求，因此正确答案为B。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1114, 1, 1, '在没有中心隔离设施或中心线的道路上，机动车遇相对方向来车时，应当如何操作？', '加速通过，减少会车时间', '靠右行驶，并与其他车辆、行人保持必要安全距离', '鸣笛示意对方让行', '停车等待对方先通过', 'B', '《道路交通安全法实施条例》第四十八条规定：在没有中心隔离设施或中心线的道路上，机动车遇相对方向来车时，应当减速靠右行驶，并与其他车辆、行人保持必要的安全距离。此为“会车安全”核心考点，常考“靠右”“减速”关键词。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1115, 1, 1, '公安交通管理部门对驾驶人的交通违法行为除依法给予行政处罚外，实行下列哪种制度？', '违法登记制度', '强制报废制度', '累积记分制度', '奖励里程制度', 'C', '根据《道路交通安全法》规定，公安机关交通管理部门对机动车驾驶人违反道路交通安全法律、法规的行为，除依法给予行政处罚外，实行累积记分制度。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1116, 1, 2, '不得驾驶具有安全隐患的机动车上道路行驶。', '正确', '错误', NULL, NULL, 'A', '根据《道路交通安全法》规定，驾驶人驾驶机动车上道路行驶前，应当对机动车的安全技术性能进行认真检查；不得驾驶安全设施不全或者机件不符合技术标准等具有安全隐患的机动车。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1117, 1, 2, '驾驶机动车不按交通信号灯指示通行的，一次记3分。', '正确', '错误', NULL, NULL, 'B', '驾驶机动车不按交通信号灯指示通行（闯红灯），一次记6分，不是3分，并处200元罚款。', NULL, '记分', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1118, 1, 2, '驾驶机动车在高速公路违法占用应急车道行驶的一次记6分。', '正确', '错误', NULL, NULL, 'A', '根据《道路交通安全违法行为记分管理办法》，驾驶机动车在高速公路或者城市快速路上违法占用应急车道行驶的，一次记6分，并处200元罚款。', NULL, '高速公路', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1119, 1, 2, '车速越快，制动距离越短。', '正确', '错误', NULL, NULL, 'B', '车速越快，制动距离越长，这是基本的物理常识，车速越快，车辆的惯性越大，需要的制动距离就越长，因此该说法错误。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1120, 1, 2, '高速公路最右侧车道的最低时速是60公里/小时。', '正确', '错误', NULL, NULL, 'A', '高速公路最右侧车道为慢车道，最低时速不得低于60公里/小时，最高时速不得超过90公里/小时，因此该说法正确。', NULL, '高速公路', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1121, 1, 2, '血液酒精含量达到80mg/100ml属于醉酒驾驶。', '正确', '错误', NULL, NULL, 'A', '根据相关法律规定，血液酒精含量≥80mg/100ml属于醉酒驾驶，涉嫌危险驾驶罪，需承担刑事责任；血液酒精含量≥20mg/100ml属于饮酒驾驶，因此该说法正确。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1122, 1, 3, '驾驶机动车上道路行驶，应当随车携带的证件和标志包括哪些？', '机动车号牌', '检验合格标志', '保险标志', '机动车行驶证', 'ABCD', '根据《中华人民共和国道路交通安全法》第十一条规定，驾驶机动车上道路行驶，应当悬挂机动车号牌，放置检验合格标志、保险标志，并随车携带机动车行驶证，因此以上四项均正确。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1123, 1, 3, '申请机动车驾驶证的人，应当符合下列哪些条件？', '年龄符合规定', '身体条件符合规定', '无妨碍安全驾驶的疾病', '无交通肇事逃逸记录', 'ABC', '申请机动车驾驶证的人，应当符合年龄、身体条件，无妨碍安全驾驶的疾病，交通肇事逃逸记录不属于申请驾驶证的禁止条件，因此正确答案为ABC。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1124, 1, 1, '驾驶机动车在道路上超车时，应当从前车的哪一侧超越？', '左侧', '右侧', '前方', '后方', 'A', '超车只能从左侧超，这是基本规则，右侧超车很危险，容易和对向车相撞，因此正确答案为A。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1125, 1, 1, '机动车驾驶人参加科目一考试，弄虚作假、冒名顶替的，取消本次考试资格，多长时间内不得再次申请考试？', '3个月', '6个月', '1年', '2年', 'C', '考试作弊、冒名顶替，后果很严重，取消资格，1年内不能再考，千万别抱有侥幸心理，因此正确答案为C。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1126, 1, 1, '驾驶机动车载货超过核定载质量30%以上的，一次记多少分？', '3分', '6分', '9分', '12分', 'A', '载货超载30%以上，记3分；超载50%以上才记6分，别记混了，因此正确答案为A。', NULL, '记分', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1127, 1, 1, '红灯亮时，右转弯车辆在什么情况下可以通行？', '只要不影响行人，就可以通行', '任何情况下都可以通行', '任何情况下都不可以通行', '只有在有右转箭头绿灯的情况下才可以通行', 'A', '红灯右转的核心是“不妨碍行人、被放行的车辆通行”，只要不影响行人，就可以通行，因此正确答案为A。', NULL, '交通信号', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1128, 1, 1, '科目一考试满分100分，多少分及以上合格？', '60分', '70分', '80分', '90分', 'D', '科目一考试满分100分，90分及以上合格，少一分都不行，考试时做完一定要检查，因此正确答案为D。', NULL, '记分', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1129, 1, 2, '科目一考试满分100分，90分及以上合格。', '正确', '错误', NULL, NULL, 'A', '记住合格线，90分及格，少一分都不行，考试时做完一定要检查。', NULL, '记分', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1130, 1, 2, '驾驶机动车载货超过核定载质量30%以上的，一次记6分。', '正确', '错误', NULL, NULL, 'B', '载货超载30%以上，记3分；超载50%以上才记6分，别记混了。', NULL, '记分', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1131, 1, 2, '红灯亮时，右转弯车辆只要不影响行人，就可以通行。', '正确', '错误', NULL, NULL, 'A', '和前面单选题对应，红灯右转的核心是“不妨碍行人、被放行的车辆通行”，只要不影响行人，就可以通行。', NULL, '交通信号', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1132, 1, 2, '驾驶人在一个记分周期内累计记分未满12分，所处罚款已经缴纳的，记分予以清除。', '正确', '错误', NULL, NULL, 'A', '根据《记分管理办法》第十九条，记分周期内记分未满12分，且所有罚款已缴清的，记分予以清除。但若存在未处理的违法记录，即使罚款缴清，记分仍保留。', NULL, '记分', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1133, 1, 2, '专用备胎可作为正常轮胎长期使用。', '正确', '错误', NULL, NULL, 'B', '专用备胎通常是非全尺寸轮胎，只能临时使用，不能作为正常轮胎长期使用，否则会影响车辆的行驶安全。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1134, 1, 2, '路面可变导向车道线，可随意选择通行方向。', '正确', '错误', NULL, NULL, 'B', '可变导向车道线是根据交通流量变化调整通行方向的车道，必须按照交通标志、标线的指示方向通行，不能随意选择通行方向。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1135, 1, 2, '驾驶机动车在居民区遇到行人，应连续鸣喇叭示意。', '正确', '错误', NULL, NULL, 'B', '在居民区行驶时，应当低速行驶，注意避让行人，不得连续鸣喇叭示意，以免影响居民的正常生活。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1136, 1, 2, '事故后应先设置警示标志，再抢救伤员。', '正确', '错误', NULL, NULL, 'B', '发生交通事故后，应当首先抢救伤员，然后设置警示标志，报警等待交警处理，救人第一，标志第二。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1137, 1, 2, '禁止左转的路口，禁止掉头。', '正确', '错误', NULL, NULL, 'A', '禁止左转的路口，通常也禁止掉头，因为掉头需要左转，因此禁止左转的路口禁止掉头。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1138, 1, 1, '驾驶机动车发生交通事故后当事人故意破坏、伪造现场、毁灭证据的，应当承担什么责任？', '全部责任', '主要责任', '次要责任', '同等责任', 'A', '根据《道路交通安全法实施条例》规定，当事人故意破坏、伪造现场、毁灭证据的，承担全部责任，因此正确答案为A。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1139, 1, 1, '驾驶机动车在道路上行驶，超过规定时速10%以上未达到20%的，一次记多少分？', '1分', '3分', '6分', '12分', 'A', '根据《道路交通安全违法行为记分管理办法》，驾驶机动车在道路上行驶，超过规定时速10%以上未达到20%的，一次记1分，因此正确答案为A。', NULL, '记分', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1140, 1, 1, '驾驶机动车在道路上行驶，不按规定超车、让行，或者在高速公路、城市快速路以外的道路上逆行的，一次记多少分？', '1分', '3分', '6分', '12分', 'B', '根据《道路交通安全违法行为记分管理办法》，驾驶机动车不按规定超车、让行，或者在高速公路、城市快速路以外的道路上逆行的，一次记3分，因此正确答案为B。', NULL, '高速公路', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1141, 1, 1, '驾驶机动车在道路上行驶，不按规定避让校车的，一次记多少分？', '3分', '6分', '9分', '12分', 'B', '根据《道路交通安全违法行为记分管理办法》，驾驶机动车不按规定避让校车的，一次记6分，因此正确答案为B。', NULL, '记分', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1142, 1, 2, '科目三考试分为道路驾驶技能考试和安全文明驾驶常识考试两部分。', '正确', '错误', NULL, NULL, 'A', '根据《机动车驾驶证申领和使用规定》，科目三考试分为道路驾驶技能考试和安全文明驾驶常识考试两部分，因此该说法正确。', NULL, '记分', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1143, 1, 2, '道路交通安全违法行为累积记分一个周期满分为12分。', '正确', '错误', NULL, NULL, 'A', '根据《道路交通安全法》规定，道路交通安全违法行为累积记分一个周期满分为12分，记分周期为12个月，从机动车驾驶证初次领取之日起计算，因此该说法正确。', NULL, '记分', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1144, 1, 2, '记分满12分的驾驶人拒不参加学习和考试的将被公告驾驶证停止使用。', '正确', '错误', NULL, NULL, 'A', '根据《道路交通安全法实施条例》规定，记分满12分的驾驶人拒不参加学习和考试的，将被公告驾驶证停止使用，因此该说法正确。', NULL, '记分', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1145, 1, 2, '驾驶机动车发生交通事故后当事人故意破坏、伪造现场、毁灭证据的，应当承担全部责任。', '正确', '错误', NULL, NULL, 'A', '根据《道路交通安全法实施条例》规定，当事人故意破坏、伪造现场、毁灭证据的，承担全部责任，因此该说法正确。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1146, 1, 2, '驾驶机动车在道路上行驶，超过规定时速20%以上未达到50%的，一次记6分。', '正确', '错误', NULL, NULL, 'A', '根据《道路交通安全违法行为记分管理办法》，驾驶机动车在道路上行驶，超过规定时速20%以上未达到50%的，一次记6分，因此该说法正确。', NULL, '记分', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1147, 1, 2, '驾驶机动车在道路上行驶，超过规定时速10%以上未达到20%的，一次记1分。', '正确', '错误', NULL, NULL, 'A', '根据《道路交通安全违法行为记分管理办法》，驾驶机动车在道路上行驶，超过规定时速10%以上未达到20%的，一次记1分，因此该说法正确。', NULL, '记分', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1148, 1, 2, '驾驶机动车在道路上行驶，不按规定超车、让行，或者在高速公路、城市快速路以外的道路上逆行的，一次记3分。', '正确', '错误', NULL, NULL, 'A', '根据《道路交通安全违法行为记分管理办法》，驾驶机动车不按规定超车、让行，或者在高速公路、城市快速路以外的道路上逆行的，一次记3分，因此该说法正确。', NULL, '高速公路', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1149, 1, 2, '驾驶机动车在道路上行驶，不按规定避让校车的，一次记6分。', '正确', '错误', NULL, NULL, 'A', '根据《道路交通安全违法行为记分管理办法》，驾驶机动车不按规定避让校车的，一次记6分，因此该说法正确。', NULL, '记分', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1150, 1, 2, '驾驶机动车在道路上行驶，不按规定使用灯光的，一次记1分。', '正确', '错误', NULL, NULL, 'A', '根据《道路交通安全违法行为记分管理办法》，驾驶机动车不按规定使用灯光的，一次记1分，因此该说法正确。', NULL, '记分', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1151, 1, 2, '驾驶机动车应当随身携带驾驶证。', '正确', '错误', NULL, NULL, 'A', '根据《道路交通安全法》规定，驾驶机动车时，应当随身携带机动车驾驶证，因此该说法正确。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1152, 1, 2, '有执行社区戒毒、强制隔离戒毒、社区康复措施记录的，车辆管理所将注销其驾驶证。', '正确', '错误', NULL, NULL, 'A', '根据《机动车驾驶证申领和使用规定》，有执行社区戒毒、强制隔离戒毒、社区康复措施记录的，车辆管理所应当注销其机动车驾驶证，因此该说法正确。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1153, 1, 2, '三年内有吸食、注射毒品行为，不得申请机动车驾驶证。', '正确', '错误', NULL, NULL, 'A', '根据《机动车驾驶证申领和使用规定》，三年内有吸食、注射毒品行为的，不得申请机动车驾驶证，因此该说法正确。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1154, 1, 2, '小型汽车驾驶人发生交通事故造成人员死亡，承担同等以上责任未被吊销驾驶证的，应当在记分周期结束后90日内接受审验。', '正确', '错误', NULL, NULL, 'A', '根据《机动车驾驶证申领和使用规定》，持有小型汽车驾驶证的驾驶人发生交通事故造成人员死亡承担同等以上责任未被吊销机动车驾驶证的，应当在本记分周期结束后三十日内到公安机关交通管理部门接受审验，因此该说法正确。', NULL, '记分', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1155, 1, 2, '申请轻型牵引挂车准驾车型的，年龄应满20周岁。', '正确', '错误', NULL, NULL, 'A', '根据《机动车驾驶证申领和使用规定》，申请轻型牵引挂车准驾车型的，年龄应满20周岁，因此该说法正确。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1156, 1, 2, '造成致人轻伤以上或者死亡的交通事故后逃逸，尚不构成犯罪的，一次记9分。', '正确', '错误', NULL, NULL, 'B', '根据《道路交通安全违法行为记分管理办法》，造成致人轻伤以上或者死亡的交通事故后逃逸，尚不构成犯罪的，一次记12分，不是9分，因此该说法错误。', NULL, '记分', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1157, 1, 2, '驾驶人累计记分达到12分，拒不参加学习且不接受考试的，公安机关交通管理部门将公告其驾驶证停止使用。', '正确', '错误', NULL, NULL, 'A', '根据《机动车驾驶证申领和使用规定》，驾驶人累计记分达到12分，拒不参加学习且不接受考试的，公安机关交通管理部门将公告其驾驶证停止使用，因此该说法正确。', NULL, '记分', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1158, 1, 2, '驾驶机动车在道路上行驶时，使用手机拨打或接听手持电话，将被记3分。', '正确', '错误', NULL, NULL, 'A', '根据《道路交通安全违法行为记分管理办法》，驾驶机动车时有拨打、接听手持电话等妨碍安全驾驶行为的，一次记3分，因此该说法正确。', NULL, '记分', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1159, 1, 1, '申请人以欺骗、贿赂等不正当手段取得机动车驾驶证的（被撤销的），申请人在多长时间内不得再次申领机动车驾驶证？', '3年', '2年', '1年', '6个月', 'A', '根据《机动车驾驶证申领和使用规定》，申请人以欺骗、贿赂等不正当手段取得机动车驾驶证的，公安机关交通管理部门收缴机动车驾驶证，撤销机动车驾驶许可，申请人在3年内不得再次申领机动车驾驶证，因此正确答案为A。', NULL, '驾驶证相关', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1160, 1, 2, '申请人以欺骗、贿赂等不正当手段取得机动车驾驶证的，申请人在3年内不得再次申领机动车驾驶证。', '正确', '错误', NULL, NULL, 'A', '根据《机动车驾驶证申领和使用规定》，申请人以欺骗、贿赂等不正当手段取得机动车驾驶证的，公安机关交通管理部门收缴机动车驾驶证，撤销机动车驾驶许可，申请人在3年内不得再次申领机动车驾驶证，因此该说法正确。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1161, 1, 2, '机动车驾驶证遗失、损毁无法辨认时，机动车驾驶人应当向机动车驾驶证核发地或者核发地以外的车辆管理所申请补发。', '正确', '错误', NULL, NULL, 'A', '根据《机动车驾驶证申领和使用规定》，机动车驾驶证遗失、损毁无法辨认时，机动车驾驶人应当向机动车驾驶证核发地或者核发地以外的车辆管理所申请补发，因此该说法正确。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1162, 1, 2, '驾驶机动车上路前应当检查车辆安全技术性能。', '正确', '错误', NULL, NULL, 'A', '根据《道路交通安全法》规定，驾驶人驾驶机动车上道路行驶前，应当对机动车的安全技术性能进行认真检查；不得驾驶安全设施不全或者机件不符合技术标准等具有安全隐患的机动车，因此该说法正确。', NULL, '安全法', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1163, 1, 2, '饮酒后驾驶机动车，一次记12分。', '正确', '错误', NULL, NULL, 'A', '根据《道路交通安全违法行为记分管理办法》，饮酒后驾驶机动车的，一次记12分，因此该说法正确。', NULL, '记分', '2026-05-17 15:20:56');
INSERT INTO `biz_question` VALUES (1164, 1, 2, '驾驶与准驾车型不符的机动车，不会记12分。', '正确', '错误', NULL, NULL, 'B', '根据《道路交通安全违法行为记分管理办法》，驾驶与准驾车型不符的机动车的，一次记12分，因此该说法错误。', NULL, '记分', '2026-05-17 15:20:56');
